INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111059 AS Decimal(6, 0)), N'79             ', N'ACCIONES CORRECTORAS: El personal conoce las medidas a adoptar en caso de superar los límites establecidos para los parámetros controlados, en los controles mensuales de Limpieza y desinfección.', N'Se comprobará que cuando se superan los valores marcados, el personal conoce las medidas que deben adoptarse en cada caso. Las medidas incluirán la realización de una nueva limpieza y además de solucionar el problema puntual irán encaminadas a evitar que suceda de nuevo, fundamentalmente mediante formación y adiestramiento del personal en las pautas correctas de trabajo o mediante la valoración del cambio de método, producto o frecuencia, acordes a las necesidades propias del establecimiento y actividad.', N'ACCIONES CORRECTORAS: El personal conoce las medidas a adoptar en caso de superar los límites establecidos para los parámetros controlados, en los controles mensuales de Limpieza y desinfección.', N'Se comprobará que cuando se superan los valores marcados, el personal conoce las medidas que deben adoptarse en cada caso. Las medidas incluirán la realización de una nueva limpieza y además de solucionar el problema puntual irán encaminadas a evitar que suceda de nuevo, fundamentalmente mediante formación y adiestramiento del personal en las pautas correctas de trabajo o mediante la valoración del cambio de método, producto o frecuencia, acordes a las necesidades propias del establecimiento y actividad.')
