INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111072 AS Decimal(6, 0)), N'82             ', N'Se realiza analítica de productos finales de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de productos finales, en la que se han definido Las distintas familias de productos elaborados, que se realiza una analítica microbiológica al menos trimestral de un producto final de cada familia de productos, de acuerdo a los criterios legalmente establecidos para cada una de ellas; y que se rotan las familias de productos a lo largo del tiempo.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre la misma familia de productos.', N'Se realiza analítica de productos finales de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de productos finales, en la que se han definido Las distintas familias de productos elaborados, que se realiza una analítica microbiológica al menos trimestral de un producto final de cada familia de productos, de acuerdo a los criterios legalmente establecidos para cada una de ellas; y que se rotan las familias de productos a lo largo del tiempo.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre la misma familia de productos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111073 AS Decimal(6, 0)), N'82             ', N'Se realiza analítica de materias primas de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de materias primas, en la que se han definido los distintos tipos de familias de materias primas de alto riesgo que se utilizan, que se realiza una analítica microbiológica al menos trimestral de una materia prima de cada familia, de acuerdo a sus criterios específicos legalmente establecidos; y que se rotan las familias de materias primas a lo largo del tiempo.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de inciden¬cia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre el mismo tipo de familia de materias primas.', N'Se realiza analítica de materias primas de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de materias primas, en la que se han definido los distintos tipos de familias de materias primas de alto riesgo que se utilizan, que se realiza una analítica microbiológica al menos trimestral de una materia prima de cada familia, de acuerdo a sus criterios específicos legalmente establecidos; y que se rotan las familias de materias primas a lo largo del tiempo.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de inciden¬cia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre el mismo tipo de familia de materias primas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111074 AS Decimal(6, 0)), N'82             ', N'Se realiza analítica de superficies de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de superficies, en la que se han definido las distintas superficies a controlar (que al menos incluyen tablas de corte, encimeras, bandejas, vajilla y utillaje), que se realiza una analítica microbiológica al menos trimestral de un mínimo de cinco superficies tras su limpieza de acuerdo a los siguientes criterios: = 2 enterobacterias/cm2; = 10 aerobios mesófilos/cm2.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de inciden¬cia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre el mismo tipo de superficie', N'Se realiza analítica de superficies de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha establecido una rutina de análisis de superficies, en la que se han definido las distintas superficies a controlar (que al menos incluyen tablas de corte, encimeras, bandejas, vajilla y utillaje), que se realiza una analítica microbiológica al menos trimestral de un mínimo de cinco superficies tras su limpieza de acuerdo a los siguientes criterios: = 2 enterobacterias/cm2; = 10 aerobios mesófilos/cm2.
Se comprobará que, ante un resultado incorrecto, se ha abierto una hoja de inciden¬cia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos análisis realizados sobre el mismo tipo de superficie')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111075 AS Decimal(6, 0)), N'82             ', N'Se mantienen muestras testigo en congelación para poder ser utilizadas como muestras testigo en caso de toxiinfección.', N'Se comprobará que se mantienen muestras testigo en congelación, identificadas (producto y fecha de elaboración), para poder ser utilizadas como muestras testigo en caso de un presunto brote de toxiinfección; que cada muestra testigo consta de una cantidad mínima de 200 gramos; que se encuentra en un envase estéril o desinfectado; y que se mantienen durante un mínimo de 7 días desde su consumo por los comensales del establecimiento.', N'Se mantienen muestras testigo en congelación para poder ser utilizadas como muestras testigo en caso de toxiinfección.', N'Se comprobará que se mantienen muestras testigo en congelación, identificadas (producto y fecha de elaboración), para poder ser utilizadas como muestras testigo en caso de un presunto brote de toxiinfección; que cada muestra testigo consta de una cantidad mínima de 200 gramos; que se encuentra en un envase estéril o desinfectado; y que se mantienen durante un mínimo de 7 días desde su consumo por los comensales del establecimiento.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111076 AS Decimal(6, 0)), N'82             ', N'Se ha implantado un Sistema de estudio de quejas, reclamaciones y sugerencias de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se mantienen registros de todas las quejas, reclamaciones y sugerencias de los clientes; que en estos registros consta el estudio que se ha realizado del problema señalado y de sus posibles causas, las conclusiones y responsables de este estudio, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados para constatar la solución del problema.', N'Se ha implantado un Sistema de estudio de quejas, reclamaciones y sugerencias de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se mantienen registros de todas las quejas, reclamaciones y sugerencias de los clientes; que en estos registros consta el estudio que se ha realizado del problema señalado y de sus posibles causas, las conclusiones y responsables de este estudio, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados para constatar la solución del problema.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111078 AS Decimal(6, 0)), N'82             ', N'Se ha implantado un Plan de Limpieza específico de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se han desarrollado procedimientos de limpieza y desinfección para cada zona y/o equipo, que abarcan todas las instalaciones del establecimiento y contienen información sobre:
- Los productos usados, con sus fichas de seguridad,
- Su forma de aplicación, condiciones de uso y tiempo de actuación,
- La frecuencia de limpieza, que deberá ser al menos la del apartado de limpieza y desinfección general del PGAH,
- La forma de aclarar o eliminar los restos de productos de limpieza.
- Se comprobarán los registros de limpieza, cuya frecuencia mínima será
- Mensual para instalaciones de frecuencia de limpieza inferior al mes, especialmente para las de limpieza diaria.
- Anual para las instalaciones cuya frecuencia de limpieza sea mensual o mayor.
Se comprobará que, ante la detección de un problema de limpieza, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados sobre la limpieza de esa zona o equipo.', N'Se ha implantado un Plan de Limpieza específico de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se han desarrollado procedimientos de limpieza y desinfección para cada zona y/o equipo, que abarcan todas las instalaciones del establecimiento y contienen información sobre:
- Los productos usados, con sus fichas de seguridad,
- Su forma de aplicación, condiciones de uso y tiempo de actuación,
- La frecuencia de limpieza, que deberá ser al menos la del apartado de limpieza y desinfección general del PGAH,
- La forma de aclarar o eliminar los restos de productos de limpieza.
- Se comprobarán los registros de limpieza, cuya frecuencia mínima será
- Mensual para instalaciones de frecuencia de limpieza inferior al mes, especialmente para las de limpieza diaria.
- Anual para las instalaciones cuya frecuencia de limpieza sea mensual o mayor.
Se comprobará que, ante la detección de un problema de limpieza, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados sobre la limpieza de esa zona o equipo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111079 AS Decimal(6, 0)), N'82             ', N'Se ha implantado un Plan de Formación del personal de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se han estudiado las necesidades de formación del personal y que, a partir de ellas, se ha establecido un Plan de Formación anual sobre aspectos complementarios a los obligatorios legalmente sobre higiene y manipulación (por ejemplo, APPCC, trazabilidad, nuevas tecnologías y formas de procesado, sistemática de limpieza).
Se comprobará documentalmente que el Plan de Formación anual vigente abarca a todo el personal que manipula alimentos, que incluye los cursos de formación a recibir durante el año, que sus contenidos incluyen aspectos de seguridad alimentaria y que constan las fechas previstas para la formación.
Se comprobarán los registros de la formación recibida, que demuestran el cumplimiento del Plan de formación e incluyen información sobre:
- Curso impartido. Título y contenidos.
- Fechas del curso. Horas totales.
- Responsables de la formación. Asistentes al curso.
Registros firmados de asistencia', N'Se ha implantado un Plan de Formación del personal de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se han estudiado las necesidades de formación del personal y que, a partir de ellas, se ha establecido un Plan de Formación anual sobre aspectos complementarios a los obligatorios legalmente sobre higiene y manipulación (por ejemplo, APPCC, trazabilidad, nuevas tecnologías y formas de procesado, sistemática de limpieza).
Se comprobará documentalmente que el Plan de Formación anual vigente abarca a todo el personal que manipula alimentos, que incluye los cursos de formación a recibir durante el año, que sus contenidos incluyen aspectos de seguridad alimentaria y que constan las fechas previstas para la formación.
Se comprobarán los registros de la formación recibida, que demuestran el cumplimiento del Plan de formación e incluyen información sobre:
- Curso impartido. Título y contenidos.
- Fechas del curso. Horas totales.
- Responsables de la formación. Asistentes al curso.
Registros firmados de asistencia')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111080 AS Decimal(6, 0)), N'82             ', N'Se ha implantado un Plan de Mantenimiento preventivo específico de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha elaborado un listado de equipos y maquinaria existente sujetos a mantenimiento preventivo (equipos frigoríficos y de calor, campana extractora, lavavajillas, cortadoras, etc.), y que para cada uno de ellos se dispone de Fichas Técnicas o instrucciones de mantenimiento, que incluyen:
- Operaciones de mantenimiento a realizar.
- Frecuencia de cada una.
- Responsables de su ejecución.
Se comprobarán los registros que evidencien esas operaciones de mantenimiento preventivo, a través de partes de trabajo (si lo lleva a cabo un servicio técnico externo) o de un registro de mantenimiento donde conste al menos fecha, equipo, operación realizada, responsable, ajustes realizados o incidencias.
Se comprobará que, ante la detección de un problema en el funcionamiento de un equipo, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados sobre el correcto funcionamiento de ese equipo.', N'Se ha implantado un Plan de Mantenimiento preventivo específico de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha elaborado un listado de equipos y maquinaria existente sujetos a mantenimiento preventivo (equipos frigoríficos y de calor, campana extractora, lavavajillas, cortadoras, etc.), y que para cada uno de ellos se dispone de Fichas Técnicas o instrucciones de mantenimiento, que incluyen:
- Operaciones de mantenimiento a realizar.
- Frecuencia de cada una.
- Responsables de su ejecución.
Se comprobarán los registros que evidencien esas operaciones de mantenimiento preventivo, a través de partes de trabajo (si lo lleva a cabo un servicio técnico externo) o de un registro de mantenimiento donde conste al menos fecha, equipo, operación realizada, responsable, ajustes realizados o incidencias.
Se comprobará que, ante la detección de un problema en el funcionamiento de un equipo, se ha abierto una hoja de incidencia, donde consta el problema detectado, las causas que previsiblemente lo han originado, lo que se ha hecho para solucionarlo y, en su caso, los resultados de nuevos controles realizados sobre el correcto funcionamiento de ese equipo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111081 AS Decimal(6, 0)), N'82             ', N'Se ha implantado un Sistema de trazabilidad de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha desarrollado un sistema de trazabilidad capaz de identificar tanto las materias primas como los productos terminados, relacionando ambos entre si.
Para comprobar su implantación, se hará un ejercicio de trazabilidad con un producto final elegido al azar, para el que se deberá poder identificar exactamente las materias primas con las que se elaboró, a partir de la documentación de trazabilidad. Y otro ejercicio de trazabilidad a partir de una partida de materia prima elegida al azar, para la que se deberá poder identificar exactamente los productos finales en que fue utilizada, a partir de la documentación de trazabilidad', N'Se ha implantado un Sistema de trazabilidad de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha desarrollado un sistema de trazabilidad capaz de identificar tanto las materias primas como los productos terminados, relacionando ambos entre si.
Para comprobar su implantación, se hará un ejercicio de trazabilidad con un producto final elegido al azar, para el que se deberá poder identificar exactamente las materias primas con las que se elaboró, a partir de la documentación de trazabilidad. Y otro ejercicio de trazabilidad a partir de una partida de materia prima elegida al azar, para la que se deberá poder identificar exactamente los productos finales en que fue utilizada, a partir de la documentación de trazabilidad')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111082 AS Decimal(6, 0)), N'82             ', N'Se ha realizado una calibración del termómetro portátil de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha sometido el termómetro portátil usado para los controles de temperatura del PGAH a una calibración formal con una periodicidad al menos bianual. Se constatará el cumplimiento de este punto mediante la revisión de su certificado de calibración, donde se identifique inequívocamente el termómetro calibrado, el resultado de la calibración y su fecha.', N'Se ha realizado una calibración del termómetro portátil de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se ha sometido el termómetro portátil usado para los controles de temperatura del PGAH a una calibración formal con una periodicidad al menos bianual. Se constatará el cumplimiento de este punto mediante la revisión de su certificado de calibración, donde se identifique inequívocamente el termómetro calibrado, el resultado de la calibración y su fecha.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(1 AS Decimal(3, 0)), CAST(1 AS Decimal(6, 0)), N'1              ', N'El emplazamiento del establecimiento y las medidas para su aislamiento no suponen un grave problema o amenaza para la contaminación de los alimentos que se manipulan, almacenan o comercializan.', N'Se valorarán las posibles fuentes de contaminación, así como la eficacia de cualesquiera de las medidas que hayan de adoptarse para proteger los alimentos. Los establecimientos no se ubicarán en un lugar donde, tras considerar dichas medidas protectoras, sea evidente que existe una amenaza para la inocuidad o aptitud de los alimentos o en zonas cuyo medio ambiente esta contaminado con actividades que constituyan una amenaza grave de contaminación de los alimentos.', N'El emplazamiento del establecimiento y las medidas para su aislamiento no suponen un grave problema o amenaza para la contaminación de los alimentos que se manipulan, almacenan o comercializan.', N'Se valorarán las posibles fuentes de contaminación, así como la eficacia de cualesquiera de las medidas que hayan de adoptarse para proteger los alimentos. Los establecimientos no se ubicarán en un lugar donde, tras considerar dichas medidas protectoras, sea evidente que existe una amenaza para la inocuidad o aptitud de los alimentos o en zonas cuyo medio ambiente esta contaminado con actividades que constituyan una amenaza grave de contaminación de los alimentos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(2 AS Decimal(3, 0)), CAST(3 AS Decimal(6, 0)), N'2              ', N'Las vías de acceso no permiten el cúmulo de charcos y poseen desagües que permiten la evacuación del agua de lluvia y la generada en operaciones de limpieza.', N'Dispondrán de desagües necesarios para la recogida y evacuación de las aguas procedentes de la lluvia o de la limpieza, así como los medios de limpieza necesarios.', N'Las vías de acceso no permiten el cúmulo de charcos y poseen desagües que permiten la evacuación del agua de lluvia y la generada en operaciones de limpieza.', N'Dispondrán de desagües necesarios para la recogida y evacuación de las aguas procedentes de la lluvia o de la limpieza, así como los medios de limpieza necesarios.')
