INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(2 AS Decimal(3, 0)), CAST(2 AS Decimal(6, 0)), N'2              ', N'Las vías de acceso hasta el establecimiento, están cubiertas por una superficie pavimentada apta para el trafico rodado y el transito de personas.', N'Las vías de acceso (carreteras, calles, caminos, etc.), y las zonas de tránsito que se encuentran dentro del recinto de las instalaciones o sus inmediaciones, utilizadas por vehículos y personal propio y ajeno del establecimiento, hasta la entrada en los locales e instalaciones del mismo, tendrán una superficie dura y pavimentada, apta para el trafico rodado.', N'Las vías de acceso hasta el establecimiento, están cubiertas por una superficie pavimentada apta para el trafico rodado y el transito de personas.', N'Las vías de acceso (carreteras, calles, caminos, etc.), y las zonas de tránsito que se encuentran dentro del recinto de las instalaciones o sus inmediaciones, utilizadas por vehículos y personal propio y ajeno del establecimiento, hasta la entrada en los locales e instalaciones del mismo, tendrán una superficie dura y pavimentada, apta para el trafico rodado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(3 AS Decimal(3, 0)), CAST(5 AS Decimal(6, 0)), N'3              ', N'El dise¦o y la disposición de los locales, permiten la completa limpieza y desinfección de los mismos y evita el depósito de suciedad.', N'El dise¦o y la disposición, permitirán una limpieza y desinfección fácil y adecuada y evitará el depósito de suciedad.', N'El dise¦o y la disposición de los locales, permiten la completa limpieza y desinfección de los mismos y evita el depósito de suciedad.', N'El dise¦o y la disposición, permitirán una limpieza y desinfección fácil y adecuada y evitará el depósito de suciedad.')
