INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(3 AS Decimal(3, 0)), CAST(6 AS Decimal(6, 0)), N'3              ', N'La proyección y dise¦o de los locales, evita el acceso de animales indeseables y contaminantes del medio.', N'Se tendrá en cuenta, que los edificios e instalaciones se proyecten de tal manera, que se impida que entren animales indeseables y contaminantes del medio (polvo, humos, etc.).', N'La proyección y dise¦o de los locales, evita el acceso de animales indeseables y contaminantes del medio.', N'Se tendrá en cuenta, que los edificios e instalaciones se proyecten de tal manera, que se impida que entren animales indeseables y contaminantes del medio (polvo, humos, etc.).')
