INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(6 AS Decimal(3, 0)), CAST(23 AS Decimal(6, 0)), N'6              ', N'Dispone de abastecimiento suficiente de agua para todo el procesado de los alimentos y de las actividades relacionadas con el mismo y es potable según normativa vigente.', N'Dispondrá de abastecimiento suficiente de agua potable fría y caliente, con instalaciones apropiadas para su almacenamiento, distribución y control de la temperatura, a fin de asegurar, en caso necesario, la inocuidad y la aptitud de los alimentos.
El agua potable se ajustará a lo especificado en la legislación vigente, relativa al agua de consumo público. El desvío puntual de alguno de los parámetros especificados en la legislación, no se recogerá como incumplimiento, siempre y cuando se tomen las medidas necesarias para su corrección.', N'Dispone de abastecimiento suficiente de agua para todo el procesado de los alimentos y de las actividades relacionadas con el mismo y es potable según normativa vigente.', N'Dispondrá de abastecimiento suficiente de agua potable fría y caliente, con instalaciones apropiadas para su almacenamiento, distribución y control de la temperatura, a fin de asegurar, en caso necesario, la inocuidad y la aptitud de los alimentos.
El agua potable se ajustará a lo especificado en la legislación vigente, relativa al agua de consumo público. El desvío puntual de alguno de los parámetros especificados en la legislación, no se recogerá como incumplimiento, siempre y cuando se tomen las medidas necesarias para su corrección.')
GO
