INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(8 AS Decimal(3, 0)), CAST(32 AS Decimal(6, 0)), N'8              ', N'La intensidad de luz será suficiente y acorde a las exigencias visuales de las tareas realizadas en los distintos locales.', N'Al evaluar la iluminación se tendrá en cuenta la suma de la iluminación natural y artificial. La distribución será uniforme y estará completada con luces localizadas en zonas concretas que requieren niveles de iluminación elevados. La intensidad de luz será suficiente y acorde a las exigencias visuales de las tareas realizadas en los distintos locales.', N'La intensidad de luz será suficiente y acorde a las exigencias visuales de las tareas realizadas en los distintos locales.', N'Al evaluar la iluminación se tendrá en cuenta la suma de la iluminación natural y artificial. La distribución será uniforme y estará completada con luces localizadas en zonas concretas que requieren niveles de iluminación elevados. La intensidad de luz será suficiente y acorde a las exigencias visuales de las tareas realizadas en los distintos locales.')
