INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(9 AS Decimal(3, 0)), CAST(37 AS Decimal(6, 0)), N'9              ', N'Los sistemas de ventilación forzada están construidos de forma que se facilita su limpieza.', N'Los sistemas de ventilación forzada estarán construidos de forma que se pueda acceder fácilmente a todos sus componentes para su limpieza.', N'Los sistemas de ventilación forzada están construidos de forma que se facilita su limpieza.', N'Los sistemas de ventilación forzada estarán construidos de forma que se pueda acceder fácilmente a todos sus componentes para su limpieza.')
