INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(9 AS Decimal(3, 0)), CAST(35 AS Decimal(6, 0)), N'9              ', N'Ventilación de acuerdo a las características generales sobre ventilación descritas en este punto.', N'La valoración de los sistemas de ventilación, tendrá en cuenta el tama¦o de los locales, el volumen y tipo de actividad así como los sistemas y modos de ventilación utilizados. Una correcta ventilación se valorará como tal, cuando en el local se evite, según los distintos casos, bien la presencia de humo ambiental, la presencia de olores desagradables impropios de la actividad o local, fenómenos de condensación con presencia de gotas de agua, crecimientos de moho en paredes o techos, acumulación de grasa o incrementos de temperaturas de los propios locales que puedan incidir en las características organolépticas, fisico-químicas del producto o faciliten la multiplicación bacteriana en el mismo. La temperatura tampoco deberá influir en la higiene del personal y en la manipulación de los alimentos (sudoración).', N'Ventilación de acuerdo a las características generales sobre ventilación descritas en este punto.', N'La valoración de los sistemas de ventilación, tendrá en cuenta el tama¦o de los locales, el volumen y tipo de actividad así como los sistemas y modos de ventilación utilizados. Una correcta ventilación se valorará como tal, cuando en el local se evite, según los distintos casos, bien la presencia de humo ambiental, la presencia de olores desagradables impropios de la actividad o local, fenómenos de condensación con presencia de gotas de agua, crecimientos de moho en paredes o techos, acumulación de grasa o incrementos de temperaturas de los propios locales que puedan incidir en las características organolépticas, fisico-químicas del producto o faciliten la multiplicación bacteriana en el mismo. La temperatura tampoco deberá influir en la higiene del personal y en la manipulación de los alimentos (sudoración).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(62 AS Decimal(6, 0)), N'13             ', N'Los sistemas de extracción de humos y vapores tienen filtros para grasas/partículas.', N'Los sistemas de extracción dispondrán de potencia, que permita que durante el momento de mayor actividad, no se aprecie la presencia de humos o vapores. Dispondrán de sistema de recogida de humos y vapores (campana) que cubra toda la zona de producción de humos, y sistemas de filtrado de grasas/partículas.', N'Los sistemas de extracción de humos y vapores tienen filtros para grasas/partículas.', N'Los sistemas de extracción dispondrán de potencia, que permita que durante el momento de mayor actividad, no se aprecie la presencia de humos o vapores. Dispondrán de sistema de recogida de humos y vapores (campana) que cubra toda la zona de producción de humos, y sistemas de filtrado de grasas/partículas.')
GO
