INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(48 AS Decimal(6, 0)), N'11             ', N'El almacenamiento se hace de forma que se permite una separación física adecuada que evita el contacto entre alimentos incompatibles entre sí, productos embalados con los sin embalar, materias primas con productos intermedios, materias primas susceptibles????', N'El volumen y estructura permitirá una separación física adecuada que evite el contacto entre alimentos incompatibles entre sí, productos embalados sin embalar, materias primas con productos intermedios, materias primas susceptibles de transmitir olores o sabores.
La estiba impedirá el almacenamiento de productos directamente sobre el suelo, contra paredes o techo y facilitará la circulación de aire entre los productos.
Cuando las instalaciones tengan limitados por el fabricante límites de carga, (ej. expositores), los alimentos almacenados no sobrepasarán tales límites.', N'El almacenamiento se hace de forma que se permite una separación física adecuada que evita el contacto entre alimentos incompatibles entre sí, productos embalados con los sin embalar, materias primas con productos intermedios, materias primas susceptibles????', N'El volumen y estructura permitirá una separación física adecuada que evite el contacto entre alimentos incompatibles entre sí, productos embalados sin embalar, materias primas con productos intermedios, materias primas susceptibles de transmitir olores o sabores.
La estiba impedirá el almacenamiento de productos directamente sobre el suelo, contra paredes o techo y facilitará la circulación de aire entre los productos.
Cuando las instalaciones tengan limitados por el fabricante límites de carga, (ej. expositores), los alimentos almacenados no sobrepasarán tales límites.')
GO
