INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(39 AS Decimal(6, 0)), N'10             ', N'Los materiales utilizados en la fabricación de equipos y utensilios son inocuos, atóxicos.', N'Los materiales utilizados en la fabricación de equipos y utensilios serán resistentes a la corrosión, de fácil limpieza y desinfección, impermeables, inocuos y atóxicos de forma que no puedan transmitir contaminación química a los alimentos.
 Siempre que los productos estén sin proteger, no se usará madera en la fabricación de utensilios, excepto en el caso de las trancaderas para la carne y en las mesas para el manipulado de masas panarias, en caso de carnes embaladas y en los locales de ahumado y curado.', N'Los materiales utilizados en la fabricación de equipos y utensilios son inocuos, atóxicos.', N'Los materiales utilizados en la fabricación de equipos y utensilios serán resistentes a la corrosión, de fácil limpieza y desinfección, impermeables, inocuos y atóxicos de forma que no puedan transmitir contaminación química a los alimentos.
 Siempre que los productos estén sin proteger, no se usará madera en la fabricación de utensilios, excepto en el caso de las trancaderas para la carne y en las mesas para el manipulado de masas panarias, en caso de carnes embaladas y en los locales de ahumado y curado.')
GO
