INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(45 AS Decimal(6, 0)), N'11             ', N'El establecimiento dispone de las instalaciones frigoríficas necesarias para su actividad y la capacidad es acorde a su volumen de trabajo.', N'El establecimiento dispondrá de instalaciones frigoríficas acordes a su tipo de actividad. La capacidad será acorde a su volumen de trabajo. Todo producto que se encuentre en la empresa susceptible de mantenerse a temperatura de refrigeración o congelación se almacenará en tales condiciones y además la estiba de los productos así almacenados, permitirá la correcta circulación del aire entre ellos.', N'El establecimiento dispone de las instalaciones frigoríficas necesarias para su actividad y la capacidad es acorde a su volumen de trabajo.', N'El establecimiento dispondrá de instalaciones frigoríficas acordes a su tipo de actividad. La capacidad será acorde a su volumen de trabajo. Todo producto que se encuentre en la empresa susceptible de mantenerse a temperatura de refrigeración o congelación se almacenará en tales condiciones y además la estiba de los productos así almacenados, permitirá la correcta circulación del aire entre ellos.')
GO
