INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(57 AS Decimal(6, 0)), N'12             ', N'Sistema de accionamiento de los lavamanos es a pedal, rodilla o cédula fotoeléctrica.', N'El accionamiento de los lavamanos no permitirá la recontaminación de las manos una vez limpias. Se admitirán los accionamientos a pedal, rodilla, cédula fotoeléctrica. No se admitirán aquellos de accionamiento manual típicos ni aquellos denominados como de codo.', N'Sistema de accionamiento de los lavamanos es a pedal, rodilla o cédula fotoeléctrica.', N'El accionamiento de los lavamanos no permitirá la recontaminación de las manos una vez limpias. Se admitirán los accionamientos a pedal, rodilla, cédula fotoeléctrica. No se admitirán aquellos de accionamiento manual típicos ni aquellos denominados como de codo.')
