INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(10 AS Decimal(3, 0)), CAST(56 AS Decimal(6, 0)), N'12             ', N'El número de lavamanos y su ubicación permiten que los trabajadores no se desplacen de su zona o local de trabajo, además de estar situados también en aquellas zonas de situación obligatoria.', N'Dispondrá de un número y ubicación de lavamanos que permita que los trabajadores no deban desplazarse de su zona o locales de trabajo, además de aquellos de situación obligatoria (cocinas, aseos, obradores, muelles, local de despiece, de envasado, etc.).
Los puntos a inspeccionar en el apartado de lavamanos no se limitan al utensilio en sí sino al conjunto de utensilios que obligatoriamente deben acompa¦ar al lavamanos, así como a su número y distribución.
', N'El número de lavamanos y su ubicación permiten que los trabajadores no se desplacen de su zona o local de trabajo, además de estar situados también en aquellas zonas de situación obligatoria.', N'Dispondrá de un número y ubicación de lavamanos que permita que los trabajadores no deban desplazarse de su zona o locales de trabajo, además de aquellos de situación obligatoria (cocinas, aseos, obradores, muelles, local de despiece, de envasado, etc.).
Los puntos a inspeccionar en el apartado de lavamanos no se limitan al utensilio en sí sino al conjunto de utensilios que obligatoriamente deben acompa¦ar al lavamanos, así como a su número y distribución.
')
