INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(11 AS Decimal(3, 0)), CAST(81 AS Decimal(6, 0)), N'17             ', N'Los servicios higiénicos y los vestuarios/anteaseo/zona de aseo son suficientes y acordes a las necesidades del establecimiento.', N'Los servicios y vestuarios serán acordes a las necesidades del establecimiento. Este hecho será valorado por quien realiza la inspección, que valorará  el tama¦o y la capacidad.', N'Los servicios higiénicos y los vestuarios/anteaseo/zona de aseo son suficientes y acordes a las necesidades del establecimiento.', N'Los servicios y vestuarios serán acordes a las necesidades del establecimiento. Este hecho será valorado por quien realiza la inspección, que valorará  el tama¦o y la capacidad.')
