INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(11 AS Decimal(3, 0)), CAST(71 AS Decimal(6, 0)), N'16             ', N'Dispone de servicios higiénicos de acuerdo a los criterios establecidos.', N'Los establecimientos alimentarios dispondrán de servicios higiénicos, que serán exclusivos para el personal manipulador. Esta exclusividad de uso para el personal manipulador no se aplicará a los grupos 0 y I de comedores colectivos y platos preparados, ni a los establecimientos minoristas, incluidas carnicerías y pescaderías, dado que pueden ser  utilizados por otro tipo de  personal. En aquellos establecimientos que se encuentren agrupados en centros y galerías comerciales, mercados, etc. ,se podrá computar como servicios higiénicos aquellos que son comunes para todo el personal trabajador.', N'Dispone de servicios higiénicos de acuerdo a los criterios establecidos.', N'Los establecimientos alimentarios dispondrán de servicios higiénicos, que serán exclusivos para el personal manipulador. Esta exclusividad de uso para el personal manipulador no se aplicará a los grupos 0 y I de comedores colectivos y platos preparados, ni a los establecimientos minoristas, incluidas carnicerías y pescaderías, dado que pueden ser  utilizados por otro tipo de  personal. En aquellos establecimientos que se encuentren agrupados en centros y galerías comerciales, mercados, etc. ,se podrá computar como servicios higiénicos aquellos que son comunes para todo el personal trabajador.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(11 AS Decimal(3, 0)), CAST(73 AS Decimal(6, 0)), N'16             ', N'Existe vestuario/anteaseo/zona de aseo que evita la comunicación del servicio higiénico con zonas de manipulación o almacenamiento de alimentos.', N'El servicio higiénico no podrá comunicar directamente con los locales donde se manipulen y almacenen alimentos, por lo que debe existir un vestuario/anteaseo/zona de aseo.', N'Existe vestuario/anteaseo/zona de aseo que evita la comunicación del servicio higiénico con zonas de manipulación o almacenamiento de alimentos.', N'El servicio higiénico no podrá comunicar directamente con los locales donde se manipulen y almacenen alimentos, por lo que debe existir un vestuario/anteaseo/zona de aseo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(11 AS Decimal(3, 0)), CAST(78 AS Decimal(6, 0)), N'17             ', N'Los vestuarios/anteaseo/zona de aseo disponen de lavamanos y taquillas individuales para cada trabajador y de tama¦o y capacidad suficiente para guardar toda la ropa y calzado de forma ordenada.', N'Los vestuarios/anteaseo/zona de aseo dispondrán de lavamanos de características similares a las descritas en la IT 10, y taquillas individuales para cada trabajador y de tama¦o y capacidad suficiente para guardar toda la ropa y calzado, de forma ordenada. Los establecimientos que se encuentren agrupados en centros y galerías comerciales, mercados, etc. , que disponen de servicios higiénicos comunes y exclusivos para el personal manipulador, cabe la posibilidad de que o bien dispongan de vestuarios exclusivos o, en su defecto, se permitirá que la taquilla se pueda colocar en la trastienda o en la sala de ventas.', N'Los vestuarios/anteaseo/zona de aseo disponen de lavamanos y taquillas individuales para cada trabajador y de tama¦o y capacidad suficiente para guardar toda la ropa y calzado de forma ordenada.', N'Los vestuarios/anteaseo/zona de aseo dispondrán de lavamanos de características similares a las descritas en la IT 10, y taquillas individuales para cada trabajador y de tama¦o y capacidad suficiente para guardar toda la ropa y calzado, de forma ordenada. Los establecimientos que se encuentren agrupados en centros y galerías comerciales, mercados, etc. , que disponen de servicios higiénicos comunes y exclusivos para el personal manipulador, cabe la posibilidad de que o bien dispongan de vestuarios exclusivos o, en su defecto, se permitirá que la taquilla se pueda colocar en la trastienda o en la sala de ventas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(11 AS Decimal(3, 0)), CAST(75 AS Decimal(6, 0)), N'16             ', N'La correcta ventilación evita la presencia de olores desagradables, humedad, condensación.', N'Dispondrán de ventilación natural o forzada que cumplan con los requisitos y funciones descritas en la IT general para la ventilación de tal modo que se eviten olores desagradables, humedad, condensación.', N'La correcta ventilación evita la presencia de olores desagradables, humedad, condensación.', N'Dispondrán de ventilación natural o forzada que cumplan con los requisitos y funciones descritas en la IT general para la ventilación de tal modo que se eviten olores desagradables, humedad, condensación.')
