INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(12 AS Decimal(3, 0)), CAST(90 AS Decimal(6, 0)), N'20             ', N'En las zonas donde se manipulan alimentos no se observan prácticas antihigiénicas.', N'En las zonas donde se manipulen alimentos, estará prohibido todo acto que pueda dar lugar a una contaminación de los mismos, como comer, fumar, escupir, mascar chicle u otras prácticas antihigiénicas.', N'En las zonas donde se manipulan alimentos no se observan prácticas antihigiénicas.', N'En las zonas donde se manipulen alimentos, estará prohibido todo acto que pueda dar lugar a una contaminación de los mismos, como comer, fumar, escupir, mascar chicle u otras prácticas antihigiénicas.')
