INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(12 AS Decimal(3, 0)), CAST(86 AS Decimal(6, 0)), N'20             ', N'Se realiza el lavado, de manos/guantes cuando es necesario durante la manipulación.', N'Se realizará el lavado y desinfección de manos, siempre que su grado de suciedad pueda afectar a la inocuidad de los alimentos, y siempre: al inicio del trabajo, antes de incorporarse a su puesto de trabajo, después de una ausencia, después de usar el retrete, después de manipular alimentos crudos o cualquier otro material susceptible de producir contaminación. Si para manipular los alimentos se emplean guantes, éstos se mantendrán en perfectas condiciones de limpieza e higiene, y se realizará el lavado frecuente de los mismos, siguiendo los mismos criterios que para el lavado de manos. Si se utilizan guantes desechables, se renovarán al menos en cada jornada laboral.', N'Se realiza el lavado, de manos/guantes cuando es necesario durante la manipulación.', N'Se realizará el lavado y desinfección de manos, siempre que su grado de suciedad pueda afectar a la inocuidad de los alimentos, y siempre: al inicio del trabajo, antes de incorporarse a su puesto de trabajo, después de una ausencia, después de usar el retrete, después de manipular alimentos crudos o cualquier otro material susceptible de producir contaminación. Si para manipular los alimentos se emplean guantes, éstos se mantendrán en perfectas condiciones de limpieza e higiene, y se realizará el lavado frecuente de los mismos, siguiendo los mismos criterios que para el lavado de manos. Si se utilizan guantes desechables, se renovarán al menos en cada jornada laboral.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(12 AS Decimal(3, 0)), CAST(84 AS Decimal(6, 0)), N'19             ', N'Dispone de indumentaria completa y limpia en cualquier momento del proceso productivo de acuerdo con las características descritas en este punto.', N'Al comienzo de cada jornada laboral, el personal dispondrá y utilizará vestimenta completa, con mangas, clara, limpia y de uso exclusivo. Además dispondrá a lo largo de la jornada laboral, de otra indumentaria si fuera necesario, bien porque la que está utilizando esté excesivamente sucia o porque cambie de actividad a otra más limpia, o por cualquier otro motivo por el que se puedan producir contaminaciones. El calzado/botas será de fácil limpieza y desinfección.', N'Dispone de indumentaria completa y limpia en cualquier momento del proceso productivo de acuerdo con las características descritas en este punto.', N'Al comienzo de cada jornada laboral, el personal dispondrá y utilizará vestimenta completa, con mangas, clara, limpia y de uso exclusivo. Además dispondrá a lo largo de la jornada laboral, de otra indumentaria si fuera necesario, bien porque la que está utilizando esté excesivamente sucia o porque cambie de actividad a otra más limpia, o por cualquier otro motivo por el que se puedan producir contaminaciones. El calzado/botas será de fácil limpieza y desinfección.')
GO
