GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(12 AS Decimal(3, 0)), CAST(87 AS Decimal(6, 0)), N'20             ', N'Se realiza el lavado correcto de manos/guantes. ', N'Las manos se lavarán bajo un flujo de agua tibia, enjabonadas y friccionadas durante al menos 15 segundos, posteriormente se enjuagarán y se secarán con toalla desechable de un solo uso o bajo aire caliente ( si no se trata de zonas de manipulación).', N'Se realiza el lavado correcto de manos/guantes. ', N'Las manos se lavarán bajo un flujo de agua tibia, enjabonadas y friccionadas durante al menos 15 segundos, posteriormente se enjuagarán y se secarán con toalla desechable de un solo uso o bajo aire caliente ( si no se trata de zonas de manipulación).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(106 AS Decimal(6, 0)), N'22             ', N'Los locales o zonas de limpieza específicas, se mantienen separadas de las zonas de manipulación, de forma que se evitan contaminaciones y salpicaduras', N'Cuando existan locales o zonas de limpieza específicas, estas se mantendrán separadas de las zonas de manipulación, de forma que se eviten contaminaciones y salpicaduras.', N'Los locales o zonas de limpieza específicas, se mantienen separadas de las zonas de manipulación, de forma que se evitan contaminaciones y salpicaduras', N'Cuando existan locales o zonas de limpieza específicas, estas se mantendrán separadas de las zonas de manipulación, de forma que se eviten contaminaciones y salpicaduras.')
