INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(104 AS Decimal(6, 0)), N'21             ', N'El personal cumple las condiciones técnicas de uso y conoce y cumple con las precauciones de uso.', N'El personal que utilice los productos de limpieza, cumplirá las condiciones técnicas de utilización de los productos y conocerá y cumplirá las precauciones de uso.', N'El personal cumple las condiciones técnicas de uso y conoce y cumple con las precauciones de uso.', N'El personal que utilice los productos de limpieza, cumplirá las condiciones técnicas de utilización de los productos y conocerá y cumplirá las precauciones de uso.')
