INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(105 AS Decimal(6, 0)), N'21             ', N'En la zona de manipulación no se encuentra ninguna sustancia tóxica que pueda contaminar los alimentos, salvo que puntualmente sea necesaria por razones de higiene', N'No se encontrará en la zona de manipulación, ninguna sustancia tóxica que pueda contaminar los alimentos, salvo que puntualmente sea necesario por razones de higiene.', N'En la zona de manipulación no se encuentra ninguna sustancia tóxica que pueda contaminar los alimentos, salvo que puntualmente sea necesaria por razones de higiene', N'No se encontrará en la zona de manipulación, ninguna sustancia tóxica que pueda contaminar los alimentos, salvo que puntualmente sea necesario por razones de higiene.')
