INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(95 AS Decimal(6, 0)), N'21             ', N'La limpieza de zonas relevantes se lleva a cabo de modo que se cumple con los requisitos exigidos.', N'El establecimiento mantendrá en todos sus locales y utensilios un estado de limpieza correcto y acorde a la actividad y uso de la zona o local. Durante la inspección visual, se determinará la ausencia de residuos o suciedad distintas a la actividad normal e inmediata,  propias del local o zona y del tipo de establecimiento, recordando que incluye la prohibición de esparcir sobre el suelo, serrín o sustancias similares y distintas a las propiamente autorizadas.
De forma más concreta, en las zonas donde se manipulen alimentos se valorará la presencia de manchas detectables al tacto, manchas visibles, granulaciones en superficies, restos superficiales de grasa y restos sólidos, no admitiendo como limpieza suficiente cuando se aprecie alguno de los puntos antes expuestos. ', N'La limpieza de zonas relevantes se lleva a cabo de modo que se cumple con los requisitos exigidos.', N'El establecimiento mantendrá en todos sus locales y utensilios un estado de limpieza correcto y acorde a la actividad y uso de la zona o local. Durante la inspección visual, se determinará la ausencia de residuos o suciedad distintas a la actividad normal e inmediata,  propias del local o zona y del tipo de establecimiento, recordando que incluye la prohibición de esparcir sobre el suelo, serrín o sustancias similares y distintas a las propiamente autorizadas.
De forma más concreta, en las zonas donde se manipulen alimentos se valorará la presencia de manchas detectables al tacto, manchas visibles, granulaciones en superficies, restos superficiales de grasa y restos sólidos, no admitiendo como limpieza suficiente cuando se aprecie alguno de los puntos antes expuestos. ')
GO
