INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(100 AS Decimal(6, 0)), N'21             ', N'Previamente a la aplicación de productos de limpieza, se retiran los elementos sólidos y groseros de superficies y utensilios y la limpieza se realiza sin levantar polvo ni salpicaduras.', N'Previamente a la aplicación de productos de limpieza, se retirarán los elementos sólidos y groseros de superficies y utensilios. La limpieza se realizará cuidando no levantar polvo ni salpicaduras que puedan contaminar los productos.', N'Previamente a la aplicación de productos de limpieza, se retiran los elementos sólidos y groseros de superficies y utensilios y la limpieza se realiza sin levantar polvo ni salpicaduras.', N'Previamente a la aplicación de productos de limpieza, se retirarán los elementos sólidos y groseros de superficies y utensilios. La limpieza se realizará cuidando no levantar polvo ni salpicaduras que puedan contaminar los productos.')
