INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(102 AS Decimal(6, 0)), N'21             ', N'Tras el aclarado no se aprecian restos de detergentes u olores a productos químicos utilizados durante la limpieza que pudieran afectar a los alimentos.', N'Los residuos de detergentes y desinfectantes se eliminarán con abundante agua potable. Tras el aclarado, no se apreciarán restos de detergentes u olores a productos químicos utilizados durante la limpieza, que pudieran afectar a los alimentos.', N'Tras el aclarado no se aprecian restos de detergentes u olores a productos químicos utilizados durante la limpieza que pudieran afectar a los alimentos.', N'Los residuos de detergentes y desinfectantes se eliminarán con abundante agua potable. Tras el aclarado, no se apreciarán restos de detergentes u olores a productos químicos utilizados durante la limpieza, que pudieran afectar a los alimentos.')
