INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(13 AS Decimal(3, 0)), CAST(96 AS Decimal(6, 0)), N'21             ', N'Los productos químicos utilizados en la limpieza, son acordes al tipo de suciedad y superficie o local a tratar, aptos para uso alimentario perfectamente identificados y etiquetados.', N'Los productos químicos utilizados en la limpieza, serán acordes al tipo de suciedad y superficie o local a tratar, aptos para uso alimentario y perfectamente identificados y etiquetados mediante rótulos que indiquen su toxicidad y modo de empleo. En aquellos locales o útiles sin contacto con alimentos como los servicios higiénicos, suelos, sumideros, desagües, oficinas, etc. se podrán utilizar otros productos comerciales de limpieza.', N'Los productos químicos utilizados en la limpieza, son acordes al tipo de suciedad y superficie o local a tratar, aptos para uso alimentario perfectamente identificados y etiquetados.', N'Los productos químicos utilizados en la limpieza, serán acordes al tipo de suciedad y superficie o local a tratar, aptos para uso alimentario y perfectamente identificados y etiquetados mediante rótulos que indiquen su toxicidad y modo de empleo. En aquellos locales o útiles sin contacto con alimentos como los servicios higiénicos, suelos, sumideros, desagües, oficinas, etc. se podrán utilizar otros productos comerciales de limpieza.')
GO
