INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(14 AS Decimal(3, 0)), CAST(113 AS Decimal(6, 0)), N'23             ', N'Dispone de un plan DD.', N'Dispondrá de un plan de desratización y desinsectación que garantice la destrucción sistemática de roedores insectos y otras plagas. En el mismo se explicará la frecuencia de los tratamientos, productos utilizados, formas de uso e incluirá planos sobre la localización de cebos.
Los tratamientos se aplicarán de acuerdo al plan establecido, por lo que para poder realizar esta verificación, la empresa dispondrá de registros en los que al menos figuren los siguientes datos:
Fecha de realización de la operación
Locales de aplicación en cada fecha
Descripción de incidencias (consumo, desaparición de cebos etc.).', N'Dispone de un plan DD.', N'Dispondrá de un plan de desratización y desinsectación que garantice la destrucción sistemática de roedores insectos y otras plagas. En el mismo se explicará la frecuencia de los tratamientos, productos utilizados, formas de uso e incluirá planos sobre la localización de cebos.
