INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(116 AS Decimal(6, 0)), N'25             ', N'Los subproductos/desechos y contenedores se retiran de forma continua de la zona de manipulación, sin que se produzca acumulo de restos o contenedores.', N'Los desechos y subproductos se evacuarán de la zona de manipulación de forma continua, cada vez que se llenen los recipientes, no se producirá el acumulo de subproductos, desechos y/o contenedores llenos en los lugares de trabajo. Cuando los decomisos se eliminen por conductos destinados a tal fin, estarán construidos de forma que se evite la contaminación de materias primas o productos.', N'Los subproductos/desechos y contenedores se retiran de forma continua de la zona de manipulación, sin que se produzca acumulo de restos o contenedores.', N'Los desechos y subproductos se evacuarán de la zona de manipulación de forma continua, cada vez que se llenen los recipientes, no se producirá el acumulo de subproductos, desechos y/o contenedores llenos en los lugares de trabajo. Cuando los decomisos se eliminen por conductos destinados a tal fin, estarán construidos de forma que se evite la contaminación de materias primas o productos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(118 AS Decimal(6, 0)), N'25             ', N'Si la retirada no es diaria, los contenedores con subproductos/desechos, se retiran del local /zona de almacenamiento con una frecuencia que garantiza la higiene del establecimiento.', N'Si la retirada de los contenedores de la empresa no se realiza a diario, y por tanto se almacenan hasta su retirada, esta se realizará con una frecuencia que garantice la higiene del establecimiento. ', N'Si la retirada no es diaria, los contenedores con subproductos/desechos, se retiran del local /zona de almacenamiento con una frecuencia que garantiza la higiene del establecimiento.', N'Si la retirada de los contenedores de la empresa no se realiza a diario, y por tanto se almacenan hasta su retirada, esta se realizará con una frecuencia que garantice la higiene del establecimiento. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(115 AS Decimal(6, 0)), N'24             ', N'Dispone de contenedores (de tipo adecuado a la actividad del establecimiento) que garantizan la recogida y eliminación higiénica de los subproductos y desechos.', N'Para evitar contaminaciones, los desechos y subproductos no destinados a consumo humano, no estarán en contacto con los productos destinados a consumo humano.
Los desechos y subproductos de tipo orgánico se recogerán en recipientes especiales que serán estanco, no corrosivos, con tapa y no permitirán la salida de líquido de los mismos. Serán de uso exclusivo para almacenamiento de subproductos, permitirán la recogida higiénica de los mismos de acuerdo con el volumen generado por la empresa y estarán diferenciados del resto de recipientes utilizados en el establecimiento, por el color, tama¦o o identificación expresa.
Los desechos de tipo inorgánico podrán ser de características diferentes a las citadas en el punto anterior, dependiendo de la actividad del establecimiento, y de igual forma, garantizarán su recogida y eliminación.', N'Dispone de contenedores (de tipo adecuado a la actividad del establecimiento) que garantizan la recogida y eliminación higiénica de los subproductos y desechos.', N'Para evitar contaminaciones, los desechos y subproductos no destinados a consumo humano, no estarán en contacto con los productos destinados a consumo humano.
Los desechos y subproductos de tipo orgánico se recogerán en recipientes especiales que serán estanco, no corrosivos, con tapa y no permitirán la salida de líquido de los mismos. Serán de uso exclusivo para almacenamiento de subproductos, permitirán la recogida higiénica de los mismos de acuerdo con el volumen generado por la empresa y estarán diferenciados del resto de recipientes utilizados en el establecimiento, por el color, tama¦o o identificación expresa.
Los desechos de tipo inorgánico podrán ser de características diferentes a las citadas en el punto anterior, dependiendo de la actividad del establecimiento, y de igual forma, garantizarán su recogida y eliminación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(117 AS Decimal(6, 0)), N'25             ', N'Los contenedores se retiran a diario del establecimiento y si no es así, disponen de un local para su almacenamiento.', N'La retirada de los contenedores de la empresa será diaria, en su defecto existirá un local o zona de almacenamiento refrigerado en caso de subproductos de tipo orgánico o un local o zona no refrigerada en caso de desechos inorgánicos. El local/zona en cada caso, no permitirá el acceso de plagas, ni la contaminación de alimentos, agua potable, edificios y vías de acceso. En caso de almacenamiento de los contenedores de subproductos orgánicos, en cámaras de refrigeración destinadas a alimentos, se realizará en los contenedores descritos en el apartado correspondiente a recipientes para subproductos de tipo orgánico y estarán correctamente cerrados y separados del resto de productos alimenticios. ', N'Los contenedores se retiran a diario del establecimiento y si no es así, disponen de un local para su almacenamiento.', N'La retirada de los contenedores de la empresa será diaria, en su defecto existirá un local o zona de almacenamiento refrigerado en caso de subproductos de tipo orgánico o un local o zona no refrigerada en caso de desechos inorgánicos. El local/zona en cada caso, no permitirá el acceso de plagas, ni la contaminación de alimentos, agua potable, edificios y vías de acceso. En caso de almacenamiento de los contenedores de subproductos orgánicos, en cámaras de refrigeración destinadas a alimentos, se realizará en los contenedores descritos en el apartado correspondiente a recipientes para subproductos de tipo orgánico y estarán correctamente cerrados y separados del resto de productos alimenticios. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(120 AS Decimal(6, 0)), N'26             ', N'Si hay productos objeto de devolución cuentan con documentación.', N'En el caso de devoluciones, el establecimiento contará con documentación que indique al menos las fechas de devolución, productos devueltos, cantidad, causa de las devoluciones y destino de las mismas.', N'Si hay productos objeto de devolución cuentan con documentación.', N'En el caso de devoluciones, el establecimiento contará con documentación que indique al menos las fechas de devolución, productos devueltos, cantidad, causa de las devoluciones y destino de las mismas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(15 AS Decimal(3, 0)), CAST(119 AS Decimal(6, 0)), N'25             ', N'Si hay productos objeto de devolución, están correctamente almacenados, separados del resto de productos e identificados como objeto de devolución.', N'Los productos objeto de devolución (por indicación del productor, superar la fecha de caducidad o consumo preferente o por otros motivos comerciales que no supongan riesgo de contaminación durante el almacenamiento y transporte) se almacenarán en régimen de frío, si son productos que requieren temperatura controlada, o en la zona de almacenamiento general del establecimiento si son productos que no requieren mantenimiento de temperatura. En cualquier caso, estos productos se dispondrán separados del resto de los productos almacenados y estarán identificados como productos objeto de devolución.', N'Si hay productos objeto de devolución, están correctamente almacenados, separados del resto de productos e identificados como objeto de devolución.', N'Los productos objeto de devolución (por indicación del productor, superar la fecha de caducidad o consumo preferente o por otros motivos comerciales que no supongan riesgo de contaminación durante el almacenamiento y transporte) se almacenarán en régimen de frío, si son productos que requieren temperatura controlada, o en la zona de almacenamiento general del establecimiento si son productos que no requieren mantenimiento de temperatura. En cualquier caso, estos productos se dispondrán separados del resto de los productos almacenados y estarán identificados como productos objeto de devolución.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(127 AS Decimal(6, 0)), N'29             ', N'Si se transportan distintos tipos de alimentos, u otro tipo de productos permitidos o devoluciones, hay separación efectiva entre ellos.', N'Si se transportan distintos tipos de alimentos u otros de tipo no alimentario (siempre que no sean tóxicos ni susceptibles de producir contaminación en los alimentos con los que se transportan, ni decomisos), se acondicionará la carga para que exista separación efectiva entre ellos. Los productos procedentes de devoluciones, podrán ser transportados con alimentos aptos para consumo siempre que no exista riesgo de alteración.', N'Si se transportan distintos tipos de alimentos, u otro tipo de productos permitidos o devoluciones, hay separación efectiva entre ellos.', N'Si se transportan distintos tipos de alimentos u otros de tipo no alimentario (siempre que no sean tóxicos ni susceptibles de producir contaminación en los alimentos con los que se transportan, ni decomisos), se acondicionará la carga para que exista separación efectiva entre ellos. Los productos procedentes de devoluciones, podrán ser transportados con alimentos aptos para consumo siempre que no exista riesgo de alteración.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(126 AS Decimal(6, 0)), N'29             ', N'La estiba evita el contacto con el suelo u otros utensilios y permite la circulación de aire.', N'Los productos no envasados no contactarán con el suelo o con otros utensilios que sean susceptibles de ser pisados. La estiba permitirá la circulación de aire entre los productos.', N'La estiba evita el contacto con el suelo u otros utensilios y permite la circulación de aire.', N'Los productos no envasados no contactarán con el suelo o con otros utensilios que sean susceptibles de ser pisados. La estiba permitirá la circulación de aire entre los productos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(129 AS Decimal(6, 0)), N'30             ', N'Los vehículos están autorizados para el tipo de transporte que realizan.', N'Los vehículos de transporte a temperatura regulada, dispondrán del certificado de conformidad emitido por la autoridad competente de las Comunidades Autónomas (ITV) que garantice, que el tipo de vehículo es el necesario para las condiciones exigidas por los productos que transporta. ', N'Los vehículos están autorizados para el tipo de transporte que realizan.', N'Los vehículos de transporte a temperatura regulada, dispondrán del certificado de conformidad emitido por la autoridad competente de las Comunidades Autónomas (ITV) que garantice, que el tipo de vehículo es el necesario para las condiciones exigidas por los productos que transporta. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(128 AS Decimal(6, 0)), N'29             ', N'Los vehículos están limpios.', N'Los vehículos, antes de realizar la carga de alimentos estarán en buenas condiciones de limpieza que se mantendrán durante el transporte. ', N'Los vehículos están limpios.', N'Los vehículos, antes de realizar la carga de alimentos estarán en buenas condiciones de limpieza que se mantendrán durante el transporte. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(122 AS Decimal(6, 0)), N'27             ', N'La caja del vehículo es estanca y aislada.', N'La caja o cisterna destinada a contener alimentos y productos alimentarios, no tendrá ningún accesorio o instalación que no pertenezca a la propia carga o sistema de enfriamiento y/o calefacción y no tendrá comunicación directa con la cabina del conductor.', N'La caja del vehículo es estanca y aislada.', N'La caja o cisterna destinada a contener alimentos y productos alimentarios, no tendrá ningún accesorio o instalación que no pertenezca a la propia carga o sistema de enfriamiento y/o calefacción y no tendrá comunicación directa con la cabina del conductor.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(132 AS Decimal(6, 0)), N'30             ', N'El transporte frigorífico no se compatibiliza con el transporte de productos susceptibles de producir contaminación.', N'No se podrá realizar el transporte frigorífico de alimentos y productos alimentarios con otros que sean susceptibles de producir contaminación.', N'El transporte frigorífico no se compatibiliza con el transporte de productos susceptibles de producir contaminación.', N'No se podrá realizar el transporte frigorífico de alimentos y productos alimentarios con otros que sean susceptibles de producir contaminación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111016 AS Decimal(6, 0)), N'74             ', N'La carne de vacuno procedente de animales que precisan extracción de columna según la norma, no la lleva.', N'Se comprobará a través de los albaranes y/o en la etiqueta la edad de los animales y su procedencia, para comprobar si se ha extraído la columna vertebral en los casos en los que la norma lo exige (a fecha enero 2017 se extraerá la columna en animales de más de 30 meses procedentes de países de riesgo controlado: Irlanda, Grecia, Francia, Polonia y Reino Unido).

Desde el 7/7/2016 España ha pasado a ser un país de riesgo insignificante de EEB, en consecuencia, no es obligatorio la extracción de la columna en bovinos de más de 30 meses', N'La carne de vacuno procedente de animales que precisan extracción de columna según la norma, no la lleva.', N'Se comprobará a través de los albaranes y/o en la etiqueta la edad de los animales y su procedencia, para comprobar si se ha extraído la columna vertebral en los casos en los que la norma lo exige (a fecha enero 2017 se extraerá la columna en animales de más de 30 meses procedentes de países de riesgo controlado: Irlanda, Grecia, Francia, Polonia y Reino Unido).

Desde el 7/7/2016 España ha pasado a ser un país de riesgo insignificante de EEB, en consecuencia, no es obligatorio la extracción de la columna en bovinos de más de 30 meses')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111018 AS Decimal(6, 0)), N'74             ', N'Los huevos están correctamente envasados, etiquetados y están limpios y enteros.', N'Se comprobará que los huevos están marcados individualmente con su número de identificación y en el envase consta la fecha de duración mínima. Además están limpios y enteros.

En aquellos casos en los que el establecimiento productor (entre 50 y 1000 gallinas) esté acogido a flexibilidad se tendrán en cuenta las normas específicas sobre el etiquetado del envase.', N'Los huevos están correctamente envasados, etiquetados y están limpios y enteros.', N'Se comprobará que los huevos están marcados individualmente con su número de identificación y en el envase consta la fecha de duración mínima. Además están limpios y enteros.

En aquellos casos en los que el establecimiento productor (entre 50 y 1000 gallinas) esté acogido a flexibilidad se tendrán en cuenta las normas específicas sobre el etiquetado del envase.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(124 AS Decimal(6, 0)), N'28             ', N'Tiene termómetro visible /registro continuo, según proceda.', N'Los vehículos que realizan transporte de productos a temperatura regulada, estarán equipados con un dispositivo de medida (termómetro) y registro continuo de la temperatura interior de la caja. El elemento de lectura irá montado en un lugar fácilmente visible desde el exterior.
Los vehículos que realicen el transporte de productos para reparto y autoventa (el realizado en los núcleos urbanos mediante vehículos que retornan sistemáticamente a su origen en un plazo máximo de 24 horas efectuando actos de venta y facturación a clientes (autoventa), o entregando mercancías a través de albaranes preestablecidos (reparto)), y en general, los vehículos de transporte a temperatura regulada que no realizan solamente reparto y autoventa sino que realizan viajes a distancias más largas o de mayor duración las (clases RRC(refrigerado reforzado clase C), FRC (frigorífico reforzado clase C) y FRF(frigorífico refrigerado clase F) si no transportan ultracongelados; no estarán obligados a instalar el dispositivo de registro de temperaturas (llevarán dispositivo de lectura). Estos vehículos garantizarán aunque se realicen paradas, el mantenimiento de la temperatura exigida por los productos que transportan.', N'Tiene termómetro visible /registro continuo, según proceda.', N'Los vehículos que realizan transporte de productos a temperatura regulada, estarán equipados con un dispositivo de medida (termómetro) y registro continuo de la temperatura interior de la caja. El elemento de lectura irá montado en un lugar fácilmente visible desde el exterior.
Los vehículos que realicen el transporte de productos para reparto y autoventa (el realizado en los núcleos urbanos mediante vehículos que retornan sistemáticamente a su origen en un plazo máximo de 24 horas efectuando actos de venta y facturación a clientes (autoventa), o entregando mercancías a través de albaranes preestablecidos (reparto)), y en general, los vehículos de transporte a temperatura regulada que no realizan solamente reparto y autoventa sino que realizan viajes a distancias más largas o de mayor duración las (clases RRC(refrigerado reforzado clase C), FRC (frigorífico reforzado clase C) y FRF(frigorífico refrigerado clase F) si no transportan ultracongelados; no estarán obligados a instalar el dispositivo de registro de temperaturas (llevarán dispositivo de lectura). Estos vehículos garantizarán aunque se realicen paradas, el mantenimiento de la temperatura exigida por los productos que transportan.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(123 AS Decimal(6, 0)), N'28             ', N'El tipo de vehículo a temperatura regulada es el adecuado para los productos que transporta. ', N'Los vehículos que transportan productos que requieren para su mantenimiento una temperatura y grado de humedad específica, serán adecuados a los productos que transporta (refrigerados, congelados, caloríficos). ', N'El tipo de vehículo a temperatura regulada es el adecuado para los productos que transporta. ', N'Los vehículos que transportan productos que requieren para su mantenimiento una temperatura y grado de humedad específica, serán adecuados a los productos que transporta (refrigerados, congelados, caloríficos). ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(125 AS Decimal(6, 0)), N'28             ', N'Los vehículos cisterna que tienen  varios compartimentos, están correctamente separados.', N'En los vehículos cisterna, que pueden tener uno o varios compartimentos, cada uno tendrá una boca de entrada y de vaciado. La separación entre los compartimentos será con tabiques verticales.', N'Los vehículos cisterna que tienen  varios compartimentos, están correctamente separados.', N'En los vehículos cisterna, que pueden tener uno o varios compartimentos, cada uno tendrá una boca de entrada y de vaciado. La separación entre los compartimentos será con tabiques verticales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(130 AS Decimal(6, 0)), N'30             ', N'La temperatura de acuerdo a los productos que se transportan es la exigida.', N'Cuando se requieran condiciones especiales de temperatura para el transporte, la temperatura en el interior de la caja en el momento de la carga, será la correspondiente a la exigida por el tipo de alimentos que transporte y se mantendrá durante todo el trayecto. Si se transportan simultáneamente diferentes alimentos o productos alimentarios, con diferentes condiciones de conservación en cuanto a temperaturas, serán compatibles entre sí, y ninguna de las mercancías será causa de alteración o modificación de las otras en cuanto a polvo, olor, contaminación, partículas orgánicas o minerales.', N'La temperatura de acuerdo a los productos que se transportan es la exigida.', N'Cuando se requieran condiciones especiales de temperatura para el transporte, la temperatura en el interior de la caja en el momento de la carga, será la correspondiente a la exigida por el tipo de alimentos que transporte y se mantendrá durante todo el trayecto. Si se transportan simultáneamente diferentes alimentos o productos alimentarios, con diferentes condiciones de conservación en cuanto a temperaturas, serán compatibles entre sí, y ninguna de las mercancías será causa de alteración o modificación de las otras en cuanto a polvo, olor, contaminación, partículas orgánicas o minerales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(131 AS Decimal(6, 0)), N'30             ', N'Las operaciones de carga y descarga se realizan de forma que no permiten elevaciones de Tª. ', N'Las operaciones de carga y descarga se realizarán de forma rápida a fin de evitar la elevación de temperatura, por lo que, no se podrán encontrar vehículos con productos alimentarios cargados con las puertas abiertas y sin estar realizando la actividad de carga. ', N'Las operaciones de carga y descarga se realizan de forma que no permiten elevaciones de Tª. ', N'Las operaciones de carga y descarga se realizarán de forma rápida a fin de evitar la elevación de temperatura, por lo que, no se podrán encontrar vehículos con productos alimentarios cargados con las puertas abiertas y sin estar realizando la actividad de carga. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(16 AS Decimal(3, 0)), CAST(121 AS Decimal(6, 0)), N'27             ', N'Los vehículos disponen de medios para proteger los productos que transporta.', N'Los vehículos, tendrán condiciones que permitan la protección de los alimentos durante el transporte, y aunque estas condiciones serán diferentes dependiendo del tipo de alimento que transporten, en general no permitirán la contaminación de los alimentos o envases ni por agentes externos ni por las características propias del vehículo, permitirán la separación física entre los distintos tipos de alimentos y de estos, con productos no alimenticios y permitirán el mantenimiento de temperatura y humedad que eviten el deterioro o el crecimiento de microorganismos, en los productos transportados.', N'Los vehículos disponen de medios para proteger los productos que transporta.', N'Los vehículos, tendrán condiciones que permitan la protección de los alimentos durante el transporte, y aunque estas condiciones serán diferentes dependiendo del tipo de alimento que transporten, en general no permitirán la contaminación de los alimentos o envases ni por agentes externos ni por las características propias del vehículo, permitirán la separación física entre los distintos tipos de alimentos y de estos, con productos no alimenticios y permitirán el mantenimiento de temperatura y humedad que eviten el deterioro o el crecimiento de microorganismos, en los productos transportados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(2057 AS Decimal(6, 0)), N'32             ', N'No se comercializan productos y derivados cárnicos elaborados en dichos establecimientos a los que se hayan adicionado aditivos en dosis superiores a las reglamentadas o no autorizados.', N'Los productos no podrán comercializarse si se les ha adicionado aditivos no autorizados o en dosis superiores a las permitidas', N' ', N'Los productos no podrán comercializarse si se les ha adicionado aditivos no autorizados o en dosis superiores a las permitidas')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(142 AS Decimal(6, 0)), N'32             ', N'Los productos finales son retirados de los locales o áreas de elaboración en cuanto se han realizado las manipulaciones que precisan.', N'
El mismo criterio se empleará para los productos elaborados en el establecimiento, que serán retirados lo antes posible de las zonas de trabajo.', N'Los productos finales son retirados de los locales o áreas de elaboración en cuanto se han realizado las manipulaciones que precisan.', N'
El mismo criterio se empleará para los productos elaborados en el establecimiento, que serán retirados lo antes posible de las zonas de trabajo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(151 AS Decimal(6, 0)), N'33             ', N'En los procesos productivos no existe transito de personal, útiles o equipamiento móvil desde locales, zonas o actividades más sucias hacia otras más limpias, y si lo hay únicamente se realiza con higienización previa.', N'Como norma general se aplicará siempre el principio de Marcha hacia adelante y el proceso productivo estará organizado de forma que el flujo de la actividad se realice avanzando siempre desde los locales, áreas de producción o actividades más sucias hacia los locales, zonas o actividades más limpias.
Por el contrario, el flujo del personal, utensilios, equipamiento móvil, desechos y subproductos será siempre retrocediendo desde las zonas, locales o actividades más limpias hacia las más contaminadas, de manera que no puedan producirse contaminaciones o recontaminaciones secundarias, de los productos finales, por arrastre de contaminantes desde las zonas o actividades más sucias. Para poder avanzar hacia zonas más limpias tanto el personal como los útiles y equipos móviles deben higienizarse adecuadamente.', N'En los procesos productivos no existe transito de personal, útiles o equipamiento móvil desde locales, zonas o actividades más sucias hacia otras más limpias, y si lo hay únicamente se realiza con higienización previa.', N'Como norma general se aplicará siempre el principio de Marcha hacia adelante y el proceso productivo estará organizado de forma que el flujo de la actividad se realice avanzando siempre desde los locales, áreas de producción o actividades más sucias hacia los locales, zonas o actividades más limpias.
Por el contrario, el flujo del personal, utensilios, equipamiento móvil, desechos y subproductos será siempre retrocediendo desde las zonas, locales o actividades más limpias hacia las más contaminadas, de manera que no puedan producirse contaminaciones o recontaminaciones secundarias, de los productos finales, por arrastre de contaminantes desde las zonas o actividades más sucias. Para poder avanzar hacia zonas más limpias tanto el personal como los útiles y equipos móviles deben higienizarse adecuadamente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(136 AS Decimal(6, 0)), N'32             ', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento se manipulan higiénicamente. Sin contacto con estructuras, útiles y equipamiento sin higienizar, desperdicios u otras fuentes que l????', N'Todos los alimentos, materias primas, ingredientes, productos intermedios y productos finales serán preparados, fabricados, transformados, almacenados, conservados, distribuidos, transportados y expuestos en condiciones tales que se evite su deterioro o contaminación que pueda convertirlos en impropios para el consumo humano y peligrosos para la salud, por lo que:
Se manipularán evitando su contaminación a través de superficies, utensilios, equipamiento, recipientes manipuladores, corrientes de aire, agua, etc. que no reúnan condiciones de higiene. En particular se evitará el contacto, y contaminación de los mismos, con suelos, paredes, materiales de embalado o cualquier otra estructura o equipamiento de material no apto para contactar con alimentos o no susceptible de una adecuada higienización.
Se manipularán evitando su contaminación por contacto o a través de desperdicios, desechos, subproductos o materias primas sin higienizar.', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento se manipulan higiénicamente. Sin contacto con estructuras, útiles y equipamiento sin higienizar, desperdicios u otras fuentes que l????', N'Todos los alimentos, materias primas, ingredientes, productos intermedios y productos finales serán preparados, fabricados, transformados, almacenados, conservados, distribuidos, transportados y expuestos en condiciones tales que se evite su deterioro o contaminación que pueda convertirlos en impropios para el consumo humano y peligrosos para la salud, por lo que:
Se manipularán evitando su contaminación a través de superficies, utensilios, equipamiento, recipientes manipuladores, corrientes de aire, agua, etc. que no reúnan condiciones de higiene. En particular se evitará el contacto, y contaminación de los mismos, con suelos, paredes, materiales de embalado o cualquier otra estructura o equipamiento de material no apto para contactar con alimentos o no susceptible de una adecuada higienización.
Se manipularán evitando su contaminación por contacto o a través de desperdicios, desechos, subproductos o materias primas sin higienizar.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(139 AS Decimal(6, 0)), N'32             ', N'Las condiciones en las que se manipulan, almacenan, comercializan o exponen los alimentos (y en su caso materias primas e ingredientes) que pueden mantenerse a temperatura ambiente, evitan su deterioro.', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios (materias primas, ingredientes, productos intermedios y productos acabados) puedan mantenerse a temperatura ambiente, su manipulación, almacenamiento, transporte y exposición se realizará en condiciones de higiene tales que eviten su deterioro: Control de humedad ambiental, no exposición directa a la luz solar, estiba adecuada, etc.', N'Las condiciones en las que se manipulan, almacenan, comercializan o exponen los alimentos (y en su caso materias primas e ingredientes) que pueden mantenerse a temperatura ambiente, evitan su deterioro.', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios (materias primas, ingredientes, productos intermedios y productos acabados) puedan mantenerse a temperatura ambiente, su manipulación, almacenamiento, transporte y exposición se realizará en condiciones de higiene tales que eviten su deterioro: Control de humedad ambiental, no exposición directa a la luz solar, estiba adecuada, etc.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(146 AS Decimal(6, 0)), N'32             ', N'No se utilizan aromas y/o aditivos o, en el caso de estar autorizado su uso, los agentes aromáticos y aditivos utilizados son exclusivamente los autorizados para cada producto (o tipo de productos) que elabora, conserva o comercializa el establecimiento', N'
Cuando al elaborar, conservar o comercializar alimentos (y en su caso materias primas e ingredientes) esté autorizado el uso de agentes aromáticos y/o aditivos: Únicamente podrán utilizarse los autorizados expresamente para ese tipo de producto/s, o categorías de productos, en la R.T.S. de Agentes Aromáticos y en las correspondientes Listas Positivas de Aditivos. Así mismo sus condiciones de uso, en cuanto a empleo/s y dosis máxima autorizada, estarán sujetas a las condiciones de utilización recogidas en las mencionadas Normas para cada producto o categoría de productos.', N'No se utilizan aromas y/o aditivos o, en el caso de estar autorizado su uso, los agentes aromáticos y aditivos utilizados son exclusivamente los autorizados para cada producto (o tipo de productos) que elabora, conserva o comercializa el establecimiento', N'
Cuando al elaborar, conservar o comercializar alimentos (y en su caso materias primas e ingredientes) esté autorizado el uso de agentes aromáticos y/o aditivos: Únicamente podrán utilizarse los autorizados expresamente para ese tipo de producto/s, o categorías de productos, en la R.T.S. de Agentes Aromáticos y en las correspondientes Listas Positivas de Aditivos. Así mismo sus condiciones de uso, en cuanto a empleo/s y dosis máxima autorizada, estarán sujetas a las condiciones de utilización recogidas en las mencionadas Normas para cada producto o categoría de productos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(149 AS Decimal(6, 0)), N'33             ', N'En los procesos productivos están claramente definidas las áreas de trabajo y los circuitos de producción, no existen cruces en los mismos que puedan dar lugar a contaminaciones o recontaminaciones  secundarias', N'Además, deberán estar claramente definidas las áreas de trabajo en las que se van a realizar las diferentes operaciones del proceso productivo, de manera que se asegure la separación de los circuitos de los productos y no den lugar  a cruces o retrocesos en las líneas de producción que puedan producir contaminaciones o recontaminaciones secundarias.', N'En los procesos productivos están claramente definidas las áreas de trabajo y los circuitos de producción, no existen cruces en los mismos que puedan dar lugar a contaminaciones o recontaminaciones  secundarias', N'Además, deberán estar claramente definidas las áreas de trabajo en las que se van a realizar las diferentes operaciones del proceso productivo, de manera que se asegure la separación de los circuitos de los productos y no den lugar  a cruces o retrocesos en las líneas de producción que puedan producir contaminaciones o recontaminaciones secundarias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(145 AS Decimal(6, 0)), N'32             ', N'Las condiciones en las que se manipulen, almacenen o comercialicen los alimentos ( y en su caso materias primas e ingredientes) permiten la rotación de existencias y remociones periódicas, en función del tiempo de almacenamiento y condiciones de conservac????', N'
Las condiciones en las que se manipulen, almacenen o comercialicen los alimentos (y en su caso materias primas e ingredientes) permitirán la rotación de existencias y remociones periódicas, en función del tiempo de almacenamiento y condiciones de conservación que exija el producto.', N'Las condiciones en las que se manipulen, almacenen o comercialicen los alimentos ( y en su caso materias primas e ingredientes) permiten la rotación de existencias y remociones periódicas, en función del tiempo de almacenamiento y condiciones de conservac????', N'
Las condiciones en las que se manipulen, almacenen o comercialicen los alimentos (y en su caso materias primas e ingredientes) permitirán la rotación de existencias y remociones periódicas, en función del tiempo de almacenamiento y condiciones de conservación que exija el producto.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(143 AS Decimal(6, 0)), N'32             ', N'Los locales e instalaciones del establecimiento alimentario no se utilizan para otras actividades o usos contaminantes.', N'
Los locales, instalaciones y equipos de los establecimientos o actividades alimentarias deberán utilizarse para el fin para el que fueron concebidos, no pudiéndose utilizar para cualquier otra actividad que suponga riesgo de contaminación de los mismos o de los alimentos que en ellos se manipulan, transforman, transportan, conservan, almacenan o exponen.
Así mismo estará prohibida la utilización o tenencia en los establecimientos alimentarios (o en sus locales anexos) de productos o equipamiento cuyo empleo no esté justificado dentro de la/s actividad/es alimentarías para la/s que está autorizado.', N'Los locales e instalaciones del establecimiento alimentario no se utilizan para otras actividades o usos contaminantes.', N'
Los locales, instalaciones y equipos de los establecimientos o actividades alimentarias deberán utilizarse para el fin para el que fueron concebidos, no pudiéndose utilizar para cualquier otra actividad que suponga riesgo de contaminación de los mismos o de los alimentos que en ellos se manipulan, transforman, transportan, conservan, almacenan o exponen.
Así mismo estará prohibida la utilización o tenencia en los establecimientos alimentarios (o en sus locales anexos) de productos o equipamiento cuyo empleo no esté justificado dentro de la/s actividad/es alimentarías para la/s que está autorizado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(140 AS Decimal(6, 0)), N'32             ', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, se almacenan y conservan en los locales o instalaciones habilitadas para tal fin.', N'
Los productos alimenticios (materias primas, ingredientes, productos intermedios y productos acabados) recepcionados en el establecimiento alimentario se almacenarán y conservarán hasta su uso o distribución en las instalaciones o locales habilitados para tal fin.', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, se almacenan y conservan en los locales o instalaciones habilitadas para tal fin.', N'
Los productos alimenticios (materias primas, ingredientes, productos intermedios y productos acabados) recepcionados en el establecimiento alimentario se almacenarán y conservarán hasta su uso o distribución en las instalaciones o locales habilitados para tal fin.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(134 AS Decimal(6, 0)), N'31             ', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, proceden de establecimientos autorizados.', N'El origen de todos los alimentos, materias primas, e ingredientes será tal que pueda garantizar la salubridad de los mismos y estará acreditado a través de su etiquetado y/o marcado sanitario y/o documentación de acompa¦amiento comercial.', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, proceden de establecimientos autorizados.', N'El origen de todos los alimentos, materias primas, e ingredientes será tal que pueda garantizar la salubridad de los mismos y estará acreditado a través de su etiquetado y/o marcado sanitario y/o documentación de acompa¦amiento comercial.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(147 AS Decimal(6, 0)), N'32             ', N'Dispone de estudios que garanticen los productos durante el periodo de utilización', N'
Cuando el establecimiento elabore, transforme o envase productos que por su naturaleza, presentación comercial, o condiciones de conservación estén sujetos a un periodo de vida útil limitado, deberá contar con estudios que demuestren la validez del periodo durante el cual está garantizada la salubridad de los mismos (estudios de caducidad).', N'Dispone de estudios que garanticen los productos durante el periodo de utilización', N'
Cuando el establecimiento elabore, transforme o envase productos que por su naturaleza, presentación comercial, o condiciones de conservación estén sujetos a un periodo de vida útil limitado, deberá contar con estudios que demuestren la validez del periodo durante el cual está garantizada la salubridad de los mismos (estudios de caducidad).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(138 AS Decimal(6, 0)), N'32             ', N'Los alimentos que se conservan, comercializan o exponen en caliente, se mantienen a una temperatura que no origina riesgos para la salud. ', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios deban conservarse, distribuirse y servirse en caliente, una vez concluida la fase de tratamiento térmico se mantendrán a una temperatura que no origine riesgos para la salud.', N'Los alimentos que se conservan, comercializan o exponen en caliente, se mantienen a una temperatura que no origina riesgos para la salud. ', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios deban conservarse, distribuirse y servirse en caliente, una vez concluida la fase de tratamiento térmico se mantendrán a una temperatura que no origine riesgos para la salud.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(137 AS Decimal(6, 0)), N'32             ', N'Al elaborarar, manipular, conservar, comercializar o exponer alimentos (y en su caso materias primas e ingredientes)  que deben mantenerse a bajas temperaturas, se mantiene la cadena de frío.', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios deban conservarse y comercializarse a bajas temperaturas, se enfriarán cuanto antes, una vez concluida la fase de tratamiento térmico (o la fase final de la preparación en caso de que este no se aplique) a una temperatura que no de lugar a riesgos para la salud y se mantendrá constante la cadena de frío.', N'Al elaborarar, manipular, conservar, comercializar o exponer alimentos (y en su caso materias primas e ingredientes)  que deben mantenerse a bajas temperaturas, se mantiene la cadena de frío.', N'Las materias primas, ingredientes, productos intermedios y productos acabados en los que pueda producirse la multiplicación de microorganismos, y en su caso la formación de toxinas, de manera que se conviertan en impropios (por perdida de sus caracteres organolepticos, sus cualidades nutritivas, etc.) o peligrosos para el consumo humano, deberán manipularse, conservarse, transportarse y exponerse a temperaturas que eviten su deterioro y no den lugar a riesgos para la salud:
Cuando los productos alimenticios deban conservarse y comercializarse a bajas temperaturas, se enfriarán cuanto antes, una vez concluida la fase de tratamiento térmico (o la fase final de la preparación en caso de que este no se aplique) a una temperatura que no de lugar a riesgos para la salud y se mantendrá constante la cadena de frío.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(150 AS Decimal(6, 0)), N'33             ', N'En los procesos productivos, los productos elaborados o manipulados avanzan siempre desde locales, zonas o actividades de mayor contaminación (más sucias) hacia otras de menor contaminación (más limpias).', N'Como norma general se aplicará siempre el principio de Marcha hacia adelante y el proceso productivo estará organizado de forma que el flujo de la actividad se realice avanzando siempre desde los locales, áreas de producción o actividades más sucias hacia los locales, zonas o actividades más limpias.
En los procesos productivos, el flujo del producto estará establecido de tal manera que este avance siempre desde las zonas o actividades de mayor contaminación hacia las menos contaminadas.', N'En los procesos productivos, los productos elaborados o manipulados avanzan siempre desde locales, zonas o actividades de mayor contaminación (más sucias) hacia otras de menor contaminación (más limpias).', N'Como norma general se aplicará siempre el principio de Marcha hacia adelante y el proceso productivo estará organizado de forma que el flujo de la actividad se realice avanzando siempre desde los locales, áreas de producción o actividades más sucias hacia los locales, zonas o actividades más limpias.
En los procesos productivos, el flujo del producto estará establecido de tal manera que este avance siempre desde las zonas o actividades de mayor contaminación hacia las menos contaminadas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(141 AS Decimal(6, 0)), N'32             ', N'Las materias primas, ingredientes y productos intermedios se introducen en los locales o áreas de elaboración a medida que se van necesitando.', N'
Se introducirán en los locales o áreas de trabajo a medida que se vayan necesitando, evitando almacenarlos o mantenerlos en las zonas de elaboración, recepción, zonas de paso, de expedición y demás locales con otros fines.', N'Las materias primas, ingredientes y productos intermedios se introducen en los locales o áreas de elaboración a medida que se van necesitando.', N'
Se introducirán en los locales o áreas de trabajo a medida que se vayan necesitando, evitando almacenarlos o mantenerlos en las zonas de elaboración, recepción, zonas de paso, de expedición y demás locales con otros fines.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(133 AS Decimal(6, 0)), N'31             ', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, por sus características y estado de conservación, son aptos para consumo humano.', N'Todos los alimentos (y materias primas e ingredientes utilizados en su elaboración) serán aptos para el consumo humano: Productos (naturales, transformados o sintetizados) destinados a la alimentación humana y que por su naturaleza, composición, ausencia de contaminación, grado de frescura y estado de conservación, su consumo o utilización como materia prima o ingrediente no suponga  riesgo para la salud. Encontrándose, además, dentro del periodo de vida comercial establecido para los mismos.
Estarán en tales condiciones que se puedan considerar inocuos: No causarán da¦o al consumidor cuando se preparen y/o consuman de acuerdo con el uso al que se destinan.', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento, por sus características y estado de conservación, son aptos para consumo humano.', N'Todos los alimentos (y materias primas e ingredientes utilizados en su elaboración) serán aptos para el consumo humano: Productos (naturales, transformados o sintetizados) destinados a la alimentación humana y que por su naturaleza, composición, ausencia de contaminación, grado de frescura y estado de conservación, su consumo o utilización como materia prima o ingrediente no suponga  riesgo para la salud. Encontrándose, además, dentro del periodo de vida comercial establecido para los mismos.
Estarán en tales condiciones que se puedan considerar inocuos: No causarán da¦o al consumidor cuando se preparen y/o consuman de acuerdo con el uso al que se destinan.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(135 AS Decimal(6, 0)), N'32             ', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento se mantienen debidamente protegidos, de manera que se evite su contaminación', N'Todos los alimentos, materias primas, ingredientes, productos intermedios y productos finales serán preparados, fabricados, transformados, almacenados, conservados, distribuidos, transportados y expuestos en condiciones tales que se evite su deterioro o contaminación que pueda convertirlos en impropios para el consumo humano y peligrosos para la salud, por lo que:
Estarán protegidos contra cualquier foco de contaminación que pueda hacerlos no aptos para el consumo humano o nocivos para la salud.', N'Los alimentos (y en su caso materias primas e ingredientes) elaborados, utilizados o comercializados por el establecimiento se mantienen debidamente protegidos, de manera que se evite su contaminación', N'Todos los alimentos, materias primas, ingredientes, productos intermedios y productos finales serán preparados, fabricados, transformados, almacenados, conservados, distribuidos, transportados y expuestos en condiciones tales que se evite su deterioro o contaminación que pueda convertirlos en impropios para el consumo humano y peligrosos para la salud, por lo que:
Estarán protegidos contra cualquier foco de contaminación que pueda hacerlos no aptos para el consumo humano o nocivos para la salud.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(148 AS Decimal(6, 0)), N'33             ', N'La sistemática de trabajo del establecimiento está organizada de tal modo que se evitan contaminaciones cruzadas.', N'La organización, cadencia y secuencia de las diferentes actividades que se desarrollan en los establecimientos alimentarios (sobre todo en los procesos de elaboración o manipulación de productos no envasados) estarán establecidas de tal manera que permitan unas prácticas correctas de higiene de los alimentos e impidan su acúmulo en las zonas de elaboración y la contaminación cruzada de los mismos, provocada por otros alimentos, materias primas, el equipo y superficies de trabajo, los materiales de envasado/embalado, desechos y subproductos, e incluso el personal manipulador.', N'La sistemática de trabajo del establecimiento está organizada de tal modo que se evitan contaminaciones cruzadas.', N'La organización, cadencia y secuencia de las diferentes actividades que se desarrollan en los establecimientos alimentarios (sobre todo en los procesos de elaboración o manipulación de productos no envasados) estarán establecidas de tal manera que permitan unas prácticas correctas de higiene de los alimentos e impidan su acúmulo en las zonas de elaboración y la contaminación cruzada de los mismos, provocada por otros alimentos, materias primas, el equipo y superficies de trabajo, los materiales de envasado/embalado, desechos y subproductos, e incluso el personal manipulador.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(17 AS Decimal(3, 0)), CAST(144 AS Decimal(6, 0)), N'32             ', N'No se observan en el establecimiento productos o equipamiento cuya utilización no esté justificada.', N'
Los locales, instalaciones y equipos de los establecimientos o actividades alimentarias deberán utilizarse para el fin para el que fueron concebidos, no pudiéndose utilizar para cualquier otra actividad que suponga riesgo de contaminación de los mismos o de los alimentos que en ellos se manipulan, transforman, transportan, conservan, almacenan o exponen.
Así mismo estará prohibida la utilización o tenencia en los establecimientos alimentarios (o en sus locales anexos) de productos o equipamiento cuyo empleo no esté justificado dentro de la/s actividad/es alimentarías para la/s que está autorizado.', N'No se observan en el establecimiento productos o equipamiento cuya utilización no esté justificada.', N'
Los locales, instalaciones y equipos de los establecimientos o actividades alimentarias deberán utilizarse para el fin para el que fueron concebidos, no pudiéndose utilizar para cualquier otra actividad que suponga riesgo de contaminación de los mismos o de los alimentos que en ellos se manipulan, transforman, transportan, conservan, almacenan o exponen.
Así mismo estará prohibida la utilización o tenencia en los establecimientos alimentarios (o en sus locales anexos) de productos o equipamiento cuyo empleo no esté justificado dentro de la/s actividad/es alimentarías para la/s que está autorizado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(18 AS Decimal(3, 0)), CAST(152 AS Decimal(6, 0)), N'34             ', N'Todos los manipuladores han recibido formación correspondiente a la actividad desarrollada.', N'El responsable del establecimiento se asegurará de que todos los manipuladores han recibido formación por un programa aprobado en la CAPV o si la han recibido en otro lugar, la entidad cuenta con la autorización de esa Comunidad Autónoma. La formación recibida por los manipuladores les permite desarrollar prácticas correctas de seguridad e higiene de los alimentos y se corresponderá con la actividad desarrollada. El responsable del establecimiento presentará los documentos de acreditación de la formación los manipuladores que incluirá información de todos y cada uno de ellos.', N'Todos los manipuladores han recibido formación correspondiente a la actividad desarrollada.', N'El responsable del establecimiento se asegurará de que todos los manipuladores han recibido formación por un programa aprobado en la CAPV o si la han recibido en otro lugar, la entidad cuenta con la autorización de esa Comunidad Autónoma. La formación recibida por los manipuladores les permite desarrollar prácticas correctas de seguridad e higiene de los alimentos y se corresponderá con la actividad desarrollada. El responsable del establecimiento presentará los documentos de acreditación de la formación los manipuladores que incluirá información de todos y cada uno de ellos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(18 AS Decimal(3, 0)), CAST(155 AS Decimal(6, 0)), N'34             ', N'Los documentos acreditativos están vigentes.', N'El documento acreditativo estará en vigencia, lo cual se comprobará mediante la fecha que figura en el mismo. ', N'Los documentos acreditativos están vigentes.', N'El documento acreditativo estará en vigencia, lo cual se comprobará mediante la fecha que figura en el mismo. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(19 AS Decimal(3, 0)), CAST(159 AS Decimal(6, 0)), N'36             ', N'Antes de su reutilización son debidamente higienizados.', N'Antes de cada nueva utilización, serán sometidos a una limpieza e higienización, mediante un sistema que garantice las condiciones higiénico?sanitarias del primer uso.', N'Antes de su reutilización son debidamente higienizados.', N'Antes de cada nueva utilización, serán sometidos a una limpieza e higienización, mediante un sistema que garantice las condiciones higiénico?sanitarias del primer uso.')
