INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(20 AS Decimal(3, 0)), CAST(178 AS Decimal(6, 0)), N'41             ', N'Los materiales y productos en contacto directo con alimentos utilizados para el etiquetado o marcado de los mismos, están autorizados, son de uso alimentario, no ceden componentes, ni modifican la composición, ni alteran los caracteres organolépticos de l????', N'Los materiales utilizados para etiquetado y marcado en contacto directo con los alimentos habrán de estar autorizados para uso alimentario, estar fabricados de conformidad con las buenas practicas de fabricación para que en condiciones normales o previsibles de empleo, no cedan componentes a los productos alimenticios en cantidad que pueda:
Representar un peligro para la salud humana.
Ocasionar una modificación inaceptable de la composición de estos.
Alterar los caracteres organolepticos.', N'Los materiales y productos en contacto directo con alimentos utilizados para el etiquetado o marcado de los mismos, están autorizados, son de uso alimentario, no ceden componentes, ni modifican la composición, ni alteran los caracteres organolépticos de l????', N'Los materiales utilizados para etiquetado y marcado en contacto directo con los alimentos habrán de estar autorizados para uso alimentario, estar fabricados de conformidad con las buenas practicas de fabricación para que en condiciones normales o previsibles de empleo, no cedan componentes a los productos alimenticios en cantidad que pueda:
Representar un peligro para la salud humana.
Ocasionar una modificación inaceptable de la composición de estos.
Alterar los caracteres organolepticos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(20 AS Decimal(3, 0)), CAST(177 AS Decimal(6, 0)), N'40             ', N'Tiene establecido un sistema  y procedimiento mediante el cual, en  cualquier fase del proceso de producción - transformación puede identificar el origen de los productos o sustancias incorporadas o utilizadas para la obtención de un producto alimentario,????', N'Se entiende por trazabilidad; la posibilidad de encontrar y seguir el rastro a través de todas las etapas de producción, transformación y distribución de un alimento, un pienso, un animal destinado a la producción de alimentos o una sustancia destinada a ser incorporada en alimentos o piensos o con probabilidad de serlo.
En todas las etapas de la producción, la transformación y la distribución deberá asegurarse la trazabilidad de los alimentos y de cualquier otra sustancia destinada a ser incorporada en un alimento o con probabilidad de serlo.
Los titulares de empresas alimentarias deberán poder identificar a cualquier persona que les haya suministrado un alimento, o cualquier sustancia destinada a ser incorporada en un alimento, o con probabilidad de serlo. Para tal fin, deberán disponer de sistemas y procedimientos que permitan poner esta información a disposición de las autoridades competentes, si estas lo solicitan.', N'Tiene establecido un sistema  y procedimiento mediante el cual, en  cualquier fase del proceso de producción - transformación puede identificar el origen de los productos o sustancias incorporadas o utilizadas para la obtención de un producto alimentario,????', N'Se entiende por trazabilidad; la posibilidad de encontrar y seguir el rastro a través de todas las etapas de producción, transformación y distribución de un alimento, un pienso, un animal destinado a la producción de alimentos o una sustancia destinada a ser incorporada en alimentos o piensos o con probabilidad de serlo.
En todas las etapas de la producción, la transformación y la distribución deberá asegurarse la trazabilidad de los alimentos y de cualquier otra sustancia destinada a ser incorporada en un alimento o con probabilidad de serlo.
Los titulares de empresas alimentarias deberán poder identificar a cualquier persona que les haya suministrado un alimento, o cualquier sustancia destinada a ser incorporada en un alimento, o con probabilidad de serlo. Para tal fin, deberán disponer de sistemas y procedimientos que permitan poner esta información a disposición de las autoridades competentes, si estas lo solicitan.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(20 AS Decimal(3, 0)), CAST(176 AS Decimal(6, 0)), N'40             ', N'Tiene establecido un sistema  y procedimiento que permita tener  identificadas las empresas que le suministran y a las que aporta o vende  sus productos, indicando al menos; la naturaleza del producto, lote, fecha de entrada/salida y cantidad; mediante al????', N'Se entiende por trazabilidad; la posibilidad de encontrar y seguir el rastro a través de todas las etapas de producción, transformación y distribución de un alimento, un pienso, un animal destinado a la producción de alimentos o una sustancia destinada a ser incorporada en alimentos o piensos o con probabilidad de serlo.
En todas las etapas de la producción, la transformación y la distribución deberá asegurarse la trazabilidad de los alimentos y de cualquier otra sustancia destinada a ser incorporada en un alimento o con probabilidad de serlo.
Los titulares de empresas alimentarias deberán poder identificar a cualquier persona que les haya suministrado un alimento, o cualquier sustancia destinada a ser incorporada en un alimento, o con probabilidad de serlo. Para tal fin, deberán disponer de sistemas y procedimientos que permitan poner esta información a disposición de las autoridades competentes, si estas lo solicitan.', N'Tiene establecido un sistema  y procedimiento que permita tener  identificadas las empresas que le suministran y a las que aporta o vende  sus productos, indicando al menos; la naturaleza del producto, lote, fecha de entrada/salida y cantidad; mediante al????', N'Se entiende por trazabilidad; la posibilidad de encontrar y seguir el rastro a través de todas las etapas de producción, transformación y distribución de un alimento, un pienso, un animal destinado a la producción de alimentos o una sustancia destinada a ser incorporada en alimentos o piensos o con probabilidad de serlo.
En todas las etapas de la producción, la transformación y la distribución deberá asegurarse la trazabilidad de los alimentos y de cualquier otra sustancia destinada a ser incorporada en un alimento o con probabilidad de serlo.
Los titulares de empresas alimentarias deberán poder identificar a cualquier persona que les haya suministrado un alimento, o cualquier sustancia destinada a ser incorporada en un alimento, o con probabilidad de serlo. Para tal fin, deberán disponer de sistemas y procedimientos que permitan poner esta información a disposición de las autoridades competentes, si estas lo solicitan.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111025 AS Decimal(6, 0)), N'75             ', N'El aceite de fritura se cambia antes que se produzca deterioro de los caracteres organolépticos del mismo (cambios de color, olor, punto de humo, formación de espumas...).', N'El establecimiento tiene sistematizado el proceso del cambio de aceite. Se revisará el aceite que contienen las freidoras y se comprobarán las características organolépticas del mismo. Se tomará medida de compuestos polares utilizando un medidor de compuestos polares o tiras colorimétricas con el fin de determinar si la sistemática de cambio de aceite establecida por la empresa es suficiente para asegurar que no alcanza niveles de compuestos polares superiores al 25%.', N'El aceite de fritura se cambia antes que se produzca deterioro de los caracteres organolépticos del mismo (cambios de color, olor, punto de humo, formación de espumas...).', N'El establecimiento tiene sistematizado el proceso del cambio de aceite. Se revisará el aceite que contienen las freidoras y se comprobarán las características organolépticas del mismo. Se tomará medida de compuestos polares utilizando un medidor de compuestos polares o tiras colorimétricas con el fin de determinar si la sistemática de cambio de aceite establecida por la empresa es suficiente para asegurar que no alcanza niveles de compuestos polares superiores al 25%.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111026 AS Decimal(6, 0)), N'75             ', N'La temperatura en el centro del producto de los alimentos cocinados alcanza los 65º C.', N'Los alimentos que se están cocinando en ese momento llegan en el centro del producto a 65º C y que el calor se distribuye correctamente por todo el producto. Se tendrá en cuenta, tal y como aparece en el Plan genérico, que se podrán exceptuar algunos platos a petición del consumidor. Además se comprobará que la temperatura de nuestro termómetro se corresponde con las anotadas en el registro.', N'La temperatura en el centro del producto de los alimentos cocinados alcanza los 65º C.', N'Los alimentos que se están cocinando en ese momento llegan en el centro del producto a 65º C y que el calor se distribuye correctamente por todo el producto. Se tendrá en cuenta, tal y como aparece en el Plan genérico, que se podrán exceptuar algunos platos a petición del consumidor. Además se comprobará que la temperatura de nuestro termómetro se corresponde con las anotadas en el registro.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(20 AS Decimal(3, 0)), CAST(174 AS Decimal(6, 0)), N'39             ', N'Se aprecia y figuran indicados, la identificación del lote, fecha de caducidad o consumo preferente, las condiciones de conservación y utilización, la identificación del establecimiento.', N'En el etiquetado se indicará la información correspondiente a:
1- Lote: conjunto de unidades de venta de un producto alimenticio producido, fabricado o envasado en circunstancias prácticamente idénticas. Será determinado en su caso por el productor o envasador o fabricante o primer vendedor establecido en el interior de la CEE. Irá precedido de la letra L o palabra Lote. Cuando los productos no estén envasados, la indicación del lote figurará en el embalaje o en el recipiente o, en su defecto en los documentos comerciales pertinentes.
La indicación del lote no será obligatoria en los siguientes casos: 
- En los productos agrícolas que al salir de la explotación sean vendidos o entregados a centros de almacenamiento, envasado, preparación o transformación.
- Cuando en los puntos de venta al consumidor final, los productos alimenticios no estén previamente envasados, sean envasados a petición del comprador o previamente envasados para su venta inmediata.
- En los envases o recipientes de menos de 10 cm 2.
- Cuando la fecha de duración mínima o la fecha de caducidad figure en el etiquetado, el producto alimenticio podrá no ir acompa¦ado de la indicación del lote, siempre que dicha fecha tenga, por lo menos, el día y el mes indicados claramente y en orden.
2- Estará indicada la fecha de duración mínima hasta la cual el producto alimenticio mantiene sus propiedades especificas en condiciones de conservación apropiadas o, en su caso, la fecha de caducidad (productos muy perecederos).
3- Figurarán indicadas, las condiciones especiales de conservación y utilización.
4- Se harán constar los datos de identificación de la industria: nombre, la razón social o la denominación del fabricante, envasador o vendedor establecido en la Comunidad Económica Europea y, en todo caso, su domicilio, debiendo coincidir los datos de identificación de la industria con los que consten en la autorización sanitaria.
Los alimentos importados de terceros países deben hacer constar el país de origen.', N'Se aprecia y figuran indicados, la identificación del lote, fecha de caducidad o consumo preferente, las condiciones de conservación y utilización, la identificación del establecimiento.', N'En el etiquetado se indicará la información correspondiente a:
1- Lote: conjunto de unidades de venta de un producto alimenticio producido, fabricado o envasado en circunstancias prácticamente idénticas. Será determinado en su caso por el productor o envasador o fabricante o primer vendedor establecido en el interior de la CEE. Irá precedido de la letra L o palabra Lote. Cuando los productos no estén envasados, la indicación del lote figurará en el embalaje o en el recipiente o, en su defecto en los documentos comerciales pertinentes.
La indicación del lote no será obligatoria en los siguientes casos: 
- En los productos agrícolas que al salir de la explotación sean vendidos o entregados a centros de almacenamiento, envasado, preparación o transformación.
- Cuando en los puntos de venta al consumidor final, los productos alimenticios no estén previamente envasados, sean envasados a petición del comprador o previamente envasados para su venta inmediata.
- En los envases o recipientes de menos de 10 cm 2.
- Cuando la fecha de duración mínima o la fecha de caducidad figure en el etiquetado, el producto alimenticio podrá no ir acompa¦ado de la indicación del lote, siempre que dicha fecha tenga, por lo menos, el día y el mes indicados claramente y en orden.
2- Estará indicada la fecha de duración mínima hasta la cual el producto alimenticio mantiene sus propiedades especificas en condiciones de conservación apropiadas o, en su caso, la fecha de caducidad (productos muy perecederos).
3- Figurarán indicadas, las condiciones especiales de conservación y utilización.
4- Se harán constar los datos de identificación de la industria: nombre, la razón social o la denominación del fabricante, envasador o vendedor establecido en la Comunidad Económica Europea y, en todo caso, su domicilio, debiendo coincidir los datos de identificación de la industria con los que consten en la autorización sanitaria.
Los alimentos importados de terceros países deben hacer constar el país de origen.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2163 AS Decimal(6, 0)), N'80             ', N'Se han realizado pruebas de caducidad para los distintos productos elaborados y son suficientes', N'Se verificará que cuando una empresa se responsabiliza de una determinada duración para sus productos, prueba previamente que al final del tiempo asignado, el producto sigue siendo aceptable desde el punto de vista de su seguridad. Por lo tanto deben realizarse pruebas que nos demuestren que al final de su vida útil el producto reúne las especificaciones marcadas. Las pruebas realizadas serán registradas.', N' ', N'Se verificará que cuando una empresa se responsabiliza de una determinada duración para sus productos, prueba previamente que al final del tiempo asignado, el producto sigue siendo aceptable desde el punto de vista de su seguridad. Por lo tanto deben realizarse pruebas que nos demuestren que al final de su vida útil el producto reúne las especificaciones marcadas. Las pruebas realizadas serán registradas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(855 AS Decimal(6, 0)), N'3              ', N'Si recibe carne congelada, precisa de un local o un emplazamiento para descongelar las materias primas. ', N'Los establecimientos que empleen como materia prima la carne congelada es necesario que dispongan de un local o emplazamiento para descongelar las materias primas.', N' ', N'Los establecimientos que empleen como materia prima la carne congelada es necesario que dispongan de un local o emplazamiento para descongelar las materias primas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2162 AS Decimal(6, 0)), N'80             ', N'Se recogen adecuadamente las quejas de los clientes y devoluciones y se adoptan las medidas necesarias', N'Se comprobará que las quejas de clientes y devoluciones se recogen siempre que tengan relación con aspectos sanitarios. Se valorará cómo se ha recogido el motivo de la queja, cómo se ha analizado y buscado la causa, así como la solución que se ha dado en cada caso, tanto para solucionarlo como para evitar que se repita de nuevo. Tras el análisis las soluciones a adoptar pueden ser puntuales o afectar a alguna parte del plan de autocontrol y requerir cambios sustanciales. Las medidas adoptadas deberán estar registradas en todos los casos.', N' ', N'Se comprobará que las quejas de clientes y devoluciones se recogen siempre que tengan relación con aspectos sanitarios. Se valorará cómo se ha recogido el motivo de la queja, cómo se ha analizado y buscado la causa, así como la solución que se ha dado en cada caso, tanto para solucionarlo como para evitar que se repita de nuevo. Tras el análisis las soluciones a adoptar pueden ser puntuales o afectar a alguna parte del plan de autocontrol y requerir cambios sustanciales. Las medidas adoptadas deberán estar registradas en todos los casos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2161 AS Decimal(6, 0)), N'80             ', N'Se realizan las auditorías según están planificadas, son completas y en caso de detectarse desviaciones se adoptan las medidas necesarias', N'Se verificará que las auditorías se realizan según el calendario previsto, que son realizadas por los responsables nombrados y que incluyen la verificación de los principios del sistema  (revisión de los resultados de la vigilancia y de las acciones correctoras principalmente) y de los planes de apoyo. Se comprobará que para ello se han utilizado unos listados de comprobación que se cumplimentan en cada una de ellas y nos permiten analizar los aspectos auditados y los criterios utilizados así como sus resultados
Se valorará también que en caso de resultados incorrectos se han adoptado medidas que solucionen los problemas detectados, incluso un replanteamiento del propio sistema de autocontrol, si fuera necesario. Las medidas adoptadas deberán estar registradas en todos los casos.
', N' ', N'Se verificará que las auditorías se realizan según el calendario previsto, que son realizadas por los responsables nombrados y que incluyen la verificación de los principios del sistema  (revisión de los resultados de la vigilancia y de las acciones correctoras principalmente) y de los planes de apoyo. Se comprobará que para ello se han utilizado unos listados de comprobación que se cumplimentan en cada una de ellas y nos permiten analizar los aspectos auditados y los criterios utilizados así como sus resultados
Se valorará también que en caso de resultados incorrectos se han adoptado medidas que solucionen los problemas detectados, incluso un replanteamiento del propio sistema de autocontrol, si fuera necesario. Las medidas adoptadas deberán estar registradas en todos los casos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2164 AS Decimal(6, 0)), N'80             ', N'Se han realizado pruebas de validación y se consideran suficientes para confirmar que el sistema es válido', N'Fundamentalmente las medidas preventivas y los límites críticos deben de ser válidos para el objetivo que se persigue y por tanto se debe poder demostrar que los parámetros utilizados en ambos casos son los necesarios para que la producción de los alimentos sea segura.
Hay parámetros de la legislación vigente y otros amparados por la bibliografía que se utilizan en el plan y no precisarían en principio de validación a no ser que deban de sufrir algún ajuste específico en la empresa. En cambio hay otros que deberán demostrarse que son eficaces mediante pruebas concretas. Se comprobará que se han hecho las pruebas de validación necesarias y que queda constancia escrita de ello.', N' ', N'Fundamentalmente las medidas preventivas y los límites críticos deben de ser válidos para el objetivo que se persigue y por tanto se debe poder demostrar que los parámetros utilizados en ambos casos son los necesarios para que la producción de los alimentos sea segura.
Hay parámetros de la legislación vigente y otros amparados por la bibliografía que se utilizan en el plan y no precisarían en principio de validación a no ser que deban de sufrir algún ajuste específico en la empresa. En cambio hay otros que deberán demostrarse que son eficaces mediante pruebas concretas. Se comprobará que se han hecho las pruebas de validación necesarias y que queda constancia escrita de ello.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2160 AS Decimal(6, 0)), N'80             ', N'Se realizan controles analíticos que verifican la eficacia de la limpieza y en caso de resultado desfavorable se adoptan las medidas necesarias', N'El auditor comprobará que se realizan análisis de superficies, instalaciones y de maquinaria una vez limpias, de forma que se verifique la eficacia del proceso de limpieza. Se comprobará el cumplimiento del plan en cuanto a los parámetros a analizar y la frecuencia de dichos análisis, que dependerá a su vez de la contaminación que pueden aportar directamente al producto en caso de detectarse una limpieza inadecuada. 

El auditor valorará además que ante resultados incorrectos se han adoptado medidas destinadas a investigar si el problema es que no se ha ejecutado el plan correctamente o que a pesar de ejecutarse el plan no funciona. Este último caso será menos frecuente ya que el plan de limpieza antes de su puesta en marcha suele ser validado para demostrar su eficacia, pero pueden darse peque¦os cambios en el sistema productivo de la empresa que hagan que el sistema que se puso en marcha ya no funcione en las actuales circunstancias. En cada caso las medidas serán diferentes pero en ambos deben evitar que suceda de nuevo. Puede ocurrir que incluso el problema pueda afectar directamente al producto elaborado y por tanto se han de tomar medidas para que ese producto no llegue a los canales de comercialización. Las medidas adoptadas deberán estar registradas en todos los casos.
', N' ', N'El auditor comprobará que se realizan análisis de superficies, instalaciones y de maquinaria una vez limpias, de forma que se verifique la eficacia del proceso de limpieza. Se comprobará el cumplimiento del plan en cuanto a los parámetros a analizar y la frecuencia de dichos análisis, que dependerá a su vez de la contaminación que pueden aportar directamente al producto en caso de detectarse una limpieza inadecuada. 

El auditor valorará además que ante resultados incorrectos se han adoptado medidas destinadas a investigar si el problema es que no se ha ejecutado el plan correctamente o que a pesar de ejecutarse el plan no funciona. Este último caso será menos frecuente ya que el plan de limpieza antes de su puesta en marcha suele ser validado para demostrar su eficacia, pero pueden darse peque¦os cambios en el sistema productivo de la empresa que hagan que el sistema que se puso en marcha ya no funcione en las actuales circunstancias. En cada caso las medidas serán diferentes pero en ambos deben evitar que suceda de nuevo. Puede ocurrir que incluso el problema pueda afectar directamente al producto elaborado y por tanto se han de tomar medidas para que ese producto no llegue a los canales de comercialización. Las medidas adoptadas deberán estar registradas en todos los casos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2169 AS Decimal(6, 0)), N'82             ', N'Las BPF(s) implantadas previenen realmente los peligros detectados en cada etapa por este motivo', N'Hay que valorar si, conocido el proceso de trabajo, no se han obviado prácticas de fabricación necesarias o que algunas de las planteadas no cumplen con el objetivo (evitar contaminaciones relacionadas con el propio proceso productivo) y  por tanto no son suficientes
Por otro lado las normas de higiene sirven para prevenir contaminaciones provenientes directamente del propio personal manipulador, por tanto deberemos valorar si se han obviado algunas que tengan este objetivo.
', N' ', N'Hay que valorar si, conocido el proceso de trabajo, no se han obviado prácticas de fabricación necesarias o que algunas de las planteadas no cumplen con el objetivo (evitar contaminaciones relacionadas con el propio proceso productivo) y  por tanto no son suficientes
Por otro lado las normas de higiene sirven para prevenir contaminaciones provenientes directamente del propio personal manipulador, por tanto deberemos valorar si se han obviado algunas que tengan este objetivo.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2165 AS Decimal(6, 0)), N'81             ', N'Se sigue la sistemática prevista para revisar el APPCC/HACCP cuando se realizan cambios y esta sistemática es correcta', N'Se deberá comprobar que se han realizado las revisiones previstas en el sistema, cuando se ha producido algún cambio en el sistema productivo, en el producto, en las instalaciones y maquinaria, o en cualquier actividad de la empresa y se comprobarán las modificaciones que estos cambios hayan podido suponer para el sistema.
También deben existir revisiones periódicas aunque no hayan existido estos cambios, ya que aspectos como el análisis de peligros deben ser revisados con respecto a las novedades científicas que tengan alguna relación con la empresa.', N' ', N'Se deberá comprobar que se han realizado las revisiones previstas en el sistema, cuando se ha producido algún cambio en el sistema productivo, en el producto, en las instalaciones y maquinaria, o en cualquier actividad de la empresa y se comprobarán las modificaciones que estos cambios hayan podido suponer para el sistema.
También deben existir revisiones periódicas aunque no hayan existido estos cambios, ya que aspectos como el análisis de peligros deben ser revisados con respecto a las novedades científicas que tengan alguna relación con la empresa.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2170 AS Decimal(6, 0)), N'82             ', N'Se comprueba y se registra el cumplimiento de las BPF(s)', N'Se valorará si se realizan estas comprobaciones de la forma prevista, con la frecuencia indicada y por los responsables establecidos, así como si se registran sus resultados.

La comprobación del cumplimiento de las BPF(s) será diferente según su consideración dentro del sistema de autocontrol. Si algunas de ellas han sido consideradas medidas preventivas para PCC(s), su comprobación estará marcada por la vigilancia del sistema APPCC/HACCP y deberá cumplir lo que se ha indicado para ella. Pero muchas de estas prácticas estarán incluidas en un manual y constituirán un Plan de Apoyo al Sistema. En este caso es igualmente necesario que se compruebe su cumplimiento con una periodicidad suficiente para asegurar que se detectan  desviaciones y se adoptan medidas para corregirlas. Esta comprobación debe registrarse y para ello pueden usarse unos listados de comprobación que son chequeados por personal diferente al propio que realiza las manipulaciones y que por ello puede mantener cierta objetividad.
', N' ', N'Se valorará si se realizan estas comprobaciones de la forma prevista, con la frecuencia indicada y por los responsables establecidos, así como si se registran sus resultados.

La comprobación del cumplimiento de las BPF(s) será diferente según su consideración dentro del sistema de autocontrol. Si algunas de ellas han sido consideradas medidas preventivas para PCC(s), su comprobación estará marcada por la vigilancia del sistema APPCC/HACCP y deberá cumplir lo que se ha indicado para ella. Pero muchas de estas prácticas estarán incluidas en un manual y constituirán un Plan de Apoyo al Sistema. En este caso es igualmente necesario que se compruebe su cumplimiento con una periodicidad suficiente para asegurar que se detectan  desviaciones y se adoptan medidas para corregirlas. Esta comprobación debe registrarse y para ello pueden usarse unos listados de comprobación que son chequeados por personal diferente al propio que realiza las manipulaciones y que por ello puede mantener cierta objetividad.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2166 AS Decimal(6, 0)), N'81             ', N'Cuando se realizan los cambios, se registran los mismos, y se actualiza el fechado y versionado', N'Se comprobará que los cambios se han registrado y que la documentación está actualizada en todo momento. Para ello es necesario que cada uno de los documentos esté registrado y fechado de forma que cuando exista un cambio todos los implicados sepan cual es la versión actualizada.', N' ', N'Se comprobará que los cambios se han registrado y que la documentación está actualizada en todo momento. Para ello es necesario que cada uno de los documentos esté registrado y fechado de forma que cuando exista un cambio todos los implicados sepan cual es la versión actualizada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2168 AS Decimal(6, 0)), N'82             ', N'El personal conoce las BPF(s) establecidas para cada etapa del proceso y se cumplen', N'Se deberá comprobar si el personal manipulador conoce tanto las prácticas de higiene generales como las instrucciones de trabajo específicas para cada puesto. Para hacer esta valoración deberemos entrevistarnos con el personal, así como observar su trabajo, al igual que podremos disponer de registros de formación en el caso de que esta haya sido reglada. Con todo ello comprobaremos que el personal conoce las pautas marcadas por el plan y cómo ha sido realizada esa formación. 

Así mismo, se trata de comprobar si las BPF(s) establecidas se cumplen tal y como se han planteado, y cuando hablamos de  BPF(s) nos estamos refiriendo tanto a las especificaciones relacionadas con la higiene e indumentaria, como a los procedimientos de trabajo establecidos para prevenir contaminaciones o multiplicaciones derivadas del propio proceso de trabajo, en cada una de las etapas. Así se comprobará que se cumplen las instrucciones destinadas a prevenir contaminaciones cruzadas entre distintas materias primas, entre materias primas con productos elaborados, o ambos con equipos y superficies. Igualmente se comprobará que se cumplen aquellas que evitan las multiplicaciones bacterianas debido a la propia duración del proceso productivo o por tratamientos inadecuados. También se comprobará que se adoptan las prácticas necesarias para un correcto almacenamiento (temperaturas, estiba, rotación de stock, en caso de uso de envases de cristal prevención de problemas derivados de roturas u otros aspectos como la gestión de residuos y basuras etc .

En definitiva, se trata de comprobar la correcta ejecución de las BPF(s) definidas en el manual. 
', N' ', N'Se deberá comprobar si el personal manipulador conoce tanto las prácticas de higiene generales como las instrucciones de trabajo específicas para cada puesto. Para hacer esta valoración deberemos entrevistarnos con el personal, así como observar su trabajo, al igual que podremos disponer de registros de formación en el caso de que esta haya sido reglada. Con todo ello comprobaremos que el personal conoce las pautas marcadas por el plan y cómo ha sido realizada esa formación. 

Así mismo, se trata de comprobar si las BPF(s) establecidas se cumplen tal y como se han planteado, y cuando hablamos de  BPF(s) nos estamos refiriendo tanto a las especificaciones relacionadas con la higiene e indumentaria, como a los procedimientos de trabajo establecidos para prevenir contaminaciones o multiplicaciones derivadas del propio proceso de trabajo, en cada una de las etapas. Así se comprobará que se cumplen las instrucciones destinadas a prevenir contaminaciones cruzadas entre distintas materias primas, entre materias primas con productos elaborados, o ambos con equipos y superficies. Igualmente se comprobará que se cumplen aquellas que evitan las multiplicaciones bacterianas debido a la propia duración del proceso productivo o por tratamientos inadecuados. También se comprobará que se adoptan las prácticas necesarias para un correcto almacenamiento (temperaturas, estiba, rotación de stock, en caso de uso de envases de cristal prevención de problemas derivados de roturas u otros aspectos como la gestión de residuos y basuras etc .

En definitiva, se trata de comprobar la correcta ejecución de las BPF(s) definidas en el manual. 
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2167 AS Decimal(6, 0)), N'82             ', N' El Manual de BPF(s)es completo y está correctamente dise¦ado', N'Se valorará si el Manual de BPF(s) establece procedimientos de trabajo correctos para cada etapa del proceso, incluyendo procedimientos de manipulación que eviten la contaminación de los productos por el personal manipulador, así como pautas de trabajo concretas que eviten peligros procedentes de manipulaciones indebidas.', N' ', N'Se valorará si el Manual de BPF(s) establece procedimientos de trabajo correctos para cada etapa del proceso, incluyendo procedimientos de manipulación que eviten la contaminación de los productos por el personal manipulador, así como pautas de trabajo concretas que eviten peligros procedentes de manipulaciones indebidas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2159 AS Decimal(6, 0)), N'80             ', N'Se realizan controles analíticos del agua  y en caso de resultado desfavorable se adoptan las medidas necesarias', N'Se comprobará que se realizan controles analíticos del agua, para los parámetros marcados y con la frecuencia que en el plan se establece. Los parámetros y la frecuencia de dichos controles dependerá del origen del agua y se ajustará como mínimo a lo indicado en la reglamentación de aguas correspondiente, de forma que garantice que el agua utilizada en todo el proceso productivo de la industria es siempre potable.



En caso de establecimientos que se abastecen de una red de agua potable pero disponen de depósito intermedio propio y en aquellos que disponen de recursos de agua potable propios, en la auditoria deberá valorarse además de los resultados, que el procedimiento de control que llevan a cabo se ajusta al programado y es suficiente para garantizar la idoneidad de esa agua.

En caso de resultados incorrectos se comprobará que se adoptan las medidas necesarias para evitar que producto que ha podido contaminarse con el agua siga los canales de comercialización y evitar también que vuelva a suceder de nuevo. Las medidas adoptadas deberán estar registradas en todos los casos.', N' ', N'Se comprobará que se realizan controles analíticos del agua, para los parámetros marcados y con la frecuencia que en el plan se establece. Los parámetros y la frecuencia de dichos controles dependerá del origen del agua y se ajustará como mínimo a lo indicado en la reglamentación de aguas correspondiente, de forma que garantice que el agua utilizada en todo el proceso productivo de la industria es siempre potable.



En caso de establecimientos que se abastecen de una red de agua potable pero disponen de depósito intermedio propio y en aquellos que disponen de recursos de agua potable propios, en la auditoria deberá valorarse además de los resultados, que el procedimiento de control que llevan a cabo se ajusta al programado y es suficiente para garantizar la idoneidad de esa agua.

En caso de resultados incorrectos se comprobará que se adoptan las medidas necesarias para evitar que producto que ha podido contaminarse con el agua siga los canales de comercialización y evitar también que vuelva a suceder de nuevo. Las medidas adoptadas deberán estar registradas en todos los casos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(350 AS Decimal(6, 0)), N'50             ', N'Los establos reúnen las condiciones de estructuras, materiales, ventilación , cama, protección, bebederos, comederos etc.', N'Los locales de estabulación deberán disponer de los siguientes elementos:
Deberán disponer, para estabular adecuadamente los animales, de un número suficiente de corrales dotados de protección para resguardarlos de la intemperie. Se protegerá a los animales de las inclemencias del tiempo. Cuando hayan estado expuestos a un tiempo húmedo y con temperaturas altas, se les refrescará con medios adecuados.
Suelos que reduzcan al mínimo el riesgo de resbalones y no causen heridas a los animales que estén en contacto con ellos
Las estructuras y materiales deben estar dise¦ados y mantenidos de tal manera que eviten lesiones en los animales: ausencia de aristas, bordes cortantes, agujeros ,etc.
Ventilación adecuada para las condiciones extremas previsibles de temperatura y humedad. Cuando sea necesario un sistema de ventilación mecánica, se dispondrá de un sistema de recambio que en caso de avería entre en funcionamiento inmediatamente;
Iluminación de intensidad suficiente para poder examinar todos los animales en cualquier momento, debiendo disponer en caso de necesidad de una iluminación artificial de recambio adecuada;
Bebederos para todos los animales.En caso necesario, cantidades suficientes de cama adecuada para todos los animales que permanezcan mas de un día en dichos locales.', N'Los establos reúnen las condiciones de estructuras, materiales, ventilación , cama, protección, bebederos, comederos etc.', N'Los locales de estabulación deberán disponer de los siguientes elementos:
Deberán disponer, para estabular adecuadamente los animales, de un número suficiente de corrales dotados de protección para resguardarlos de la intemperie. Se protegerá a los animales de las inclemencias del tiempo. Cuando hayan estado expuestos a un tiempo húmedo y con temperaturas altas, se les refrescará con medios adecuados.
Suelos que reduzcan al mínimo el riesgo de resbalones y no causen heridas a los animales que estén en contacto con ellos
Las estructuras y materiales deben estar dise¦ados y mantenidos de tal manera que eviten lesiones en los animales: ausencia de aristas, bordes cortantes, agujeros ,etc.
Ventilación adecuada para las condiciones extremas previsibles de temperatura y humedad. Cuando sea necesario un sistema de ventilación mecánica, se dispondrá de un sistema de recambio que en caso de avería entre en funcionamiento inmediatamente;
Iluminación de intensidad suficiente para poder examinar todos los animales en cualquier momento, debiendo disponer en caso de necesidad de una iluminación artificial de recambio adecuada;
Bebederos para todos los animales.En caso necesario, cantidades suficientes de cama adecuada para todos los animales que permanezcan mas de un día en dichos locales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(863 AS Decimal(6, 0)), N'20             ', N'En caso de preparación manual, el personal de producción de carne picada y de preparados de carne lleva máscara buconasal. Cuando la autoridad así lo imponga, llevará también guantes lisos, impermeables.', N'En caso de preparación manual, el personal encargado de la producción de carne picada y de los preparados de carne deberá, además, llevar una máscara buconasal. La autoridad competente podrá también imponer el uso de guantes lisos, impermeables y desechables, o similares que puedan limpiarse y desinfectarse.', N' ', N'En caso de preparación manual, el personal encargado de la producción de carne picada y de los preparados de carne deberá, además, llevar una máscara buconasal. La autoridad competente podrá también imponer el uso de guantes lisos, impermeables y desechables, o similares que puedan limpiarse y desinfectarse.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(861 AS Decimal(6, 0)), N'11             ', N'Para la ultracongelación de las carnes dispone de equipos tecnológicos adecuados.', N'La ultracongelación de las carne picada y preparados de carne sólo se podrá realizar si el establecimiento dispone de un equipo adecuado tecnológicamente a este fin (túnel de congelación, abatidor de temperatura, etc.)', N' ', N'La ultracongelación de las carne picada y preparados de carne sólo se podrá realizar si el establecimiento dispone de un equipo adecuado tecnológicamente a este fin (túnel de congelación, abatidor de temperatura, etc.)')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2151 AS Decimal(6, 0)), N'78             ', N'El personal implicado conoce perfectamente el sistema de vigilancia y lo cumple', N'El auditor comprobará que el personal encargado de la vigilancia conoce perfectamente el sistema de vigilancia. Para ello se valorará su conocimiento de las instrucciones referidas a cómo realizar cada una de las vigilancias, la utilización de los distintos aparatos de medida en caso de ser necesarios, si tiene claros los límites críticos para cada una de esas vigilancias. Se comprobará además que es el responsable asignado quien realmente los realiza y con la frecuencia establecida.', N' ', N'El auditor comprobará que el personal encargado de la vigilancia conoce perfectamente el sistema de vigilancia. Para ello se valorará su conocimiento de las instrucciones referidas a cómo realizar cada una de las vigilancias, la utilización de los distintos aparatos de medida en caso de ser necesarios, si tiene claros los límites críticos para cada una de esas vigilancias. Se comprobará además que es el responsable asignado quien realmente los realiza y con la frecuencia establecida.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2150 AS Decimal(6, 0)), N'78             ', N'El sistema de vigilancia es completo y está correctamente dise¦ado', N'Se comprobará que el sistema de vigilancia es completo, y que incluye qué vigilancia se va a realizar, cómo va a hacerse (procedimiento suficientemente definido), quién lo va a realizar y con qué frecuencia, y que esta vigilancia se ajusta a la realidad constatada en la empresa.', N' ', N'Se comprobará que el sistema de vigilancia es completo, y que incluye qué vigilancia se va a realizar, cómo va a hacerse (procedimiento suficientemente definido), quién lo va a realizar y con qué frecuencia, y que esta vigilancia se ajusta a la realidad constatada en la empresa.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(871 AS Decimal(6, 0)), N'32             ', N'En caso de utilizar carne refrigerada como materia prima, su obtención no excede de:
.- Carne ave 3 días desde sacrificio.
.- Resto carnes 7 días desde sacrificio.
.- Carne de vacuno deshuesada y envasada al vacio 15 días desde sacrificio. ', N'Si se utiliza carne refrigerada en la elaboración de la carne picada se deberá tener en cuenta que su preparación no podrá excederse de:
.- Tres días desde el sacrificio si es carne de ave de corral.
.- Siete días desde el sacrificio para el resto de animales diferentes al ave.
.- Quince días desde el sacrificio si es carne de vacuno deshuesada y envasada al vacio.', N' ', N'Si se utiliza carne refrigerada en la elaboración de la carne picada se deberá tener en cuenta que su preparación no podrá excederse de:
.- Tres días desde el sacrificio si es carne de ave de corral.
.- Siete días desde el sacrificio para el resto de animales diferentes al ave.
.- Quince días desde el sacrificio si es carne de vacuno deshuesada y envasada al vacio.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2152 AS Decimal(6, 0)), N'78             ', N'El sistema de vigilancia es suficiente para evitar que producto que supere el límite crítico sea comercializado', N'El sistema de vigilancia debe de ser tal que permita adoptar acciones correctoras a tiempo de evitar que un producto que pueda haber superado un límite crítico sea comercializado sin haberse valorado la influencia de la superación de ese límite. Por lo tanto, conociendo la realidad de la empresa, sus ritmos y flujos, cómo  y cuándo se realiza la vigilancia y el resultado de las acciones correctoras adoptadas, valoraremos si el sistema de vigilancia establecido es el necesario para el objetivo anteriormente planteado', N' ', N'El sistema de vigilancia debe de ser tal que permita adoptar acciones correctoras a tiempo de evitar que un producto que pueda haber superado un límite crítico sea comercializado sin haberse valorado la influencia de la superación de ese límite. Por lo tanto, conociendo la realidad de la empresa, sus ritmos y flujos, cómo  y cuándo se realiza la vigilancia y el resultado de las acciones correctoras adoptadas, valoraremos si el sistema de vigilancia establecido es el necesario para el objetivo anteriormente planteado')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2171 AS Decimal(6, 0)), N'82             ', N'Se adoptan y registran las medidas para corregir las desviaciones detectadas

', N'Mediante el estudio de los registros, se valorará si se han adoptado medidas al comprobar incumplimientos de este apartado. Al evaluar el tipo de medidas adoptadas encontraremos que en realidad dependen de lo encontrado. Así, si lo que se detecta es que no se cumple lo indicado en el plan, bien por desconocimiento o bien porque el personal a pesar de conocer lo que debe hacer, no lo  hace correctamente, debe reeducarse ese personal, mientras que si lo ocurrido, es que ha cambiado de alguna forma el proceso productivo,  es necesario modificar el plan. ', N' ', N'Mediante el estudio de los registros, se valorará si se han adoptado medidas al comprobar incumplimientos de este apartado. Al evaluar el tipo de medidas adoptadas encontraremos que en realidad dependen de lo encontrado. Así, si lo que se detecta es que no se cumple lo indicado en el plan, bien por desconocimiento o bien porque el personal a pesar de conocer lo que debe hacer, no lo  hace correctamente, debe reeducarse ese personal, mientras que si lo ocurrido, es que ha cambiado de alguna forma el proceso productivo,  es necesario modificar el plan. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2153 AS Decimal(6, 0)), N'78             ', N'Se registra adecuadamente la vigilancia para todos los parámetros a vigilar y con la frecuencia establecida', N'Se comprobará que la vigilancia siempre se registra  para todos los parámetros previstos y con la frecuencia establecida. Además se valorará que las anotaciones sean inteligibles y se ajusten al sistema previsto. Por otro lado, debemos intentar averiguar si esas anotaciones son fruto de vigilancias reales o se han falsificado, para lo que contaremos con los registros que se realizan el   día de la visita y observaremos cómo se realizan las vigilancias correspondientes durante el tiempo que estamos en la empresa. Esto junto con la entrevista con el personal encargado de estas funciones nos debe ayudar a averiguarlo', N' ', N'Se comprobará que la vigilancia siempre se registra  para todos los parámetros previstos y con la frecuencia establecida. Además se valorará que las anotaciones sean inteligibles y se ajusten al sistema previsto. Por otro lado, debemos intentar averiguar si esas anotaciones son fruto de vigilancias reales o se han falsificado, para lo que contaremos con los registros que se realizan el   día de la visita y observaremos cómo se realizan las vigilancias correspondientes durante el tiempo que estamos en la empresa. Esto junto con la entrevista con el personal encargado de estas funciones nos debe ayudar a averiguarlo')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2157 AS Decimal(6, 0)), N'80             ', N'Se realizan controles analíticos de materias primas que verifican sus especificaciones, y en caso de resultado desfavorable se adoptan las medidas necesarias', N'Se comprobará que los controles analíticos se realizan según lo previsto en el plan, tanto en lo referente a los parámetros analizados como en la frecuencia del análisis. Se analizarán los parámetros microbiológicos y físico-químicos que se incluyen en las especificaciones y servirán para verificar que los distintos proveedores homologados previamente, siguen cumpliendo las características iniciales.

Se valorará si el personal encargado de la verificación conoce los límites a cumplir para cada parámetro. Estos límites serán legales, recomendaciones bibliográficas o niveles admitidos en la empresa previamente validados y que por supuesto estén dentro de límites legales o recomendados por estamentos científicos reconocidos. 

Se comprobará igualmente que en caso de resultados fuera de los límites se adoptan medidas para evitar que esas materias primas puedan suponer un problema para el producto elaborado y que además evitan que vuelva a suceder de nuevo. Las medidas adoptadas deberán estar registradas en todos los casos.
', N' ', N'Se comprobará que los controles analíticos se realizan según lo previsto en el plan, tanto en lo referente a los parámetros analizados como en la frecuencia del análisis. Se analizarán los parámetros microbiológicos y físico-químicos que se incluyen en las especificaciones y servirán para verificar que los distintos proveedores homologados previamente, siguen cumpliendo las características iniciales.

Se valorará si el personal encargado de la verificación conoce los límites a cumplir para cada parámetro. Estos límites serán legales, recomendaciones bibliográficas o niveles admitidos en la empresa previamente validados y que por supuesto estén dentro de límites legales o recomendados por estamentos científicos reconocidos. 

Se comprobará igualmente que en caso de resultados fuera de los límites se adoptan medidas para evitar que esas materias primas puedan suponer un problema para el producto elaborado y que además evitan que vuelva a suceder de nuevo. Las medidas adoptadas deberán estar registradas en todos los casos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2158 AS Decimal(6, 0)), N'80             ', N'Se realizan controles analíticos de productos finales que verifican sus especificaciones y en caso de resultado desfavorable se adoptan las medidas necesarias', N'Se comprobará que se realizan los controles analíticos de producto final indicados en el plan, para los parámetros marcados en las especificaciones y con la frecuencia prevista. Estos análisis servirán para verificar que el sistema implantado funciona ya que los resultados obtenidos nos demuestran que estamos obteniendo productos seguros. Igual que en el caso anterior el personal responsable conocerá los límites a cumplir.
Se debe comprobar además que tras resultados incorrectos se han tomado medidas con el producto final de forma que no se comercialice o si ya se ha comercializado se valore su retirada del mercado, que además ha supuesto una revisión del plan para encontrar el posible fallo y porqué no se ha detectado durante el proceso productivo. Las medidas adoptadas deberán estar registradas en todos los casos.
', N' ', N'Se comprobará que se realizan los controles analíticos de producto final indicados en el plan, para los parámetros marcados en las especificaciones y con la frecuencia prevista. Estos análisis servirán para verificar que el sistema implantado funciona ya que los resultados obtenidos nos demuestran que estamos obteniendo productos seguros. Igual que en el caso anterior el personal responsable conocerá los límites a cumplir.
Se debe comprobar además que tras resultados incorrectos se han tomado medidas con el producto final de forma que no se comercialice o si ya se ha comercializado se valore su retirada del mercado, que además ha supuesto una revisión del plan para encontrar el posible fallo y porqué no se ha detectado durante el proceso productivo. Las medidas adoptadas deberán estar registradas en todos los casos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2156 AS Decimal(6, 0)), N'80             ', N'El sistema de verificación es completo y está correctamente dise¦ado', N'Se comprobará que el sistema de verificación implantado asegura que las  actuaciones realizadas se ajustan al Plan establecido y que éste sigue siendo eficaz para producir alimentos seguros. Cada actividad de verificación incluirá qué se va a hacer, cómo, quién lo hará, cuando y si procede, donde.', N' ', N'Se comprobará que el sistema de verificación implantado asegura que las  actuaciones realizadas se ajustan al Plan establecido y que éste sigue siendo eficaz para producir alimentos seguros. Cada actividad de verificación incluirá qué se va a hacer, cómo, quién lo hará, cuando y si procede, donde.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2154 AS Decimal(6, 0)), N'79             ', N'Las acciones correctoras son completas y están correctamente dise¦adas', N'Se valorará si las acciones correctoras son las adecuadas en cada caso, es decir, contienen medidas para volver a poner el sistema bajo control, medidas para evitar que el producto fabricado durante la desviación no supongan un problema de seguridad y/o medidas para evitar que vuelva a suceder de nuevo', N' ', N'Se valorará si las acciones correctoras son las adecuadas en cada caso, es decir, contienen medidas para volver a poner el sistema bajo control, medidas para evitar que el producto fabricado durante la desviación no supongan un problema de seguridad y/o medidas para evitar que vuelva a suceder de nuevo')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2155 AS Decimal(6, 0)), N'79             ', N'Se han adoptado acciones correctoras cada vez que se ha superado el límite crítico y se han registrado correctamente', N'Se valorará si el personal encargado de adoptar las acciones correctoras conoce que cada vez que el personal encargado del sistema de vigilancia  indique que se ha superado un límite crítico, deben adoptarse acciones correctoras y cuales son las previstas para cada caso. El personal de vigilancia y el que adopta las acciones correctoras puede ser el mismo y si no lo es, el primero debe tener claro cuales son los pasos a dar, para que el segundo conozca que se ha superado un límite y que debe adoptar las medidas de forma inmediata. Además se comprobará que se han adoptado acciones en todos los casos que se ha superado un límite y que se han registrado. 
Las acciones adoptadas serán en principio las previstas en el propio plan, aunque a veces se deban adoptar algunas no previstas o se tengan que hacer valoraciones para cada caso. Si esto ocurre hay que determinar si esas nuevas acciones correctoras deben incorporarse al plan o si simplemente son actuaciones puntuales para un caso determinado.', N' ', N'Se valorará si el personal encargado de adoptar las acciones correctoras conoce que cada vez que el personal encargado del sistema de vigilancia  indique que se ha superado un límite crítico, deben adoptarse acciones correctoras y cuales son las previstas para cada caso. El personal de vigilancia y el que adopta las acciones correctoras puede ser el mismo y si no lo es, el primero debe tener claro cuales son los pasos a dar, para que el segundo conozca que se ha superado un límite y que debe adoptar las medidas de forma inmediata. Además se comprobará que se han adoptado acciones en todos los casos que se ha superado un límite y que se han registrado. 
Las acciones adoptadas serán en principio las previstas en el propio plan, aunque a veces se deban adoptar algunas no previstas o se tengan que hacer valoraciones para cada caso. Si esto ocurre hay que determinar si esas nuevas acciones correctoras deben incorporarse al plan o si simplemente son actuaciones puntuales para un caso determinado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2172 AS Decimal(6, 0)), N'83             ', N'El Plan L+D es completo y está correctamente dise¦ado', N'Se valorará si el Plan L+D es completo, e incluye instrucciones de limpieza y desinfección específicas para cada zona y/o equipo, así como los productos usados, su composición y su forma de uso', N' ', N'Se valorará si el Plan L+D es completo, e incluye instrucciones de limpieza y desinfección específicas para cada zona y/o equipo, así como los productos usados, su composición y su forma de uso')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(817 AS Decimal(6, 0)), N'32             ', N'La empresa controla por muestreo que en las conservas se realizan pruebas de incubación de 7 días a +37ºC, ó de 10 días a +35ºC, u otra combinación tiempo / temperatura autorizada.', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa controlará que en las conservas de productos cárnicos se realizan pruebas de incubación de siete días a +37ºC ó de diez dias a +35ºC, ó cualquier otra combinación tiempo/temperatura reconocida como equivalente por la autoridad competente.', N' ', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa controlará que en las conservas de productos cárnicos se realizan pruebas de incubación de siete días a +37ºC ó de diez dias a +35ºC, ó cualquier otra combinación tiempo/temperatura reconocida como equivalente por la autoridad competente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2174 AS Decimal(6, 0)), N'83             ', N'Se comprueba y registra el cumplimiento del Plan de L+D', N'Del plan L+D se debe registrar tanto el cumplimiento de la frecuencia establecida para las distintas zonas, como el cumplimiento del método establecido. La frecuencia de limpieza normalmente la registran las personas que la están realizando, mientras que la correcta ejecución del método lo evalúa, también normalmente, una persona ajena a esta actividad, que puede ser objetiva al respecto. Mientras que el primero de los registros se utiliza cada vez que se ejecuta la limpieza, el segundo suele tener una periodicidad mayor y se suele utilizar un listado de comprobación que nos permite examinar si se cumplen las distintas actividades propuestas en el plan. Por tanto se deberá comprobar la existencia de estos registros y si la forma de cumplimentarse se ajusta a lo fijado en el plan.', N' ', N'Del plan L+D se debe registrar tanto el cumplimiento de la frecuencia establecida para las distintas zonas, como el cumplimiento del método establecido. La frecuencia de limpieza normalmente la registran las personas que la están realizando, mientras que la correcta ejecución del método lo evalúa, también normalmente, una persona ajena a esta actividad, que puede ser objetiva al respecto. Mientras que el primero de los registros se utiliza cada vez que se ejecuta la limpieza, el segundo suele tener una periodicidad mayor y se suele utilizar un listado de comprobación que nos permite examinar si se cumplen las distintas actividades propuestas en el plan. Por tanto se deberá comprobar la existencia de estos registros y si la forma de cumplimentarse se ajusta a lo fijado en el plan.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2143 AS Decimal(6, 0)), N'75             ', N'El personal conoce la posibilidad de presentación de esos peligros y su implicación en los mismos', N'Se valorará si el personal conoce cuáles son los peligros relevantes que pueden presentarse en la empresa y sus causas, ya que de sus actuaciones derivará por un lado la prevención de la aparición de los mismos y por otro el control del cumplimiento de las medidas propuestas para prevenirlos.', N' ', N'Se valorará si el personal conoce cuáles son los peligros relevantes que pueden presentarse en la empresa y sus causas, ya que de sus actuaciones derivará por un lado la prevención de la aparición de los mismos y por otro el control del cumplimiento de las medidas propuestas para prevenirlos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2144 AS Decimal(6, 0)), N'75             ', N'Las medidas preventivas están correctamente dise¦adas y son suficientes para prevenir realmente los peligros o reducirlos a niveles aceptables ', N'Se comprobará que existen medidas preventivas suficientes para reducir los peligros a niveles aceptables.

Puede que se detecte que hay peligros para los que no se adoptan realmente medidas preventivas, bien porque a pesar de estar bien dise¦adas, no se ejecutan en su totalidad o no se ejecutan tal como indica el manual o bien porque no están correctamente dise¦adas. Esto último puede ocurrir porque las medidas planteadas son medidas preventivas demasiado generales que no incluyen instrucciones específicas que prevengan el peligro concreto o porque ni siquiera se han establecido al no haberse tenido en cuenta ese peligro y su causa.

El auditor ha de hacerse una idea completa del grado de eficacia de las medidas adoptadas y encontrar pruebas de ello, de forma que si decide que no son suficientes pueda presentar evidencias o justificar esta decisión. 
', N' ', N'Se comprobará que existen medidas preventivas suficientes para reducir los peligros a niveles aceptables.

Puede que se detecte que hay peligros para los que no se adoptan realmente medidas preventivas, bien porque a pesar de estar bien dise¦adas, no se ejecutan en su totalidad o no se ejecutan tal como indica el manual o bien porque no están correctamente dise¦adas. Esto último puede ocurrir porque las medidas planteadas son medidas preventivas demasiado generales que no incluyen instrucciones específicas que prevengan el peligro concreto o porque ni siquiera se han establecido al no haberse tenido en cuenta ese peligro y su causa.

El auditor ha de hacerse una idea completa del grado de eficacia de las medidas adoptadas y encontrar pruebas de ello, de forma que si decide que no son suficientes pueda presentar evidencias o justificar esta decisión. 
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2142 AS Decimal(6, 0)), N'75             ', N'El análisis de peligros es completo y se han identificado correctamente todos los peligros relevantes teniendo en cuenta la realidad de la empresa', N'Se deberá comprobar que el análisis de peligros realizado es completo, y que ningún peligro relevante se ha obviado, teniendo en cuenta la realidad de la empresa. Para ello se deberá valorar que no faltan etapas por analizar, que se han tenido en cuenta la influencia de la actividad, producto, proceso de trabajo, instalaciones, equipo y personal en cada una de esas etapas y que para todas ellas se han tenido en cuenta los peligros físicos, químicos y microbiológicos que son relevantes (bien por su alta posibilidad de presentación o por su gravedad) para el objetivo perseguido, es decir, para la producción de alimentos seguros.', N' ', N'Se deberá comprobar que el análisis de peligros realizado es completo, y que ningún peligro relevante se ha obviado, teniendo en cuenta la realidad de la empresa. Para ello se deberá valorar que no faltan etapas por analizar, que se han tenido en cuenta la influencia de la actividad, producto, proceso de trabajo, instalaciones, equipo y personal en cada una de esas etapas y que para todas ellas se han tenido en cuenta los peligros físicos, químicos y microbiológicos que son relevantes (bien por su alta posibilidad de presentación o por su gravedad) para el objetivo perseguido, es decir, para la producción de alimentos seguros.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(796 AS Decimal(6, 0)), N'10             ', N'Los establecimientos de elaboración de estómagos, vegigas e intestinos tratados, disponen de los equipos necesarios. ', N'Los establecimientos en los que se elaboran estómagos, vejigas e intestinos tratados, dispondrán de:
