GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(797 AS Decimal(6, 0)), N'10             ', N'Loa establecimientos que elaboran gelatinas y colágenos disponen de los equipos necesarios.', N'Los establecimientos en los que se elaboran gelatinas y colágenos dispondrán de:
%u2022Equipos para realizar el triturado previo de las materias primas.
%u2022Equipos para realizar el desgrasado con agua caliente.
%u2022Equipos para los tratamientos con ácidos y luego con álcalis.
%u2022Equipos para la esterilización a 138-140ºC  durante 4 segundo, u otro proceso equivalente.
', N' ', N'Los establecimientos en los que se elaboran gelatinas y colágenos dispondrán de:
%u2022Equipos para realizar el triturado previo de las materias primas.
%u2022Equipos para realizar el desgrasado con agua caliente.
%u2022Equipos para los tratamientos con ácidos y luego con álcalis.
%u2022Equipos para la esterilización a 138-140ºC  durante 4 segundo, u otro proceso equivalente.
')
