INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2141 AS Decimal(6, 0)), N'74             ', N'El diagrama de flujo se ajusta a la realidad de la empresa.', N'Se comprobará en la visita a planta que el/los diagrama/s de flujo del plan se ajusta/n a las distintas etapas del proceso productivo que realmente se dan en la empresa. Además se comprobará que bajo una misma etapa no se dan tareas distintas que no se hayan tenido en cuenta posteriormente en el análisis de peligros y si alguna de las etapas no se realiza conforme se había planteado y ello supone un cambio en el mencionado análisis de peligros.

Cuando se detectan este tipo de errores su corrección pasa por completar el documento con la parte que falta, pero que en todo caso no invalidan el análisis de peligros y el resto del plan. En este caso se indicarán éstos errores y se continuará con la auditoría.

Pero también se pueden detectar errores que indiquen que el diagrama tiene nada o muy poco que ver con la realidad de la empresa y que por ello el análisis de peligros y el plan elaborado que se consideró auditable en la revisión documental, no sirvan para la empresa en cuestión. Normalmente esto ocurrirá para una parte de los procesos productivos,  y en este caso se actuará como en el caso anterior, indicando los errores y continuando con la auditoría. Aunque pudiera ocurrir en algún caso, que tras analizar el diagrama de flujo se considere que el plan no se ajusta en nada a la realidad de la empresa y por tanto no puede realizarse la auditoría. En este caso se le indicará a la empresa que presente un nuevo plan completo, que deberá pasar por el proceso de valoración de documentos. ', N' ', N'Se comprobará en la visita a planta que el/los diagrama/s de flujo del plan se ajusta/n a las distintas etapas del proceso productivo que realmente se dan en la empresa. Además se comprobará que bajo una misma etapa no se dan tareas distintas que no se hayan tenido en cuenta posteriormente en el análisis de peligros y si alguna de las etapas no se realiza conforme se había planteado y ello supone un cambio en el mencionado análisis de peligros.

Cuando se detectan este tipo de errores su corrección pasa por completar el documento con la parte que falta, pero que en todo caso no invalidan el análisis de peligros y el resto del plan. En este caso se indicarán éstos errores y se continuará con la auditoría.

Pero también se pueden detectar errores que indiquen que el diagrama tiene nada o muy poco que ver con la realidad de la empresa y que por ello el análisis de peligros y el plan elaborado que se consideró auditable en la revisión documental, no sirvan para la empresa en cuestión. Normalmente esto ocurrirá para una parte de los procesos productivos,  y en este caso se actuará como en el caso anterior, indicando los errores y continuando con la auditoría. Aunque pudiera ocurrir en algún caso, que tras analizar el diagrama de flujo se considere que el plan no se ajusta en nada a la realidad de la empresa y por tanto no puede realizarse la auditoría. En este caso se le indicará a la empresa que presente un nuevo plan completo, que deberá pasar por el proceso de valoración de documentos. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(792 AS Decimal(6, 0)), N'10             ', N'Si elabora conservas cárnicas, dispone de dispositivo de lavado de recipientes tras el cierre y antes del tratamiento por calor.', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Un dispositivo para el lavado con agua potable a una temperatura suficientemente elevada, para eliminar las grasas de los recipientes tras el cierre hermético y antes de ser sometidos al autoclave.', N' ', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Un dispositivo para el lavado con agua potable a una temperatura suficientemente elevada, para eliminar las grasas de los recipientes tras el cierre hermético y antes de ser sometidos al autoclave.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(799 AS Decimal(6, 0)), N'58             ', N'En los establecimientos de elaboración de grasas animales fundidas, chicharrones y subproductos de extracción, se dispone de aparato para la plastificación o cristalización de la grasa, salvo si sólo expide grasas fundidas en estado líquido.', N'Los establecimientos en los que se elaboran grasas animales fundidas, chicharrones y subproductos de extracción dispondrán de:
Un aparato para la plastificación o cristalización de la grasa, que facilite el envasado y embalaje, excepto si el establecimiento expide únicamente grasas animales fundidas en estado líquido.', N' ', N'Los establecimientos en los que se elaboran grasas animales fundidas, chicharrones y subproductos de extracción dispondrán de:
Un aparato para la plastificación o cristalización de la grasa, que facilite el envasado y embalaje, excepto si el establecimiento expide únicamente grasas animales fundidas en estado líquido.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(814 AS Decimal(6, 0)), N'32             ', N'La empresa controla por muestreo que los productos cárnicos destinados a almacenamiento a temperatura ambiente son tratados térmicamente para destruir o inactivar gérmenes y esporas de patógenos.', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa dispondrá de un procedimiento definido según criterios tales como, tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o inactivación de los gérmenes patógenos y todo esporo de microorganismos.', N' ', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa dispondrá de un procedimiento definido según criterios tales como, tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o inactivación de los gérmenes patógenos y todo esporo de microorganismos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(813 AS Decimal(6, 0)), N'32             ', N'En los establecimientos que fabrican conservas cárnicas los termómetros del equipo de tratamiento térmico se contrastan periódicamente.', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
Los termómetros del equipo de tratamiento térmico se contrastarán periódicamente.', N' ', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
Los termómetros del equipo de tratamiento térmico se contrastarán periódicamente.')
GO
