INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(795 AS Decimal(6, 0)), N'10             ', N'En los establecimientos de elaboración de grasas animales fundidas, chicharrones dispone de los equipos necesarios', N'Los establecimientos en los que se elaboran grasas animales fundidas y chicharrones dispondrán de: 
%u2022En caso necesario, una instalación para la trituración de las materias primas.
%u2022Un equipo para extraer la grasa mediante calentamiento, presión u otro método apropiado.
%u2022Recipientes que permitan conservar las grasas en estado líquido.
%u2022Un aparato para la plastificación o cristalización de la grasa, que facilite el envasado y embalaje, excepto si el establecimiento expide únicamente grasas animales fundidas en estado líquido.
%u2022Equipos apropiados para la preparación de productos a base de grasas animales fundidas mezcladas con otros productos alimenticios y/o condimentos, en su caso.', N' ', N'Los establecimientos en los que se elaboran grasas animales fundidas y chicharrones dispondrán de: 
%u2022En caso necesario, una instalación para la trituración de las materias primas.
%u2022Un equipo para extraer la grasa mediante calentamiento, presión u otro método apropiado.
%u2022Recipientes que permitan conservar las grasas en estado líquido.
%u2022Un aparato para la plastificación o cristalización de la grasa, que facilite el envasado y embalaje, excepto si el establecimiento expide únicamente grasas animales fundidas en estado líquido.
%u2022Equipos apropiados para la preparación de productos a base de grasas animales fundidas mezcladas con otros productos alimenticios y/o condimentos, en su caso.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(770 AS Decimal(6, 0)), N'3              ', N'Dispone de los locales exigidos según el tipo de producto cárnico elaborado.', N'Locales especiales
Según el tipo de producto cárnico elaborado, el establecimiento constará de:
%u2022Un local o un emplazamiento para quitar el embalaje.
%u2022Un local o un emplazamiento para descongelar las materias primas. 
%u2022Un local para las operaciones de despiece. 
%u2022Un local para el tratamiento térmico (cocción).
%u2022Un local o una instalación para los tratamientos de secado y curación. 
%u2022Un local o instalación para el ahumado. 
%u2022Un local para desalar, poner a remojo o realizar cualquier otro tratamiento de las tripas naturales y productos similares, si estas operaciones no han sido realizadas en origen. 
%u2022Un local para la limpieza previa de las materias primas, en caso necesario. 
%u2022Un local para la salazón.
%u2022Un local para el desmoldado, troceado, loncheado, o deshuesado, en su caso, de los productos cárnicos destinados a ser envasados para su presentación comercial, provisto, si fuera necesario de un dispositivo de climatización. ', N' ', N'Locales especiales
Según el tipo de producto cárnico elaborado, el establecimiento constará de:
%u2022Un local o un emplazamiento para quitar el embalaje.
%u2022Un local o un emplazamiento para descongelar las materias primas. 
%u2022Un local para las operaciones de despiece. 
%u2022Un local para el tratamiento térmico (cocción).
%u2022Un local o una instalación para los tratamientos de secado y curación. 
%u2022Un local o instalación para el ahumado. 
%u2022Un local para desalar, poner a remojo o realizar cualquier otro tratamiento de las tripas naturales y productos similares, si estas operaciones no han sido realizadas en origen. 
%u2022Un local para la limpieza previa de las materias primas, en caso necesario. 
%u2022Un local para la salazón.
%u2022Un local para el desmoldado, troceado, loncheado, o deshuesado, en su caso, de los productos cárnicos destinados a ser envasados para su presentación comercial, provisto, si fuera necesario de un dispositivo de climatización. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(787 AS Decimal(6, 0)), N'10             ', N'Dispone de dispositivo para la desinfección de útiles, provisto de agua a una temperatura mínima de 82ºC o de otros métodos  aprobados.', N'Dispondrán de instalaciones apropiadas para la limpieza y desinfección de equipos y útiles dotados de agua a una temperatura mínima de 82ºC, o bien otros métodos de desinfección aprobados por la autoridad competente, para la desinfección del material y los utensilios. ', N' ', N'Dispondrán de instalaciones apropiadas para la limpieza y desinfección de equipos y útiles dotados de agua a una temperatura mínima de 82ºC, o bien otros métodos de desinfección aprobados por la autoridad competente, para la desinfección del material y los utensilios. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(782 AS Decimal(6, 0)), N'3              ', N'Los establecimientos que fabriquen  platos cocinados cárnicos, disponen de un local exclusivo para este uso cuando la preparación del dichos platos cárnicos precise de etapas, manipulaciones o tratamientos que no puedan ser realizados en los locales menci????', N'Los establecimientos que fabriquen  platos cocinados cárnicos, dispondrán de un local exclusivo para este uso cuando la preparación del dichos platos cárnicos precise de etapas, manipulaciones o tratamientos que no puedan ser realizados en los locales mencionados en anteriores y se considere que existe riesgo de contaminación.', N' ', N'Los establecimientos que fabriquen  platos cocinados cárnicos, dispondrán de un local exclusivo para este uso cuando la preparación del dichos platos cárnicos precise de etapas, manipulaciones o tratamientos que no puedan ser realizados en los locales mencionados en anteriores y se considere que existe riesgo de contaminación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(735 AS Decimal(6, 0)), N'47             ', N'No se les ata las patas a animales antes de ser aturdidos.', N'Sujeción de los animales antes de su aturdido, sacrificio o matanza:
No  se atarán las patas de los animales. Los animales podrán ser suspendidos para su sacrificio, siempre que se tomen las medidas adecuadas para que las aves que vayan a someterse al aturdido se encuentren en un estado de relajación que permita efectuar dicha operación con eficacia y sin pérdidas de tiempo innecesarias.
Por otra parte, el hecho de bloquear a un animal en un sistema de sujeción no podrá considerarse en modo alguno como una suspensión.', N' ', N'Sujeción de los animales antes de su aturdido, sacrificio o matanza:
No  se atarán las patas de los animales. Los animales podrán ser suspendidos para su sacrificio, siempre que se tomen las medidas adecuadas para que las aves que vayan a someterse al aturdido se encuentren en un estado de relajación que permita efectuar dicha operación con eficacia y sin pérdidas de tiempo innecesarias.
Por otra parte, el hecho de bloquear a un animal en un sistema de sujeción no podrá considerarse en modo alguno como una suspensión.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(734 AS Decimal(6, 0)), N'47             ', N'Los animales transportados en contenedores se sacrifican lo antes posible. De no ser así se les suministra agua y alimentos.', N'Los animales que hayan sido transportados en contenedores serán sacrificados lo antes posible. De no ser así, se les suministrará en caso necesario agua y alimentos.', N' ', N'Los animales que hayan sido transportados en contenedores serán sacrificados lo antes posible. De no ser así, se les suministrará en caso necesario agua y alimentos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111035 AS Decimal(6, 0)), N'76             ', N'Los productos se descongelan en cámara, microondas u otro sistema rápido o en agua fría. El agua de escurrido se recoge en un recipiente.', N'Se observará que el producto que está descongelándose, está en cámara (especialmente si se trata de pescados que pueden formar histamina como la anchoa, el atún o el bonito). En el caso de que el producto se esté descongelando en agua, es agua fría.
En la cámara se coloca el producto que se vaya a descongelar sobre un recipiente que recoge el líquido de escurrido, para evitar que pueda contaminar otros alimentos', N'Los productos se descongelan en cámara, microondas u otro sistema rápido o en agua fría. El agua de escurrido se recoge en un recipiente.', N'Se observará que el producto que está descongelándose, está en cámara (especialmente si se trata de pescados que pueden formar histamina como la anchoa, el atún o el bonito). En el caso de que el producto se esté descongelando en agua, es agua fría.
En la cámara se coloca el producto que se vaya a descongelar sobre un recipiente que recoge el líquido de escurrido, para evitar que pueda contaminar otros alimentos')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(736 AS Decimal(6, 0)), N'47             ', N'El aturdido se realiza con métodos autorizados.', N'Los métodos autorizados para el aturdido son los siguientes:
Electro narcosis: Con pinzas de electrocución o inmersión en tanques de agua:
Cuando se empleen tanques de agua para el aturdido de aves de corral, deberá ser posible regular el nivel del agua de modo que permita un buen contacto con la cabeza del ave.
La intensidad de la corriente utilizada en este caso y la duración de su aplicación serán determinadas de tal modo que se garantice que el estado de inconsciencia sobrevenga inmediatamente y se prolongue hasta la muerte del animal.
Cuando las aves de corral sean aturdidas por grupos en un tanque de agua, se mantendrá un voltaje suficiente para producir una corriente de una intensidad eficaz para conseguir el aturdido de todas y cada una de las aves.
Deberán tomarse las medidas oportunas para garantizar un buen paso de la corriente y, en especial, un buen contacto y el mojado de dicho contacto entre las patas y los ganchos de suspensión.
Los tanques de agua para aves de corral tendrán un tama¦o y una profundidad adecuados al tipo de ave que vaya a sacrificarse y no se desbordarán a la entrada. El electrodo que se sumerja en el agua tendrá la longitud del tanque de agua.
Los sistemas de aturdido eléctrico dispondrán de un dispositivo que permita en todo momento la comprobación de la frecuencia y la intensidad de la descarga y que impida el funcionamiento del sistema si los parámetros no son los adecuados:
En caso necesario, deberá disponerse de un sistema auxiliar manual.
Decapitación y dislocación del cuello: se aplicarán estos procedimientos únicamente para la matanza de aves de corral, previa autorización de la autoridad competente que deberá verificar, en particular, su utilización por personal facultado para ello.
', N' ', N'Los métodos autorizados para el aturdido son los siguientes:
Electro narcosis: Con pinzas de electrocución o inmersión en tanques de agua:
Cuando se empleen tanques de agua para el aturdido de aves de corral, deberá ser posible regular el nivel del agua de modo que permita un buen contacto con la cabeza del ave.
La intensidad de la corriente utilizada en este caso y la duración de su aplicación serán determinadas de tal modo que se garantice que el estado de inconsciencia sobrevenga inmediatamente y se prolongue hasta la muerte del animal.
Cuando las aves de corral sean aturdidas por grupos en un tanque de agua, se mantendrá un voltaje suficiente para producir una corriente de una intensidad eficaz para conseguir el aturdido de todas y cada una de las aves.
Deberán tomarse las medidas oportunas para garantizar un buen paso de la corriente y, en especial, un buen contacto y el mojado de dicho contacto entre las patas y los ganchos de suspensión.
Los tanques de agua para aves de corral tendrán un tama¦o y una profundidad adecuados al tipo de ave que vaya a sacrificarse y no se desbordarán a la entrada. El electrodo que se sumerja en el agua tendrá la longitud del tanque de agua.
Los sistemas de aturdido eléctrico dispondrán de un dispositivo que permita en todo momento la comprobación de la frecuencia y la intensidad de la descarga y que impida el funcionamiento del sistema si los parámetros no son los adecuados:
En caso necesario, deberá disponerse de un sistema auxiliar manual.
Decapitación y dislocación del cuello: se aplicarán estos procedimientos únicamente para la matanza de aves de corral, previa autorización de la autoridad competente que deberá verificar, en particular, su utilización por personal facultado para ello.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(763 AS Decimal(6, 0)), N'3              ', N'Dispone de instalaciones para el veterinario oficial.', N'Dispondrá de un local correctamente acondicionado y con elementos dotados de llave, a disposición del servicio de inspección, si la cantidad de producción requiere su presencia con regularidad. Cuando no se requiera la presencia permanente del servicio de inspección, será suficiente un mueble que pueda cerrarse con llave con capacidad suficiente para el almacenamiento de material y la custodia de equipos.
', N' ', N'Dispondrá de un local correctamente acondicionado y con elementos dotados de llave, a disposición del servicio de inspección, si la cantidad de producción requiere su presencia con regularidad. Cuando no se requiera la presencia permanente del servicio de inspección, será suficiente un mueble que pueda cerrarse con llave con capacidad suficiente para el almacenamiento de material y la custodia de equipos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(784 AS Decimal(6, 0)), N'3              ', N'En los establecimientos de elaboración de grasas animales fundidas, se dispone de cámara frigorífica cuando las materias primas no son procesadas dentro de las 12 horas siguientes a su obtención.', N'En los establecimientos que elaboren grasas animales fundidas, se dispondrá como mínimo de cámaras frigoríficas cuando no se realice el procesado dentro de las 12 horas siguientes al del día de su obtención.', N' ', N'En los establecimientos que elaboren grasas animales fundidas, se dispondrá como mínimo de cámaras frigoríficas cuando no se realice el procesado dentro de las 12 horas siguientes al del día de su obtención.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2140 AS Decimal(6, 0)), N'74             ', N'El diagrama de flujo es completo.', N'Se comprobará que hay un diagrama de flujo para cada proceso realizado, que abarca todas las etapas e ingredientes, sin agrupaciones excesivas, reflejando fielmente todos los diferentes pasos que lo componen. Se comprobará igualmente que la descripción de las características de las etapas es suficiente para poder valorar posteriormente el análisis de peligros.', N' ', N'Se comprobará que hay un diagrama de flujo para cada proceso realizado, que abarca todas las etapas e ingredientes, sin agrupaciones excesivas, reflejando fielmente todos los diferentes pasos que lo componen. Se comprobará igualmente que la descripción de las características de las etapas es suficiente para poder valorar posteriormente el análisis de peligros.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2139 AS Decimal(6, 0)), N'73             ', N'Se ajustan los productos finales elaborados o comercializados por la empresa a sus especificaciones.', N'Se comprobará que los productos finales se ajustan a las especificaciones marcadas por la propia empresa o establecidas por la empresa de origen. Cuando se valore su ajuste se tratará de revisar si en su elaboración se han utilizado los ingredientes previstos, si los tratamientos sufridos son los indicados, si los envases y embalajes son igualmente los indicados, si se ha etiquetado conforme a lo planificado, si se conserva adecuadamente y se indica cual debe ser su sistema de conservación posterior, si se indican instrucciones al consumidor de su uso, así como si el sistema de distribución y transporte es el adecuado para el producto.', N' ', N'Se comprobará que los productos finales se ajustan a las especificaciones marcadas por la propia empresa o establecidas por la empresa de origen. Cuando se valore su ajuste se tratará de revisar si en su elaboración se han utilizado los ingredientes previstos, si los tratamientos sufridos son los indicados, si los envases y embalajes son igualmente los indicados, si se ha etiquetado conforme a lo planificado, si se conserva adecuadamente y se indica cual debe ser su sistema de conservación posterior, si se indican instrucciones al consumidor de su uso, así como si el sistema de distribución y transporte es el adecuado para el producto.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(788 AS Decimal(6, 0)), N'10             ', N'Si elabora conservas cárnicas, los equipos de tratamiento térmico poseen dispositivos de control y registro de temperaturas.', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Los equipos de tratamiento térmico deberán poseer dispositivos de control y registro para garantizar que los recipientes han recibido el tratamiento térmico adecuado.', N' ', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Los equipos de tratamiento térmico deberán poseer dispositivos de control y registro para garantizar que los recipientes han recibido el tratamiento térmico adecuado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(780 AS Decimal(6, 0)), N'3              ', N'Si elabora conservas cárnicas, dispone de local o instalación para enfriamiento y secado tras el tratamiento por calor.', N'Los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas), además de las condiciones generales y especiales mencionadas en puntos anteriores, dispondrán de:
Un local, lugar o instalación apropiados para el enfriamiento  y el secado  de los recipientes después del tratamiento por calor.', N' ', N'Los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas), además de las condiciones generales y especiales mencionadas en puntos anteriores, dispondrán de:
Un local, lugar o instalación apropiados para el enfriamiento  y el secado  de los recipientes después del tratamiento por calor.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(794 AS Decimal(6, 0)), N'10             ', N'Se dispone de equipo para el examen de los cierres.', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Deberá  disponerse de un equipo adecuado para el examen de secciones perpendiculares de los cierres de los recipientes cerrados.', N' ', N'En los establecimientos que elaboren productos pasteurizados o esterilizados (Conservas Cárnicas):
Deberá  disponerse de un equipo adecuado para el examen de secciones perpendiculares de los cierres de los recipientes cerrados.')
GO
