INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2138 AS Decimal(6, 0)), N'73             ', N'Hay especificaciones para todos los productos finales.', N'Se comprobará que existen especificaciones que incluyen a todos los productos elaborados y/o comercializados.', N' ', N'Se comprobará que existen especificaciones que incluyen a todos los productos elaborados y/o comercializados.')
