INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2137 AS Decimal(6, 0)), N'73             ', N'Las especificaciones de producto final son completas.', N'Se comprobará que las especificaciones de los productos finales son completas, es decir, incluyen como mínimo: denominación del producto, ingredientes utilizados, tratamientos sufridos, envases y embalajes utilizados, sistema de conservación, vida útil e instrucciones del producto así como su etiquetado y sistema de distribución y transporte. También incluirán los criterios de seguridad correspondientes, tanto físico-químicos como microbiológicos.', N' ', N'Se comprobará que las especificaciones de los productos finales son completas, es decir, incluyen como mínimo: denominación del producto, ingredientes utilizados, tratamientos sufridos, envases y embalajes utilizados, sistema de conservación, vida útil e instrucciones del producto así como su etiquetado y sistema de distribución y transporte. También incluirán los criterios de seguridad correspondientes, tanto físico-químicos como microbiológicos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2173 AS Decimal(6, 0)), N'83             ', N'El personal conoce las instrucciones marcadas en el plan L+D, se cumplen y son las adecuadas para cada zona y/o equipo', N'Se comprobará si el personal conoce las instrucciones específicas de limpieza para cada área, la frecuencia para cada una de ellas, los productos a utilizar y sus instrucciones, las precauciones en caso de productos tóxicos%u2026.. Para ello nos entrevistaremos con personal que realiza estas labores, observaremos su trabajo y revisaremos los planes de formación. Con todo ellos seremos capaces de valorar el conocimiento del personal y si ha habido formación específica en la materia.

Se comprobará que en el establecimiento se cumplen las instrucciones marcadas por el plan para las distintas zonas, tanto en la frecuencia, como en los productos utilizados como en el método de realizarse la misma. Para realizar esta comprobación se intentará ver al personal de limpieza en sus labores y hablar con ellos. En caso de tratarse de personal con turnos muy diferentes a los del auditor deberemos intentar ver su trabajo, aunque en caso de no poder hacerlo dispondremos de los registros de frecuencia de limpieza, podremos ver los productos que realmente utilizan, veremos también el resultado de la limpieza y si nos parece suficiente e incluso tendremos analíticas que nos ayudarán en nuestra valoración. Respecto a los productos utilizados, valoraremos si por su composición o almacenamiento suponen un peligro de contaminación para los alimentos. Todo ello nos dará una idea de si el plan es adecuado o no, aunque  no veamos al personal ejecutándolo.
', N' ', N'Se comprobará si el personal conoce las instrucciones específicas de limpieza para cada área, la frecuencia para cada una de ellas, los productos a utilizar y sus instrucciones, las precauciones en caso de productos tóxicos%u2026.. Para ello nos entrevistaremos con personal que realiza estas labores, observaremos su trabajo y revisaremos los planes de formación. Con todo ellos seremos capaces de valorar el conocimiento del personal y si ha habido formación específica en la materia.

Se comprobará que en el establecimiento se cumplen las instrucciones marcadas por el plan para las distintas zonas, tanto en la frecuencia, como en los productos utilizados como en el método de realizarse la misma. Para realizar esta comprobación se intentará ver al personal de limpieza en sus labores y hablar con ellos. En caso de tratarse de personal con turnos muy diferentes a los del auditor deberemos intentar ver su trabajo, aunque en caso de no poder hacerlo dispondremos de los registros de frecuencia de limpieza, podremos ver los productos que realmente utilizan, veremos también el resultado de la limpieza y si nos parece suficiente e incluso tendremos analíticas que nos ayudarán en nuestra valoración. Respecto a los productos utilizados, valoraremos si por su composición o almacenamiento suponen un peligro de contaminación para los alimentos. Todo ello nos dará una idea de si el plan es adecuado o no, aunque  no veamos al personal ejecutándolo.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(816 AS Decimal(6, 0)), N'32             ', N'La empresa controla por muestreo la producción diaria para garantizar la eficacia del cierre.', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa controlará la producción diaria, para garantizar la eficacia del cierre.', N' ', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
La empresa controlará la producción diaria, para garantizar la eficacia del cierre.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(820 AS Decimal(6, 0)), N'32             ', N'A¦aden al agua de los autoclaves sustancias (anticorrosivos, ó ablandadores y desinfectantes) contando con autorización.', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
Los recipientes deberán :
Rechazarse si han sufrido da¦os o estuvieran mal fabricados.
Rechazarse o limpiarse, inmediatamente antes del llenado, mediante los dispositivos de limpieza eficaces. No se permite la utilización de agua no corriente.
En su caso, escurrirse durante el tiempo suficiente, tras la limpieza y antes de proceder al llenado.
En su caso, lavarse con agua potable a una temperatura suficientemente  elevada para eliminar las grasas  tras el cierre hermético  y antes de ser sometidos al autoclave.
Enfriarse tras el calentamiento, en agua que posea contenido residual de cloro o en agua que se ajuste al resto de parámetros sanitarios de las aguas potables.
Los recipientes herméticamente cerrados se retirarán de los aparatos de calentamiento a una temperatura tal que asegure la rápida evaporación de la humedad. No serán  manipulados antes de que estén completamente secos.
Los recipientes que presenten formaciones de gas, se someterán  a un examen complementario.

Los termómetros del equipo de tratamiento térmico se contrastarán periódicamente.
La empresa dispondrá de un procedimiento definido según criterios tales como, tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o inactivación de los gérmenes patógenos y todo esporo de microorganismos.
La empresa controlará la producción diaria, para garantizar la eficacia del cierre.
La empresa controlará que en las conservas de productos cárnicos se realizan pruebas de incubación de siete días a +37ºC ó de diez dias a +35ºC, ó cualquier otra combinación tiempo/temperatura reconocida como equivalente por la autoridad competente.
La empresa controlará que el agua de enfriamiento tras su utilización, tiene un contenido residual de cloro o se ajusta al resto de parámetros sanitarios de las aguas potables.
Se permite la adición de sustancias, previa autorización de la autoridad competente, al agua de los autoclaves, para evitar la corrosión de las latas y ablandar y desinfectar el agua.
Se permite el empleo de agua reciclada para enfriar los recipientes que hayan sido sometidos a un tratamiento por calor. Esta agua deberá filtrarse  y tratarse con cloro, según lo previsto en la normativa vigente.
El agua reciclada se mantendrá en circuito cerrado de forma que no pueda ser utilizada para otros fines. No obstante, cuando no exista  peligro de contaminación el suelo podrá limpiarse al final del período de trabajo con el agua  utilizada para enfriar los recipientes, así como con el agua de los autoclaves.', N' ', N'En los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas):
Los recipientes deberán :
Rechazarse si han sufrido da¦os o estuvieran mal fabricados.
Rechazarse o limpiarse, inmediatamente antes del llenado, mediante los dispositivos de limpieza eficaces. No se permite la utilización de agua no corriente.
En su caso, escurrirse durante el tiempo suficiente, tras la limpieza y antes de proceder al llenado.
En su caso, lavarse con agua potable a una temperatura suficientemente  elevada para eliminar las grasas  tras el cierre hermético  y antes de ser sometidos al autoclave.
Enfriarse tras el calentamiento, en agua que posea contenido residual de cloro o en agua que se ajuste al resto de parámetros sanitarios de las aguas potables.
Los recipientes herméticamente cerrados se retirarán de los aparatos de calentamiento a una temperatura tal que asegure la rápida evaporación de la humedad. No serán  manipulados antes de que estén completamente secos.
Los recipientes que presenten formaciones de gas, se someterán  a un examen complementario.

Los termómetros del equipo de tratamiento térmico se contrastarán periódicamente.
La empresa dispondrá de un procedimiento definido según criterios tales como, tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o inactivación de los gérmenes patógenos y todo esporo de microorganismos.
La empresa controlará la producción diaria, para garantizar la eficacia del cierre.
La empresa controlará que en las conservas de productos cárnicos se realizan pruebas de incubación de siete días a +37ºC ó de diez dias a +35ºC, ó cualquier otra combinación tiempo/temperatura reconocida como equivalente por la autoridad competente.
La empresa controlará que el agua de enfriamiento tras su utilización, tiene un contenido residual de cloro o se ajusta al resto de parámetros sanitarios de las aguas potables.
Se permite la adición de sustancias, previa autorización de la autoridad competente, al agua de los autoclaves, para evitar la corrosión de las latas y ablandar y desinfectar el agua.
Se permite el empleo de agua reciclada para enfriar los recipientes que hayan sido sometidos a un tratamiento por calor. Esta agua deberá filtrarse  y tratarse con cloro, según lo previsto en la normativa vigente.
El agua reciclada se mantendrá en circuito cerrado de forma que no pueda ser utilizada para otros fines. No obstante, cuando no exista  peligro de contaminación el suelo podrá limpiarse al final del período de trabajo con el agua  utilizada para enfriar los recipientes, así como con el agua de los autoclaves.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2186 AS Decimal(6, 0)), N'86             ', N'El personal conoce las exigencias a proveedores, y se comprueba y registra el cumplimiento de dichas exigencias', N'Se comprobará que el personal encargado de la homologación de proveedores conoce las instrucciones recogidas en el plan y que esas exigencias se cumplen.

Por su parte, la empresa debe poder asegurar que los proveedores han sido debidamente informados de las condiciones exigidas, así como que cumplen los requisitos establecidos bien mediante  auditorías, boletines de análisis, documentación acreditativa u otros métodos.

Para ello se comprobará si existe un listado de proveedores homologados y el registro de los controles, auditorías, documentación acreditativa, que se han aplicado a cada proveedor para su homologación.', N' ', N'Se comprobará que el personal encargado de la homologación de proveedores conoce las instrucciones recogidas en el plan y que esas exigencias se cumplen.

Por su parte, la empresa debe poder asegurar que los proveedores han sido debidamente informados de las condiciones exigidas, así como que cumplen los requisitos establecidos bien mediante  auditorías, boletines de análisis, documentación acreditativa u otros métodos.

Para ello se comprobará si existe un listado de proveedores homologados y el registro de los controles, auditorías, documentación acreditativa, que se han aplicado a cada proveedor para su homologación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2187 AS Decimal(6, 0)), N'86             ', N'El personal conoce las especificaciones sobre las materias primas y se comprueban y se registran estas exigencias.', N'Se comprobará que el personal encargado conoce las especificaciones para las diferentes materias primas y servicios y la forma de  llevar a cabo los controles que debe aplicar  para cada materia prima o servicio. 
También hay que valorar que conoce las medidas correctoras necesarias en caso de que se detecte que uno de los parámetros a vigilar ha superado el límite se¦alado.
 
Así mismo se comprobará in situ, que el personal encargado cumple las instrucciones especificadas, así como las frecuencias marcadas en el plan, en cuanto a las materias primas y servicios. 

Igualmente se comprobarán los registros de los últimos días.', N' ', N'Se comprobará que el personal encargado conoce las especificaciones para las diferentes materias primas y servicios y la forma de  llevar a cabo los controles que debe aplicar  para cada materia prima o servicio. 
También hay que valorar que conoce las medidas correctoras necesarias en caso de que se detecte que uno de los parámetros a vigilar ha superado el límite se¦alado.
 
Así mismo se comprobará in situ, que el personal encargado cumple las instrucciones especificadas, así como las frecuencias marcadas en el plan, en cuanto a las materias primas y servicios. 

Igualmente se comprobarán los registros de los últimos días.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2185 AS Decimal(6, 0)), N'86             ', N'Existen especificaciones para todas las materias primas y son completas', N'Se valorará si el plan incluye especificaciones para todas las materias primas y los materiales auxiliares, abarcando todos los criterios de seguridad necesarios: composición, criterios microbiológicos, fisico-químicos, de condiciones de conservación y transporte, etiquetado, caducidad, documentación%u2026', N' ', N'Se valorará si el plan incluye especificaciones para todas las materias primas y los materiales auxiliares, abarcando todos los criterios de seguridad necesarios: composición, criterios microbiológicos, fisico-químicos, de condiciones de conservación y transporte, etiquetado, caducidad, documentación%u2026')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2188 AS Decimal(6, 0)), N'86             ', N'Existen registros de las desviaciones detectadas y de las medidas previstas que se han aplicado.', N'Se comprobará no sólo que el personal responsable de las vigilancias conoce las medidas correctoras a aplicar siempre que se detecte alguna desviación, si no que dispone de los medios y la autoridad para llevarlas a cabo tal y como estén establecidas en el Plan. Se comprobará el registro de todas las incidencias y no conformidades relacionadas con el suministro de las materias primas y servicios,  junto con el de las acciones correctoras realizadas. ', N' ', N'Se comprobará no sólo que el personal responsable de las vigilancias conoce las medidas correctoras a aplicar siempre que se detecte alguna desviación, si no que dispone de los medios y la autoridad para llevarlas a cabo tal y como estén establecidas en el Plan. Se comprobará el registro de todas las incidencias y no conformidades relacionadas con el suministro de las materias primas y servicios,  junto con el de las acciones correctoras realizadas. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2190 AS Decimal(6, 0)), N'87             ', N'El personal encargado conoce las instrucciones del plan y éstas se cumplen', N'Se valorará si el personal encargado de las labores de mantenimiento conoce las instrucciones incluidas en el plan. Para ello se tendrá en cuenta que estas labores normalmente las hace personal específico de la empresa y cuando se trata de labores más complejas las realizan técnicos especialistas subcontratados. Así, el personal de la empresa debe conocer cuales son las actividades que le corresponden y su frecuencia, así como hacer el seguimiento de si se cumplen las labores a realizar por personal ajeno. Para realizar esta valoración, nos entrevistaremos con el personal de mantenimiento, para ver su grado de conocimiento del plan.
   
Se comprobará también, que tanto el personal de la empresa, como el personal ajeno a ella, cumplen con las instrucciones indicadas en el Plan de Mantenimiento para la maquinaria e instalaciones, además de hacerlo con la frecuencia propuesta. 

Se comprobará que se revisa periódicamente el estado general de mantenimiento de la empresa, con el fin de corregir aquellas deficiencias que se presenten.', N' ', N'Se valorará si el personal encargado de las labores de mantenimiento conoce las instrucciones incluidas en el plan. Para ello se tendrá en cuenta que estas labores normalmente las hace personal específico de la empresa y cuando se trata de labores más complejas las realizan técnicos especialistas subcontratados. Así, el personal de la empresa debe conocer cuales son las actividades que le corresponden y su frecuencia, así como hacer el seguimiento de si se cumplen las labores a realizar por personal ajeno. Para realizar esta valoración, nos entrevistaremos con el personal de mantenimiento, para ver su grado de conocimiento del plan.
   
Se comprobará también, que tanto el personal de la empresa, como el personal ajeno a ella, cumplen con las instrucciones indicadas en el Plan de Mantenimiento para la maquinaria e instalaciones, además de hacerlo con la frecuencia propuesta. 

Se comprobará que se revisa periódicamente el estado general de mantenimiento de la empresa, con el fin de corregir aquellas deficiencias que se presenten.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2191 AS Decimal(6, 0)), N'87             ', N'Se comprueba y registra las actuaciones realizadas.', N'Además se comprobará que las actividades realizadas se han registrado correctamente', N' ', N'Además se comprobará que las actividades realizadas se han registrado correctamente')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2189 AS Decimal(6, 0)), N'87             ', N'El Plan de mantenimiento de maquinaria e instalaciones es completo y está correctamente dise¦ado', N'Se valorará si el plan de mantenimiento establece el procedimiento a seguir para garantizar el mantenimiento tanto de las instalaciones como de la maquinaria, e incluirá el listado de instalaciones y maquinaria a mantener, sistemas de prevención y reparación, así como frecuencias y responsables de su ejecución.', N' ', N'Se valorará si el plan de mantenimiento establece el procedimiento a seguir para garantizar el mantenimiento tanto de las instalaciones como de la maquinaria, e incluirá el listado de instalaciones y maquinaria a mantener, sistemas de prevención y reparación, así como frecuencias y responsables de su ejecución.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2184 AS Decimal(6, 0)), N'86             ', N'El Plan de Control de Proveedores es completo y está correctamente dise¦ado
', N'Se valorará si el plan de control de proveedores recoge las características exigidas a todas las empresas proveedoras, así como, el procedimiento para aprobar los proveedores, para prescindir de ellos y la forma de garantizar cada proveedor el cumplimiento de sus especificaciones.', N' ', N'Se valorará si el plan de control de proveedores recoge las características exigidas a todas las empresas proveedoras, así como, el procedimiento para aprobar los proveedores, para prescindir de ellos y la forma de garantizar cada proveedor el cumplimiento de sus especificaciones.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2183 AS Decimal(6, 0)), N'85             ', N'Todos los operarios han recibido formación de acuerdo a lo programado y esta se registra adecuadamente', N'Se comprobará que todos los operarios implicados han recibido formación específica que garantice un grado de capacitación suficiente para la correcta implantación y funcionamiento del Sistema de Autocontrol.

Se comprobará la existencia de registros que prueben la formación recibida por los trabajadores, bien haya sido impartida por una empresa externa o por personal de la propia empresa.

En cualquiera de los casos, se deberá comprobar que se recoge, como mínimo, la siguiente información:
-Registro de los cursos impartidos: Título, fecha, horario, lugar.  
-Responsable de la formación.
-Personal docente y su capacitación profesional. 
-Relación de las personas a las que se les ha impartido.
', N' ', N'Se comprobará que todos los operarios implicados han recibido formación específica que garantice un grado de capacitación suficiente para la correcta implantación y funcionamiento del Sistema de Autocontrol.

Se comprobará la existencia de registros que prueben la formación recibida por los trabajadores, bien haya sido impartida por una empresa externa o por personal de la propia empresa.

En cualquiera de los casos, se deberá comprobar que se recoge, como mínimo, la siguiente información:
-Registro de los cursos impartidos: Título, fecha, horario, lugar.  
-Responsable de la formación.
-Personal docente y su capacitación profesional. 
-Relación de las personas a las que se les ha impartido.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2182 AS Decimal(6, 0)), N'85             ', N'El plan de formación es completo y está correctamente dise¦ado', N'Se valorará si el plan de formación garantiza que el personal conoce sus funciones en el marco del Sistema HACCP y los procedimientos de trabajo que ha de aplicar, en función de su puesto de trabajo. Para ello debe incluir la formación a recibir, sus contenidos, frecuencia, responsables de la misma y personal que la ha de recibir, abarcando a todo el personal necesario por su actividad en la empresa.', N' ', N'Se valorará si el plan de formación garantiza que el personal conoce sus funciones en el marco del Sistema HACCP y los procedimientos de trabajo que ha de aplicar, en función de su puesto de trabajo. Para ello debe incluir la formación a recibir, sus contenidos, frecuencia, responsables de la misma y personal que la ha de recibir, abarcando a todo el personal necesario por su actividad en la empresa.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2175 AS Decimal(6, 0)), N'83             ', N'Se adoptan y registran las medidas para corregir las desviaciones detectadas', N'Mediante el estudio de los registros se valorará si se han adoptado medidas  cuando se detectan desviaciones tanto en el cumplimiento de la frecuencia cómo en el del método previsto. Dependiendo del  motivo del incumplimiento serán las soluciones, así por ejemplo en caso de incumplimientos de aplicación del plan, las soluciones pasarán por una reeducación del personal manipulador y un seguimiento exhaustivo hasta conseguir que se trabaje conforme está planificado, o en caso de incumplimientos por cambio de necesidades pasarán por una replanificación de la limpieza. ', N' ', N'Mediante el estudio de los registros se valorará si se han adoptado medidas  cuando se detectan desviaciones tanto en el cumplimiento de la frecuencia cómo en el del método previsto. Dependiendo del  motivo del incumplimiento serán las soluciones, así por ejemplo en caso de incumplimientos de aplicación del plan, las soluciones pasarán por una reeducación del personal manipulador y un seguimiento exhaustivo hasta conseguir que se trabaje conforme está planificado, o en caso de incumplimientos por cambio de necesidades pasarán por una replanificación de la limpieza. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2176 AS Decimal(6, 0)), N'83             ', N'Es aparentemente eficaz el Plan de limpieza para todo el establecimiento.', N'Se comprobará que el establecimiento mantiene en todos sus locales y utensilios un estado de limpieza correcto y acorde a la actividad. 
Se valorará la presencia de manchas, restos superficiales de grasa y restos sólidos, no admitiendo como limpieza suficiente cuando se aprecie suciedad visible no justificable por la actividad normal e inmediata.', N' ', N'Se comprobará que el establecimiento mantiene en todos sus locales y utensilios un estado de limpieza correcto y acorde a la actividad. 
Se valorará la presencia de manchas, restos superficiales de grasa y restos sólidos, no admitiendo como limpieza suficiente cuando se aprecie suciedad visible no justificable por la actividad normal e inmediata.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2177 AS Decimal(6, 0)), N'84             ', N'El Plan de Control de plagas es completo y está correctamente dise¦ado', N'Se valorará si el Plan de control de plagas establece los procedimientos adecuados para evitar que lleguen a presentarse plagas en el establecimiento, y a detectarlas, controlarlas y combatirlas si se presentan. Este plan contará con medidas pasivas y en su caso activas,  en caso de uso de productos tóxicos se conocerá su composición y forma de aplicación (frecuencia, tiempo de actuación, tiempo de espera, localización de cebos, etc.). Así mismo incluirá  procedimientos para evitar la contaminación de productos y personas.', N' ', N'Se valorará si el Plan de control de plagas establece los procedimientos adecuados para evitar que lleguen a presentarse plagas en el establecimiento, y a detectarlas, controlarlas y combatirlas si se presentan. Este plan contará con medidas pasivas y en su caso activas,  en caso de uso de productos tóxicos se conocerá su composición y forma de aplicación (frecuencia, tiempo de actuación, tiempo de espera, localización de cebos, etc.). Así mismo incluirá  procedimientos para evitar la contaminación de productos y personas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2178 AS Decimal(6, 0)), N'84             ', N'El personal conoce las instrucciones específicas para la prevención y el control de las plagas (insectos, roedores, parásitos) y lo ejecuta correctamente', N'Se pueden dar dos tipos de situaciones, una que la empresa haya subcontratado los servicios de control de plagas y otra que sea personal de la propia empresa quien lo realice.

 En caso de personal externo no tendremos la posibilidad de entrevistarnos con ellos para ver su formación, pero a través de su trabajo valoraremos la ejecución del mismo, es decir, si conoce el tipo de problemas que se presentan según la industria de que se trate y su ubicación, si emplea las sustancia adecuadas para eliminar esos problemas, si la colocación de sustancias y cebos es la adecuada para evitar la posible contaminación de los alimentos y si se ajusta al mapa de cebos propuesto. Además valoraremos si la frecuencia prevista es suficiente para evitar la aparición de plagas.

En caso de ser personal interno quien lo realiza podremos además valorar el conocimiento de las instrucciones específicas incluidas en este plan. 

Además de estos tratamientos, se comprobará si se adoptan medidas pasivas de lucha cuyo mantenimiento y limpieza dependen en todos los casos de la industria.
', N' ', N'Se pueden dar dos tipos de situaciones, una que la empresa haya subcontratado los servicios de control de plagas y otra que sea personal de la propia empresa quien lo realice.

 En caso de personal externo no tendremos la posibilidad de entrevistarnos con ellos para ver su formación, pero a través de su trabajo valoraremos la ejecución del mismo, es decir, si conoce el tipo de problemas que se presentan según la industria de que se trate y su ubicación, si emplea las sustancia adecuadas para eliminar esos problemas, si la colocación de sustancias y cebos es la adecuada para evitar la posible contaminación de los alimentos y si se ajusta al mapa de cebos propuesto. Además valoraremos si la frecuencia prevista es suficiente para evitar la aparición de plagas.

En caso de ser personal interno quien lo realiza podremos además valorar el conocimiento de las instrucciones específicas incluidas en este plan. 

Además de estos tratamientos, se comprobará si se adoptan medidas pasivas de lucha cuyo mantenimiento y limpieza dependen en todos los casos de la industria.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2179 AS Decimal(6, 0)), N'84             ', N'Se  registran los tratamientos aplicados', N'Se valorará si se registran correctamente los tratamientos aplicados. Cada tratamiento incluirá datos de cuándo se ha realizado, qué se ha observado respecto al tratamiento impuesto anteriormente y el nuevo tratamiento aplicado.

También se registrará el mantenimiento y limpieza de los sistemas de lucha pasivos.
', N' ', N'Se valorará si se registran correctamente los tratamientos aplicados. Cada tratamiento incluirá datos de cuándo se ha realizado, qué se ha observado respecto al tratamiento impuesto anteriormente y el nuevo tratamiento aplicado.

También se registrará el mantenimiento y limpieza de los sistemas de lucha pasivos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2192 AS Decimal(6, 0)), N'87             ', N'Se registran las reparaciones realizadas para corregir las averías o imprevistos en la maquinaria o instalaciones.', N'Se comprobará que hay registros de aquellas actuaciones o reparaciones que se hayan tenido que realizar consecuencia de averías o accidentes ocurridos durante el proceso productivo.

Además, tras adoptar este tipo de medidas, puede que en algún caso tengan que hacer una valoración de aptitud de producto elaborado, al detectarse problemas en maquinaria y equipos que incida directamente en la producción de alimentos seguros.
', N' ', N'Se comprobará que hay registros de aquellas actuaciones o reparaciones que se hayan tenido que realizar consecuencia de averías o accidentes ocurridos durante el proceso productivo.

Además, tras adoptar este tipo de medidas, puede que en algún caso tengan que hacer una valoración de aptitud de producto elaborado, al detectarse problemas en maquinaria y equipos que incida directamente en la producción de alimentos seguros.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2181 AS Decimal(6, 0)), N'84             ', N'Es aparentemente eficaz el Plan implantado', N'Se comprobará que el conjunto de medidas adoptadas para el control de plagas es tal que no se observan en los distintos locales del establecimiento la presencia de insectos, roedores o cualquier indicio que haga sospechar su presencia. (heces, pelos, plumas etc.)', N' ', N'Se comprobará que el conjunto de medidas adoptadas para el control de plagas es tal que no se observan en los distintos locales del establecimiento la presencia de insectos, roedores o cualquier indicio que haga sospechar su presencia. (heces, pelos, plumas etc.)')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2180 AS Decimal(6, 0)), N'84             ', N'Se han adoptado y registrado medidas cuando se ha detectado la presencia de plagas', N'Se valorará si cuando en la empresa se haya detectado la presencia de algún tipo de plaga se ha estudiado el origen del problema, es decir, si el problema reside en que los métodos adoptados no tienen su efecto o si es que el problema es nuevo y no se han tomado medidas contra él.', N' ', N'Se valorará si cuando en la empresa se haya detectado la presencia de algún tipo de plaga se ha estudiado el origen del problema, es decir, si el problema reside en que los métodos adoptados no tienen su efecto o si es que el problema es nuevo y no se han tomado medidas contra él.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2149 AS Decimal(6, 0)), N'77             ', N'El personal dedicado a la vigilancia conoce tanto los límites basados en datos objetivos como los basados en instrucciones concretas de trabajo y es capaz de discernir entre lo aceptable y lo no aceptable', N'Se valorará si el personal que realiza la vigilancia tiene claros los límites críticos establecidos en los distintos PCC(s). No sólo debe conocer los límites basados en datos objetivos sino también aquellos basados en instrucciones de trabajo, para determinar fácilmente si se supera o no el límite crítico y adoptar las medidas correctoras con suficiente rapidez.
Por otro lado, es interesante que la empresa tenga previstos unos niveles objetivos y unas tolerancias que permitan tener un margen de corrección antes de superar los verdaderos límites críticos y por tanto se valorará si el personal que realiza la vigilancia tiene claro cuando se trata de un nivel objetivo y  cuando de un límite crítico, así como de las actuaciones a realizar en cada uno de los casos.', N' ', N'Se valorará si el personal que realiza la vigilancia tiene claros los límites críticos establecidos en los distintos PCC(s). No sólo debe conocer los límites basados en datos objetivos sino también aquellos basados en instrucciones de trabajo, para determinar fácilmente si se supera o no el límite crítico y adoptar las medidas correctoras con suficiente rapidez.
Por otro lado, es interesante que la empresa tenga previstos unos niveles objetivos y unas tolerancias que permitan tener un margen de corrección antes de superar los verdaderos límites críticos y por tanto se valorará si el personal que realiza la vigilancia tiene claro cuando se trata de un nivel objetivo y  cuando de un límite crítico, así como de las actuaciones a realizar en cada uno de los casos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2193 AS Decimal(6, 0)), N'87             ', N'Es aparentemente eficaz el Plan de mantenimiento ', N'Se comprobará que las medidas previstas por la empresa son suficientes para mantener en estado correcto todas sus instalaciones y maquinaria.  Se valorará la eficacia del plan de mantenimiento observando si hay presencia de desperfectos en equipos y estructuras. 
En aquellos casos en que se realicen reparaciones u obras, se valorará en qué momento tienen lugar y su influencia en el desarrollo de la actividad alimentaria así como las medidas adoptadas para evitar cualquier riesgo sanitario.
', N' ', N'Se comprobará que las medidas previstas por la empresa son suficientes para mantener en estado correcto todas sus instalaciones y maquinaria.  Se valorará la eficacia del plan de mantenimiento observando si hay presencia de desperfectos en equipos y estructuras. 
En aquellos casos en que se realicen reparaciones u obras, se valorará en qué momento tienen lugar y su influencia en el desarrollo de la actividad alimentaria así como las medidas adoptadas para evitar cualquier riesgo sanitario.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2195 AS Decimal(6, 0)), N'88             ', N'El personal conoce las instrucciones específicas sobre la trazabilidad de los productos en las fases de producción en las que pueden estar implicados y éstas se cumplen, pudiendo relacionar los productos (tanto en una dirección como en otra) con las mater????', N'Se comprobará que las  personas encargadas, o que intervienen en el proceso productivo conocen perfectamente las instrucciones y forma de realizar la trazabilidad de los productos de forma que no exista posibilidad de confusión en el seguimiento de éste.

Se valorará si las actividades necesarias para asegurar la trazabilidad, se llevan a cabo con la frecuencia o prontitud adecuadas, de tal forma que no exista posibilidad de confusión entre los distintos productos, partidas o lotes, bien sea de materias primas, productos intermedios o finales.
 
La documentación generada en el proceso productivo, permitirá seguir el rastro del producto elaborado desde el inicio de éste y a lo largo de todas sus fases, incluido el primer punto de distribución. Este seguimiento también podrá realizarse en sentido ascendente hasta las materias primas y su proveedor.', N' ', N'Se comprobará que las  personas encargadas, o que intervienen en el proceso productivo conocen perfectamente las instrucciones y forma de realizar la trazabilidad de los productos de forma que no exista posibilidad de confusión en el seguimiento de éste.

Se valorará si las actividades necesarias para asegurar la trazabilidad, se llevan a cabo con la frecuencia o prontitud adecuadas, de tal forma que no exista posibilidad de confusión entre los distintos productos, partidas o lotes, bien sea de materias primas, productos intermedios o finales.
 
La documentación generada en el proceso productivo, permitirá seguir el rastro del producto elaborado desde el inicio de éste y a lo largo de todas sus fases, incluido el primer punto de distribución. Este seguimiento también podrá realizarse en sentido ascendente hasta las materias primas y su proveedor.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(837 AS Decimal(6, 0)), N'39             ', N'Si no se deduce de la denominación comercial aparece en la relación de ingredientes la especie o especies a partir de las cuales se ha obtenido la carne.', N'Relación de ingredientes, que incluirá la especie o especies a partir de las cuales se ha obtenido la carne, en la medida en que esto no se deduzca claramente de la denominación comercial del producto.', N' ', N'Relación de ingredientes, que incluirá la especie o especies a partir de las cuales se ha obtenido la carne, en la medida en que esto no se deduzca claramente de la denominación comercial del producto.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(836 AS Decimal(6, 0)), N'32             ', N'No se adicionan aditivos en dosis superiores a las legisladas.', N'No podrán comercializarse productos cárnicos a los que se les haya adicionado aditivos en dosis superiores a las siguientes:
Insertar enlace con las listas positivas de aditivos y aromas.', N' ', N'No podrán comercializarse productos cárnicos a los que se les haya adicionado aditivos en dosis superiores a las siguientes:
Insertar enlace con las listas positivas de aditivos y aromas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(844 AS Decimal(6, 0)), N'40             ', N'Los productos van acompa¦ados durante su transporte de un documento de acompa¦amiento comercial, que incluye la marca sanitaria, y es conservado por el destinatario durante al menos un a¦o.', N'

Los productos cárnicos y otros productos de origen animal irán acompa¦ados durante su transporte de un documento de acompa¦amiento comercial que incluirá la marca sanitaria. Deberá ser conservado por el destinatario durante un periodo mínimo de un a¦o.', N' ', N'

Los productos cárnicos y otros productos de origen animal irán acompa¦ados durante su transporte de un documento de acompa¦amiento comercial que incluirá la marca sanitaria. Deberá ser conservado por el destinatario durante un periodo mínimo de un a¦o.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(830 AS Decimal(6, 0)), N'32             ', N'En los establecimientos que fabrican grasas animales fundidas, chicharrones y subproductos de extracción, las materias primas se someten a extracción, seguida de separación de la grasa, por métodos adecuados y sin utilización de disolventes.', N'En los establecimientos en los que se fabriquen grasas animales fundidas, chicharrones y subproductos de extracción:
Las materias primas se someterán a extracción mediante calentamiento, presión u otro método apropiado, seguido de la separación de la grasa mediante decantación, centrifugación, filtración u otro método adecuado. No podrán utilizarse disolventes.
', N' ', N'En los establecimientos en los que se fabriquen grasas animales fundidas, chicharrones y subproductos de extracción:
Las materias primas se someterán a extracción mediante calentamiento, presión u otro método apropiado, seguido de la separación de la grasa mediante decantación, centrifugación, filtración u otro método adecuado. No podrán utilizarse disolventes.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(823 AS Decimal(6, 0)), N'32             ', N'En los establecimientos que fabrican platos cocinados cárnicos, en caso de tratamiento por calor separado, y cuando  tras éste, el producto cárnico, se mezcla con los demás ingredientes:
El tiempo en que la temperatura de éste está entre 10 y 60ºC es un ????', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
En caso de tratamiento por calor separado, inmediatamente después de éste el producto cárnico que forma parte del plato cocinado deberá :
Bien mezclarse con los demás ingredientes, en tal caso el tiempo en que la temperatura del producto cárnico esté comprendida entre 10ºC y 60ºC deberá reducirse a un máximo de dos horas
Bien refrigerarse a una temperatura inferior o igual a 10ºC antes de mezclarse con los demás ingredientes.
No obstante, la autoridad competente podrá autorizar otros métodos de preparación.', N' ', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
En caso de tratamiento por calor separado, inmediatamente después de éste el producto cárnico que forma parte del plato cocinado deberá :
Bien mezclarse con los demás ingredientes, en tal caso el tiempo en que la temperatura del producto cárnico esté comprendida entre 10ºC y 60ºC deberá reducirse a un máximo de dos horas
Bien refrigerarse a una temperatura inferior o igual a 10ºC antes de mezclarse con los demás ingredientes.
No obstante, la autoridad competente podrá autorizar otros métodos de preparación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(824 AS Decimal(6, 0)), N'32             ', N'En los establecimientos que fabrican platos cocinados cárnicos, los componentes del plato cocinado, son refrigerados a temperatura -< +10ºC en su parte central antes de 2 horas tras la cocción, y a temperatura de almacenamiento lo antes posible, ó supera ????', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
Todos los componentes del plato cocinado deberán refrigerarse a una temperatura inferior o igual a +10ºC, en su parte central, antes de transcurridas dos horas del final de la cocción y a temperatua de almacenamiento lo antes posible. No obstante, la autoridad competente autorizará al establecimiento a superar el período de dos horas por razones tecnológicas y siempre que se garantice la salubridad del producto acabado.', N' ', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
Todos los componentes del plato cocinado deberán refrigerarse a una temperatura inferior o igual a +10ºC, en su parte central, antes de transcurridas dos horas del final de la cocción y a temperatua de almacenamiento lo antes posible. No obstante, la autoridad competente autorizará al establecimiento a superar el período de dos horas por razones tecnológicas y siempre que se garantice la salubridad del producto acabado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(825 AS Decimal(6, 0)), N'32             ', N'En los establecimientos que fabrican platos cocinados cárnicos, cuando el plato cocinado va a congelarse, ésta operación se realiza inmediatamente tras el enfriado.', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
Si el plato cocinado va a ser congelado, esta operación deberá realizarse inmediatamente después del enfriado.', N' ', N'En los establecimientos en los que se fabriquen platos cocinados cárnicos:
Si el plato cocinado va a ser congelado, esta operación deberá realizarse inmediatamente después del enfriado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(845 AS Decimal(6, 0)), N'39             ', N'En el caso de platos cocinados cárnicos se incluye la mención de especies animales así como la fecha de fabricación expresada como plazo retrospectivo a partir de la fecha de consumo preferente.', N'
El etiquetado de los platos cocinados cárnicos deberá incluir la mención de las especies animales así como la fecha de fabricación. Dicha fecha de fabricación se expresará como tal o como un plazo retrospectivo a partir de la fecha de consumo preferente (Ej. fecha de fabricación: ?30 días antes de la fecha de consumo preferente?).', N' ', N'
El etiquetado de los platos cocinados cárnicos deberá incluir la mención de las especies animales así como la fecha de fabricación. Dicha fecha de fabricación se expresará como tal o como un plazo retrospectivo a partir de la fecha de consumo preferente (Ej. fecha de fabricación: ?30 días antes de la fecha de consumo preferente?).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(841 AS Decimal(6, 0)), N'46             ', N'Figura marca sanitaria visible, legible e indeleble, y va impresa en etiqueta, en el producto o en el envase (caso de que envase y embalaje constituyan una unidad de venta o que varios productos provistos de la marca se embalen, en el embalaje).', N'Podrá imprimirse en el producto mismo o en el envase, si está envasado individualmente, o en una etiqueta. En el caso de que envase y embalaje constituyan una unidad de venta, bastará con que la marca se coloque en el embalaje.
Cuando los productos cárnicos, provistos de la marca sanitaria sean posteriormente embalados, se colocará también la marca en el embalaje.', N' ', N'Podrá imprimirse en el producto mismo o en el envase, si está envasado individualmente, o en una etiqueta. En el caso de que envase y embalaje constituyan una unidad de venta, bastará con que la marca se coloque en el embalaje.
Cuando los productos cárnicos, provistos de la marca sanitaria sean posteriormente embalados, se colocará también la marca en el embalaje.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2203 AS Decimal(6, 0)), N'89             ', N'Se adoptan y registran las medidas aplicadas cuando se detectan desviaciones', N'Estarán registradas las medidas aplicadas en el caso de que se hayan detectado desviaciones o el equipo a calibrar no esté dentro del criterio o periodo de aceptación. Se valorará la eficacia o conveniencia de las medidas previstas aplicadas en función de la mayor o menor trascendencia del equipo implicado.', N' ', N'Estarán registradas las medidas aplicadas en el caso de que se hayan detectado desviaciones o el equipo a calibrar no esté dentro del criterio o periodo de aceptación. Se valorará la eficacia o conveniencia de las medidas previstas aplicadas en función de la mayor o menor trascendencia del equipo implicado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2196 AS Decimal(6, 0)), N'88             ', N'Se registran las medidas previstas aplicadas cuando se ha detectado alguna incidencia', N'En el registro de medidas correctoras quedará perfectamente identificado el lotes/s que estaba en proceso y que ha sufrido cualquier tipo de incidencia, junto con las medidas que se aplicaron.
A partir de un lote dado, se podrá identificar de forma rápida las incidencias, controles y medidas que tuvieron lugar o se realizaron durante ese proceso.
', N' ', N'En el registro de medidas correctoras quedará perfectamente identificado el lotes/s que estaba en proceso y que ha sufrido cualquier tipo de incidencia, junto con las medidas que se aplicaron.
A partir de un lote dado, se podrá identificar de forma rápida las incidencias, controles y medidas que tuvieron lugar o se realizaron durante ese proceso.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2197 AS Decimal(6, 0)), N'88             ', N'Hay mecanismos adecuados que permitan la retirada de forma eficaz del producto distribuido', N'La trazabilidad debe ser tal que asegure la efectividad de los mecanismos de retirada del producto del mercado.
Deberá existir un registro actualizado para el primer punto de distribución de tal forma que en caso de detectarse alguna anomalía de producto distribuido, se pueda llevar a cabo una retirada de este en el menor tiempo y la mayor eficacia posible.
', N' ', N'La trazabilidad debe ser tal que asegure la efectividad de los mecanismos de retirada del producto del mercado.
Deberá existir un registro actualizado para el primer punto de distribución de tal forma que en caso de detectarse alguna anomalía de producto distribuido, se pueda llevar a cabo una retirada de este en el menor tiempo y la mayor eficacia posible.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2198 AS Decimal(6, 0)), N'88             ', N'Se identifica claramente el Producto No Apto', N'Un producto puede ser identificado como No Apto como consecuencia de las vigilancias realizadas dentro del programa de autocontrol que informen de una pérdida de control o superación de algún límite crítico. 
Se comprobará que los productos %u201CNo aptos%u201D se identifican sin posibilidad de confusión.
Se comprobará que hay registros de que los productos %u201CNo aptos%u201D se han derivado al destino previsto.
', N' ', N'Un producto puede ser identificado como No Apto como consecuencia de las vigilancias realizadas dentro del programa de autocontrol que informen de una pérdida de control o superación de algún límite crítico. 
Se comprobará que los productos %u201CNo aptos%u201D se identifican sin posibilidad de confusión.
Se comprobará que hay registros de que los productos %u201CNo aptos%u201D se han derivado al destino previsto.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2199 AS Decimal(6, 0)), N'89             ', N'El Plan de contrastación de equipos de medida y/o calibración es completo y está correctamente dise¦ado', N'Se valorará si el plan de contrastación/calibración desarrolla procedimientos para asegurar que todos los equipos de medida den valores correctos. Debe contener un listado de aparatos a calibrar, sistema utilizado, la frecuencia y  precisión requerida, así como el sistema de identificación de los aparatos una vez calibrados.', N' ', N'Se valorará si el plan de contrastación/calibración desarrolla procedimientos para asegurar que todos los equipos de medida den valores correctos. Debe contener un listado de aparatos a calibrar, sistema utilizado, la frecuencia y  precisión requerida, así como el sistema de identificación de los aparatos una vez calibrados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2200 AS Decimal(6, 0)), N'89             ', N'El personal encargado conoce y ejecuta el Plan de Calibración/Contrastación', N'En función de la complejidad de los equipos, la calibración/contrastación puede ser realizada por el propio personal de la empresa o bien por una empresa externa capacitada para realizarlo.
En cualquiera de los dos casos se comprobará que el personal conoce el plan de calibración/contrastación en la medida que le afecte y abarca todos los aparatos de medida necesarios en la empresa. 
', N' ', N'En función de la complejidad de los equipos, la calibración/contrastación puede ser realizada por el propio personal de la empresa o bien por una empresa externa capacitada para realizarlo.
En cualquiera de los dos casos se comprobará que el personal conoce el plan de calibración/contrastación en la medida que le afecte y abarca todos los aparatos de medida necesarios en la empresa. 
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2194 AS Decimal(6, 0)), N'88             ', N'El plan de trazabilidad es completo y está correctamente dise¦ado', N'Se valorará si el plan de trazabilidad planteado permite identificar y relacionar entre sí los productos terminados y sus materias primas, así como seguir el rastro del producto final hasta su punto de distribución. Igualmente vendrá definido el sistema de loteado que utiliza.', N' ', N'Se valorará si el plan de trazabilidad planteado permite identificar y relacionar entre sí los productos terminados y sus materias primas, así como seguir el rastro del producto final hasta su punto de distribución. Igualmente vendrá definido el sistema de loteado que utiliza.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2202 AS Decimal(6, 0)), N'89             ', N'Existen registros de las actividades de calibración/contrastación llevadas a cabo para cada equipo', N'Se comprobará que existe un listado de equipos y aparatos a calibrar/contrastar, tanto de los instrumentos utilizados para la calibración/ contrastación interna, como de los sistemas de medida instalados en los equipos y en las máquinas que intervienen en los diferentes procesos de fabricación.
También existirán registros de aparatos calibrados, con la fecha en que se realizó, el responsable de su ejecución, el método usado y el periodo de validez. 
Se comprobará que existen registros de los resultados obtenidos cuando se ha llevado a cabo la calibración o contrastación, no sólo del proceso de calibración/contrastación, si no también si se ha detectado si el aparato estaba funcionando correctamente y/o grado de desviación.
', N' ', N'Se comprobará que existe un listado de equipos y aparatos a calibrar/contrastar, tanto de los instrumentos utilizados para la calibración/ contrastación interna, como de los sistemas de medida instalados en los equipos y en las máquinas que intervienen en los diferentes procesos de fabricación.
También existirán registros de aparatos calibrados, con la fecha en que se realizó, el responsable de su ejecución, el método usado y el periodo de validez. 
Se comprobará que existen registros de los resultados obtenidos cuando se ha llevado a cabo la calibración o contrastación, no sólo del proceso de calibración/contrastación, si no también si se ha detectado si el aparato estaba funcionando correctamente y/o grado de desviación.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2201 AS Decimal(6, 0)), N'89             ', N'Están identificados los aparatos a calibrar indicando su estado de calibración y el personal conoce e identifica el estado de calibración de los equipos', N'Se comprobará que los equipos o sistemas de medida están identificados y/o codificados de acuerdo al Plan. Esta identificación se utilizará en todos los documentos que hagan referencia a los equipos, para garantizar la trazabilidad documental de todos sus datos y registros.
Se comprobará que el personal conoce y sabe interpretar el estado de calibración/contrastación de los equipos, (si están dentro del periodo de calibración, si este se ha superado o si está fuera de uso) y las medidas a aplicar en estas circunstancias.
', N' ', N'Se comprobará que los equipos o sistemas de medida están identificados y/o codificados de acuerdo al Plan. Esta identificación se utilizará en todos los documentos que hagan referencia a los equipos, para garantizar la trazabilidad documental de todos sus datos y registros.
Se comprobará que el personal conoce y sabe interpretar el estado de calibración/contrastación de los equipos, (si están dentro del periodo de calibración, si este se ha superado o si está fuera de uso) y las medidas a aplicar en estas circunstancias.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2148 AS Decimal(6, 0)), N'77             ', N'Los límites críticos se han establecido de forma correcta y realmente mantienen el peligro bajo control', N'Lo que se busca es valorar si los límites críticos propuestos mantienen el peligro bajo control conociendo la realidad de la empresa o en caso contrario no son suficientes. También debe valorarse si son reales, es decir no son simplemente un dato que se escribe en un documento y que después no se cumple porque es inaplicable. Estos límites, en caso de duda, deben de ser demostrables o justificables (validación previa de los límites críticos). Esta validación podrá ser en casos legislativa, en otros casos estará basada en la  bibliografía y en otros precisará de estudios o pruebas que demuestren su idoneidad. 
Por otro lado se comprobará que en cada PCC existen límites para cada una de las distintas medidas preventivas que  eviten un determinado peligro.
', N' ', N'Lo que se busca es valorar si los límites críticos propuestos mantienen el peligro bajo control conociendo la realidad de la empresa o en caso contrario no son suficientes. También debe valorarse si son reales, es decir no son simplemente un dato que se escribe en un documento y que después no se cumple porque es inaplicable. Estos límites, en caso de duda, deben de ser demostrables o justificables (validación previa de los límites críticos). Esta validación podrá ser en casos legislativa, en otros casos estará basada en la  bibliografía y en otros precisará de estudios o pruebas que demuestren su idoneidad. 
Por otro lado se comprobará que en cada PCC existen límites para cada una de las distintas medidas preventivas que  eviten un determinado peligro.
')
GO
