INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1033 AS Decimal(6, 0)), N'3              ', N'Dispone de una zona de recepción que está situada a la entrada de la industria y dispone de algún sistema permanente que impide que los vehículos a motor (tractor, camión o similar) accedan a la zona de elaboración o almacenes.', N'Zona de recepción
Estará situada a la entrada de la industria y dispondrá de algún sistema permanente que impida que los vehículos a motor (tractor, camión o similar) accedan a la zona de elaboración o almacenes.', N' ', N'Zona de recepción
