INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1042 AS Decimal(6, 0)), N'58             ', N'Se garantiza la imposibilidad de mezcla con otras aguas o retornos a la conducción del agua destinada a su envasado.', N'Las aguas se conducirán mediante tuberías cerradas que deberán discurrir de forma que se evite su posible contaminación o alteración. Asimismo, se limitarán los empalmes y válvulas, cabos extremos u otras derivaciones a las necesariamente imprescindibles, debiendo garantizar la imposibilidad de mezcla con otras aguas o retornos a la conducción del agua destinada a su envasado.', N' ', N'Las aguas se conducirán mediante tuberías cerradas que deberán discurrir de forma que se evite su posible contaminación o alteración. Asimismo, se limitarán los empalmes y válvulas, cabos extremos u otras derivaciones a las necesariamente imprescindibles, debiendo garantizar la imposibilidad de mezcla con otras aguas o retornos a la conducción del agua destinada a su envasado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1041 AS Decimal(6, 0)), N'58             ', N'Se limitan los empalmes y válvulas, cabos extremos u otras derivaciones a las necesariamente imprescindibles. ', N'Las aguas se conducirán mediante tuberías cerradas que deberán discurrir de forma que se evite su posible contaminación o alteración. Asimismo, se limitarán los empalmes y válvulas, cabos extremos u otras derivaciones a las necesariamente imprescindibles, debiendo garantizar la imposibilidad de mezcla con otras aguas o retornos a la conducción del agua destinada a su envasado.', N' ', N'Las aguas se conducirán mediante tuberías cerradas que deberán discurrir de forma que se evite su posible contaminación o alteración. Asimismo, se limitarán los empalmes y válvulas, cabos extremos u otras derivaciones a las necesariamente imprescindibles, debiendo garantizar la imposibilidad de mezcla con otras aguas o retornos a la conducción del agua destinada a su envasado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1043 AS Decimal(6, 0)), N'58             ', N'Toda la conducción del agua destinada a ser envasada es inspeccionable.', N'Toda la conducción del agua destinada a ser envasada deberá ser inspeccionable, quedando se¦alizada de forma continua con una banda blanca y con flechas indicadoras de la dirección de circulación del líquido. ', N' ', N'Toda la conducción del agua destinada a ser envasada deberá ser inspeccionable, quedando se¦alizada de forma continua con una banda blanca y con flechas indicadoras de la dirección de circulación del líquido. ')
GO
