INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1030 AS Decimal(6, 0)), N'39             ', N'Los productos cuya conservación sólo esté garantizada durante un periodo limitado tras la aplicación de un tratamiento llevan una inscripción visible de las condiciones de almacenamiento.', N'Los productos cuya conservación sólo esté garantizada durante un periodo limitado tras la aplicación del tratamiento tales como salazón, ahumado, desecación o escabechado, deberán llevar en el envase y/o embalaje una inscripción claramente visible que indique las condiciones de almacenamiento.', N' ', N'Los productos cuya conservación sólo esté garantizada durante un periodo limitado tras la aplicación del tratamiento tales como salazón, ahumado, desecación o escabechado, deberán llevar en el envase y/o embalaje una inscripción claramente visible que indique las condiciones de almacenamiento.')
GO
