INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1053 AS Decimal(6, 0)), N'39             ', N'En caso que el establecimiento  elabore con destino exclusivo para su exportación a países no pertenecientes a la Comunidad Económica Europea y que no cumplan lo dispuesto en la normativa aplicable llevan impresa en su embalaje la palabra EXPORT. Además, ????', N'Las aguas de bebida envasadas que se elaboren con destino exclusivo para su exportación a países no pertenecientes a la Comunidad Económica Europea y que no cumplan lo dispuesto en la normativa aplicable llevarán impresa en su embalaje la palabra EXPORT. Además, su etiqueta deberá llevar la palabra EXPORT, o cualquier otro signo que reglamentariamente se indique y que permita identificarlo inequívocamente para evitar que el producto sea comercializado y consumido en Espa¦a.', N' ', N'Las aguas de bebida envasadas que se elaboren con destino exclusivo para su exportación a países no pertenecientes a la Comunidad Económica Europea y que no cumplan lo dispuesto en la normativa aplicable llevarán impresa en su embalaje la palabra EXPORT. Además, su etiqueta deberá llevar la palabra EXPORT, o cualquier otro signo que reglamentariamente se indique y que permita identificarlo inequívocamente para evitar que el producto sea comercializado y consumido en Espa¦a.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1054 AS Decimal(6, 0)), N'39             ', N'El etiquetado debe cumplir con las especificaciones recogidas en el Anexo 4 de esta IT.', N'El etiquetado debe cumplir con las especificaciones recogidas en el Anexo 4 de esta IT.', N' ', N'El etiquetado debe cumplir con las especificaciones recogidas en el Anexo 4 de esta IT.')
