INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1056 AS Decimal(6, 0)), N'32             ', N'Los controles analíticos se llevan a cabo según aparece reflejado en el párrafo 21.1 de esta IT.', N'Los correspondientes controles analíticos incluirán como mínimo las siguientes determinaciones, en los períodos máximos citados:
Al menos cada cinco a¦os, el agua de los puntos de emergencia deberá ser controlada mediante un análisis completo físico-químico y de posibles contaminantes.
Con periodicidad, al menos trimestral, deberá controlarse el agua y su análisis comprenderá, como mínimo, todas las determinaciones microbiológicas previstas en esta Reglamentación y las físico-químicas indicadoras de posible contaminación, así como la conductividad, los componentes mayoritarios y aquellos parámetros que caractericen a dicha agua.
En cada jornada laboral deberán realizarse análisis sobre muestras de producto terminado que comprenderán, por lo menos, los parámetros indicadores de contaminación microbiológica.', N' ', N'Los correspondientes controles analíticos incluirán como mínimo las siguientes determinaciones, en los períodos máximos citados:
Al menos cada cinco a¦os, el agua de los puntos de emergencia deberá ser controlada mediante un análisis completo físico-químico y de posibles contaminantes.
Con periodicidad, al menos trimestral, deberá controlarse el agua y su análisis comprenderá, como mínimo, todas las determinaciones microbiológicas previstas en esta Reglamentación y las físico-químicas indicadoras de posible contaminación, así como la conductividad, los componentes mayoritarios y aquellos parámetros que caractericen a dicha agua.
En cada jornada laboral deberán realizarse análisis sobre muestras de producto terminado que comprenderán, por lo menos, los parámetros indicadores de contaminación microbiológica.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1049 AS Decimal(6, 0)), N'32             ', N'Dispone de resultados analíticos de los productos finales y los mismos no contienen aditivos/aromas por encima de la Dosis Máxima permitida, o en caso de superarla la empresa ha tomado las medidas necesarias para eliminar el riesgo.', N'Solamente podrán utilizarse los aprobados para estos productos  en las lista positiva de aditivos y aromas y respetando las dosis máximas establecidas para cada uno de ellos.', N' ', N'Solamente podrán utilizarse los aprobados para estos productos  en las lista positiva de aditivos y aromas y respetando las dosis máximas establecidas para cada uno de ellos.')
GO
