INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1044 AS Decimal(6, 0)), N'58             ', N'La conducción del agua destinada a ser envasada está se¦alizada de forma continua con una banda blanca y con flechas indicadoras de la dirección de circulación del líquido.', N'Toda la conducción del agua destinada a ser envasada deberá ser inspeccionable, quedando se¦alizada de forma continua con una banda blanca y con flechas indicadoras de la dirección de circulación del líquido. ', N' ', N'Toda la conducción del agua destinada a ser envasada deberá ser inspeccionable, quedando se¦alizada de forma continua con una banda blanca y con flechas indicadoras de la dirección de circulación del líquido. ')
