INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1045 AS Decimal(6, 0)), N'58             ', N'El circuito de conducción de agua destinada a ser envasada, y especialmente los depósitos y máquinas de llenado, tienen dispositivos que permiten una eficaz limpieza y esterilización periódica, mediante vapor de agua o productos microbicidas autorizados p????', N'Todo circuito de conducción de agua destinada a ser envasada, y especialmente los depósitos y máquinas de llenado, tendrán dispositivos que permitan una eficaz limpieza y esterilización periódica, mediante vapor de agua o productos microbicidas autorizados para su empleo en este tipo de industrias.', N' ', N'Todo circuito de conducción de agua destinada a ser envasada, y especialmente los depósitos y máquinas de llenado, tendrán dispositivos que permitan una eficaz limpieza y esterilización periódica, mediante vapor de agua o productos microbicidas autorizados para su empleo en este tipo de industrias.')
