INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1052 AS Decimal(6, 0)), N'38             ', N'En las fases consideradas, incluido el transporte, las aguas objeto de esta Reglamentación únicamente se comercializan en envases destinados para su distribución al consumidor final, debidamente etiquetados y cerrados.', N'En las fases consideradas, incluido el transporte, las aguas objeto de esta Reglamentación únicamente podrán comercializarse en envases destinados para su distribución al consumidor final, debidamente etiquetados y cerrados.', N' ', N'En las fases consideradas, incluido el transporte, las aguas objeto de esta Reglamentación únicamente podrán comercializarse en envases destinados para su distribución al consumidor final, debidamente etiquetados y cerrados.')
