INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1001 AS Decimal(6, 0)), N'39             ', N'Todos los envases en cada envío de moluscos bivalvos vivos llevan una marca sanitaria que contiene toda la información obligatoria: (País expedidor, Especie de moluscos bivalvos ( nombre común y nombre científico), Identificación del centro de expedición ????', N'Todos los envases en cada envío de moluscos bivalvos vivos llevarán una marca sanitaria que deberá contener los siguientes datos:
País expedidor
Especie de moluscos bivalvos ( nombre común y nombre científico)
Identificación del centro de expedición mediante el número de Registro General Sanitario de Alimentos
Fecha de envasado, que incluirá como mínimo el día y el mes
La fecha de caducidad podrá ser sustituida por la mención ?estos animales deben de estar vivos en el momento de la compra?
La marca sanitaria podrá estar impresa en el envase, en una etiqueta separada, fijada a éste o en su interior. También podrá estar fijada por presión o grapada; sólo podrán utilizarse marcas autoadhesivas que no puedan quitarse. Cada modelo de la marca sanitaria sólo podrá ser utilizado una vez y no será transferible.
La marca sanitaria deberá ser resistente e impermeable, y las informaciones que incluya serán legibles, indelebles y estarán escritas con caracteres claros.', N' ', N'Todos los envases en cada envío de moluscos bivalvos vivos llevarán una marca sanitaria que deberá contener los siguientes datos:
País expedidor
Especie de moluscos bivalvos ( nombre común y nombre científico)
Identificación del centro de expedición mediante el número de Registro General Sanitario de Alimentos
Fecha de envasado, que incluirá como mínimo el día y el mes
La fecha de caducidad podrá ser sustituida por la mención ?estos animales deben de estar vivos en el momento de la compra?
La marca sanitaria podrá estar impresa en el envase, en una etiqueta separada, fijada a éste o en su interior. También podrá estar fijada por presión o grapada; sólo podrán utilizarse marcas autoadhesivas que no puedan quitarse. Cada modelo de la marca sanitaria sólo podrá ser utilizado una vez y no será transferible.
La marca sanitaria deberá ser resistente e impermeable, y las informaciones que incluya serán legibles, indelebles y estarán escritas con caracteres claros.')
GO
