INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1219 AS Decimal(6, 0)), N'12             ', N'Sistema de accionamiento de los lavamanos o lavamanos fregadero es a pedal, rodilla o cédula fotoeléctrica.', N'Fregadero, lavamanos  diferente al del aseo
Los establecimientos contaran al menos con un lavamanos y fregadero para limpieza de utensilios. O en su defecto lavamanos-fregadero conjunto de accionamiento no manual ubicado preferentemente en la trastienda cuando exista.
Cuando realicen fraccionado o loncheado próximo a esa zona se ubicara un lavamanos. Este lavamanos puede  ser sustituido por el lavamanos-fregadero de accionamiento no manual cuando no se disponga de almacén o trastienda o no sea posible ubicar el fregadero en otro lugar.', N' ', N'Fregadero, lavamanos  diferente al del aseo
Los establecimientos contaran al menos con un lavamanos y fregadero para limpieza de utensilios. O en su defecto lavamanos-fregadero conjunto de accionamiento no manual ubicado preferentemente en la trastienda cuando exista.
Cuando realicen fraccionado o loncheado próximo a esa zona se ubicara un lavamanos. Este lavamanos puede  ser sustituido por el lavamanos-fregadero de accionamiento no manual cuando no se disponga de almacén o trastienda o no sea posible ubicar el fregadero en otro lugar.')
GO
