INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1212 AS Decimal(6, 0)), N'39             ', N'Los productos pesqueros están etiquetados de origen con la siguiente información: -País de origen, Categoría de calibre, Categoría de frescura y fecha en que se determina, Peso neto ( para envasados), Nombre científico y comercial de la especie, Forma de ????', N'El pescado fresco, refrigerado o cocido, debe venir etiquetado en el envase o embalaje desde su primera puesta en venta o en aquellas especies que por su tama¦o u otras razones físicas se expongan para la primera venta sin embalaje ni envasado, las indicaciones aparecerán en el documento de acompa¦amiento comercial. El contenido de estas indicaciones debe de ser el siguiente:
País de origen
Categoría de calibre
Categoría de frescura y fecha en que se determina
Peso neto ( para envasados)
Nombre científico y comercial de la especie
Forma de obtención
Modo de presentación y tratamiento
Expedidor, número de autorización oficial y domicilio
La primera categoría de frescura y fecha serán las que correspondan en el momento de su primera venta. En caso de que durante el circuito comercial, se modifiquen o se alteren las condiciones de frescura, en la etiqueta, en cada momento, se hará constar, por el tenedor del producto, que será responsable de su clasificación, la nueva categoría de frescura y fecha en que ésta se determine
El contenido del etiquetado ha de servir de información en la venta al consumidor final, pero en el caso de que la etiqueta no sea plenamente visible será expuesto en los lugares de venta en una tablilla o cartel de tal forma que éste pueda identificar las características del producto, conteniendo, como mínimo, las siguientes especificaciones: país de origen, calibre, frescura, nombre comercial, forma de obtención y modo de presentación y tratamiento
Los productos que se envasen por los titulares del comercio minorista y se presenten de esta forma el mismo día del envasado para su venta inmediata deberán cumplir con las condiciones de etiqueta mencionada anteriormente.', N' ', N'El pescado fresco, refrigerado o cocido, debe venir etiquetado en el envase o embalaje desde su primera puesta en venta o en aquellas especies que por su tama¦o u otras razones físicas se expongan para la primera venta sin embalaje ni envasado, las indicaciones aparecerán en el documento de acompa¦amiento comercial. El contenido de estas indicaciones debe de ser el siguiente:
País de origen
Categoría de calibre
Categoría de frescura y fecha en que se determina
Peso neto ( para envasados)
Nombre científico y comercial de la especie
Forma de obtención
Modo de presentación y tratamiento
Expedidor, número de autorización oficial y domicilio
La primera categoría de frescura y fecha serán las que correspondan en el momento de su primera venta. En caso de que durante el circuito comercial, se modifiquen o se alteren las condiciones de frescura, en la etiqueta, en cada momento, se hará constar, por el tenedor del producto, que será responsable de su clasificación, la nueva categoría de frescura y fecha en que ésta se determine
El contenido del etiquetado ha de servir de información en la venta al consumidor final, pero en el caso de que la etiqueta no sea plenamente visible será expuesto en los lugares de venta en una tablilla o cartel de tal forma que éste pueda identificar las características del producto, conteniendo, como mínimo, las siguientes especificaciones: país de origen, calibre, frescura, nombre comercial, forma de obtención y modo de presentación y tratamiento
Los productos que se envasen por los titulares del comercio minorista y se presenten de esta forma el mismo día del envasado para su venta inmediata deberán cumplir con las condiciones de etiqueta mencionada anteriormente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1246 AS Decimal(6, 0)), N'32             ', N'Las carnes frescas de aves y sus despojos se almacenan en refrigeración a temperaturas internas iguales o inferiores a +4ºC. Las carnes y despojos congelados se almacenan a una Tª  igual o inferior a -12ºC.', N'Durante el almacenamiento en refrigeración, las carnes frescas de aves de corral y sus despojos deben mantenerse a temperaturas internas iguales o inferiores a +4ºC.
 Las carnes de aves y sus despojos congelados se almacenarán a una Tª igual o inferior a -12ºC.
', N' ', N'Durante el almacenamiento en refrigeración, las carnes frescas de aves de corral y sus despojos deben mantenerse a temperaturas internas iguales o inferiores a +4ºC.
 Las carnes de aves y sus despojos congelados se almacenarán a una Tª igual o inferior a -12ºC.
')
