INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1210 AS Decimal(6, 0)), N'32             ', N'Los crustáceos que deben comercializarse en vivo llegan en este estado hasta su venta al consumidor.', N'Los crustáceos que deben comercializarse en vivo deberán llegar en este estado hasta su venta al consumidor.', N' ', N'Los crustáceos que deben comercializarse en vivo deberán llegar en este estado hasta su venta al consumidor.')
