INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1079 AS Decimal(6, 0)), N'3              ', N'Dispone de cocina suficientemente aislada.', N'Recinto de cocina.
Los establecimientos deben disponer de recinto de cocina. Este local ha de estar aislado de cualquier otro ajeno a éste fin. Pueden permitirse ventanas de servicio o aperturas para facilitar la distribución de la actividad, siempre que la ventilación sea correcta y no se realicen operaciones que puedan contaminar los alimentos. También son válidas las cortinas de aire, siempre y cuando sean efectivas.
', N' ', N'Recinto de cocina.
Los establecimientos deben disponer de recinto de cocina. Este local ha de estar aislado de cualquier otro ajeno a éste fin. Pueden permitirse ventanas de servicio o aperturas para facilitar la distribución de la actividad, siempre que la ventilación sea correcta y no se realicen operaciones que puedan contaminar los alimentos. También son válidas las cortinas de aire, siempre y cuando sean efectivas.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1081 AS Decimal(6, 0)), N'3              ', N'Dispone de zonas o superficies de trabajo diferenciadas para manipular los diferentes tipos de materias primas (carne, pescado y verdura).', N'Separación de zonas de preparación según producto.
Los establecimientos deben disponer de zonas o superficies de trabajo diferenciadas para manipular los diferentes tipos de materias primas (carne, pescado y verdura) de forma que se eviten contaminaciones cruzadas entre las mismas.

', N' ', N'Separación de zonas de preparación según producto.
Los establecimientos deben disponer de zonas o superficies de trabajo diferenciadas para manipular los diferentes tipos de materias primas (carne, pescado y verdura) de forma que se eviten contaminaciones cruzadas entre las mismas.

')
GO
