INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1125 AS Decimal(6, 0)), N'3              ', N'Dispone de dispositivo/local de almacén o despensa.', N'Deben disponer de un almacén o despensa para el almacenamiento de productos que no requieran temperaturas de refrigeración para su conservación, perfectamente aislado y separado del resto de dependencias.
Si las actividades que realiza el establecimiento no requieren de almacén, existirá un dispositivo (armario o similar) de almacenamiento.
', N' ', N'Deben disponer de un almacén o despensa para el almacenamiento de productos que no requieran temperaturas de refrigeración para su conservación, perfectamente aislado y separado del resto de dependencias.
