INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1108 AS Decimal(6, 0)), N'3              ', N'Dispone de zonas o superficies de trabajo diferenciadas para la manipulación de materias primas y productos higienizados o listos para consumo.', N'Separación de zona limpia y zona sucia.
Los establecimientos deben disponer de zonas o superficies de trabajo diferenciadas para la manipulación de materias primas (zona sucia) y productos higienizados (zona limpia: manipulación de alimentos tras el  tratamiento térmico y/o listos para consumo) de forma que se eviten contaminaciones cruzadas entre las mismas.
', N' ', N'Separación de zona limpia y zona sucia.
Los establecimientos deben disponer de zonas o superficies de trabajo diferenciadas para la manipulación de materias primas (zona sucia) y productos higienizados (zona limpia: manipulación de alimentos tras el  tratamiento térmico y/o listos para consumo) de forma que se eviten contaminaciones cruzadas entre las mismas.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1117 AS Decimal(6, 0)), N'17             ', N'Dispone de zona de vestuario exclusiva para el personal manipulador (no procede si se preparan menos de 300 comidas/día).', N'Los comedores institucionales con elaboración deben disponer de vestuarios exclusivos para el personal manipulador. No obstante, se admitirá que sean compartidos con otro personal si están correctamente dotados , se encuentran cerca de la cocina y el establecimiento elabora un número inferior a 300 comidas/día.', N' ', N'Los comedores institucionales con elaboración deben disponer de vestuarios exclusivos para el personal manipulador. No obstante, se admitirá que sean compartidos con otro personal si están correctamente dotados , se encuentran cerca de la cocina y el establecimiento elabora un número inferior a 300 comidas/día.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2147 AS Decimal(6, 0)), N'76             ', N'El personal encargado de la vigilancia conoce los PCC(s) y su significado', N'El auditor debe comprobar que el personal encargado de realizar las vigilancias conoce perfectamente cuales son los puntos de control crítico de la industria y  la importancia que tienen sus actividades de vigilancia, ya que de esos controles depende el conocer si esas etapas, procesos o puntos, se mantienen dentro de unos parámetros predeterminados, lo que evita la puesta en el mercado de productos no seguros.', N' ', N'El auditor debe comprobar que el personal encargado de realizar las vigilancias conoce perfectamente cuales son los puntos de control crítico de la industria y  la importancia que tienen sus actividades de vigilancia, ya que de esos controles depende el conocer si esas etapas, procesos o puntos, se mantienen dentro de unos parámetros predeterminados, lo que evita la puesta en el mercado de productos no seguros.')
GO
