INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(933 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona de envasado ( en local de manipulación en frío).', N'Local/ zona envasado.
Se podrá envasar en el local de manipulación en frío siempre que las actividades realizadas en el local de manipulación no supongan ningún riesgo de contaminación cruzada de los productos y no se hayan permitido por el trabajo en continuo actividades como las de descabezado y decapitado o salazón.', N' ', N'Local/ zona envasado.
Se podrá envasar en el local de manipulación en frío siempre que las actividades realizadas en el local de manipulación no supongan ningún riesgo de contaminación cruzada de los productos y no se hayan permitido por el trabajo en continuo actividades como las de descabezado y decapitado o salazón.')
