INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(992 AS Decimal(6, 0)), N'32             ', N'Una vez depurados los moluscos se lavan con abundante agua de mar limpia o agua potable, que no es reciclada.', N'Una vez terminada la depuración, deberán lavarse minuciosamente los moluscos bivalvos con abundante agua limpia, potable o de mar, lo que podrá llevarse a cabo, si fuere necesario, dentro de la piscina de depuración. No se reciclará el agua utilizada.', N' ', N'Una vez terminada la depuración, deberán lavarse minuciosamente los moluscos bivalvos con abundante agua limpia, potable o de mar, lo que podrá llevarse a cabo, si fuere necesario, dentro de la piscina de depuración. No se reciclará el agua utilizada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(993 AS Decimal(6, 0)), N'32             ', N'Los moluscos bivalvos poseen las características visuales propias de la frescura y viabilidad.', N'Los moluscos bivalvos  poseerán las características visuales propias de la frescura y la viabilidad, incluida la ausencia de suciedad en la concha, una reacción a la percusión adecuada y una cantidad normal de líquido ínter valvar.', N' ', N'Los moluscos bivalvos  poseerán las características visuales propias de la frescura y la viabilidad, incluida la ausencia de suciedad en la concha, una reacción a la percusión adecuada y una cantidad normal de líquido ínter valvar.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(991 AS Decimal(6, 0)), N'32             ', N'Durante la depuración en la piscina no habrá crustáceos ni otras especies marinas.', N'Durante la depuración no podrá haber crustáceos, peces ni otras especies marinas en la piscina de depuración al mismo tiempo que moluscos bivalvos.', N' ', N'Durante la depuración no podrá haber crustáceos, peces ni otras especies marinas en la piscina de depuración al mismo tiempo que moluscos bivalvos.')
