INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1006 AS Decimal(6, 0)), N'54             ', N'Se registra las horas de llenado y vaciado de los sistemas de depuración ( duración de la depuración).', N'Los centros de depuración llevarán un registro en el que se anoten con regularidad:
Las horas de llenado y vaciado de los sistemas de depuración ( duración de la depuración)
Estos datos deberán clasificarse cronológicamente y archivarse durante un periodo de tiempo que será al menos de doce meses.', N' ', N'Los centros de depuración llevarán un registro en el que se anoten con regularidad:
Las horas de llenado y vaciado de los sistemas de depuración ( duración de la depuración)
Estos datos deberán clasificarse cronológicamente y archivarse durante un periodo de tiempo que será al menos de doce meses.')
