INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(990 AS Decimal(6, 0)), N'32             ', N'El espesor de las capas apiladas de moluscos no impide la apertura la apertura de las conchas durante el proceso de depuración.', N'El espesor de las capas apiladas de moluscos no deberá impedir la apertura la apertura de las conchas durante el proceso de depuración.', N' ', N'El espesor de las capas apiladas de moluscos no deberá impedir la apertura la apertura de las conchas durante el proceso de depuración.')
