INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(958 AS Decimal(6, 0)), N'32             ', N'Se realizan pruebas diarias de eficacia del engatillado o de cualquier otro método de cierre hermético, mediante cortes transversales de las juntas de los envases cerrados y sus resultados son satisfactorios.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, con el objeto de garantizar la eficacia del engatillado o de cualquier otro método de cierre hermético, se tomarán muestras de la producción diaria a intervalos previamente fijados.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, con el objeto de garantizar la eficacia del engatillado o de cualquier otro método de cierre hermético, se tomarán muestras de la producción diaria a intervalos previamente fijados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(989 AS Decimal(6, 0)), N'32             ', N'Cuando en una piscina de depuración contiene varias especies de moluscos, la duración del tratamiento es la aplicable a la especie que precisa el tiempo de depuración mas prolongado.', N'Cuando en una piscina de depuración contenga varias especies de moluscos, la duración del tratamiento será la aplicable a la especie que precise el tiempo de depuración mas prolongado.', N' ', N'Cuando en una piscina de depuración contenga varias especies de moluscos, la duración del tratamiento será la aplicable a la especie que precise el tiempo de depuración mas prolongado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(987 AS Decimal(6, 0)), N'32             ', N'El tiempo de los moluscos bivalvos en depuración se valida por zonas de clasificación mediante análisis periódicos de los moluscos antes de introducirse en la piscina de depuración y una vez pasado el tiempo considerado suficiente para esta depuración.', N'El tiempo de los moluscos bivalvos en depuración dependerá de la carga microbiana de los moluscos de origen. Por tanto deberá validarse el tiempo de depuración por zonas de clasificación mediante análisis periódicos de los moluscos antes de introducirse en la piscina de depuración y una vez pasado el tiempo considerado suficiente para esta depuración.', N' ', N'El tiempo de los moluscos bivalvos en depuración dependerá de la carga microbiana de los moluscos de origen. Por tanto deberá validarse el tiempo de depuración por zonas de clasificación mediante análisis periódicos de los moluscos antes de introducirse en la piscina de depuración y una vez pasado el tiempo considerado suficiente para esta depuración.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(996 AS Decimal(6, 0)), N'32             ', N'Las industrias realizan análisis microbiológicos periódicos del agua una vez tratada.', N'El agua tratada se somete a análisis microbiológicos periódicos que garantizan que reúne las siguientes condiciones:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli
Salmonella: ausencia ', N' ', N'El agua tratada se somete a análisis microbiológicos periódicos que garantizan que reúne las siguientes condiciones:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli
Salmonella: ausencia ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(981 AS Decimal(6, 0)), N'10             ', N'Cuando se trata de un circuito cerrado, dispone de sistema de filtrado previo del agua, que está dotado con válvula de retroflujo que permite su limpieza y evita el apelmazamiento de las capas filtrantes.', N'Cuando se trate de un circuito cerrado, dispondrá de sistema de filtrado previo del agua, que estará dotado con válvula de retroflujo que permitirá su limpieza y evitará el apelmazamiento de las capas filtrantes.', N' ', N'Cuando se trate de un circuito cerrado, dispondrá de sistema de filtrado previo del agua, que estará dotado con válvula de retroflujo que permitirá su limpieza y evitará el apelmazamiento de las capas filtrantes.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(994 AS Decimal(6, 0)), N'32             ', N'Las industrias realizan análisis microbiológicos periódicos de los moluscos bivalvos una vez depurados.', N'Los moluscos bivalvos una vez depurados serán sometidos a análisis microbiológicos periódicos  suficientes que garanticen que los productos que comercializan no sobrepasan los siguientes valores:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli por cada 100gr de carne de molusco y líquido intervalvar en una prueba NMP ( NPP), en la que se utilicen cinco tubos y tres diluciones o en cualquier otro método de análisis bacteriológico de precisión equivalente demostrada.
Salmonella: ausencia en 25gr de carne de molusco
PSP ( toxina paralizante de los moluscos): 80 microgramos por 100gr en las partes comestibles de los moluscos, según el método de análisis biológico, al que puede asociarse un método químico de detección de saxitoxina o cualquier otro reconocido por la normativa comunitaria. En caso de discrepancia sobre los resultados, el método de referencia deberá ser el biológico
DSP( toxina diarreica de los moluscos): No debe de dar reacción positiva respecto a est toxina en las partes comestibles de los moluscos.
El agua una vez depurada será sometida a análisis microbiológicos periódicos  suficientes que garanticen que el sistema empleado para la depuración es adecuado
ASP ( toxina amnésica de los moluscos): No deberá sobrepasar los 20 microgramos de ácido domoico por gramo
A falta de métodos habituales de detección de virus y de normas virológicas, el control sanitario se basará en el recuento de bacterias fecales.', N' ', N'Los moluscos bivalvos una vez depurados serán sometidos a análisis microbiológicos periódicos  suficientes que garanticen que los productos que comercializan no sobrepasan los siguientes valores:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli por cada 100gr de carne de molusco y líquido intervalvar en una prueba NMP ( NPP), en la que se utilicen cinco tubos y tres diluciones o en cualquier otro método de análisis bacteriológico de precisión equivalente demostrada.
Salmonella: ausencia en 25gr de carne de molusco
PSP ( toxina paralizante de los moluscos): 80 microgramos por 100gr en las partes comestibles de los moluscos, según el método de análisis biológico, al que puede asociarse un método químico de detección de saxitoxina o cualquier otro reconocido por la normativa comunitaria. En caso de discrepancia sobre los resultados, el método de referencia deberá ser el biológico
DSP( toxina diarreica de los moluscos): No debe de dar reacción positiva respecto a est toxina en las partes comestibles de los moluscos.
El agua una vez depurada será sometida a análisis microbiológicos periódicos  suficientes que garanticen que el sistema empleado para la depuración es adecuado
ASP ( toxina amnésica de los moluscos): No deberá sobrepasar los 20 microgramos de ácido domoico por gramo
A falta de métodos habituales de detección de virus y de normas virológicas, el control sanitario se basará en el recuento de bacterias fecales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(995 AS Decimal(6, 0)), N'32             ', N'Los resultados analíticos se encuentran dentro de los valores aceptables y en su defecto se han adoptado las medidas necesarias para evitar que su comercialización suponga un riesgo para la salud pública.. ', N'Los moluscos bivalvos una vez depurados serán sometidos a análisis microbiológicos periódicos  suficientes que garanticen que los productos que comercializan no sobrepasan los siguientes valores:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli por cada 100gr de carne de molusco y líquido intervalvar en una prueba NMP ( NPP), en la que se utilicen cinco tubos y tres diluciones o en cualquier otro método de análisis bacteriológico de precisión equivalente demostrada.
Salmonella: ausencia en 25gr de carne de molusco
PSP ( toxina paralizante de los moluscos): 80 microgramos por 100gr en las partes comestibles de los moluscos, según el método de análisis biológico, al que puede asociarse un método químico de detección de saxitoxina o cualquier otro reconocido por la normativa comunitaria. En caso de discrepancia sobre los resultados, el método de referencia deberá ser el biológico
DSP( toxina diarreica de los moluscos): No debe de dar reacción positiva respecto a est toxina en las partes comestibles de los moluscos.
El agua una vez depurada será sometida a análisis microbiológicos periódicos  suficientes que garanticen que el sistema empleado para la depuración es adecuado
ASP ( toxina amnésica de los moluscos): No deberá sobrepasar los 20 microgramos de ácido domoico por gramo
A falta de métodos habituales de detección de virus y de normas virológicas, el control sanitario se basará en el recuento de bacterias fecales.', N' ', N'Los moluscos bivalvos una vez depurados serán sometidos a análisis microbiológicos periódicos  suficientes que garanticen que los productos que comercializan no sobrepasan los siguientes valores:
Coliformes fecales /E.coli: menor que 300coliformes fecales o menos de 230 E.coli por cada 100gr de carne de molusco y líquido intervalvar en una prueba NMP ( NPP), en la que se utilicen cinco tubos y tres diluciones o en cualquier otro método de análisis bacteriológico de precisión equivalente demostrada.
Salmonella: ausencia en 25gr de carne de molusco
PSP ( toxina paralizante de los moluscos): 80 microgramos por 100gr en las partes comestibles de los moluscos, según el método de análisis biológico, al que puede asociarse un método químico de detección de saxitoxina o cualquier otro reconocido por la normativa comunitaria. En caso de discrepancia sobre los resultados, el método de referencia deberá ser el biológico
DSP( toxina diarreica de los moluscos): No debe de dar reacción positiva respecto a est toxina en las partes comestibles de los moluscos.
El agua una vez depurada será sometida a análisis microbiológicos periódicos  suficientes que garanticen que el sistema empleado para la depuración es adecuado
ASP ( toxina amnésica de los moluscos): No deberá sobrepasar los 20 microgramos de ácido domoico por gramo
A falta de métodos habituales de detección de virus y de normas virológicas, el control sanitario se basará en el recuento de bacterias fecales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1005 AS Decimal(6, 0)), N'54             ', N'Se registra la fecha y cantidad de moluscos bivalvos vivos entregados al centro de depuración y el número de los documentos de registro correspondiente.', N'Los centros de depuración llevarán un registro en el que se anoten con regularidad:
La fecha y cantidad de moluscos bivalvos vivos entregados al centro de depuración y el número de los documentos de registro correspondiente
Estos datos deberán clasificarse cronológicamente y archivarse durante un periodo de tiempo que será al menos de doce meses.', N' ', N'Los centros de depuración llevarán un registro en el que se anoten con regularidad:
La fecha y cantidad de moluscos bivalvos vivos entregados al centro de depuración y el número de los documentos de registro correspondiente
Estos datos deberán clasificarse cronológicamente y archivarse durante un periodo de tiempo que será al menos de doce meses.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(985 AS Decimal(6, 0)), N'32             ', N'El sistema de depuración permite que los moluscos reanuden rápidamente su alimentación por filtración y que queden limpios de residuos contaminantes, no vuelvan a contaminarse, y se mantengan con vida en condiciones adecuadas para el envasado, almacenamie????', N'El sistema de depuración deberá permitir que los moluscos reanuden rápidamente su alimentación por filtración y que queden limpios de residuos contaminantes, no vuelvan a contaminarse, y se mantengan con vida en condiciones adecuadas para el envasado, almacenamiento y transporte que precedan a su comercialización.', N' ', N'El sistema de depuración deberá permitir que los moluscos reanuden rápidamente su alimentación por filtración y que queden limpios de residuos contaminantes, no vuelvan a contaminarse, y se mantengan con vida en condiciones adecuadas para el envasado, almacenamiento y transporte que precedan a su comercialización.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(986 AS Decimal(6, 0)), N'32             ', N'El sistema de depuración del agua de mar es suficiente y su eficacia está validada. ', N'El sistema de depuración del agua de mar es suficiente y su eficacia está validada. Es decir, antes de su puesta en marcha deberán realizarse análisis microbiológicos que aseguren que el sistema es capaz de eliminar los microorganismos del agua una vez tratada.', N' ', N'El sistema de depuración del agua de mar es suficiente y su eficacia está validada. Es decir, antes de su puesta en marcha deberán realizarse análisis microbiológicos que aseguren que el sistema es capaz de eliminar los microorganismos del agua una vez tratada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(963 AS Decimal(6, 0)), N'32             ', N'Se controla y registra la temperatura y tiempo de ahumado para aquellos productos tratados por el humo.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio del ahumado, deberá controlarse la temperatura y tiempo sometidos a la acción del humo.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio del ahumado, deberá controlarse la temperatura y tiempo sometidos a la acción del humo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(980 AS Decimal(6, 0)), N'10             ', N'Las piscinas reciben una cantidad de agua de mar limpia y tienen una capacidad de desagüe suficiente para el volumen de productos que se someta a depuración.', N'Dispondrá de un sistema de depuración que permita que los moluscos bivalvos vuelvan rápidamente a alimentarse por filtración, eliminen los microorganismos contaminantes, no vuelvan a contaminarse y se mantengan con vida. Las piscinas dispondrán de un equipo de renovación de agua de mar limpia que les permita recibir una cantidad de agua suficiente por hora y por tonelada de moluscos bivalvos vivos tratados.', N' ', N'Dispondrá de un sistema de depuración que permita que los moluscos bivalvos vuelvan rápidamente a alimentarse por filtración, eliminen los microorganismos contaminantes, no vuelvan a contaminarse y se mantengan con vida. Las piscinas dispondrán de un equipo de renovación de agua de mar limpia que les permita recibir una cantidad de agua suficiente por hora y por tonelada de moluscos bivalvos vivos tratados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(988 AS Decimal(6, 0)), N'32             ', N'Las partidas se depositan en las piscinas separadas por lotes sin mezclar animales de procedencias de distinta clasificación.', N'Se depositarán siempre las partidas separadas en lotes sin mezclar en la misma piscina animales de procedencias de distinta clasificación.', N' ', N'Se depositarán siempre las partidas separadas en lotes sin mezclar en la misma piscina animales de procedencias de distinta clasificación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(964 AS Decimal(6, 0)), N'32             ', N'Para la producción de humo no se utiliza madera pintada, barnizada, encolada o que haya sufrido un tratamiento químico para su conservación.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio del ahumado, en la producción de humo por combustión no se podrá utilizar madera pintada, barnizada, encolada o que haya sufrido un tratamiento químico para su conservación (alquitrán, etc.).', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio del ahumado, en la producción de humo por combustión no se podrá utilizar madera pintada, barnizada, encolada o que haya sufrido un tratamiento químico para su conservación (alquitrán, etc.).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(965 AS Decimal(6, 0)), N'32             ', N'Los productos pesqueros que han sido sometidos extrusión mecánica el producto se congela rápidamente, se incorpora a un producto destinado a la congelación o a un tratamiento estabilizador.', N'Cuando un producto pesquero ha sido sometido a un proceso de extrusión mecánica, el producto obtenido se congela rápidamente, se incorpora a un producto destinado a la congelación o a un tratamiento estabilizador.', N' ', N'Cuando un producto pesquero ha sido sometido a un proceso de extrusión mecánica, el producto obtenido se congela rápidamente, se incorpora a un producto destinado a la congelación o a un tratamiento estabilizador.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(966 AS Decimal(6, 0)), N'38             ', N'Los recipientes utilizados para ENVASAR, DESPACHAR O ALMACENAR productos pesqueros frescos permitan evacuar con facilidad el agua de fusión.', N'Los recipientes utilizados para envasar, despachar o almacenar productos pesqueros frescos deben permitir que se evacue el agua de fusión con facilidad. ', N' ', N'Los recipientes utilizados para envasar, despachar o almacenar productos pesqueros frescos deben permitir que se evacue el agua de fusión con facilidad. ')
