INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(961 AS Decimal(6, 0)), N'32             ', N'Se controla y registra el PH alcanzado en aquellos productos sometidos a tratamiento de acidificación.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la acidificación del producto, es decir, la bajada del PH, deberá controlarse y anotarse el PH final alcanzado.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la acidificación del producto, es decir, la bajada del PH, deberá controlarse y anotarse el PH final alcanzado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(962 AS Decimal(6, 0)), N'32             ', N'Se controla y registra la AW final alcanzada en aquellos productos sometidos a desecación.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la disminución de la actividad agua del producto ( desecación), deberá controlarse y registrarse la AW final alcanzada.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la disminución de la actividad agua del producto ( desecación), deberá controlarse y registrarse la AW final alcanzada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(972 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona de almacenamiento y/o depuración con piscinas o tanques adecuados para mantener los moluscos vivos y depurarlos en agua de mar tratada.', N'Local/zona de almacenamiento y/o depuración, con piscinas o tanques adecuados para mantener los moluscos vivos y depurarlos en agua de mar tratada.', N' ', N'Local/zona de almacenamiento y/o depuración, con piscinas o tanques adecuados para mantener los moluscos vivos y depurarlos en agua de mar tratada.')
