INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(925 AS Decimal(6, 0)), N'3              ', N'Dispone de local de descabezado y eviscerado.', N'Local de descabezado y eviscerado.
No podrá alternarse con ninguna otra operación considerada  limpia, a no ser que el proceso de trabajo sea en continuo y se realice en zonas diferentes ( puestos de trabajo diferentes), pudiendo en este caso computarse con el local de fileteado y corte en rodaja y con el de salazón.', N' ', N'Local de descabezado y eviscerado.
No podrá alternarse con ninguna otra operación considerada  limpia, a no ser que el proceso de trabajo sea en continuo y se realice en zonas diferentes ( puestos de trabajo diferentes), pudiendo en este caso computarse con el local de fileteado y corte en rodaja y con el de salazón.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(926 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona (dentro del local de descabezado y eviscerado) para el  fileteado y corte en rodaja. ', N'Local de fileteado y corte en rodaja.
Podrá efectuarse la actividad en el local de descabezado y eviscerado siempre que el proceso de trabajo sea continuo y en zonas diferentes, mediante un sistema mecánico o manual continuo.', N' ', N'Local de fileteado y corte en rodaja.
Podrá efectuarse la actividad en el local de descabezado y eviscerado siempre que el proceso de trabajo sea continuo y en zonas diferentes, mediante un sistema mecánico o manual continuo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(955 AS Decimal(6, 0)), N'32             ', N'Se dispone de un registro del procedimiento del tratamiento térmico de conservación ( esterilización), definido según el tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, dispondrá de un registro del procedimiento definido según criterios teles como tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o in activación de los gérmenes patógenos y todo esporo de microorganismos.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, dispondrá de un registro del procedimiento definido según criterios teles como tiempo de calentamiento, temperatura, tama¦o y tipo de recipiente, llenado y líquido de cobertura. Este procedimiento deberá garantizar la destrucción o in activación de los gérmenes patógenos y todo esporo de microorganismos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(928 AS Decimal(6, 0)), N'3              ', N'Dispone de local de enfriamiento.', N'Local de enfriamiento
Referido a local con sistema que permita la bajada de temperatura de los productos o a un abatidor de temperatura ( cámara de refrigeración).', N' ', N'Local de enfriamiento
Referido a local con sistema que permita la bajada de temperatura de los productos o a un abatidor de temperatura ( cámara de refrigeración).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(765 AS Decimal(6, 0)), N'3              ', N'Dispone de varios locales independientes para los distintos procesos de fabricación y de envasado o estos se realizan de forma continua e higiénica en el mismo local.', N'Local de fabricación y envasado
Dispondrá de uno o varios locales, independientes y suficientemente amplios, para los distintos procesos de fabricación y el envasado de los productos cárnicos. No obstante distintas operaciones podrán efectuarse en el mismo local, cuando éste tenga un dise¦o y dimensiones adecuados y el proceso se realice de forma continua e higiénica, quedando exceptuados aquellos que precisen locales específicos recogidos en el punto 12.', N' ', N'Local de fabricación y envasado
Dispondrá de uno o varios locales, independientes y suficientemente amplios, para los distintos procesos de fabricación y el envasado de los productos cárnicos. No obstante distintas operaciones podrán efectuarse en el mismo local, cuando éste tenga un dise¦o y dimensiones adecuados y el proceso se realice de forma continua e higiénica, quedando exceptuados aquellos que precisen locales específicos recogidos en el punto 12.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1014 AS Decimal(6, 0)), N'6              ', N'El agua utilizada en el procesado de los alimentos y en las actividades relacionadas con el mismo así como en la limpieza, es potable según normativa vigente o de agua de mar limpia.', N'El agua utilizada en el procesado de los alimentos y en las actividades relacionadas con el mismo, así como en la limpieza podrá ser
potable, según normativa vigente,
agua de mar limpia (agua de mar o salobre que no presenta contaminación microbiológica, sustancias nocivas y/o plancton marino tóxico en cantidades que puedan alterar la calidad sanitaria de los productos pesqueros).', N' ', N'El agua utilizada en el procesado de los alimentos y en las actividades relacionadas con el mismo, así como en la limpieza podrá ser
potable, según normativa vigente,
agua de mar limpia (agua de mar o salobre que no presenta contaminación microbiológica, sustancias nocivas y/o plancton marino tóxico en cantidades que puedan alterar la calidad sanitaria de los productos pesqueros).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(960 AS Decimal(6, 0)), N'32             ', N'Las sal utilizada en el salazón no es reutilizada.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la adicción de sal, está no podrá ser reutilizada.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la adicción de sal, está no podrá ser reutilizada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(953 AS Decimal(6, 0)), N'32             ', N'Los resultados de los análisis microbiológicos son de acordes a la norma.', N'Los productos pesqueros serán sometidos a análisis microbiológicos periódicos suficientes que garanticen que los productos que comercializan no sobrepasan los siguientes valores:
1-Productos de la pesca frescos, salpresados, refrigerados y congelados:
-Rto aerobios mesó filos: (31ºC+-1ºC): max 1x 106/g
-Enterobacteriacea totales: max. 1x103
-Salmonella ? Shigella: aus/25gr
2-Productos seco-salados, salazones y desecados
-Rto de colonias aerobias mesó filas (31ºC+-1ºC): Max 1x106/g
-Enterobacteriaceae totales: Max 1x103/g
-Salmonella-Shigella. AUS/25g
3-Productos cocidos
-Recuento de colonias aerobias mesó filas (31ºC+-1ºC): Max 1x105/g
-Enterobacteriaceae totales: Max 1x103/g
-Salmonella-Shigella. AUS/25g
.Staphylococcus aureus enterotoxigénico: Max 1x102/g
4- Semiconservas en vinagre
-Recuento de colonias aerobias mesó filas (31ºC+-1ºC): Max 1x103/g
-Enterobacteriaceae totales: Max 1x102/g
-Salmonella-Shigella. AUS/25g
5-Anchoas en aceite. Este tipo de productos se someterá a preincubación durante 10 días a 17ºC
-Recuento de colonias aerobias mesó filas (31ºC+-1ºC): Max 1x105/g
-Recuento de anaerobios: Max 1x104/g
-Enterobacteriaceae totales: AUS/g
-Salmonella-Shigella. AUS/25g
-Staphylococcus aureus enterotoxigénico: AUS/g
-Toxina de Clostridium botulinum: AUS
6-Productos Ahumados
a- Para envases metálicos, este tipo de productos se someterá a preincubación durante diez días a 17ºC
b- Para envases empaquetados al vacío, este tipo de productos se someterá a preincubación durante tres días a 17ºC
c- Límites:
A)Como norma general
Rto.colonias aerobias mesó filas (31ºC+-1ºC): n -- 5; c -- 3; m -- 1x10 5/g; M -- 1x10 6/g
Enterobacteriaceae totales: n -- 5; c -- 3; m -- 1x10 2/g; M -- 1x10 3/g
Salmonella-Shigella: n -- 5; c -- 0; m -- AUS/255g; M -- 0
