INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(956 AS Decimal(6, 0)), N'32             ', N'Se llevan a cabo pruebas de incubación de los productos sometidos a tratamiento térmico y sus resultados están dentro de la norma.', N'Con el fin de comprobar que los productos transformados han sido efectivamente sometidos a un tratamiento adecuado se llevarán a cabo controles por muestreo mediante Pªs de incubación: Incubación a 37ºC/7d o 35ºC/10d o combinación equivalente validada y exámenes microbiológicos del contenido y de los envases cuyo contenido estará dentro de los valores mencionados en el apartado de criterios microbiológicos de los productos pesqueros.', N' ', N'Con el fin de comprobar que los productos transformados han sido efectivamente sometidos a un tratamiento adecuado se llevarán a cabo controles por muestreo mediante Pªs de incubación: Incubación a 37ºC/7d o 35ºC/10d o combinación equivalente validada y exámenes microbiológicos del contenido y de los envases cuyo contenido estará dentro de los valores mencionados en el apartado de criterios microbiológicos de los productos pesqueros.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(957 AS Decimal(6, 0)), N'32             ', N'Se controlan y registran cada uno de los tratamientos térmicos aplicados.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, cada uno de esos tratamientos deberá controlarse y registrarse.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de un tratamiento térmico, cada uno de esos tratamientos deberá controlarse y registrarse.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(983 AS Decimal(6, 0)), N'32             ', N'Sólo se admitirán aquellos moluscos procedentes de zonas autorizadas y clasificadas  A, B,  por la autoridad competente.', N'Sólo se admitirán aquellos moluscos procedentes de zonas autorizadas y clasificadas  A, B  por la autoridad competente. Los procedentes de zonas de clase C, sólo podrán ir al consumo después de su reinstalación durante un período prolongado.
Zonas tipo A: En dichas zonas, los moluscos bivalvos vivos tendrán menos de 300 coliformes fecales o menos de 230 E. Coli por cada 100 gramos de carne de molusco y líquido ínter valvar. Los moluscos bivalvos extraídos de dichas zonas podrán ser destinados al consumo humano directo
Zonas tipo B: Los moluscos bivalvos vivos en estas zonas presentarán un índice igual o inferior a 6000 coliformes fecales por cada 100 gramos de carne o 4600 E. coli por cada 100 gramos de carne en el 90% de las muestras. Los moluscos bivalvos extraídos de estas zonas se destinarán al mercado y al consumo humano tras someterse a un tratamiento en un centro de depuración o tras su reinstalación
Zonas tipo C: Los moluscos bivalvos vivos destinados al mercado únicamente tras su reinstalación durante un largo periodo de tiempo (mínimo 2 meses), asociada o no a una depuración o después de una depuración intensiva, y tendrán un índice inferior de 60000 coliformes fecales por cada 100 gramos de carne.', N' ', N'Sólo se admitirán aquellos moluscos procedentes de zonas autorizadas y clasificadas  A, B  por la autoridad competente. Los procedentes de zonas de clase C, sólo podrán ir al consumo después de su reinstalación durante un período prolongado.
Zonas tipo A: En dichas zonas, los moluscos bivalvos vivos tendrán menos de 300 coliformes fecales o menos de 230 E. Coli por cada 100 gramos de carne de molusco y líquido ínter valvar. Los moluscos bivalvos extraídos de dichas zonas podrán ser destinados al consumo humano directo
Zonas tipo B: Los moluscos bivalvos vivos en estas zonas presentarán un índice igual o inferior a 6000 coliformes fecales por cada 100 gramos de carne o 4600 E. coli por cada 100 gramos de carne en el 90% de las muestras. Los moluscos bivalvos extraídos de estas zonas se destinarán al mercado y al consumo humano tras someterse a un tratamiento en un centro de depuración o tras su reinstalación
Zonas tipo C: Los moluscos bivalvos vivos destinados al mercado únicamente tras su reinstalación durante un largo periodo de tiempo (mínimo 2 meses), asociada o no a una depuración o después de una depuración intensiva, y tendrán un índice inferior de 60000 coliformes fecales por cada 100 gramos de carne.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(959 AS Decimal(6, 0)), N'32             ', N'Se controla y registra la concentración de sal adicionada.', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la adicción de sal deberá controlarse y registrarse la concentración de sal empleada, con el fin de verificar la homogeneidad y consistencia del proceso.', N' ', N'Cuando los productos pesqueros hayan sido sometidos a un proceso de conservación por medio de la adicción de sal deberá controlarse y registrarse la concentración de sal empleada, con el fin de verificar la homogeneidad y consistencia del proceso.')
GO
