INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(984 AS Decimal(6, 0)), N'32             ', N'Antes de la depuración los moluscos bivalvos son lavados con agua de mar limpia o con agua potable.', N'Antes de su depuración, los moluscos bivalvos vivos serán lavados con agua de mar limpia a presión o con agua potable a fin de quitarles el barro. Este lavado también podrá realizarse en las piscinas de depuración siempre que se dejen abiertos los desagües durante todo el lavado inicial y siempre que se deje, entre las dos operaciones, el tiempo suficiente para que las piscinas estén limpias.', N' ', N'Antes de su depuración, los moluscos bivalvos vivos serán lavados con agua de mar limpia a presión o con agua potable a fin de quitarles el barro. Este lavado también podrá realizarse en las piscinas de depuración siempre que se dejen abiertos los desagües durante todo el lavado inicial y siempre que se deje, entre las dos operaciones, el tiempo suficiente para que las piscinas estén limpias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(781 AS Decimal(6, 0)), N'3              ', N'Si elabora conservas cárnicas, dispone de laboratorio propio o está concertado con laboratorio autorizado para los exámenes microbiológicos.', N'Los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas), además de las condiciones generales y especiales mencionadas en puntos anteriores, dispondrán de:
Dispondrá de laboratorio propio para los examenes microbiológicos de contenido y recipientes o, en su caso, estará concertado con laboratorio autorizado.', N' ', N'Los establecimientos que fabriquen productos pasteurizados o esterilizados contenidos en recipientes herméticamente cerrados (conservas cárnicas), además de las condiciones generales y especiales mencionadas en puntos anteriores, dispondrán de:
Dispondrá de laboratorio propio para los examenes microbiológicos de contenido y recipientes o, en su caso, estará concertado con laboratorio autorizado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(639 AS Decimal(6, 0)), N'10             ', N'Dispone de medios para la limpieza de embalajes si éstos son recuperables.', N'Medios para la limpieza de embalajes, si son recuperables y se realiza dicha actividad en la industria.', N' ', N'Medios para la limpieza de embalajes, si son recuperables y se realiza dicha actividad en la industria.')
