INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(391 AS Decimal(6, 0)), N'30             ', N'Dispone de medios que mantengan las temperaturas internas de las carnes (c.refrigeradas -<+7ºC, despojos -<+3ºC, c. congeladas -< -12ºC. ).', N'Para el transporte de carnes frescas (refrigeradas o congeladas) se dispondrá de medios que mantengan las temperaturas internas de las carnes.
Para carnes refrigeradas y carnes despiezadas de la canal -menor que +7ºC
Para despojos refrigerados estén o no unidas a sus canales -menor que +3ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC', N' ', N'Para el transporte de carnes frescas (refrigeradas o congeladas) se dispondrá de medios que mantengan las temperaturas internas de las carnes.
Para carnes refrigeradas y carnes despiezadas de la canal -menor que +7ºC
Para despojos refrigerados estén o no unidas a sus canales -menor que +3ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC')
GO
