INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(356 AS Decimal(6, 0)), N'51             ', N'El sistema de sujeción facilita que el aturdido sea eficaz.', N'Cuando los animales sean aturdidos por medios mecánicos o eléctricos aplicados a la cabeza el sistema de sujeción permitirá aplicar y hacer funcionar el aparato con facilidad, precisión y durante el tiempo necesario. El instrumental, material de sujeción, equipos e instalaciones deberán ser dise¦ados, construidos, conservados y utilizados de modo que el aturdido o la matanza pueda efectuarse de forma rápida y eficaz. ', N' ', N'Cuando los animales sean aturdidos por medios mecánicos o eléctricos aplicados a la cabeza el sistema de sujeción permitirá aplicar y hacer funcionar el aparato con facilidad, precisión y durante el tiempo necesario. El instrumental, material de sujeción, equipos e instalaciones deberán ser dise¦ados, construidos, conservados y utilizados de modo que el aturdido o la matanza pueda efectuarse de forma rápida y eficaz. ')
GO
