INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(385 AS Decimal(6, 0)), N'3              ', N'Dispone de local específico para operaciones de despiece, deshuesado y envasado, con emplazamientos diferenciados según sea despiece y deshuesado o envasado.', N'Deben disponer de un local específico para las operaciones de despiece, deshuesado y envasado, teniendo en cuenta que al menos el despiece y deshuesado se realizarán en emplazamientos diferentes a los de las operaciones de envasado.', N' ', N'Deben disponer de un local específico para las operaciones de despiece, deshuesado y envasado, teniendo en cuenta que al menos el despiece y deshuesado se realizarán en emplazamientos diferentes a los de las operaciones de envasado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(357 AS Decimal(6, 0)), N'51             ', N'La sujeción respeta las normas de manejo.', N'Manejo:Los animales: se sujetarán de forma adecuada para evitarles en la medida de lo posible todo dolor, sufrimiento, agitación, herida o contusión evitables.
No obstante, en el caso del sacrificio ritual será obligatoria la sujeción de los animales antes del sacrificio mediante un procedimiento mecánico, con el fin de evitar a dichos animales dolores, sufrimientos y excitaciones, así como heridas o contusiones.
Se prohíbe suspender a los animales antes del aturdido, el hecho de bloquear a un animal en un sistema de sujeción no podrá considerarse en modo alguno como una suspensión.
No se atarán las patas de los animales como método de sujección.
Los animales aturdidos o sacrificados por medios mecánicos o eléctricos aplicados a la cabeza, se presentarán en una posición que permita aplicar y hacer funcionar el aparato con facilidad, precisión y durante el tiempo necesario. Queda, no obstante, autorizado el recurso a medios adecuados de restricción de los movimientos de la cabeza en el caso de solípedos y vacunos.
Se prohíbe utilizar los aparatos de aturdido eléctrico para efectuar la sujeción o inmovilización o para obligar a los animales a moverse.', N' ', N'Manejo:Los animales: se sujetarán de forma adecuada para evitarles en la medida de lo posible todo dolor, sufrimiento, agitación, herida o contusión evitables.
No obstante, en el caso del sacrificio ritual será obligatoria la sujeción de los animales antes del sacrificio mediante un procedimiento mecánico, con el fin de evitar a dichos animales dolores, sufrimientos y excitaciones, así como heridas o contusiones.
Se prohíbe suspender a los animales antes del aturdido, el hecho de bloquear a un animal en un sistema de sujeción no podrá considerarse en modo alguno como una suspensión.
No se atarán las patas de los animales como método de sujección.
Los animales aturdidos o sacrificados por medios mecánicos o eléctricos aplicados a la cabeza, se presentarán en una posición que permita aplicar y hacer funcionar el aparato con facilidad, precisión y durante el tiempo necesario. Queda, no obstante, autorizado el recurso a medios adecuados de restricción de los movimientos de la cabeza en el caso de solípedos y vacunos.
Se prohíbe utilizar los aparatos de aturdido eléctrico para efectuar la sujeción o inmovilización o para obligar a los animales a moverse.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1979 AS Decimal(6, 0)), N'3              ', N'Dispone de local o dispositivo para el almacenamiento de envases y embalajes.', N'Debe disponer de un local o dispositivo para el almacenamiento de envases y embalajes, el cual podrá compartirse con el almacén de materias primas envasadas, siempre que ambos, estén suficientemente separados y protegidos de polvo y contaminaciones.', N' ', N'Debe disponer de un local o dispositivo para el almacenamiento de envases y embalajes, el cual podrá compartirse con el almacén de materias primas envasadas, siempre que ambos, estén suficientemente separados y protegidos de polvo y contaminaciones.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1983 AS Decimal(6, 0)), N'3              ', N'Dispone de local / zona de limpieza de útiles y maquinaria.', N'Dispondrá de una zona específica o local para la limpieza de los útiles y la maquinaria de trabajo.

La necesidad de disponer de zona o local estará en función del volumen de producción, la cantidad de útiles y maquinaria a limpiar y la coincidencia o no de las operaciones de elaboración y lavado. En todo caso, en los establecimientos de carácter industrial, dispondrán un local específico para las operaciones de limpieza.
', N' ', N'Dispondrá de una zona específica o local para la limpieza de los útiles y la maquinaria de trabajo.

La necesidad de disponer de zona o local estará en función del volumen de producción, la cantidad de útiles y maquinaria a limpiar y la coincidencia o no de las operaciones de elaboración y lavado. En todo caso, en los establecimientos de carácter industrial, dispondrán un local específico para las operaciones de limpieza.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1984 AS Decimal(6, 0)), N'3              ', N'Dispone de local / zona para el envasado.', N'Los establecimientos que elaboran y envasan productos de pastelería para su comercialización en otros establecimientos y puntos de venta, deben disponer de una zona específica o local de envasado, acorde al volumen de actividad.

Las operaciones de envasado podrán realizarse en la misma zona o local de manipulación de producto elaborado o que no precisa de tratamiento posterior, siempre que el local o zona sea suficientemente amplia y las operaciones de embalado no se realicen en la misma.
', N' ', N'Los establecimientos que elaboran y envasan productos de pastelería para su comercialización en otros establecimientos y puntos de venta, deben disponer de una zona específica o local de envasado, acorde al volumen de actividad.

Las operaciones de envasado podrán realizarse en la misma zona o local de manipulación de producto elaborado o que no precisa de tratamiento posterior, siempre que el local o zona sea suficientemente amplia y las operaciones de embalado no se realicen en la misma.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1985 AS Decimal(6, 0)), N'3              ', N'Dispone de local / zona para el embalado.', N'Los establecimientos de carácter industrial que comercialicen sus productos embalados, deben disponer de un local de embalado específico.

Las operaciones de embalaje podrán realizarse en el mismo local de envasado, siempre que el local sea suficientemente amplio y se diferencien claramente ambas zonas, de modo que permita garantizar la higiene de las operaciones.
', N' ', N'Los establecimientos de carácter industrial que comercialicen sus productos embalados, deben disponer de un local de embalado específico.

Las operaciones de embalaje podrán realizarse en el mismo local de envasado, siempre que el local sea suficientemente amplio y se diferencien claramente ambas zonas, de modo que permita garantizar la higiene de las operaciones.
')
GO
