INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2002 AS Decimal(6, 0)), N'32             ', N'Si el establecimiento elabora con destino a fines específicos hielo con agua del mar, con soluciones de sal o de otros productos, está autorizado.', N'La única materia prima que puede utilizarse en la elaboración del hielo es el del agua potable, química y bacteriológicamente. Sin embargo, para asegurar la conservación del pescado podrá utilizarse agua del mar no contaminada.', N' ', N'La única materia prima que puede utilizarse en la elaboración del hielo es el del agua potable, química y bacteriológicamente. Sin embargo, para asegurar la conservación del pescado podrá utilizarse agua del mar no contaminada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2003 AS Decimal(6, 0)), N'32             ', N'Si el establecimiento elabora hielo con destino a fines específicos con agua de mar, con soluciones de sal o de otros, lo hace con caracteres tales que no pueda confundirse, en ningún caso con hielo alimenticio.', N'La elaboración de hielo con agua de mar, con soluciones de sal, o de otros productos, deberá autorizarse exclusivamente con destino a fines específicos y con caracteres que no puedan confundirse con hielo alimenticio.
', N' ', N'La elaboración de hielo con agua de mar, con soluciones de sal, o de otros productos, deberá autorizarse exclusivamente con destino a fines específicos y con caracteres que no puedan confundirse con hielo alimenticio.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2009 AS Decimal(6, 0)), N'3              ', N'La disposición, equipamiento y uso de las diferentes zonas de trabajo dificulta la contaminación cruzada, al menos entre carnes frescas y productos cárnicos higienizados.', N'La disposición de las diferentes zonas de trabajo será de tal forma que dificulte la contaminación cruzada, permitiendo la adopción de prácticas correctas en la manipulación de los alimentos; teniendo en cuenta que se trabaja con carne fresca de distintas especies, incluyendo aves, con derivados cárnicos tratados por el calor (en algún caso de consumo directo), con derivados lácteos, etc., resulta importante definir según su destino tanto las zonas, superficies y utensilios de trabajo, al menos, según sean empleados para carnes frescas, o para el resto de productos.', N' ', N'La disposición de las diferentes zonas de trabajo será de tal forma que dificulte la contaminación cruzada, permitiendo la adopción de prácticas correctas en la manipulación de los alimentos; teniendo en cuenta que se trabaja con carne fresca de distintas especies, incluyendo aves, con derivados cárnicos tratados por el calor (en algún caso de consumo directo), con derivados lácteos, etc., resulta importante definir según su destino tanto las zonas, superficies y utensilios de trabajo, al menos, según sean empleados para carnes frescas, o para el resto de productos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2012 AS Decimal(6, 0)), N'28             ', N'Los productos son transportados acompa¦ados de un documento que recoge la información correspondiente, o en  caso de reparto a domicilio particular: ticket.
', N'Los traslados a establecimientos de comidas preparadas irán acompa¦ados de un documento interno o albarán en el que como mínimo se incluirá la siguiente información:
- nº de autorización del establecimiento de origen
- relación de productos que ampara
- destino o, en su caso, justificante de venta al consumidor.
En el caso de reparto a domicilio particular, será suficiente con el justificante de venta (ticket).
', N' ', N'Los traslados a establecimientos de comidas preparadas irán acompa¦ados de un documento interno o albarán en el que como mínimo se incluirá la siguiente información:
- nº de autorización del establecimiento de origen
- relación de productos que ampara
- destino o, en su caso, justificante de venta al consumidor.
En el caso de reparto a domicilio particular, será suficiente con el justificante de venta (ticket).
