INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(429 AS Decimal(6, 0)), N'55             ', N'La Sala de despiece cuenta con autorización expresa para la extracción de la columna vertebral de vacunos > 30 meses.', N'La extracción de columna vertebral de vacunos mayores de 30 meses, puede ser realizada en sala de despiece, previa autorización expresa de la autoridad sanitaria competente de la Comunidad Autónoma y con un protocolo de actuación concreto, que garantice la seguridad de dichas  operaciones y la completa retirada de la columna para su correcta destrucción.', N' ', N'La extracción de columna vertebral de vacunos mayores de 30 meses, puede ser realizada en sala de despiece, previa autorización expresa de la autoridad sanitaria competente de la Comunidad Autónoma y con un protocolo de actuación concreto, que garantice la seguridad de dichas  operaciones y la completa retirada de la columna para su correcta destrucción.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(474 AS Decimal(6, 0)), N'32             ', N'Los embalajes que contienen las canales, despiece y despojos de ave se reciben íntegros.', N'En la recepción de las canales no envasadas individualmente y que se comercializan en cajas de plástico o similares, debe comprobarse que vienen protegidas con un sistema que evite la contaminación de las mismas generada durante las operaciones de carga, descarga, transporte y su posterior almacenamiento.
En la recepción de canales, despiece y despojos envasados y embalados, se debe comprobar la integridad de los embalajes.', N' ', N'En la recepción de las canales no envasadas individualmente y que se comercializan en cajas de plástico o similares, debe comprobarse que vienen protegidas con un sistema que evite la contaminación de las mismas generada durante las operaciones de carga, descarga, transporte y su posterior almacenamiento.
En la recepción de canales, despiece y despojos envasados y embalados, se debe comprobar la integridad de los embalajes.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(513 AS Decimal(6, 0)), N'38             ', N'Las carnes despiezadas y los despojos se envasan.', N'La carne despiezada y sus despojos deberán estar provistos de un envase protector. ', N' ', N'La carne despiezada y sus despojos deberán estar provistos de un envase protector. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(518 AS Decimal(6, 0)), N'46             ', N'Los trozos y despojos obtenidos en la sala de despiece, envasados y embalados, llevan la marca sanitaria en etiquetas o material de envasado y/o embalado.', N'Marcado de inspección veterinaria en carne fresca de ave.
El sello de inspección sanitaria figurará:
En la superficie externa de las envolturas y/ o embalajes de las canales embaladas individualmente y de las partes de canales y despojos embalados en peque¦as cantidades.
Bajo las envolturas de las canales envasadas individualmente y de las partes de canales y despojos envasados en peque¦as cantidades, siempre que el marcado sanitario sea visible desde el exterior.
Cuando el marcado sanitario figure en una etiqueta adherida en el envase o en el embalaje o impreso en el mismo, se aplicará de tal forma que se rompa al abrir el envase o el embalaje. Solo será admisible que la marca sanitaria no se rompa cuando el propio envase o embalaje se destruya al abrirse y sea imposible su reutilización.
Cuando se vuelva a embalar la carne de otro establecimiento distinto de aquel donde fue envasada, el envase llevará la marca de inspección veterinaria original de la sala de despiece que efectuó el envasado y el embalaje llevará la marca de inspección veterinaria del centro de embalado.
', N' ', N'Marcado de inspección veterinaria en carne fresca de ave.
El sello de inspección sanitaria figurará:
En la superficie externa de las envolturas y/ o embalajes de las canales embaladas individualmente y de las partes de canales y despojos embalados en peque¦as cantidades.
Bajo las envolturas de las canales envasadas individualmente y de las partes de canales y despojos envasados en peque¦as cantidades, siempre que el marcado sanitario sea visible desde el exterior.
Cuando el marcado sanitario figure en una etiqueta adherida en el envase o en el embalaje o impreso en el mismo, se aplicará de tal forma que se rompa al abrir el envase o el embalaje. Solo será admisible que la marca sanitaria no se rompa cuando el propio envase o embalaje se destruya al abrirse y sea imposible su reutilización.
Cuando se vuelva a embalar la carne de otro establecimiento distinto de aquel donde fue envasada, el envase llevará la marca de inspección veterinaria original de la sala de despiece que efectuó el envasado y el embalaje llevará la marca de inspección veterinaria del centro de embalado.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(502 AS Decimal(6, 0)), N'32             ', N'La evisceración de las canales de patos y ocas para la producción de foie gras sacrificados en la explotación de engorde se realiza en un plazo menor o igual a 24 horas.', N'El transporte de las canales de patos y ocas destinados a la producción de ?foie gras? obtenidas por sacrificio en la propia explotación de origen se hará de forma inmediata, en condiciones higiénicas y a una temperatura máxima de +4ºC acompa¦adas del certificado sanitario correspondiente y su evisceración se realizará en un plazo -menor que 24 horas.
En el caso de las aves de evisceración diferida (New York dressed) la evisceración debe realizarse dentro de los 15 días posteriores a su sacrificio en el matadero. ', N' ', N'El transporte de las canales de patos y ocas destinados a la producción de ?foie gras? obtenidas por sacrificio en la propia explotación de origen se hará de forma inmediata, en condiciones higiénicas y a una temperatura máxima de +4ºC acompa¦adas del certificado sanitario correspondiente y su evisceración se realizará en un plazo -menor que 24 horas.
En el caso de las aves de evisceración diferida (New York dressed) la evisceración debe realizarse dentro de los 15 días posteriores a su sacrificio en el matadero. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(490 AS Decimal(6, 0)), N'11             ', N'Todos los locales frigoríficos y la sala de despiece disponen de tele termómetro registrado, identificando hora y fecha de los registros. Estos se obtienen al menos dos veces por hora.', N'En todos los locales frigoríficos y la sala de despiece se dispondrá de tele termómetro registrador. La temperatura deberá registrarse de modo que se disponga de un registro permanente de la Tª, incluso identificando la hora y fecha de los registros. No se acepta el registro manual de la Tª, sea cual fuere su frecuencia.
En los casos en los que un tele termómetro registrador estuviere conectado a un sistema informatizado, los registros podrán ser continuos o intermitentes. Cuando se obtuvieren registros de modo intermitente, deberán obtenerse al menos dos veces por hora.', N' ', N'En todos los locales frigoríficos y la sala de despiece se dispondrá de tele termómetro registrador. La temperatura deberá registrarse de modo que se disponga de un registro permanente de la Tª, incluso identificando la hora y fecha de los registros. No se acepta el registro manual de la Tª, sea cual fuere su frecuencia.
En los casos en los que un tele termómetro registrador estuviere conectado a un sistema informatizado, los registros podrán ser continuos o intermitentes. Cuando se obtuvieren registros de modo intermitente, deberán obtenerse al menos dos veces por hora.')
GO
