INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(358 AS Decimal(6, 0)), N'52             ', N'Se realiza aturdido previo al sangrado en todas las especies. Exceptuados sacrificios rituales.', N'Todos los animales serán aturdidos antes de ser sangrados.
No obstante, en el caso del sacrificio ritual se hace una excepción con respecto a esta práctica.', N' ', N'Todos los animales serán aturdidos antes de ser sangrados.
No obstante, en el caso del sacrificio ritual se hace una excepción con respecto a esta práctica.')
