INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(644 AS Decimal(6, 0)), N'38             ', N'Los envases utilizados son siempre nuevos.', N'Los envases y embalajes de los huevos pueden ser de dos tipos:
Peque¦os embalajes o envases: son los embalajes, bandejas, o alveolos (con exclusión de las bandejas o alveolos no envueltos) con un contenido igual o inferior a 36 huevos.
El envase deberá ser siempre nuevo; estando  prohibida su reutilización.
Grandes embalajes o embalajes: son los embalajes recipientes, o contenedores no cerrados con un contenido superior a 36 huevos.', N' ', N'Los envases y embalajes de los huevos pueden ser de dos tipos:
Peque¦os embalajes o envases: son los embalajes, bandejas, o alveolos (con exclusión de las bandejas o alveolos no envueltos) con un contenido igual o inferior a 36 huevos.
El envase deberá ser siempre nuevo; estando  prohibida su reutilización.
Grandes embalajes o embalajes: son los embalajes recipientes, o contenedores no cerrados con un contenido superior a 36 huevos.')
GO
