INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(671 AS Decimal(6, 0)), N'7              ', N'La ubicación de los sistemas de retención de sólidos y depuración de aguas residuales es la adecuada.', N'La ubicación de los sistemas de retención, desbaste de sólidos y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared del resto de operaciones propias de dicha zona.
', N' ', N'La ubicación de los sistemas de retención, desbaste de sólidos y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared del resto de operaciones propias de dicha zona.
')
