INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(641 AS Decimal(6, 0)), N'32             ', N'Si clasifican huevos de diferentes productores:
Llevan un registro correcto y lo conservan durante al menos 6 meses.', N'Huevos procedentes de diferentes productores :
Si los centros clasifican también huevos de productores externos en los que no se vaya a indicar la fecha de puesta; dichos huevos serán almacenados y manipulados por separado . Se llevarán registros por separado de la recepción de los huevos y de la categoría de dichos huevos.
Registros:
Deberán registrar los datos siguientes:
Las cantidades diarias por productor  de huevos llegados al  centro en los que se vaya a indicar la fecha de puesta, o en los que ésta  ya haya sido estampada en la explotación, así como el nombre, dirección y número de registro del productor.
La clasificación diaria de calidad y peso de dichos huevos
El número o peso de los huevos vendidos, por categorías de peso y por comprador y el nombre y dirección de éste.
En los contenedores y documentos que acompa¦en  a los huevos en los que se va a indicar la fecha de puesta , figurarán los siguientes datos:
la fecha de puesta
el nombre, dirección y número del productor, así  como el código del gallinero de donde proceden los huevos
la fecha de envío
el  número o peso de los huevos entregados.
Esta información se guardará durante un período de 6 meses en el centro de clasificación.', N' ', N'Huevos procedentes de diferentes productores :
Si los centros clasifican también huevos de productores externos en los que no se vaya a indicar la fecha de puesta; dichos huevos serán almacenados y manipulados por separado . Se llevarán registros por separado de la recepción de los huevos y de la categoría de dichos huevos.
Registros:
Deberán registrar los datos siguientes:
Las cantidades diarias por productor  de huevos llegados al  centro en los que se vaya a indicar la fecha de puesta, o en los que ésta  ya haya sido estampada en la explotación, así como el nombre, dirección y número de registro del productor.
La clasificación diaria de calidad y peso de dichos huevos
El número o peso de los huevos vendidos, por categorías de peso y por comprador y el nombre y dirección de éste.
En los contenedores y documentos que acompa¦en  a los huevos en los que se va a indicar la fecha de puesta , figurarán los siguientes datos:
la fecha de puesta
el nombre, dirección y número del productor, así  como el código del gallinero de donde proceden los huevos
la fecha de envío
el  número o peso de los huevos entregados.
Esta información se guardará durante un período de 6 meses en el centro de clasificación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(633 AS Decimal(6, 0)), N'10             ', N'Dispone de equipo de inspección visual automático o permanentemente controlado por un operario.', N'Equipo de inspección visual de los huevos cuyo funcionamiento está controlado permanentemente por un operario y que permita examinar la calidad de cada huevo por separado. En caso de utilizarse una máquina automática el equipo deberá estar provisto de una lámpara autónoma para dicha inspección. Se podrá dispensar la  presencia permanente del operario en los sistemas automáticos. ', N' ', N'Equipo de inspección visual de los huevos cuyo funcionamiento está controlado permanentemente por un operario y que permita examinar la calidad de cada huevo por separado. En caso de utilizarse una máquina automática el equipo deberá estar provisto de una lámpara autónoma para dicha inspección. Se podrá dispensar la  presencia permanente del operario en los sistemas automáticos. ')
GO
