INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(628 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona diferenciada de almacén de huevos a clasificar o su abastecimiento es directo desde la granja', N'Local o zona diferenciada  de recepción con capacidad adecuada al volumen de huevos a clasificar (no será necesaria en los establecimientos en los cuales el abastecimiento de huevos se hace directamente desde la granja a través de cinta transportadora a la clasificadora).', N' ', N'Local o zona diferenciada  de recepción con capacidad adecuada al volumen de huevos a clasificar (no será necesaria en los establecimientos en los cuales el abastecimiento de huevos se hace directamente desde la granja a través de cinta transportadora a la clasificadora).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(643 AS Decimal(6, 0)), N'32             ', N'No se realiza ninguna de las prácticas prohibidas.', N'Prácticas prohibidas:
No se podrán lavar ni limpiar los huevos de la cat. A ni antes ni después de la clasificación.
No se podrán conservar ni refrigerar artificialmente en locales con temperaturas inferiores a 5º C.
Los huevos rotos accidentalmente, solamente se entregarán a la industria, no alimentaria, de transformación.
Realizar la estiba de huevos refrigerados o conservados directamente sobre el suelo y sin la separación necesaria entre los productos o estos con suelo paredes y techo, para que asegure una buena circulación del aire.
Prohibido introducir en cámaras para su conservación los huevos que hayan sido marcados en su cáscara.
Los huevos conservados en cámaras, una vez extraídos de las mismas no podrán someterse a un nuevo proceso de conservación por el frío, con excepción de los huevos destinados a industrialización.', N' ', N'Prácticas prohibidas:
No se podrán lavar ni limpiar los huevos de la cat. A ni antes ni después de la clasificación.
No se podrán conservar ni refrigerar artificialmente en locales con temperaturas inferiores a 5º C.
Los huevos rotos accidentalmente, solamente se entregarán a la industria, no alimentaria, de transformación.
Realizar la estiba de huevos refrigerados o conservados directamente sobre el suelo y sin la separación necesaria entre los productos o estos con suelo paredes y techo, para que asegure una buena circulación del aire.
Prohibido introducir en cámaras para su conservación los huevos que hayan sido marcados en su cáscara.
Los huevos conservados en cámaras, una vez extraídos de las mismas no podrán someterse a un nuevo proceso de conservación por el frío, con excepción de los huevos destinados a industrialización.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(605 AS Decimal(6, 0)), N'59             ', N'La denominación de venta del producto es preparado para lactantes o, en su caso, leche para lactantes.', N'Estos productos se comercializarán bajo la denominación de preparado para lactantes, sin embargo la denominación de alimentos elaborados totalmente a partir de las proteínas procedentes de la leche de vaca será la siguiente: leche para lactantes.
', N' ', N'Estos productos se comercializarán bajo la denominación de preparado para lactantes, sin embargo la denominación de alimentos elaborados totalmente a partir de las proteínas procedentes de la leche de vaca será la siguiente: leche para lactantes.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(625 AS Decimal(6, 0)), N'63             ', N'Se aprecian y figuran las indicaciones sobre contraindicaciones, utilidad, vía de administración, enfermedad a la que se destina.', N'
? En el etiquetado figurará además:
La declaración Para el tratamiento dietético en la que el espacio en blanco se completará con la enfermedad para el que vaya destinado.
Si procede, una declaración sobre las precauciones adecuadas y las contraindicaciones.
Una descripción de las propiedades y características pertinentes que expliquen la utilidad del producto, en particular en lo que se refiere a los nutrientes que hayan sido a¦adidos, reducidos, eliminados o modificados de otra forma,  así como la justificación para su uso.
Si procede, una advertencia de que el producto no debe administrarse por vía parenteral.', N' ', N'
? En el etiquetado figurará además:
La declaración Para el tratamiento dietético en la que el espacio en blanco se completará con la enfermedad para el que vaya destinado.
Si procede, una declaración sobre las precauciones adecuadas y las contraindicaciones.
Una descripción de las propiedades y características pertinentes que expliquen la utilidad del producto, en particular en lo que se refiere a los nutrientes que hayan sido a¦adidos, reducidos, eliminados o modificados de otra forma,  así como la justificación para su uso.
Si procede, una advertencia de que el producto no debe administrarse por vía parenteral.')
