INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(626 AS Decimal(6, 0)), N'1              ', N'Si es un establecimiento anexo a una granja de producción:
Está suficientemente aislado de esta.', N'Todos los establecimientos destinados a la manipulación, envasado, embalaje y almacenamiento de huevos estarán debidamente aislados de posibles focos de contaminación.
Las clasificadoras anexas a granjas de producción no podrán compartir ningún local con las mismas y únicamente se permitirá que exista una abertura en la pared para dejar paso a la cinta transportadora de los huevos. ', N' ', N'Todos los establecimientos destinados a la manipulación, envasado, embalaje y almacenamiento de huevos estarán debidamente aislados de posibles focos de contaminación.
Las clasificadoras anexas a granjas de producción no podrán compartir ningún local con las mismas y únicamente se permitirá que exista una abertura en la pared para dejar paso a la cinta transportadora de los huevos. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(627 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona de carga y descarga.', N'Local o zona de carga y descarga, situada a la entrada del establecimiento.
Se admitirá la posibilidad de realizar las actividades 5, 6, 7 y 8 (ver más adelante) en zonas diferenciadas de un solo local siempre y cuando el mismo cuente con un local previo destinado a las actividades de carga-descarga.
Se admitirá la posibilidad de habilitar una zona de carga-descarga a la entrada del almacén de huevos envasados cuando su acceso esté dotado de un sistema permanente que impida la entrada de vehículos al interior del mismo, y siempre y cuando las actividades 5 y 6 se realicen en otro local diferenciado.', N' ', N'Local o zona de carga y descarga, situada a la entrada del establecimiento.
Se admitirá la posibilidad de realizar las actividades 5, 6, 7 y 8 (ver más adelante) en zonas diferenciadas de un solo local siempre y cuando el mismo cuente con un local previo destinado a las actividades de carga-descarga.
Se admitirá la posibilidad de habilitar una zona de carga-descarga a la entrada del almacén de huevos envasados cuando su acceso esté dotado de un sistema permanente que impida la entrada de vehículos al interior del mismo, y siempre y cuando las actividades 5 y 6 se realicen en otro local diferenciado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(630 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona diferenciada para almacenamiento de huevos embalados.', N'Local o zona diferenciada de almacenamiento de huevos embalados.', N' ', N'Local o zona diferenciada de almacenamiento de huevos embalados.')
