INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(692 AS Decimal(6, 0)), N'24             ', N'Dispone de recipientes exclusivos identificados para decomisos.', N'Los recipientes de uso exclusivo para la recogida de productos dictaminados como no aptos para el consumo estarán identificados con la leyenda DECOMISO. Cuando los decomisos se eliminen por conductos destinados a tal fin, estarán construidos de forma que se evite la contaminación de materias primas o productos. ', N' ', N'Los recipientes de uso exclusivo para la recogida de productos dictaminados como no aptos para el consumo estarán identificados con la leyenda DECOMISO. Cuando los decomisos se eliminen por conductos destinados a tal fin, estarán construidos de forma que se evite la contaminación de materias primas o productos. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(675 AS Decimal(6, 0)), N'58             ', N'Se dispone de sistema de sangrado.', N'Dispondrá de sistema de sangrado, que permita la sangría completa de los animales.', N' ', N'Dispondrá de sistema de sangrado, que permita la sangría completa de los animales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(673 AS Decimal(6, 0)), N'58             ', N'Se dispone de equipos de aturdimiento e insensibilización.', N'Dispondrá de equipos de aturdimiento e insensibilización previa al sacrificio. ', N' ', N'Dispondrá de equipos de aturdimiento e insensibilización previa al sacrificio. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(697 AS Decimal(6, 0)), N'32             ', N'Se controla que los animales vivos llegan en condiciones de limpieza adecuada.', N'El matadero deberá controlar la llegada de los animales a sacrificio en condiciones de limpieza que garanticen un faenado posterior en condiciones higiénicas.', N' ', N'El matadero deberá controlar la llegada de los animales a sacrificio en condiciones de limpieza que garanticen un faenado posterior en condiciones higiénicas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(710 AS Decimal(6, 0)), N'32             ', N'La operación de escaldado se realiza de acuerdo con las especificaciones de Tª, tiempo y número de aves.', N'El número de canales que se sumergen en la cuba debe respetar la capacidad máxima de ésta, comprobándose que el agua de escaldado mantenga condiciones higiénicas durante todo el proceso, de acuerdo con las especificaciones técnicas de la misma. El tiempo de permanencia de las aves en la cuba no de debe ser superior al estipulado por las características técnicas de la misma.', N' ', N'El número de canales que se sumergen en la cuba debe respetar la capacidad máxima de ésta, comprobándose que el agua de escaldado mantenga condiciones higiénicas durante todo el proceso, de acuerdo con las especificaciones técnicas de la misma. El tiempo de permanencia de las aves en la cuba no de debe ser superior al estipulado por las características técnicas de la misma.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(718 AS Decimal(6, 0)), N'32             ', N'La refrigeración por inmersión se realiza en las condiciones descritas.', N'Las carnes de aves de corral destinadas a ser sometidas a un proceso de refrigeración por inmersión, deberán ser objeto, inmediatamente después de la evisceración, de un cuidadoso lavado por aspersión y de una inmersión inmediata. La aspersión deberá efectuarse mediante una instalación que garantice un lavado eficaz de las superficies tanto internas como externas de las canales.
El procedimiento de refrigeración por inmersión se ajustará a las siguientes normas:
Las canales pasarán por uno o varios tanques de agua, o de agua y hielo, cuyo contenido se renovará continuamente. A este respecto sólo se admitirá el sistema en el cual las canales son empujadas constantemente por medios mecánicos a través de un flujo de agua avanzando a contracorriente.
La temperatura del agua o de los tanques, medidas en los puntos de entrada y salida de las canales no deberá ser superior a + 16ºC y + 4ºC respectivamente.
Deberá realizarse de modo que se alcance la temperatura de + 4ºC en el menor plazo posible.
Si se usan varios tanques, la entrada de agua limpia fresca y el desagüe de agua usada de cada uno deberán regularse de modo que vaya disminuyendo progresivamente en el sentido del movimiento de las canales repartiéndose el agua fresca y limpia entre ellos.
Las canales no deberán permanecer en el primer tramo del equipo o en el primer tanque durante más de media hora, ni en el resto del equipo o en los demás tanques más tiempo del estrictamente necesario. Cada vez que se interrumpa el funcionamiento de la instalación, el veterinario oficial deberá comprobar, antes de que se vuelva a poner en funcionamiento, que las canales siguen cumpliendo las exigencias legales y que son aptas para el consumo humano, o deberá adoptar las medidas adecuadas, en caso contrario, para que sean transportadas lo antes posible al local destinado a almacenar las carnes no aptas para consumo humano.
Todos los elementos del equipo serán  vaciados completamente, limpiados y desinfectados siempre que sea necesario, al final de la jornada de trabajo y al menos una vez al día.', N' ', N'Las carnes de aves de corral destinadas a ser sometidas a un proceso de refrigeración por inmersión, deberán ser objeto, inmediatamente después de la evisceración, de un cuidadoso lavado por aspersión y de una inmersión inmediata. La aspersión deberá efectuarse mediante una instalación que garantice un lavado eficaz de las superficies tanto internas como externas de las canales.
El procedimiento de refrigeración por inmersión se ajustará a las siguientes normas:
Las canales pasarán por uno o varios tanques de agua, o de agua y hielo, cuyo contenido se renovará continuamente. A este respecto sólo se admitirá el sistema en el cual las canales son empujadas constantemente por medios mecánicos a través de un flujo de agua avanzando a contracorriente.
La temperatura del agua o de los tanques, medidas en los puntos de entrada y salida de las canales no deberá ser superior a + 16ºC y + 4ºC respectivamente.
Deberá realizarse de modo que se alcance la temperatura de + 4ºC en el menor plazo posible.
Si se usan varios tanques, la entrada de agua limpia fresca y el desagüe de agua usada de cada uno deberán regularse de modo que vaya disminuyendo progresivamente en el sentido del movimiento de las canales repartiéndose el agua fresca y limpia entre ellos.
Las canales no deberán permanecer en el primer tramo del equipo o en el primer tanque durante más de media hora, ni en el resto del equipo o en los demás tanques más tiempo del estrictamente necesario. Cada vez que se interrumpa el funcionamiento de la instalación, el veterinario oficial deberá comprobar, antes de que se vuelva a poner en funcionamiento, que las canales siguen cumpliendo las exigencias legales y que son aptas para el consumo humano, o deberá adoptar las medidas adecuadas, en caso contrario, para que sean transportadas lo antes posible al local destinado a almacenar las carnes no aptas para consumo humano.
Todos los elementos del equipo serán  vaciados completamente, limpiados y desinfectados siempre que sea necesario, al final de la jornada de trabajo y al menos una vez al día.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(717 AS Decimal(6, 0)), N'32             ', N'Las carnes frescas se limpian y refrigeran inmediatamente tras la inspección y retirada de las vísceras.', N'Al finalizar la inspección y la retirada de las vísceras, las carnes frescas deberán limpiarse y refrigerarse inmediatamente según las normas de higiene, hasta alcanzar las temperaturas reglamentarias.', N' ', N'Al finalizar la inspección y la retirada de las vísceras, las carnes frescas deberán limpiarse y refrigerarse inmediatamente según las normas de higiene, hasta alcanzar las temperaturas reglamentarias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(742 AS Decimal(6, 0)), N'47             ', N'No se practica ninguna operación antes del sangrado completo de los animales.', N'Se sangrará a los animales objeto de un aturdido mediante la incisión de al menos una arteria carótida o de los vasos de los que nacen. Tras la incisión de los vasos sanguíneos, no se someterá a los animales a ninguna otra operación de preparación de la canal ni a estimulación eléctrica alguna antes de que haya cesado el sangrado.', N' ', N'Se sangrará a los animales objeto de un aturdido mediante la incisión de al menos una arteria carótida o de los vasos de los que nacen. Tras la incisión de los vasos sanguíneos, no se someterá a los animales a ninguna otra operación de preparación de la canal ni a estimulación eléctrica alguna antes de que haya cesado el sangrado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(706 AS Decimal(6, 0)), N'32             ', N'Las canales y/o vísceras no contactan ni con el suelo ni con las estructuras.', N'Se evitará que cualquier parte de la canal o vísceras contacten con el suelo o con las estructuras.
Además de las consideraciones generales de higiene descritas en el punto anterior, se tendrán en cuenta las siguientes consideraciones específicas según la fase del faenado a tratar.', N' ', N'Se evitará que cualquier parte de la canal o vísceras contacten con el suelo o con las estructuras.
Además de las consideraciones generales de higiene descritas en el punto anterior, se tendrán en cuenta las siguientes consideraciones específicas según la fase del faenado a tratar.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(712 AS Decimal(6, 0)), N'32             ', N'El desplumado se realiza de forma inmediata y completa.', N'El desplumado deberá ser inmediato y completo.', N' ', N'El desplumado deberá ser inmediato y completo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(728 AS Decimal(6, 0)), N'46             ', N'El marcado sanitario se coloca correctamente según las unidades de envasado o en carnes directamente.', N'-El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado.
-Dependiendo del tipo de presentación, la marca podrá fijarse directamente en el producto, en el envase o en el embalaje, o bien estamparse en una etiqueta fijada a cualquiera de los tres. La marca podrá consistir también en una etiqueta inamovible de material resistente.
-En el caso de los embalajes que contengan carne despiezada o despojos, la marca deberá fijarse a una etiqueta sujeta al embalaje, o estamparse en el embalaje, de tal modo que quede destruida cuando éste se abra. Esto no será necesario, sin embargo, si el proceso de apertura destruye el embalaje. Cuando el envase ofrezca la misma protección que el embalaje, la etiqueta podrá colocarse en el envase.
-Cuando los productos se introduzcan en contenedores de transporte o en grandes embalajes y se destinen a su posterior manipulación, transformación, envasado o embalado en otro establecimiento, la marca podrá fijarse en la superficie exterior del contenedor o embalaje.
-Cuando los productos se pongan en el mercado en embalajes destinados al suministro directo al consumidor final, bastará con fijar la marca únicamente en el exterior de dicho embalaje. Cuando la marca se aplique directamente a los productos, los colores utilizados deberán estar autorizados de conformidad con las normas comunitarias para el uso de sustancias colorantes en los productos alimenticios.', N' ', N'-El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado.
-Dependiendo del tipo de presentación, la marca podrá fijarse directamente en el producto, en el envase o en el embalaje, o bien estamparse en una etiqueta fijada a cualquiera de los tres. La marca podrá consistir también en una etiqueta inamovible de material resistente.
-En el caso de los embalajes que contengan carne despiezada o despojos, la marca deberá fijarse a una etiqueta sujeta al embalaje, o estamparse en el embalaje, de tal modo que quede destruida cuando éste se abra. Esto no será necesario, sin embargo, si el proceso de apertura destruye el embalaje. Cuando el envase ofrezca la misma protección que el embalaje, la etiqueta podrá colocarse en el envase.
-Cuando los productos se introduzcan en contenedores de transporte o en grandes embalajes y se destinen a su posterior manipulación, transformación, envasado o embalado en otro establecimiento, la marca podrá fijarse en la superficie exterior del contenedor o embalaje.
-Cuando los productos se pongan en el mercado en embalajes destinados al suministro directo al consumidor final, bastará con fijar la marca únicamente en el exterior de dicho embalaje. Cuando la marca se aplique directamente a los productos, los colores utilizados deberán estar autorizados de conformidad con las normas comunitarias para el uso de sustancias colorantes en los productos alimenticios.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(769 AS Decimal(6, 0)), N'3              ', N'Dispone de local o dispositivo para almacenar los aditivos y/o especias y/o condimentos.', N'Local o dispositivo para aditivos
Dispondrá de un local o dispositivo para almacenar los aditivos alimentarios, especias y condimentos si procede. ', N' ', N'Local o dispositivo para aditivos
Dispondrá de un local o dispositivo para almacenar los aditivos alimentarios, especias y condimentos si procede. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(732 AS Decimal(6, 0)), N'47             ', N'Los contenedores donde se transportan los animales se manipulan con cuidado.', N'Los contenedores donde se transporten animales se manipularán con cuidado y se prohibe arrojarlos, dejarlos caer o volcarlos. Cuando sea posible, se cargarán y descargarán horizontalmente por medios mecánicos.', N' ', N'Los contenedores donde se transporten animales se manipularán con cuidado y se prohibe arrojarlos, dejarlos caer o volcarlos. Cuando sea posible, se cargarán y descargarán horizontalmente por medios mecánicos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(725 AS Decimal(6, 0)), N'40             ', N'El documento de acompa¦amiento comercial de carnes durante el transporte reúne los requisitos del mismo.', N'Las carnes durante el transporte irán acompa¦adas de un documento de acompa¦amiento comercial emitido por el matadero que reunirá los siguientes requisitos:
Llevará la marca sanitaria del matadero (sello de inspección veterinaria).
Día de producción de las carnes.
Este documento deberá ser conservado por el destinatario un periodo mínimo de un a¦o.', N' ', N'Las carnes durante el transporte irán acompa¦adas de un documento de acompa¦amiento comercial emitido por el matadero que reunirá los siguientes requisitos:
Llevará la marca sanitaria del matadero (sello de inspección veterinaria).
Día de producción de las carnes.
Este documento deberá ser conservado por el destinatario un periodo mínimo de un a¦o.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(727 AS Decimal(6, 0)), N'46             ', N'El marcado de inspección veterinaria reúne los requisitos especificados de información, tama¦o, dígitos etc.', N'El marcado de inspección veterinaria deberá reunir las siguientes características:
-El material usado para el marcado deberá reunir todas las exigencias de higiene
-La marca deberá ser legible e indeleble, y sus caracteres fácilmente descifrables. Se fijará de forma que quede claramente visible para las autoridades competentes.
-La marca deberá indicar el nombre del país en el que esté ubicado el establecimiento, que podrá figurar con todas sus letras o abreviado en un código de dos letras conforme a la norma ISO correspondiente.
Para los Estados miembros, sin embargo, dichos códigos son los siguientes: AT, BE, DE, DK, ES, FI, FR, GR, IE, IT, LU, NL, PT, SE y UK.
Los operadores de empresa alimentaria podrán seguir utilizando, hasta que se acaben o hayan de ser sustituidos, existencias y equipos que habían encargado antes de la entrada en vigor del Reglamento 853/2004.
-La marca deberá indicar el número de autorización del establecimiento. 
-Las marcas fijadas deberán tener forma oval y contendrán las siglas CE, EC, EF, EG, EK o EY.
', N' ', N'El marcado de inspección veterinaria deberá reunir las siguientes características:
-El material usado para el marcado deberá reunir todas las exigencias de higiene
-La marca deberá ser legible e indeleble, y sus caracteres fácilmente descifrables. Se fijará de forma que quede claramente visible para las autoridades competentes.
-La marca deberá indicar el nombre del país en el que esté ubicado el establecimiento, que podrá figurar con todas sus letras o abreviado en un código de dos letras conforme a la norma ISO correspondiente.
Para los Estados miembros, sin embargo, dichos códigos son los siguientes: AT, BE, DE, DK, ES, FI, FR, GR, IE, IT, LU, NL, PT, SE y UK.
Los operadores de empresa alimentaria podrán seguir utilizando, hasta que se acaben o hayan de ser sustituidos, existencias y equipos que habían encargado antes de la entrada en vigor del Reglamento 853/2004.
-La marca deberá indicar el número de autorización del establecimiento. 
-Las marcas fijadas deberán tener forma oval y contendrán las siglas CE, EC, EF, EG, EK o EY.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(741 AS Decimal(6, 0)), N'47             ', N'El sangrado se realiza lo antes posible tras el aturdido del ave.', N'El sangrado de los animales que hayan sido aturdidos comenzará lo antes posible después del aturdido y se deberá efectuar de manera que se provoque un desangrado rápido, profuso y completo. En cualquier caso, deberá efectuarse el sangrado antes de que el animal recobre el conocimiento.', N' ', N'El sangrado de los animales que hayan sido aturdidos comenzará lo antes posible después del aturdido y se deberá efectuar de manera que se provoque un desangrado rápido, profuso y completo. En cualquier caso, deberá efectuarse el sangrado antes de que el animal recobre el conocimiento.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(767 AS Decimal(6, 0)), N'3              ', N'Dispone de locales y en su caso cámaras frigoríficas, separados según se encuentren embalados o no embalados, para el almacenamiento de materias primas y productos cárnicos.', N'Locales de almacenamiento
Los establecimientos que procedan a la fabricación, manipulación y envasado de productos cárnicos dispondrán de locales distintos para los embalados de los no embalados, para el almacenamiento, en su caso en régimen de frío, de materias primas, productos intermedios y productos cárnicos finales.', N' ', N'Locales de almacenamiento
Los establecimientos que procedan a la fabricación, manipulación y envasado de productos cárnicos dispondrán de locales distintos para los embalados de los no embalados, para el almacenamiento, en su caso en régimen de frío, de materias primas, productos intermedios y productos cárnicos finales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(743 AS Decimal(6, 0)), N'47             ', N'Si se sangran mediante degolladores automáticos se dispone de sistema manual auxiliar.', N'Cuando los animales sean sangrados mediante degolladores automáticos, se deberá disponer de un sistema manual auxiliar para que, en caso de fallo, los animales puedan ser sacrificados inmediatamente.', N' ', N'Cuando los animales sean sangrados mediante degolladores automáticos, se deberá disponer de un sistema manual auxiliar para que, en caso de fallo, los animales puedan ser sacrificados inmediatamente.')
GO
