INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(713 AS Decimal(6, 0)), N'32             ', N'Las plumas se retiran en condiciones que eviten contaminaciones.', N'Las plumas deben retirarse en forma continua o tan a menudo como sea necesario durante la jornada de trabajo. Las plumas transportadas por el agua corriente de modo continuo deberán separarse del agua que deberá ir a parar a la evacuación.', N' ', N'Las plumas deben retirarse en forma continua o tan a menudo como sea necesario durante la jornada de trabajo. Las plumas transportadas por el agua corriente de modo continuo deberán separarse del agua que deberá ir a parar a la evacuación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(715 AS Decimal(6, 0)), N'32             ', N'La evisceración de patos y ocas destinados a la elaboración de pasta de hígado foie-gras se hace en las condiciones de higiene descritas.', N'En lo referente a patos y ocas criados y sacrificados para la producción de pasta de hígado ?foie-gras?, podrá efectuarse su evisceración en un plazo de veinticuatro horas, siempre que la temperatura de las canales a las que no se haya extraído las vísceras se reduzca lo antes posible, y se mantenga a una temperatura que no supere en ningún momento los 4ºC, y que dichas canales se transporten según las normas de higiene.', N' ', N'En lo referente a patos y ocas criados y sacrificados para la producción de pasta de hígado ?foie-gras?, podrá efectuarse su evisceración en un plazo de veinticuatro horas, siempre que la temperatura de las canales a las que no se haya extraído las vísceras se reduzca lo antes posible, y se mantenga a una temperatura que no supere en ningún momento los 4ºC, y que dichas canales se transporten según las normas de higiene.')
GO
