INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(678 AS Decimal(6, 0)), N'58             ', N'Dispone de equipos de evisceración adecuados.', N'Dispondrá de equipos mecánicos o manuales de evisceración dise¦ados de forma que garanticen una correcta y completa evisceración y que impidan la contaminación de las aves.', N' ', N'Dispondrá de equipos mecánicos o manuales de evisceración dise¦ados de forma que garanticen una correcta y completa evisceración y que impidan la contaminación de las aves.')
