INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(714 AS Decimal(6, 0)), N'32             ', N'La evisceración se realiza en las condiciones de higiene descritas.', N'La extracción de las vísceras se efectuará sin demora en caso de evisceración total. Las aves de corral sacrificadas se deberán abrir de forma que puedan inspeccionarse las cavidades y todas las vísceras pertinentes. Con este fin, las vísceras que vayan a inspeccionarse podrán separarse o dejarse adheridas a la canal por sus conexiones naturales. Si se separan, deberá poderse identificar su pertenencia a la canal de origen. No existe contaminación sistemática de las canales con contenido gastrointestinal debida al sistema de eviscerado.', N' ', N'La extracción de las vísceras se efectuará sin demora en caso de evisceración total. Las aves de corral sacrificadas se deberán abrir de forma que puedan inspeccionarse las cavidades y todas las vísceras pertinentes. Con este fin, las vísceras que vayan a inspeccionarse podrán separarse o dejarse adheridas a la canal por sus conexiones naturales. Si se separan, deberá poderse identificar su pertenencia a la canal de origen. No existe contaminación sistemática de las canales con contenido gastrointestinal debida al sistema de eviscerado.')
GO
