INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(676 AS Decimal(6, 0)), N'58             ', N'Se dispone de equipos de escaldado adecuados.', N'Dispondrá de equipos de escaldado. La velocidad de flujo de agua a los tanques de escaldado deberá proporcionar un reemplazamiento continuo del agua con el fin de evitar la acumulación de contaminación y de modo que el flujo del agua vaya en dirección contraria al movimiento de las aves de modo que el ave escaldada sea empujada hacia  aquel lado del tanque donde penetra el agua caliente limpia. ', N' ', N'Dispondrá de equipos de escaldado. La velocidad de flujo de agua a los tanques de escaldado deberá proporcionar un reemplazamiento continuo del agua con el fin de evitar la acumulación de contaminación y de modo que el flujo del agua vaya en dirección contraria al movimiento de las aves de modo que el ave escaldada sea empujada hacia  aquel lado del tanque donde penetra el agua caliente limpia. ')
GO
