INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(682 AS Decimal(6, 0)), N'58             ', N'Se dispone de un número adecuado de desinfectadores de útiles en su ubicación correcta.', N'Se dispondrá de un número y ubicación de dispositivos para la desinfección de útiles que permita que los trabajadores no deban de desplazarse de su zona o lugares de trabajo.', N' ', N'Se dispondrá de un número y ubicación de dispositivos para la desinfección de útiles que permita que los trabajadores no deban de desplazarse de su zona o lugares de trabajo.')
