INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1244 AS Decimal(6, 0)), N'32             ', N'Las canales no envasadas individualmente y que se reciben en recipientes (cajas de plástico o similares) vienen con un sistema de protección contra la contaminación.', N'En la recepción de las canales no envasadas individualmente y que se comercializan en cajas de plástico o similares, debe comprobarse que vienen protegidas con un sistema que evite la contaminación de las mismas generada durante las operaciones de carga, descarga, transporte y su posterior almacenamiento.
En la recepción de canales, despiece y despojos envasados y embalados, se debe comprobar la integridad de los embalajes.
', N' ', N'En la recepción de las canales no envasadas individualmente y que se comercializan en cajas de plástico o similares, debe comprobarse que vienen protegidas con un sistema que evite la contaminación de las mismas generada durante las operaciones de carga, descarga, transporte y su posterior almacenamiento.
En la recepción de canales, despiece y despojos envasados y embalados, se debe comprobar la integridad de los embalajes.
')
