INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(582 AS Decimal(6, 0)), N'25             ', N'En el caso de elaboradores:
Los desechos y subproductos se retiran de forma continua de la zona de elaboración y se almacenan adecuadamente  en el exterior del local.', N'El raspón y los residuos procedentes del prensado de la uva se retirarán de manera continua de la zona de elaboración ( sin utilizar vehículos a motor) y se almacenaran en el exterior de la empresa (en contenedores o silos) para su entrega a la industria alcoholera o para su aprovechamiento agroganadero.', N' ', N'El raspón y los residuos procedentes del prensado de la uva se retirarán de manera continua de la zona de elaboración ( sin utilizar vehículos a motor) y se almacenaran en el exterior de la empresa (en contenedores o silos) para su entrega a la industria alcoholera o para su aprovechamiento agroganadero.')
