INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(557 AS Decimal(6, 0)), N'3              ', N'El almacén de patata dispone de local previo (de descarga) o de  sistema permanente que impida la entrada de vehículos  a su interior. ', N'Almacén de materia prima:
Contará con local independiente para el almacenamiento de las patatas, con acceso independiente y  directo desde el exterior del edificio y dotado de sistema permanente que impida la entrada de vehículos al interior del mismo o en su defecto de local previo destinado a las labores de descarga y que independice el almacén de materia prima del exterior.', N' ', N'Almacén de materia prima:
Contará con local independiente para el almacenamiento de las patatas, con acceso independiente y  directo desde el exterior del edificio y dotado de sistema permanente que impida la entrada de vehículos al interior del mismo o en su defecto de local previo destinado a las labores de descarga y que independice el almacén de materia prima del exterior.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(558 AS Decimal(6, 0)), N'3              ', N'Dispone de local para las labores de fabricación / transformación, suficientemente independizado del almacén de patatas.', N'Local de transformación / procesado.
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará totalmente independizado del almacén de patatas, únicamente se admitirá una comunicación directa con el mismo a través de ventana o abertura que permita el abastecimiento automático de la peladora de patatas.', N' ', N'Local de transformación / procesado.
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará totalmente independizado del almacén de patatas, únicamente se admitirá una comunicación directa con el mismo a través de ventana o abertura que permita el abastecimiento automático de la peladora de patatas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(570 AS Decimal(6, 0)), N'3              ', N'En el caso de que reutilícen envases:
Dispone de local específico para el almacenamiento de envases retornables, ya higienizados
', N'En el supuesto que se reutilicen envases, y en el caso de que la reutilización de los mismos no sea inmediata a su limpieza e  higienización, el establecimiento deberá disponer de un local específico destinado a las labores de  almacén de envases recuperables, ya higienizados.
En el mismo los envases higienizados, y en espera de uso, permanecerán debidamente estibados,  protegidos (mediante envoltura) del polvo y cualquier otro tipo de contaminación. Dicha protección contará  con sistema que cubra la embocadura de los envases y evite  la entrada de contaminantes en el interior de los mismos. Esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado
', N' ', N'En el supuesto que se reutilicen envases, y en el caso de que la reutilización de los mismos no sea inmediata a su limpieza e  higienización, el establecimiento deberá disponer de un local específico destinado a las labores de  almacén de envases recuperables, ya higienizados.
En el mismo los envases higienizados, y en espera de uso, permanecerán debidamente estibados,  protegidos (mediante envoltura) del polvo y cualquier otro tipo de contaminación. Dicha protección contará  con sistema que cubra la embocadura de los envases y evite  la entrada de contaminantes en el interior de los mismos. Esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(571 AS Decimal(6, 0)), N'3              ', N'En el caso de elaboradores / envasadores:
Dispone de local específico o zona (dentro del almacén de producto final) para el almacenamiento de cápsulas, etiquetas, embalajes etc.
', N'Dispondrá de local especifico para el almacenamiento de cápsulas, etiquetas y embalajes, con la salvedad establecida en el punto 572.', N' ', N'Dispondrá de local especifico para el almacenamiento de cápsulas, etiquetas y embalajes, con la salvedad establecida en el punto 572.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(527 AS Decimal(6, 0)), N'3              ', N'En el caso de utilizar huevos sucios como materia prima:, Dispone de local para la limpieza de éstos. ', N'Si se utilizan huevos sucios como materia prima, dispondrá de un local destinado a la limpieza y desinfección de huevos sucios, distinto al de cascado o a otros locales donde se manipule el contenido de los huevos.', N' ', N'Si se utilizan huevos sucios como materia prima, dispondrá de un local destinado a la limpieza y desinfección de huevos sucios, distinto al de cascado o a otros locales donde se manipule el contenido de los huevos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(528 AS Decimal(6, 0)), N'3              ', N'Dispone de zona para la limpieza de útiles o, en el caso de reutilizar envases, local para el lavado e higienización de los mismos y para las labores de limpieza de útiles.', N'Zona, suficientemente diferenciada, para la limpieza y desinfección de útiles y recipientes de trabajo o, en el caso de utilizar envases retornables, local para la limpieza e higienización de los mismos. Este local podrá usarse, también, como almacén de envases retornables sin higienizar y no será necesario si estas operaciones se realizan en otro establecimiento.', N' ', N'Zona, suficientemente diferenciada, para la limpieza y desinfección de útiles y recipientes de trabajo o, en el caso de utilizar envases retornables, local para la limpieza e higienización de los mismos. Este local podrá usarse, también, como almacén de envases retornables sin higienizar y no será necesario si estas operaciones se realizan en otro establecimiento.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(530 AS Decimal(6, 0)), N'3              ', N'Si se utilizan en el proceso productivo: Dispone de local para el almacenamiento de otros productos alimenticios y  aditivos.', N'Si la actividad de la empresa es la de elaborar ovoproductos que requieran aditivos, o adición de otros productos alimenticios, dispondrá de local o dispositivo para el almacenamiento de los mismos, que reúna las condiciones específicas para su correcto mantenimiento. ', N' ', N'Si la actividad de la empresa es la de elaborar ovoproductos que requieran aditivos, o adición de otros productos alimenticios, dispondrá de local o dispositivo para el almacenamiento de los mismos, que reúna las condiciones específicas para su correcto mantenimiento. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(531 AS Decimal(6, 0)), N'3              ', N'Dispone de laboratorio propio o concertado para el análisis de todos los lotes elaborados.', N'Laboratorio propio o concertado para el análisis microbiológico de todos los lotes.', N' ', N'Laboratorio propio o concertado para el análisis microbiológico de todos los lotes.')
