INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(608 AS Decimal(6, 0)), N'59             ', N'Se aprecian y figuran indicaciones alusivas al tipo de alimentación, enriquecimiento de hierro y recomendaciones expresas.', N'En el etiquetado de estos productos figurarán además
Una indicación precisando que el producto es adecuado para la alimentación especial de lactantes desde el nacimiento, cuando no sean amamantados.
En el caso de que estos productos no estén enriquecidos con hierro, una indicación precisando que cuando el producto se administre a ni¦os mayores de cuatro meses las necesidades totales de hierro de los mismos deben satisfacerse mediante otras fuentes adecuadas.
Una indicación relativa a la superioridad de la lactancia materna y la recomendación de que el producto ha de utilizarse únicamente por el consejo de personas independientes cualificadas en medicina, nutrición, o farmacia, o de otros profesionales encargados de la asistencia materna e infantil, precedidas de la mención Aviso importante u otra equivalente.', N' ', N'En el etiquetado de estos productos figurarán además
Una indicación precisando que el producto es adecuado para la alimentación especial de lactantes desde el nacimiento, cuando no sean amamantados.
En el caso de que estos productos no estén enriquecidos con hierro, una indicación precisando que cuando el producto se administre a ni¦os mayores de cuatro meses las necesidades totales de hierro de los mismos deben satisfacerse mediante otras fuentes adecuadas.
Una indicación relativa a la superioridad de la lactancia materna y la recomendación de que el producto ha de utilizarse únicamente por el consejo de personas independientes cualificadas en medicina, nutrición, o farmacia, o de otros profesionales encargados de la asistencia materna e infantil, precedidas de la mención Aviso importante u otra equivalente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(614 AS Decimal(6, 0)), N'61             ', N'Se aprecia y figura indicada la información nutricional completa en preparados a base de cereales y alimentos infantiles para lactantes y ni¦os de corta edad.', N'En el etiquetado de estos productos figurarán la siguiente información nutricional:
El valor energético disponible, expresado en kilojulios y kilocalorías y el contenido de hidratos de carbono, proteínas y grasas expresados en forma numérica por cada 100 g o 100 ml del producto en su forma de comercialización y, cuando proceda, por la cantidad del producto propuesta para el consumo.
La cantidad media, expresada en forma numérica por cada 100 g o 100 ml del producto en su forma de comercialización y, cuando proceda, por la cantidad del producto propuesta para el consumo, de cada una de las siguientes sustancias minerales y vitaminas: Sodio, calcio, tiamina, vitamina A y vitamina C en los alimentos elaborados a base de cereales
Sodio, vitamina A, vitamina C y vitamina D en los alimentos distintos de los elaborados a base de cereales.
', N' ', N'En el etiquetado de estos productos figurarán la siguiente información nutricional:
El valor energético disponible, expresado en kilojulios y kilocalorías y el contenido de hidratos de carbono, proteínas y grasas expresados en forma numérica por cada 100 g o 100 ml del producto en su forma de comercialización y, cuando proceda, por la cantidad del producto propuesta para el consumo.
La cantidad media, expresada en forma numérica por cada 100 g o 100 ml del producto en su forma de comercialización y, cuando proceda, por la cantidad del producto propuesta para el consumo, de cada una de las siguientes sustancias minerales y vitaminas: Sodio, calcio, tiamina, vitamina A y vitamina C en los alimentos elaborados a base de cereales
Sodio, vitamina A, vitamina C y vitamina D en los alimentos distintos de los elaborados a base de cereales.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(573 AS Decimal(6, 0)), N'3              ', N'Dispone de local previo o de algún sistema permanente que impida la entrada de vehículos al interior del almacén de producto final envasado.', N'El local de almacenamiento de producto terminado, envasado, dispondrá un  local previo, destinado a las labores de carga / descarga. Dicho local estará  totalmente independizado del local de almacén y en el mismo  estará permitida la entrada de vehículos.
En su defecto el local de almacenamiento de producto final deberá  contar con algún sistema permanente que impida que los vehículos accedan al interior del mismo, de manera que las labores de carga / descarga se realicen siembre en el exterior del establecimiento
', N' ', N'El local de almacenamiento de producto terminado, envasado, dispondrá un  local previo, destinado a las labores de carga / descarga. Dicho local estará  totalmente independizado del local de almacén y en el mismo  estará permitida la entrada de vehículos.
En su defecto el local de almacenamiento de producto final deberá  contar con algún sistema permanente que impida que los vehículos accedan al interior del mismo, de manera que las labores de carga / descarga se realicen siembre en el exterior del establecimiento
')
GO
