INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(588 AS Decimal(6, 0)), N'3              ', N'Dispone de zona de carga y descarga adecuado a su actividad.', N'Dispondrá de una zona de carga y descarga sin que sea necesario su separación de la zona de almacenamiento, siempre y cuando existan dispositivos que impidan el acceso de vehículos al local; en caso de no existir dichos dispositivos, existirán un local de almacenamiento y otro de carga y descarga o vestíbulo aislados. No existirá acceso desde el local de almacenamiento de los productos envasados a zonas de manipulación o elaboración.', N' ', N'Dispondrá de una zona de carga y descarga sin que sea necesario su separación de la zona de almacenamiento, siempre y cuando existan dispositivos que impidan el acceso de vehículos al local; en caso de no existir dichos dispositivos, existirán un local de almacenamiento y otro de carga y descarga o vestíbulo aislados. No existirá acceso desde el local de almacenamiento de los productos envasados a zonas de manipulación o elaboración.')
GO
