INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(578 AS Decimal(6, 0)), N'58             ', N'En función de su actividad (elaborador, elaborador/envasador o solo envasador) dispone de toda la maquinaria y equipamiento necesario en cada fase del proceso.', N'Este tipo de industrias dispondrá de instalaciones y maquinaria automática o semiautomática (Por Ej. envasadora/taponadora con alimentación manual o semi manual de envases) adecuadas al volumen de producción.
En función de la actividad (elaboradores, solo envasadores,  elaboradores-envasadores) dispondrán, mínimamente, de la maquinaria e instalaciones necesarias para:
Estrujado / prensado
Depósitos  de elaboración / almacenamiento
Trasiego
Filtrado
Envasado
Taponado
', N' ', N'Este tipo de industrias dispondrá de instalaciones y maquinaria automática o semiautomática (Por Ej. envasadora/taponadora con alimentación manual o semi manual de envases) adecuadas al volumen de producción.
