INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(597 AS Decimal(6, 0)), N'32             ', N'Los productos que comercializa tienen la documentación que acredita su adecuación como dietéticos.', N'La empresa dispondrá de la siguiente documentación en relación con los productos que comercializa:
Si se trata de envasadores y/o elaboradores :
Documento emitido por el Departamento de Sanidad que acredite la adecuación de la comercialización de los productos como dietéticos en la categoría que le corresponda.
Documento del Ministerio de Sanidad y Consumo en el que se refleje el número de registro específico para productos dietéticos adjudicado por el Registro General Sanitario de Alimentos.
Si se trata de almacenistas (es decir se trata de una segunda comercialización):
Documento que refleje el Nº de Registro General Sanitario específico de los productos que avala su inclusión en la categoría de dietéticos.', N' ', N'La empresa dispondrá de la siguiente documentación en relación con los productos que comercializa:
Si se trata de envasadores y/o elaboradores :
Documento emitido por el Departamento de Sanidad que acredite la adecuación de la comercialización de los productos como dietéticos en la categoría que le corresponda.
Documento del Ministerio de Sanidad y Consumo en el que se refleje el número de registro específico para productos dietéticos adjudicado por el Registro General Sanitario de Alimentos.
Si se trata de almacenistas (es decir se trata de una segunda comercialización):
Documento que refleje el Nº de Registro General Sanitario específico de los productos que avala su inclusión en la categoría de dietéticos.')
GO
