INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1884 AS Decimal(6, 0)), N'3              ', N'Los  establecimientos de tratamiento disponen de una zona de recepción para los camiones cisterna.', N'Los establecimientos de tratamiento contaran con zona o muelle para recepción de los camiones cisternas. Estará situada fuera del local de almacenamiento de leche o, en el caso de tanques situados en el exterior, en una zona que no suponga ningún riesgo para el producto durante las operaciones de carga y descarga. Hay que tener en cuenta que normalmente la leche circula por circuitos cerrados desde la cisterna a los tanques y viceversa. Contará con un lavamanos de accionamiento no manual y útiles de aseo para que sea utilizado por el conductor del camión cisterna antes y después de la descarga.
', N'Los  establecimientos de tratamiento disponen de una zona de recepción para los camiones cisterna.', N'Los establecimientos de tratamiento contaran con zona o muelle para recepción de los camiones cisternas. Estará situada fuera del local de almacenamiento de leche o, en el caso de tanques situados en el exterior, en una zona que no suponga ningún riesgo para el producto durante las operaciones de carga y descarga. Hay que tener en cuenta que normalmente la leche circula por circuitos cerrados desde la cisterna a los tanques y viceversa. Contará con un lavamanos de accionamiento no manual y útiles de aseo para que sea utilizado por el conductor del camión cisterna antes y después de la descarga.
')
GO
