INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1905 AS Decimal(6, 0)), N'10             ', N'Dispone de medios mecánicos para el llenado y cierre automático de los recipientes. En el caso de llenado manual (permitido en establecimientos de poca producción) y cierre manual,   las operaciones y el dispositivo de cierre garantiza la protección del p????', N'Dispondrán de una instalación que permita efectuar mecánicamente el llenado y cierre automático de los recipientes. Este requisito no será aplicable a los bidones, las cisternas y a los envases de más de 4 litros. En el caso de cierre no automático, de un dispositivo de cierre que garantice la protección de los mismos contra las influencias nocivas del exterior.
En el caso de establecimientos de poca producción, las autoridades competentes podrán autorizar métodos de llenados alternativos que utilicen medios de llenado y de cierre que no sean automáticos siempre que dichos métodos ofrezcan garantías equivalentes.
', N'Dispone de medios mecánicos para el llenado y cierre automático de los recipientes. En el caso de llenado manual (permitido en establecimientos de poca producción) y cierre manual,   las operaciones y el dispositivo de cierre garantiza la protección del p????', N'Dispondrán de una instalación que permita efectuar mecánicamente el llenado y cierre automático de los recipientes. Este requisito no será aplicable a los bidones, las cisternas y a los envases de más de 4 litros. En el caso de cierre no automático, de un dispositivo de cierre que garantice la protección de los mismos contra las influencias nocivas del exterior.
En el caso de establecimientos de poca producción, las autoridades competentes podrán autorizar métodos de llenados alternativos que utilicen medios de llenado y de cierre que no sean automáticos siempre que dichos métodos ofrezcan garantías equivalentes.
')
GO
