INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1848 AS Decimal(6, 0)), N'32             ', N'La maquinaria y utillaje empleados en la elaboración ó transformación de los MCA, no altera las especificaciones de las materias primas ni de los productos terminados.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La maquinaria y utillaje empleados en la elaboración ó transformación de los MCA, no alterará las especificaciones de las materias primas, ni de los productos terminados.', N'La maquinaria y utillaje empleados en la elaboración ó transformación de los MCA, no altera las especificaciones de las materias primas ni de los productos terminados.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La maquinaria y utillaje empleados en la elaboración ó transformación de los MCA, no alterará las especificaciones de las materias primas, ni de los productos terminados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1856 AS Decimal(6, 0)), N'3              ', N'En los centros de recogida o centros de normalización, existe zona con dispositivos para la limpieza de las cisternas utilizadas  para el transporte de leche. Dispone de justificante en el caso de que la limpieza se efectúe en instalaciones oficialmente a????', N'Dispondrá de zona con dispositivos para la limpieza y desinfección de las cisternas utilizadas para el transporte de la leche. No obstante, dichos equipos no serán obligatorios cuando existan disposiciones que permitan la limpieza y desinfección de los medios de transporte en instalaciones oficialmente autorizadas. Después de cada transporte, o cada serie de transportes, cuando entre la descarga y la carga siguiente únicamente transcurra un lapso de tiempo corto, y en todo caso por lo menos una vez al día, los recipientes y las cisternas que se han empleado para el transporte de leche cruda se limpiarán y desinfectarán antes de volver a utilizarse.', N'En los centros de recogida o centros de normalización, existe zona con dispositivos para la limpieza de las cisternas utilizadas  para el transporte de leche. Dispone de justificante en el caso de que la limpieza se efectúe en instalaciones oficialmente a????', N'Dispondrá de zona con dispositivos para la limpieza y desinfección de las cisternas utilizadas para el transporte de la leche. No obstante, dichos equipos no serán obligatorios cuando existan disposiciones que permitan la limpieza y desinfección de los medios de transporte en instalaciones oficialmente autorizadas. Después de cada transporte, o cada serie de transportes, cuando entre la descarga y la carga siguiente únicamente transcurra un lapso de tiempo corto, y en todo caso por lo menos una vez al día, los recipientes y las cisternas que se han empleado para el transporte de leche cruda se limpiarán y desinfectarán antes de volver a utilizarse.')
GO
