INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(328 AS Decimal(6, 0)), N'40             ', N'El sistema de producción de la cadena de sacrificio permite en todo momento establecer la trazabilidad de todos los productos obtenidos del animal (canal-despojos).', N'Sistema de trazabilidad en la cadena de  producción.
El sistema de producción del matadero, permitirá establecer la trazabilidad entre los animales vivos y las canales, vísceras, subproductos y pieles.
El sistema de producción permitirá en todo momento establecer la trazabilidad en todos los productos obtenidos del animal, de forma que tras la evisceración, el pulmón, el corazón, el hígado, el bazo y el mediastino podrán o bien separarse, o dejarse adheridos a la canal por sus conexiones anatómicas. En caso de separarse, deberá dotarseles de un número o de cualquier otro medio de identificación que permita reconocer su pertenencia a la canal. Esto será válido igualmente para la cabeza, la lengua, el tubo digestivo, ri¦ones y cualquier otra parte del animal necesaria para la inspección o realización de controles sanitarios previstos por normativa.
La aptitud para consumo de las carnes se llevará a cabo con anterioridad a su desaparición de la nave de matanza o de los locales en los que estén situados.
En el ganado vacuno, el sistema de producción mantendrá la correspondencia con identificación originaria del animal (crotal orejero) a lo largo de todo el proceso de carnización hasta que la canal sea apta para el consumo.', N'El sistema de producción de la cadena de sacrificio permite en todo momento establecer la trazabilidad de todos los productos obtenidos del animal (canal-despojos).', N'Sistema de trazabilidad en la cadena de  producción.
El sistema de producción del matadero, permitirá establecer la trazabilidad entre los animales vivos y las canales, vísceras, subproductos y pieles.
El sistema de producción permitirá en todo momento establecer la trazabilidad en todos los productos obtenidos del animal, de forma que tras la evisceración, el pulmón, el corazón, el hígado, el bazo y el mediastino podrán o bien separarse, o dejarse adheridos a la canal por sus conexiones anatómicas. En caso de separarse, deberá dotarseles de un número o de cualquier otro medio de identificación que permita reconocer su pertenencia a la canal. Esto será válido igualmente para la cabeza, la lengua, el tubo digestivo, ri¦ones y cualquier otra parte del animal necesaria para la inspección o realización de controles sanitarios previstos por normativa.
La aptitud para consumo de las carnes se llevará a cabo con anterioridad a su desaparición de la nave de matanza o de los locales en los que estén situados.
En el ganado vacuno, el sistema de producción mantendrá la correspondencia con identificación originaria del animal (crotal orejero) a lo largo de todo el proceso de carnización hasta que la canal sea apta para el consumo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(323 AS Decimal(6, 0)), N'39             ', N'La sangre envasada para consumo humano se etiqueta con los datos de la industria, fecha de envasado y marca sanitaria.', N'La sangre envasada para consumo humano se etiquetará el recipiente con los  datos de la industria, fecha de envasado y marca sanitaria. La etiqueta se colocará a modo de precinto en el cierre del envase, de forma que al abrirlo se produzca la rotura de la misma.', N'La sangre envasada para consumo humano se etiqueta con los datos de la industria, fecha de envasado y marca sanitaria.', N'La sangre envasada para consumo humano se etiquetará el recipiente con los  datos de la industria, fecha de envasado y marca sanitaria. La etiqueta se colocará a modo de precinto en el cierre del envase, de forma que al abrirlo se produzca la rotura de la misma.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(293 AS Decimal(6, 0)), N'44             ', N'Las pezu¦as ,patas, cuernos,.. no se acumulan en la nave de sacrificio.', N'Las pezu¦as, patas, cuernos se eliminaran  inmediatamente de la nave de sacrificio o se depositarán en contenedores específicos hasta su retirada de la nave, no se depositarán en el suelo de la nave de sacrificio para su recogida posterior en los contenedores. ', N'Las pezu¦as ,patas, cuernos,.. no se acumulan en la nave de sacrificio.', N'Las pezu¦as, patas, cuernos se eliminaran  inmediatamente de la nave de sacrificio o se depositarán en contenedores específicos hasta su retirada de la nave, no se depositarán en el suelo de la nave de sacrificio para su recogida posterior en los contenedores. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(311 AS Decimal(6, 0)), N'32             ', N'En las operaciones de acabado-duchado de las canales se evitan las salpicaduras y contaminaciones cruzadas.', N'El duchado de canales se realizará con agua potable después de completarse la inspección  post-mortem y antes de pasar a las cámaras. Se procederá al duchado evitando que el agua salpique. Se tomarán las debidas precauciones para evitar la contaminación de las carnes frescas por el óxido, el enmohecimiento o cualquier otra consecuencia negativa del uso del agua.', N'En las operaciones de acabado-duchado de las canales se evitan las salpicaduras y contaminaciones cruzadas.', N'El duchado de canales se realizará con agua potable después de completarse la inspección  post-mortem y antes de pasar a las cámaras. Se procederá al duchado evitando que el agua salpique. Se tomarán las debidas precauciones para evitar la contaminación de las carnes frescas por el óxido, el enmohecimiento o cualquier otra consecuencia negativa del uso del agua.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(297 AS Decimal(6, 0)), N'44             ', N'La apertura de las cavidades torácica y abdominal se realiza evitando la rotura de los órganos internos y en su caso se realiza el expurgo inmediato de la zona afectada.', N'Se realizará el corte del esternón evitando rotura de órganos internos. Si se produjese rotura de los mismos se procederá al expurgo y limpieza de la zona de la canal que haya sufrido manchas de sangre o suciedad.', N'La apertura de las cavidades torácica y abdominal se realiza evitando la rotura de los órganos internos y en su caso se realiza el expurgo inmediato de la zona afectada.', N'Se realizará el corte del esternón evitando rotura de órganos internos. Si se produjese rotura de los mismos se procederá al expurgo y limpieza de la zona de la canal que haya sufrido manchas de sangre o suciedad.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(298 AS Decimal(6, 0)), N'44             ', N'Se realiza ligadura de esófago y recto en todas las especies.', N'Durante el eviscerado se adoptarán medidas para prevenir la contaminación de la canal por el contenido del intestino, y contenido del estómago procediéndose a la ligadura del esófago y recto mediante sistemas que garanticen el cierre completo de los mismos.', N'Se realiza ligadura de esófago y recto en todas las especies.', N'Durante el eviscerado se adoptarán medidas para prevenir la contaminación de la canal por el contenido del intestino, y contenido del estómago procediéndose a la ligadura del esófago y recto mediante sistemas que garanticen el cierre completo de los mismos.')
GO
