INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(300 AS Decimal(6, 0)), N'44             ', N'La evisceración se lleva a cabo en un tiempo que  evite aumento de contaminación tras el aturdimiento.', N'La evisceración se llevará a cabo en un tiempo que evite aumento de contaminación tras el aturdimiento.', N'La evisceración se lleva a cabo en un tiempo que  evite aumento de contaminación tras el aturdimiento.', N'La evisceración se llevará a cabo en un tiempo que evite aumento de contaminación tras el aturdimiento.')
