INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(306 AS Decimal(6, 0)), N'45             ', N'Los MER no se acumulan en la nave de sacrificio .', N'La evacuación de los MER de la nave de matanza se realizará con la frecuencia que marque el ritmo de la cadena de sacrificio sin que se produzca acumulo de los mismos. ', N'Los MER no se acumulan en la nave de sacrificio .', N'La evacuación de los MER de la nave de matanza se realizará con la frecuencia que marque el ritmo de la cadena de sacrificio sin que se produzca acumulo de los mismos. ')
