INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(290 AS Decimal(6, 0)), N'44             ', N'Las operaciones de la cuba de escaldado respetan las condiciones de Tª, Nº de animales y Tiempo de permanencia de los mismos en la cuba. ', N'Se respetarán las siguientes normas de higiene:
El agua de escaldado debe mantenerse a Tª constante (62-64ºC.)
El número de animales que se sumergen en la cuba debe respetar la capacidad máxima de ésta de acuerdo con las especificaciones técnicas de la misma.
El tiempo de permanencia en la cuba no debe ser superior al estipulado por las características técnicas de la misma. ', N'Las operaciones de la cuba de escaldado respetan las condiciones de Tª, Nº de animales y Tiempo de permanencia de los mismos en la cuba. ', N'Se respetarán las siguientes normas de higiene:
El agua de escaldado debe mantenerse a Tª constante (62-64ºC.)
El número de animales que se sumergen en la cuba debe respetar la capacidad máxima de ésta de acuerdo con las especificaciones técnicas de la misma.
El tiempo de permanencia en la cuba no debe ser superior al estipulado por las características técnicas de la misma. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(291 AS Decimal(6, 0)), N'44             ', N'Se realiza la eliminación completa de pelos, cerdas etc.', N'La eliminación de pelos, cerdas y restos de chamuscado y suciedad debe ser completa antes de proceder a la evisceración. Si tras realizar esta tarea mecánicamente quedasen restos de cerdas, pelos etc. se procederá al repasado manual de las mismas para su eliminación completa antes del eviscerado.', N'Se realiza la eliminación completa de pelos, cerdas etc.', N'La eliminación de pelos, cerdas y restos de chamuscado y suciedad debe ser completa antes de proceder a la evisceración. Si tras realizar esta tarea mecánicamente quedasen restos de cerdas, pelos etc. se procederá al repasado manual de las mismas para su eliminación completa antes del eviscerado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(292 AS Decimal(6, 0)), N'44             ', N'Las pezu¦as de los porcinos se eliminan completamente.', N'Las pezu¦as de los porcinos deben ser  retiradas completamente.', N'Las pezu¦as de los porcinos se eliminan completamente.', N'Las pezu¦as de los porcinos deben ser  retiradas completamente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(302 AS Decimal(6, 0)), N'45             ', N'La columna vertebral de los vacunos de más de 30 meses se retira de acuerdo a las instrucciones.', N'Retirada de la médula espinal-esquinado:
Se empleará un sistema autorizado para la extracción de la médula espinal antes de proceder al esquinado de la canal en las reses vacunas ovinas y caprinas mayores de 30 meses que garantice la eliminación de la médula espinal antes de proceder a la apertura del canal medular.
Si no se realiza la aspiración medular, debe realizarse el esquinado de manera que el canal medular quede sin abrir.
Las operaciones de extracción de la columna vertebral se podrá realizar en la propia cadena de sacrificio o se podrá llevar a cabo en un local o zona específica para este fin. En este último caso las labores de extracción de las columnas se realizaran siempre en esta ubicación no permitiéndose simultanear esta actividad con cualquier otra de manipulación de carnes en dicha zona o local, incluidas labores de carga, almacenamiento de canales, etc.
En cualquier caso ,se evitará el balanceo mediante un sistema de anclaje para la sujección de las medias canales que permita practicar el corte sin desviaciones .
Las tareas de extracción se realizarán en un tiempo que no permita la elevación de la temperatura de las canales, si no es así el local o zona habilitada, estará climatizado a temperatura inferior a 12 grados.
Se procederá a la extracción de la columna vertebral completa obteniendo la pieza entera sin fraccionamientos.
En el proceso de corte se evitará la difusión de serrines tanto en paredes y materiales circundantes como en el suelo, procediéndose a su recogida inmediata y depósito en el contenedor específico del MER.', N'La columna vertebral de los vacunos de más de 30 meses se retira de acuerdo a las instrucciones.', N'Retirada de la médula espinal-esquinado:
Se empleará un sistema autorizado para la extracción de la médula espinal antes de proceder al esquinado de la canal en las reses vacunas ovinas y caprinas mayores de 30 meses que garantice la eliminación de la médula espinal antes de proceder a la apertura del canal medular.
Si no se realiza la aspiración medular, debe realizarse el esquinado de manera que el canal medular quede sin abrir.
Las operaciones de extracción de la columna vertebral se podrá realizar en la propia cadena de sacrificio o se podrá llevar a cabo en un local o zona específica para este fin. En este último caso las labores de extracción de las columnas se realizaran siempre en esta ubicación no permitiéndose simultanear esta actividad con cualquier otra de manipulación de carnes en dicha zona o local, incluidas labores de carga, almacenamiento de canales, etc.
En cualquier caso ,se evitará el balanceo mediante un sistema de anclaje para la sujección de las medias canales que permita practicar el corte sin desviaciones .
Las tareas de extracción se realizarán en un tiempo que no permita la elevación de la temperatura de las canales, si no es así el local o zona habilitada, estará climatizado a temperatura inferior a 12 grados.
Se procederá a la extracción de la columna vertebral completa obteniendo la pieza entera sin fraccionamientos.
En el proceso de corte se evitará la difusión de serrines tanto en paredes y materiales circundantes como en el suelo, procediéndose a su recogida inmediata y depósito en el contenedor específico del MER.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(303 AS Decimal(6, 0)), N'45             ', N'La retirada de MER se realiza con un cuchillo diferenciado de uso exclusivo.', N'La retirada de MER de la canal se realizará siempre con un cuchillo diferenciado (color o sistema equivalente) de uso exclusivo para éste fin.', N'La retirada de MER se realiza con un cuchillo diferenciado de uso exclusivo.', N'La retirada de MER de la canal se realizará siempre con un cuchillo diferenciado (color o sistema equivalente) de uso exclusivo para éste fin.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(305 AS Decimal(6, 0)), N'45             ', N'Los MER se ti¦en inmediatamente.', N'Se realizará la  tinción inmediata tras el depósito en los contenedores.', N'Los MER se ti¦en inmediatamente.', N'Se realizará la  tinción inmediata tras el depósito en los contenedores.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1849 AS Decimal(6, 0)), N'32             ', N'En las plantas de elaboración y muy especialmente en los almacenes de materias primas o productos acabados, existe separación que garantiza que no se produzcan errores entre los productos que se destinan a artículos de uso alimentario y aquellos otros des????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
En las plantas de elaboración y transformación, y muy especialmente en los almacenes de materias primas o productos acabados, deberá existir el orden y la debida separación entre productos, para garantizar que no puedan existir contaminaciones o errores entre aquellos que se destinan a artículos de uso alimentario con aquellos otros que puedan destinarse a otros fines.', N'En las plantas de elaboración y muy especialmente en los almacenes de materias primas o productos acabados, existe separación que garantiza que no se produzcan errores entre los productos que se destinan a artículos de uso alimentario y aquellos otros des????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
En las plantas de elaboración y transformación, y muy especialmente en los almacenes de materias primas o productos acabados, deberá existir el orden y la debida separación entre productos, para garantizar que no puedan existir contaminaciones o errores entre aquellos que se destinan a artículos de uso alimentario con aquellos otros que puedan destinarse a otros fines.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(301 AS Decimal(6, 0)), N'45             ', N'La retirada de MER es completa.', N'La retirada de MER (material específico de riesgo) debe ser completa, asegurándose que no quedan restos en la canal-vísceras.Los materiales específicos de riesgo son los siguientes:
vacuno: el cráneo, excluida la mandíbula e incluidos el cerebro y los ojos y la médula espinal de los bovinos mayores de 12 meses, la columna vertebral, excluidas las vértebras cervicales, torácicas y lumbares y la creta media y las alas del sacro, pero incluidos los ganglios de la raíz dorsal, de los animales mayores de 30 meses, así como las amígdalas, los intestinos desde el duodeno hasta el recto y el mesenterio de los bovinos de todas las edades. ovino y caprino: el cráneo (incluido el cerebro y los ojos), las amígdalas y la médula espinal de los ovinos y caprinos de más de 12 meses o en cuya encía haya hecho erupción un incisivo definitivo y el bazo de los ovinos y caprinos de todas las edades.', N'La retirada de MER es completa.', N'La retirada de MER (material específico de riesgo) debe ser completa, asegurándose que no quedan restos en la canal-vísceras.Los materiales específicos de riesgo son los siguientes:
vacuno: el cráneo, excluida la mandíbula e incluidos el cerebro y los ojos y la médula espinal de los bovinos mayores de 12 meses, la columna vertebral, excluidas las vértebras cervicales, torácicas y lumbares y la creta media y las alas del sacro, pero incluidos los ganglios de la raíz dorsal, de los animales mayores de 30 meses, así como las amígdalas, los intestinos desde el duodeno hasta el recto y el mesenterio de los bovinos de todas las edades. ovino y caprino: el cráneo (incluido el cerebro y los ojos), las amígdalas y la médula espinal de los ovinos y caprinos de más de 12 meses o en cuya encía haya hecho erupción un incisivo definitivo y el bazo de los ovinos y caprinos de todas las edades.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(313 AS Decimal(6, 0)), N'32             ', N'El almacenamiento de las carnes en refrigeración o congelación (según proceda) se realiza de forma inmediata a la obtención de las mismas.', N'El oreo y refrigeración de las canales se realizará inmediatamente a la obtención de las canales en la línea de sacrificio.
La congelación de canales, las medias canales, las medias canales despiezadas en un máximo de tres piezas, los cuartos, los subproductos y despojos se realizará inmediatamente después de su maduración.', N'El almacenamiento de las carnes en refrigeración o congelación (según proceda) se realiza de forma inmediata a la obtención de las mismas.', N'El oreo y refrigeración de las canales se realizará inmediatamente a la obtención de las canales en la línea de sacrificio.
La congelación de canales, las medias canales, las medias canales despiezadas en un máximo de tres piezas, los cuartos, los subproductos y despojos se realizará inmediatamente después de su maduración.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(318 AS Decimal(6, 0)), N'32             ', N'Los resultados analíticos se encuentran dentro de los valores aceptables y en su defecto se ha procedido a la realización de una correcta limpieza y desinfección de dichas superficies, evitando que se repitan valores inaceptables.', N'Los valores de referencia serán loa siguientes(*):
  
Valores aceptables:
  Recuento total de colonias aeróbicas (TVC): 0-10/cm2
  Enterobacterias: 0-1/cm2

Valores inaceptables:
  Recuento total de colonias aeróbicas (TVC): > 10/cm2
  Enterobacterias: > 1/cm2

(*) Referidos a valores medios del número de colonias en los análisis de superficies.', N'Los resultados analíticos se encuentran dentro de los valores aceptables y en su defecto se ha procedido a la realización de una correcta limpieza y desinfección de dichas superficies, evitando que se repitan valores inaceptables.', N'Los valores de referencia serán loa siguientes(*):
  
Valores aceptables:
  Recuento total de colonias aeróbicas (TVC): 0-10/cm2
  Enterobacterias: 0-1/cm2

Valores inaceptables:
  Recuento total de colonias aeróbicas (TVC): > 10/cm2
  Enterobacterias: > 1/cm2

(*) Referidos a valores medios del número de colonias en los análisis de superficies.')
GO
