INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(320 AS Decimal(6, 0)), N'39             ', N'En el sistema de etiquetado facultativo, aparecen indicadas las menciones correspondientes.', N'Sistema de etiquetado facultativo de la carne de vacuno:
Nombre y/o logotipo del agente económico u organización solicitante.
Las menciones obligatorias.
Caso de incluir otra información debe contar con autorización expresa.
Caso de incluir menciones geográficas o que hagan referencia al origen, deberán expresar obligatoriamente y de forma conjunta las siguientes leyendas:
Lugar de nacimiento: (mención elegida).
Lugar/es de cría: (mención elegida).
Lugar de sacrificio: (mención elegida).
Podrá hacerse una única mención cuando coincidan origen, cría y sacrificio.
No se permitirá mención alguna que induzca a confusión o error y que no sea demostrable y controlable.', N'En el sistema de etiquetado facultativo, aparecen indicadas las menciones correspondientes.', N'Sistema de etiquetado facultativo de la carne de vacuno:
Nombre y/o logotipo del agente económico u organización solicitante.
Las menciones obligatorias.
Caso de incluir otra información debe contar con autorización expresa.
Caso de incluir menciones geográficas o que hagan referencia al origen, deberán expresar obligatoriamente y de forma conjunta las siguientes leyendas:
Lugar de nacimiento: (mención elegida).
Lugar/es de cría: (mención elegida).
Lugar de sacrificio: (mención elegida).
Podrá hacerse una única mención cuando coincidan origen, cría y sacrificio.
No se permitirá mención alguna que induzca a confusión o error y que no sea demostrable y controlable.')
GO
