INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(317 AS Decimal(6, 0)), N'32             ', N'La industria realiza análisis microbiológicos periódicos de superficies.', N'Las superficies y utensilios serán sometidas a Controles Regulares de Higiene mediante análisis microbiológicos suficientes.', N'La industria realiza análisis microbiológicos periódicos de superficies.', N'Las superficies y utensilios serán sometidas a Controles Regulares de Higiene mediante análisis microbiológicos suficientes.')
