INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(312 AS Decimal(6, 0)), N'32             ', N'Las canales y carnes consignadas o decomisadas se eliminan de la cadena de sacrificio de forma higiénica.', N'Las canales consignadas o decomisadas circularán por el ráil independiente para su retirada, que conducirá directamente a las instalaciones reservadas para dichas carnes. Dicho carril deberá salir del riel normal inmediatamente despues del lugar en el que se complete la inspección post-mortem. Podrá salir del riel normal después de la operación de pesado de la canal, siempre  y cuando se evite el contacto entre canales  durante dicho pesado. Esta línea no deberá cruzar ni tocar la línea normal. Se preferirá un bucle con uniones de los rieles que permitan la evacuación hacia las instalaciones para carnes consignadas y al área de espurgo o almacenamiento de las carnes decomisadas.
En el caso en que no sea posible instalar un raíl independiente para evacuar las carnes consignadas hacia las instalaciones, dichas carnes podrán desplazarse por el raíl normal, siempre que exista un sistema mecánico que impida el contacto entre las canales sobre el raíl.
En caso de no existir dicho sistema mecánico para la separación de canales, se aprovecharan las pausas en el trabajo para trasladarlas, siempre que no se retrase su retirada. En este caso, habrán de colocarse instalaciones apropiadas para la retirada de las canales consignadas cuando se modernice o reorganice la línea.
Las carnes de claradas no aptas para consumo se retirarán de la línea de sacrificio tan pronto como el inspector determine su inaptitud para consumo.', N'Las canales y carnes consignadas o decomisadas se eliminan de la cadena de sacrificio de forma higiénica.', N'Las canales consignadas o decomisadas circularán por el ráil independiente para su retirada, que conducirá directamente a las instalaciones reservadas para dichas carnes. Dicho carril deberá salir del riel normal inmediatamente despues del lugar en el que se complete la inspección post-mortem. Podrá salir del riel normal después de la operación de pesado de la canal, siempre  y cuando se evite el contacto entre canales  durante dicho pesado. Esta línea no deberá cruzar ni tocar la línea normal. Se preferirá un bucle con uniones de los rieles que permitan la evacuación hacia las instalaciones para carnes consignadas y al área de espurgo o almacenamiento de las carnes decomisadas.
En el caso en que no sea posible instalar un raíl independiente para evacuar las carnes consignadas hacia las instalaciones, dichas carnes podrán desplazarse por el raíl normal, siempre que exista un sistema mecánico que impida el contacto entre las canales sobre el raíl.
En caso de no existir dicho sistema mecánico para la separación de canales, se aprovecharan las pausas en el trabajo para trasladarlas, siempre que no se retrase su retirada. En este caso, habrán de colocarse instalaciones apropiadas para la retirada de las canales consignadas cuando se modernice o reorganice la línea.
Las carnes de claradas no aptas para consumo se retirarán de la línea de sacrificio tan pronto como el inspector determine su inaptitud para consumo.')
GO
