INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(329 AS Decimal(6, 0)), N'40             ', N'En el transporte de las carnes del matadero a destino van acompa¦adas del documento comercial de acompa¦amiento de carnes.', N'Las carnes durante el transporte irán acompa¦adas de un documento de acompa¦amiento comercial  que reunirá los siguientes requisitos:
Deberá ser emitido por el establecimiento de expedición.
Deberá llevar preimpreso la marca sanitaria del establecimiento (sello de inspección veterinaria)
En dicho documento figurará como mínimo el número de orden, la descripción del producto, naturaleza de la mercancía (en el caso de productos congelados se indicará la fecha de congelación mes/a¦o), número de piezas, peso, establecimiento expedidor y destinatario, fecha de envío.
En el caso de canales con columna vertebral, se indicará la edad o la fecha de nacimiento de los animales que proceden.', N'En el transporte de las carnes del matadero a destino van acompa¦adas del documento comercial de acompa¦amiento de carnes.', N'Las carnes durante el transporte irán acompa¦adas de un documento de acompa¦amiento comercial  que reunirá los siguientes requisitos:
Deberá ser emitido por el establecimiento de expedición.
Deberá llevar preimpreso la marca sanitaria del establecimiento (sello de inspección veterinaria)
En dicho documento figurará como mínimo el número de orden, la descripción del producto, naturaleza de la mercancía (en el caso de productos congelados se indicará la fecha de congelación mes/a¦o), número de piezas, peso, establecimiento expedidor y destinatario, fecha de envío.
En el caso de canales con columna vertebral, se indicará la edad o la fecha de nacimiento de los animales que proceden.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(314 AS Decimal(6, 0)), N'32             ', N'El almacenamiento de las carnes frescas o congeladas, según proceda se realiza y mantiene en las condiciones de temperatura requeridas.', N'Durante el almacenamiento en refrigeración, las carnes frescas y los despojos deben mantenerse a temperaturas internas iguales o inferiores a +7ªC para canales y sus trozos y a +3ºC para los despojos.
Las carnes destinadas a la congelación, deberán congelarse sin demora. Las carnes congeladas deberán alcanzar una temperatura interna igual o inferior a -12ºC y no podrán almacenarse a continuación a una temperatura superior a ésta.
Las carnes deberán mantener las características organolépticas y no superar el periodo de almacenamiento superior al de la vida útil, aún en las condiciones de temperatura, humedad, circulación de aire etc. requeridas para su correcto mantenimiento y almacenaje.', N'El almacenamiento de las carnes frescas o congeladas, según proceda se realiza y mantiene en las condiciones de temperatura requeridas.', N'Durante el almacenamiento en refrigeración, las carnes frescas y los despojos deben mantenerse a temperaturas internas iguales o inferiores a +7ªC para canales y sus trozos y a +3ºC para los despojos.
Las carnes destinadas a la congelación, deberán congelarse sin demora. Las carnes congeladas deberán alcanzar una temperatura interna igual o inferior a -12ºC y no podrán almacenarse a continuación a una temperatura superior a ésta.
Las carnes deberán mantener las características organolépticas y no superar el periodo de almacenamiento superior al de la vida útil, aún en las condiciones de temperatura, humedad, circulación de aire etc. requeridas para su correcto mantenimiento y almacenaje.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(308 AS Decimal(6, 0)), N'45             ', N'Tras la retirada de los MER se procede a la limpieza y desinfección de útiles e instalaciones con desinfectante autorizado.', N'Una  vez finalizadas las operaciones de extracción de los MER ,se procederá a la limpieza y desinfección adecuada de utensilios ,instalaciones y recipientes exclusivos con desinfectante clorado autorizado.', N'Tras la retirada de los MER se procede a la limpieza y desinfección de útiles e instalaciones con desinfectante autorizado.', N'Una  vez finalizadas las operaciones de extracción de los MER ,se procederá a la limpieza y desinfección adecuada de utensilios ,instalaciones y recipientes exclusivos con desinfectante clorado autorizado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(309 AS Decimal(6, 0)), N'45             ', N'Los MER procedentes de las cabezas se obtienen en las condiciones especificadas.', N'Los materiales MER procedentes de las cabezas de reses mayores de 12 meses de edad incluidas dentro del Programa de Control de Encefalopatías serán obtenidos en un local o zona específica que garantice  la manipulación sin contaminaciones cruzadas. ', N'Los MER procedentes de las cabezas se obtienen en las condiciones especificadas.', N'Los materiales MER procedentes de las cabezas de reses mayores de 12 meses de edad incluidas dentro del Programa de Control de Encefalopatías serán obtenidos en un local o zona específica que garantice  la manipulación sin contaminaciones cruzadas. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(310 AS Decimal(6, 0)), N'45             ', N'A las canales de vacunos mayores de 30 meses destinadas a establecimientos no autorizados se realiza la extracción de columna.', N'Las canales de vacunos de más de 30 meses de edad con destino a establecimientos no autorizados para la extracción del MER, serán sometidas a la retirada de la columna vertebral.', N'A las canales de vacunos mayores de 30 meses destinadas a establecimientos no autorizados se realiza la extracción de columna.', N'Las canales de vacunos de más de 30 meses de edad con destino a establecimientos no autorizados para la extracción del MER, serán sometidas a la retirada de la columna vertebral.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(169190 AS Decimal(6, 0)), N'72             ', N'Los operadores de la empresa alimentaria justifican que los manipuladores de alimentos han recibido formación en cuestiones de higiene alimentaria y Plan Genérico de Autocontrol acordes al puesto que desempeñan.', N'El operador económico de la empresa alimentaria es el responsable de que los manipuladores de alimentos hayan recibido formación en cuestiones de higiene alimentaria específicas a la actividad laboral que desempeñan en ella. Así mismo deberán recibir formación sobre el Plan genérico de Autocontrol, de forma que los manipuladores conozcan las prácticas de trabajo que se describen en el plan y el personal que realiza los controles conozca la forma de hacerlos, los límites aceptables y las acciones correctoras a adoptar cuando se superan los límites. El operador económico tiene también la responsabilidad de su supervisión.
La formación se puede adquirir a través de planes y programas de formación, instrucciones de trabajo, cursos, etc. Cuya asistencia y adquisición de conocimientos se deberá acreditar mediante la presentación de documentos como certificados, listados de asistencia etc., y que dicha formación será impartida bien por la propia empresa donde el manipulador trabaja, por empresas que se dedican a impartir dicha formación (sin necesidad de disponer de autorización administrativa), por asociaciones gremiales, y por escuelas de formación profesional o centros de enseñanza que dentro de su formación reglada imparten estas enseñanzas.

Cuando una empresa no disponga de capacidad para formar al personal podrá adquirirla mediante la contratación de los servicios.', N'Los operadores de la empresa alimentaria justifican que los manipuladores de alimentos han recibido formación en cuestiones de higiene alimentaria y Plan Genérico de Autocontrol acordes al puesto que desempeñan.', N'El operador económico de la empresa alimentaria es el responsable de que los manipuladores de alimentos hayan recibido formación en cuestiones de higiene alimentaria específicas a la actividad laboral que desempeñan en ella. Así mismo deberán recibir formación sobre el Plan genérico de Autocontrol, de forma que los manipuladores conozcan las prácticas de trabajo que se describen en el plan y el personal que realiza los controles conozca la forma de hacerlos, los límites aceptables y las acciones correctoras a adoptar cuando se superan los límites. El operador económico tiene también la responsabilidad de su supervisión.
La formación se puede adquirir a través de planes y programas de formación, instrucciones de trabajo, cursos, etc. Cuya asistencia y adquisición de conocimientos se deberá acreditar mediante la presentación de documentos como certificados, listados de asistencia etc., y que dicha formación será impartida bien por la propia empresa donde el manipulador trabaja, por empresas que se dedican a impartir dicha formación (sin necesidad de disponer de autorización administrativa), por asociaciones gremiales, y por escuelas de formación profesional o centros de enseñanza que dentro de su formación reglada imparten estas enseñanzas.

Cuando una empresa no disponga de capacidad para formar al personal podrá adquirirla mediante la contratación de los servicios.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(319 AS Decimal(6, 0)), N'39             ', N'En el etiquetado obligatorio de la carne de vacuno aparecen las siguientes indicaciones:
Nº de identificación animal
Identificación del matadero
País de origen
País/es de cría
Si coinciden los 2 anteriores aparece la leyenda Origen seguida del país de ori????', N'Las menciones que se harán constar en el etiquetado obligatorio de la carne fresca de vacuno son las siguientes:
Identificación del animal:
Nºde referencia o código de referencia que garantice la relación entre la carne y el animal o los animales; dicho nº podrá ser el número de identificación del animal del que proceda la carne de vacuno o el número de identificación correspondiente a un grupo de animales.
Identificación del matadero:
Nº de autorización del matadero en el que se ha sacrificado el animal y el Estado miembro o tercer pais en el que se encuentre el matadero: Sacrificado en:(nómbre del Estado) (nº de autorización)
País de origen: Estado miembro o tercer país de nacimiento.
País/es de cría: Estados miembros o terceros paises en los que haya tenido lugar el engorde.
En el caso de la carne de vacuno procedente de animales nacidos en la Comunidad antes del 1 de enero de 1998 y de los cuales no se disponga de datos sobre lugar de  nacimiento o cría, se sustituirá dicha mención por (Nacido antes del 1.1.98)
En el caso de la carne de vacuno procedente de animales importados vivos a la Comunidad y de los que no se disponga de datos sobre lugar de nacimiento o ce cría, se sustituirá dicha mención por (Importado vivo en la CE) o (Importado vivo de [nombre del tercer país]).
No se exige la indicación de los Estados miembros o terceros países como de cría siempre que se hayan criado durante 30 días o menos en el Estado miembro o tercer país de nacimiento o en el que se haya realizado el sacrifico y siempre que tales animales hayan sido criados en otro Estado miembro o tercer país durante un período superior a treinta días.
Si nacimiento, cría y sacrificio es en el mismo Estado miembro o en un tercer país se marcará respectivamente:
Origen: (nombre del estado miembro)
Origen: (nombre del tercer país)
Si no está disponible esta información de la carne de vacuno importada aparecerá en la etiqueta: Origen: no comunitario y Lugar de sacrificio: (nombre del tercer país).
', N'En el etiquetado obligatorio de la carne de vacuno aparecen las siguientes indicaciones:
Nº de identificación animal
Identificación del matadero
País de origen
País/es de cría
Si coinciden los 2 anteriores aparece la leyenda Origen seguida del país d????', N'Las menciones que se harán constar en el etiquetado obligatorio de la carne fresca de vacuno son las siguientes:
Identificación del animal:
Nºde referencia o código de referencia que garantice la relación entre la carne y el animal o los animales; dicho nº podrá ser el número de identificación del animal del que proceda la carne de vacuno o el número de identificación correspondiente a un grupo de animales.
Identificación del matadero:
Nº de autorización del matadero en el que se ha sacrificado el animal y el Estado miembro o tercer pais en el que se encuentre el matadero: Sacrificado en:(nómbre del Estado) (nº de autorización)
País de origen: Estado miembro o tercer país de nacimiento.
País/es de cría: Estados miembros o terceros paises en los que haya tenido lugar el engorde.
En el caso de la carne de vacuno procedente de animales nacidos en la Comunidad antes del 1 de enero de 1998 y de los cuales no se disponga de datos sobre lugar de  nacimiento o cría, se sustituirá dicha mención por (Nacido antes del 1.1.98)
En el caso de la carne de vacuno procedente de animales importados vivos a la Comunidad y de los que no se disponga de datos sobre lugar de nacimiento o ce cría, se sustituirá dicha mención por (Importado vivo en la CE) o (Importado vivo de [nombre del tercer país]).
No se exige la indicación de los Estados miembros o terceros países como de cría siempre que se hayan criado durante 30 días o menos en el Estado miembro o tercer país de nacimiento o en el que se haya realizado el sacrifico y siempre que tales animales hayan sido criados en otro Estado miembro o tercer país durante un período superior a treinta días.
Si nacimiento, cría y sacrificio es en el mismo Estado miembro o en un tercer país se marcará respectivamente:
Origen: (nombre del estado miembro)
Origen: (nombre del tercer país)
Si no está disponible esta información de la carne de vacuno importada aparecerá en la etiqueta: Origen: no comunitario y Lugar de sacrificio: (nombre del tercer país).
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(330 AS Decimal(6, 0)), N'46             ', N'El marcado de inspección veterinaria se efectúa después de que se dictamine la aptitud para consumo por parte de la Inspección Veterinaria.', N'El marcado de inspección veterinaria deberá efectuarse, una vez dictaminada la aptitud para consumo de las carnes frescas siendo responsabilidad del matadero el correcto sellado de las canales y víscerada consideradas aptas para consumo humano.', N'El marcado de inspección veterinaria se efectúa después de que se dictamine la aptitud para consumo por parte de la Inspección Veterinaria.', N'El marcado de inspección veterinaria deberá efectuarse, una vez dictaminada la aptitud para consumo de las carnes frescas siendo responsabilidad del matadero el correcto sellado de las canales y víscerada consideradas aptas para consumo humano.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(289 AS Decimal(6, 0)), N'44             ', N'La cuba de escaldado mantiene las condiciones de limpieza al comienzo de la jornada y se mantienen limpias a lo largo de todo el proceso.', N'Las cubas de escaldado deben encontrarse limpias y desinfectadas al comienzo de la jornada y se controlará que el agua de escaldado mantenga condiciones higiénicas durante todo el proceso.', N'La cuba de escaldado mantiene las condiciones de limpieza al comienzo de la jornada y se mantienen limpias a lo largo de todo el proceso.', N'Las cubas de escaldado deben encontrarse limpias y desinfectadas al comienzo de la jornada y se controlará que el agua de escaldado mantenga condiciones higiénicas durante todo el proceso.')
