INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1842 AS Decimal(6, 0)), N'32             ', N'Cuando los materiales poliméricos son del tipo materias plásticas se rigen así mismo por la LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Cuando los materiales poliméricos sean del tipo materias plásticas (polímeros de origen total ó parcialmente sintético, se regiran así mismo por la LP.', N'Cuando los materiales poliméricos son del tipo materias plásticas se rigen así mismo por la LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Cuando los materiales poliméricos sean del tipo materias plásticas (polímeros de origen total ó parcialmente sintético, se regiran así mismo por la LP.')
