INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1789 AS Decimal(6, 0)), N'32             ', N'No se realizan manipulaciones prohibidas.', N'Manipulaciones Prohibidas.
En la elaboración:
La utilización o tenencia de productos que puedan motivar confusión en cuanto a la verdadera proporción y naturaleza de los ingredientes específicos de las bebidas refrescantes.
La utilización o tenencia de materias espumígenas o mucilaginosas y de melazas.
La utilización de jarabes o ingredientes alterados, que presenten color, aspecto o sabor anormal, que estén fermentados o en fermentación y los agrios con acidez que exceda a la de su composición normal.
La utilización de anhídrido carbónico que no reúna las características indicadas.
La utilización de edulcorantes artificiales, salvo en los productos para los que se autoriza expresamente.', N'No se realizan manipulaciones prohibidas.', N'Manipulaciones Prohibidas.
En la elaboración:
La utilización o tenencia de productos que puedan motivar confusión en cuanto a la verdadera proporción y naturaleza de los ingredientes específicos de las bebidas refrescantes.
La utilización o tenencia de materias espumígenas o mucilaginosas y de melazas.
La utilización de jarabes o ingredientes alterados, que presenten color, aspecto o sabor anormal, que estén fermentados o en fermentación y los agrios con acidez que exceda a la de su composición normal.
La utilización de anhídrido carbónico que no reúna las características indicadas.
La utilización de edulcorantes artificiales, salvo en los productos para los que se autoriza expresamente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1780 AS Decimal(6, 0)), N'58             ', N'Si fuera necesario: Dispone de lavadora de envases reutilizables.', N'Si se emplean envases reutilizables, y su limpieza se realiza en el establecimiento, dispondrá de lavadora de envases que asegure la higienización de los mismos.', N'Si fuera necesario: Dispone de lavadora de envases reutilizables.', N'Si se emplean envases reutilizables, y su limpieza se realiza en el establecimiento, dispondrá de lavadora de envases que asegure la higienización de los mismos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1775 AS Decimal(6, 0)), N'3              ', N'Dispone de local  de almacenamiento de producto terminado.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
Local de almacenamiento de producto terminado.
En dicho local podrán almacenarse envases y embalajes nuevos o higienizados, cierres y etiquetas, si se mantienen adecuadamente protegidos y estibados: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases nuevos o higienizados además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido interno y externo del agua de lavado. En este supuesto podrá prescindirse de los locales 6 y 7.




', N'Dispone de local  de almacenamiento de producto terminado.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
Local de almacenamiento de producto terminado.
En dicho local podrán almacenarse envases y embalajes nuevos o higienizados, cierres y etiquetas, si se mantienen adecuadamente protegidos y estibados: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases nuevos o higienizados además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido interno y externo del agua de lavado. En este supuesto podrá prescindirse de los locales 6 y 7.




')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1776 AS Decimal(6, 0)), N'3              ', N'Si fuera preciso: Dispone de local  o lavadora estanca o aislada para el lavado e higienización de envases y embalajes reutilizables.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
Local para el lavado de envases y embalajes reutilizables.
En el caso de que se utilicen envases o embalajes cajas plásticas reutilizables, y la actividad de limpieza y desinfección de los mismos se realice en el establecimiento,  contará con un local específico para realizar las labores de limpieza e higienización.
No será necesario cuando las lavadoras sean cerradas, estancas o exista un dispositivo de aislamiento completo que impida la salida hacia el resto del local donde este ubicada la lavadora de aguas sucias, vapores etc. En este caso podrá ubicarse en el local de envasado siempre que la entrada de envases y embalajes sucios quede fuera de dicho local.





', N'Si fuera preciso: Dispone de local  o lavadora estanca o aislada para el lavado e higienización de envases y embalajes reutilizables.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
Local para el lavado de envases y embalajes reutilizables.
En el caso de que se utilicen envases o embalajes cajas plásticas reutilizables, y la actividad de limpieza y desinfección de los mismos se realice en el establecimiento,  contará con un local específico para realizar las labores de limpieza e higienización.
No será necesario cuando las lavadoras sean cerradas, estancas o exista un dispositivo de aislamiento completo que impida la salida hacia el resto del local donde este ubicada la lavadora de aguas sucias, vapores etc. En este caso podrá ubicarse en el local de envasado siempre que la entrada de envases y embalajes sucios quede fuera de dicho local.





')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1766 AS Decimal(6, 0)), N'39             ', N'Los helados y mezclas envasadas para congelar elaborados con leche o productos lácteos llevan Marca Sanitaria.', N'El etiquetado del producto, además de cumplir la norma general de etiquetado, incluirá:
Los helados y mezclas envasadas para congelar, elaborados con leche o productos lácteos, llevarán:
Marca Sanitaria de Salubridad que constará de un óvalo y en su interior:
a. En la parte superior la letra E mayúscula, en el centro el nº de R.G.S. del elaborador y en la parte inferior las siglas CEE, o bien...
b. En la parte superior, en mayúsculas ESPA#A, en el centro el nº R.G.S. del elaborador y en la parte inferior CEE.
c. En la parte superior, en mayúsculas ESPA#A, o la inicial E. En el centro una referencia al lugar en el que se indica el número de R.G.S. del establecimiento, en la parte inferior, las siglas:CEE
La marca de salubridad podrá estamparse en el envase, si el producto lleva un envase individual, o en una etiqueta pegada sobre este envase. No obstante, en el caso de peque¦os productos envasados individualmente y envasados luego conjuntamente, o en el caso de peque¦as porciones envasadas individualmente para venta al consumidor final, bastará con que la marca de salubridad se coloque en su envase colectivo.
El marcado  de salubridad se realizará en el momento de su elaboración o inmediatamente después de su elaboración en el establecimiento, en un lugar claramente visible. De forma perfectamente legible, indeleble y en caracteres fácilmente descifrables.
', N'Los helados y mezclas envasadas para congelar elaborados con leche o productos lácteos llevan Marca Sanitaria.', N'El etiquetado del producto, además de cumplir la norma general de etiquetado, incluirá:
Los helados y mezclas envasadas para congelar, elaborados con leche o productos lácteos, llevarán:
Marca Sanitaria de Salubridad que constará de un óvalo y en su interior:
a. En la parte superior la letra E mayúscula, en el centro el nº de R.G.S. del elaborador y en la parte inferior las siglas CEE, o bien...
b. En la parte superior, en mayúsculas ESPA#A, en el centro el nº R.G.S. del elaborador y en la parte inferior CEE.
c. En la parte superior, en mayúsculas ESPA#A, o la inicial E. En el centro una referencia al lugar en el que se indica el número de R.G.S. del establecimiento, en la parte inferior, las siglas:CEE
La marca de salubridad podrá estamparse en el envase, si el producto lleva un envase individual, o en una etiqueta pegada sobre este envase. No obstante, en el caso de peque¦os productos envasados individualmente y envasados luego conjuntamente, o en el caso de peque¦as porciones envasadas individualmente para venta al consumidor final, bastará con que la marca de salubridad se coloque en su envase colectivo.
El marcado  de salubridad se realizará en el momento de su elaboración o inmediatamente después de su elaboración en el establecimiento, en un lugar claramente visible. De forma perfectamente legible, indeleble y en caracteres fácilmente descifrables.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1804 AS Decimal(6, 0)), N'32             ', N'Dispone de resultados analíticos de los productos finales y las características de composición de cada uno de ellos se ajustan a lo dispuesto en su normativa de aplicación, o en caso de incumplimiento la empresa ha tomado las medidas necesarias para elimi????', N'Características del producto/s elaborado/s
Las características de composición (en cuanto a grado alcohólico, limites máximos de impurezas, residuos de metales pesados, contenidos de azucares, etc.) de los productos elaborados deberán ajustarse a lo recogido para cada uno de ellos en la legislación que le sea de aplicación, sobre Elaboración, circulación y comercio de: Ron, Anís; Whisky, Ginebra, Brandy, Aguardientes compuestos, Licores, Aperitivos sin vino base y otras bebidas derivadas de alcoholes naturales. Información adicional en el documento de Word de la It. Bebidas espirituosas.
', N'Dispone de resultados analíticos de los productos finales y las características de composición de cada uno de ellos se ajustan a lo dispuesto en su normativa de aplicación, o en caso de incumplimiento la empresa ha tomado las medidas necesarias para elimi????', N'Características del producto/s elaborado/s
Las características de composición (en cuanto a grado alcohólico, limites máximos de impurezas, residuos de metales pesados, contenidos de azucares, etc.) de los productos elaborados deberán ajustarse a lo recogido para cada uno de ellos en la legislación que le sea de aplicación, sobre Elaboración, circulación y comercio de: Ron, Anís; Whisky, Ginebra, Brandy, Aguardientes compuestos, Licores, Aperitivos sin vino base y otras bebidas derivadas de alcoholes naturales. Información adicional en el documento de Word de la It. Bebidas espirituosas.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1793 AS Decimal(6, 0)), N'3              ', N'Dispone de local para almacenamiento de materias primas.', N'Las industrias elaboradoras de bebidas espirituosas dispondrán al menos de:
