INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1786 AS Decimal(6, 0)), N'32             ', N'Las caracteristicas generales del producto terminado son correctas.', N'Producto Terminado
 Características generales:
Estar elaboradas exclusivamente con los ingredientes y productos autorizados para cada clase de bebida.
Poseer aspecto normal, color, olor y sabor característicos.
No contener alcohol en cantidad superior al 0,5 % en volumen, medido en la bebida terminada.
En las bebidas refrescantes se permite la presencia  de anhídrido sulfuroso en cantidad máxima  de 10 mg/ litro excepto en las bebidas refrescantes de zumos de frutas que será de 20 mg sin tener la obligación de declararlo en el etiquetado.
No contendrán residuos de metales en cantidades superiores a los valores máximos siguientes:
 Arsénico: 0,25 mg/l
 Plomo: 0,5 mg /l
 Cobre: 3,0 mg /l
 Zinc: 6,0 mg /l
 Hierro: 4 mg/l ( 15 mg /l si el envase es metálico )
Esta¦o: 30 mg /l (150mgr/l si el envase es metálico)
Estarán exentos de gérmenes patógenos o sus toxinas
', N'Las caracteristicas generales del producto terminado son correctas.', N'Producto Terminado
 Características generales:
Estar elaboradas exclusivamente con los ingredientes y productos autorizados para cada clase de bebida.
Poseer aspecto normal, color, olor y sabor característicos.
No contener alcohol en cantidad superior al 0,5 % en volumen, medido en la bebida terminada.
En las bebidas refrescantes se permite la presencia  de anhídrido sulfuroso en cantidad máxima  de 10 mg/ litro excepto en las bebidas refrescantes de zumos de frutas que será de 20 mg sin tener la obligación de declararlo en el etiquetado.
No contendrán residuos de metales en cantidades superiores a los valores máximos siguientes:
 Arsénico: 0,25 mg/l
 Plomo: 0,5 mg /l
 Cobre: 3,0 mg /l
 Zinc: 6,0 mg /l
 Hierro: 4 mg/l ( 15 mg /l si el envase es metálico )
Esta¦o: 30 mg /l (150mgr/l si el envase es metálico)
Estarán exentos de gérmenes patógenos o sus toxinas
')
GO
