INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1745 AS Decimal(6, 0)), N'58             ', N'Si disponen de máquinas elaboradoras-expendedoras, estas reúnen los requisitos técnicos de aplicación.', N'Si dispone de máquinas elaboradoras-expendedoras, éstas reunirán los requisitos:
Máquina elaboradora-expendedora: máquina dise¦ada y preparada para elaborar y/o expender helado elaborado a partir de la mezcla envasada para congelar.
Dispondrán de recipiente o cilindro cerrado para la elaboración del helado.
El depósito con la mezcla en reserva estará refrigerado a una Tª de 5º C. + - 1º C. Entre  4 y 6º C.
Termómetro de lectura exterior de la Tª .', N'Si disponen de máquinas elaboradoras-expendedoras, estas reúnen los requisitos técnicos de aplicación.', N'Si dispone de máquinas elaboradoras-expendedoras, éstas reunirán los requisitos:
Máquina elaboradora-expendedora: máquina dise¦ada y preparada para elaborar y/o expender helado elaborado a partir de la mezcla envasada para congelar.
Dispondrán de recipiente o cilindro cerrado para la elaboración del helado.
El depósito con la mezcla en reserva estará refrigerado a una Tª de 5º C. + - 1º C. Entre  4 y 6º C.
Termómetro de lectura exterior de la Tª .')
GO
