INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1770 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona de carga - descarga.', N'Las Industrias deberán disponer de:
Local o zona de recepción y/o expedición carga-descarga
Se admitirá la posibilidad de habilitar una zona de carga-descarga a la entrada del almacén de materias primas y del de producto final cuando el acceso a los mismos esté dotado de un sistema permanente que impida la entrada de vehículos al interior del mismo, en caso contrario ambos accesos deberán contar con un local previo destinado realizar estas tareas.
', N'Dispone de local o zona de carga - descarga.', N'Las Industrias deberán disponer de:
Local o zona de recepción y/o expedición carga-descarga
Se admitirá la posibilidad de habilitar una zona de carga-descarga a la entrada del almacén de materias primas y del de producto final cuando el acceso a los mismos esté dotado de un sistema permanente que impida la entrada de vehículos al interior del mismo, en caso contrario ambos accesos deberán contar con un local previo destinado realizar estas tareas.
')
GO
