INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1772 AS Decimal(6, 0)), N'3              ', N'Dispone de local de elaboración y envasado de las bebidas refrescantes.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
Local de elaboración  y envasado de las bebidas refrescantes.
En dicho local se realizarán higiénicamente las mezclas para obtención de los jarabes que tras su dilución y adición de anhídrido carbónico darán lugar a la bebida que se envasará de forma continua y automática.


', N'Dispone de local de elaboración y envasado de las bebidas refrescantes.', N'Las Industrias elaboradoras de bebidas refrescantes deberán disponer de:
