INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1800 AS Decimal(6, 0)), N'58             ', N'En función de los productos que elabora:
Dispone de toda la maquinaria y equipamiento necesario para la actividad que realiza.', N'Este tipo de industrias dispondrá de instalaciones y maquinaria adecuada al volumen de producción.
En función del tipo/s de producto/s que elaboren dispondrán, mínimamente, de la siguiente maquinaria e instalaciones:
Recipientes, tanques o depósitos para las labores de maceración, preparación de jarabes, aromatización, edulcorado, mezclas, etc.
Depósitos y alambiques para la fermentación alcohólica y/o destilación de productos
Tanques o depósitos para almacenamiento del producto elaborado.
Bomba de recirculación o trasiego y sus correspondientes conducciones
Filtros automáticos para clarificación y refinado de productos
Enjuagadora de envases
Envasadora - Taponadora automática o semiautomática
', N'En función de los productos que elabora:
Dispone de toda la maquinaria y equipamiento necesario para la actividad que realiza.', N'Este tipo de industrias dispondrá de instalaciones y maquinaria adecuada al volumen de producción.
En función del tipo/s de producto/s que elaboren dispondrán, mínimamente, de la siguiente maquinaria e instalaciones:
Recipientes, tanques o depósitos para las labores de maceración, preparación de jarabes, aromatización, edulcorado, mezclas, etc.
Depósitos y alambiques para la fermentación alcohólica y/o destilación de productos
Tanques o depósitos para almacenamiento del producto elaborado.
Bomba de recirculación o trasiego y sus correspondientes conducciones
Filtros automáticos para clarificación y refinado de productos
Enjuagadora de envases
Envasadora - Taponadora automática o semiautomática
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1803 AS Decimal(6, 0)), N'32             ', N'Dispone de resultados analíticos que permiten verificar las calidades y características de las materias primas, de los productos elaborados y de los productos en curso de elaboración.', N'Dispondrá de boletines de análisis, periódicos, de calidades y características de las materias primas, de los productos elaborados y de los productos en curso de elaboración.', N'Dispone de resultados analíticos que permiten verificar las calidades y características de las materias primas, de los productos elaborados y de los productos en curso de elaboración.', N'Dispondrá de boletines de análisis, periódicos, de calidades y características de las materias primas, de los productos elaborados y de los productos en curso de elaboración.')
