INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1844 AS Decimal(6, 0)), N'32             ', N'Los limites de migración de las materias plásticas están dentro de los limites permitidos.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Los materiales y objetos plásticos no deberán ceder sus componentes a los productos alimenticios en cantidades que excedan de 10 miligramos por decímetro cuadrado de superficie de material u objeto (mg/dm2) (Límite de Migración Global LMG). No obstante, dicho límite será de 60 miligramos de constituyentes liberados por kilogramo de producto alimenticio (mg/kg) en los siguientes casos:a) objetos que sean envases, comparables a envases o que puedan rellenarse, de una capacidad no inferior a 500 mililitros (ml) y no superior a 10 litros (l); b) objetos que puedan rellenarse y cuya superficie en contacto con los productos alimenticios sea imposible de calcular; c) capuchones, obturadores, tapones u otros dispositivos de cierre similares.', N'Los limites de migración de las materias plásticas están dentro de los limites permitidos.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Los materiales y objetos plásticos no deberán ceder sus componentes a los productos alimenticios en cantidades que excedan de 10 miligramos por decímetro cuadrado de superficie de material u objeto (mg/dm2) (Límite de Migración Global LMG). No obstante, dicho límite será de 60 miligramos de constituyentes liberados por kilogramo de producto alimenticio (mg/kg) en los siguientes casos:a) objetos que sean envases, comparables a envases o que puedan rellenarse, de una capacidad no inferior a 500 mililitros (ml) y no superior a 10 litros (l); b) objetos que puedan rellenarse y cuya superficie en contacto con los productos alimenticios sea imposible de calcular; c) capuchones, obturadores, tapones u otros dispositivos de cierre similares.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1834 AS Decimal(6, 0)), N'32             ', N'Si el establecimiento exclusivamente comercializa, dispone de información para la identificación de los MCAs en la que al menos figura nombre comercial y composición cualitativa y si es posible la identificación por denominación química, nº CAS y nº Einec????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
En el caso de Sustancias Existentes este número se llama también EINECS.
En el caso de sustancias Notificadas este número se llama también ELINCS.', N'Si el establecimiento exclusivamente comercializa, dispone de información para la identificación de los MCAs en la que al menos figura nombre comercial y composición cualitativa y si es posible la identificación por denominación química, nº CAS y nº Einec????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
En el caso de Sustancias Existentes este número se llama también EINECS.
En el caso de sustancias Notificadas este número se llama también ELINCS.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1839 AS Decimal(6, 0)), N'32             ', N'Los materiales poliméricos se ajustan a las restricciones y/o especificaciones que figuran de la LP en cuanto a Límite de Migración Específica (LME), Limite de migración Global (LMG) en alimentos ó simulantes, Cantidad Máxima permitida de la sustancia en ????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Los materiales poliméricos no cederán al alimento, bebida o producto alimentario sustancias que puedan suponer alteraciones de percepción organoléptica, ni migración de elementos provenientes de los mismos, en cantidad que signifique un riesgo para la salud. Los materiales poliméricos deberán ajustarse a las restricciones y/o especificaciones de la LP en cuanto a límite de migración específica (LME) en alimentos ó simulantes, cantidad máxima permitida de la sustancia en el material u objeto terminado (CM), y cualquier otra especificación y /o restricción vinculada a la sustancia ó polímero.', N'Los materiales poliméricos se ajustan a las restricciones y/o especificaciones que figuran de la LP en cuanto a Límite de Migración Específica (LME), Limite de migración Global (LMG) en alimentos ó simulantes, Cantidad Máxima permitida de la sustancia en ????', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Los materiales poliméricos no cederán al alimento, bebida o producto alimentario sustancias que puedan suponer alteraciones de percepción organoléptica, ni migración de elementos provenientes de los mismos, en cantidad que signifique un riesgo para la salud. Los materiales poliméricos deberán ajustarse a las restricciones y/o especificaciones de la LP en cuanto a límite de migración específica (LME) en alimentos ó simulantes, cantidad máxima permitida de la sustancia en el material u objeto terminado (CM), y cualquier otra especificación y /o restricción vinculada a la sustancia ó polímero.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1837 AS Decimal(6, 0)), N'32             ', N'Los materiales poliméricos autorizados que vayan a estar en contacto con los alimentos, bebidas y productos alimentarios están incluidos en las LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La que la normativa de aplicación que abarca las listas positivas de materiales y sustancias autorizadas, restricciones y demás especificaciones difiere para cada sustancia y/o tipo de material.
Los materiales poliméricos utilizables para estar en contacto con productos alimenticios ó alimentarios serán los que figuren en la LP.', N'Los materiales poliméricos autorizados que vayan a estar en contacto con los alimentos, bebidas y productos alimentarios están incluidos en las LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La que la normativa de aplicación que abarca las listas positivas de materiales y sustancias autorizadas, restricciones y demás especificaciones difiere para cada sustancia y/o tipo de material.
Los materiales poliméricos utilizables para estar en contacto con productos alimenticios ó alimentarios serán los que figuren en la LP.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1851 AS Decimal(6, 0)), N'32             ', N'En caso de utilizar compresores de aire para la elaboración de MCA, éstos disponen de filtros para eliminar aceites.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Si se utilizan gases en el proceso de fabricación (por ejemplo en operaciones de moldeo), éste estará libre de impurezas contaminantes. En el caso de precisarse compresores de gases, dispondrán de sistema de filtrado para eliminar aceites.', N'En caso de utilizar compresores de aire para la elaboración de MCA, éstos disponen de filtros para eliminar aceites.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
Si se utilizan gases en el proceso de fabricación (por ejemplo en operaciones de moldeo), éste estará libre de impurezas contaminantes. En el caso de precisarse compresores de gases, dispondrán de sistema de filtrado para eliminar aceites.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1852 AS Decimal(6, 0)), N'39             ', N'Las etiquetas de los MCAs son visibles, claramente legibles e indelebles.', N'Los materiales y objetos finales destinados a estar en contacto con alimentos irán etiquetados de forma visible, claramente legible e indeleble con una ó varias de las menciones que siguen: a) la leyenda para uso alimentario. b) una mención específica referente a su empleo. Por ejemplo: Maquina de café, botella de vino, cuchara de sopa, etc. c)el símbolo de la copa y el tenedor.', N'Las etiquetas de los MCAs son visibles, claramente legibles e indelebles.', N'Los materiales y objetos finales destinados a estar en contacto con alimentos irán etiquetados de forma visible, claramente legible e indeleble con una ó varias de las menciones que siguen: a) la leyenda para uso alimentario. b) una mención específica referente a su empleo. Por ejemplo: Maquina de café, botella de vino, cuchara de sopa, etc. c)el símbolo de la copa y el tenedor.')
GO
