INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1794 AS Decimal(6, 0)), N'3              ', N'Dispone de local/es de fabricación - elaboración.', N'Las industrias elaboradoras de bebidas espirituosas dispondrán al menos de:
Local/es de fabricación / elaboración.
Destinado a las diversas labores necesarias para la elaboración de la/s bebida/s espirituosa/s que fabrique el establecimiento: Fermentación alcohólica y destilación, maceración / infusión / digestión, preparación y adición de jarabes, aromatización, edulcoración, coloración, mezcla, ensamble, etc.


', N'Dispone de local/es de fabricación - elaboración.', N'Las industrias elaboradoras de bebidas espirituosas dispondrán al menos de:
Local/es de fabricación / elaboración.
Destinado a las diversas labores necesarias para la elaboración de la/s bebida/s espirituosa/s que fabrique el establecimiento: Fermentación alcohólica y destilación, maceración / infusión / digestión, preparación y adición de jarabes, aromatización, edulcoración, coloración, mezcla, ensamble, etc.


')
GO
