INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1816 AS Decimal(6, 0)), N'11             ', N'Disponen de sistema de registro gráfico de temperatura para las cámaras de refrigeración en las que se almacenen alimentos o productos alimenticios durante más de ocho días y para todas las cámaras de mantenimiento de congelados.', N'Las cámaras de almacenaje de productos refrigerados durante más de ocho días, así como las cámaras de congelación dispondrán de un sistema de registro gráfico o automático de la temperatura.', N'Disponen de sistema de registro gráfico de temperatura para las cámaras de refrigeración en las que se almacenen alimentos o productos alimenticios durante más de ocho días y para todas las cámaras de mantenimiento de congelados.', N'Las cámaras de almacenaje de productos refrigerados durante más de ocho días, así como las cámaras de congelación dispondrán de un sistema de registro gráfico o automático de la temperatura.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1822 AS Decimal(6, 0)), N'3              ', N'La separación del local de carga y descarga con el local de almacén es completa, salvo en el caso de almacenaje de productos debidamente envasados y frutas, verduras y tubérculos en los que es suficiente con un dispositivo que impida el acceso de vehículo????', N'El local de carga y descarga se encontrará separado de manera completa de la zona de almacenaje excepto en el almacenamiento de producto  envasado y frutas, verduras y tubérculos no envasados, en los que no será necesario esta separación siempre y cuando existan dispositivos que impidan el acceso de vehículos al local, evitándose cualquier posible contaminación del producto alimentario que se trate, permitiendo las operaciones de carga y descarga al abrigo del sol y de las inclemencias del tiempo, cuando sea necesario proteger al producto de estas circunstancias o cualesquiera otras, que puedan determinar una posible contaminación o alteración de los mismos.', N'La separación del local de carga y descarga con el local de almacén es completa, salvo en el caso de almacenaje de productos debidamente envasados y frutas, verduras y tubérculos en los que es suficiente con un dispositivo que impida el acceso de vehículo????', N'El local de carga y descarga se encontrará separado de manera completa de la zona de almacenaje excepto en el almacenamiento de producto  envasado y frutas, verduras y tubérculos no envasados, en los que no será necesario esta separación siempre y cuando existan dispositivos que impidan el acceso de vehículos al local, evitándose cualquier posible contaminación del producto alimentario que se trate, permitiendo las operaciones de carga y descarga al abrigo del sol y de las inclemencias del tiempo, cuando sea necesario proteger al producto de estas circunstancias o cualesquiera otras, que puedan determinar una posible contaminación o alteración de los mismos.')
GO
