INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1835 AS Decimal(6, 0)), N'32             ', N'Las materias primas y aditivos empleadas en la fabricación y/o transformación de MCA poliméricos estarán incluidos en las LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La que la normativa de aplicación que abarca las listas positivas de materiales y sustancias autorizadas, restricciones y demás especificaciones difiere para cada sustancia y/o tipo de material.
Los materiales poliméricos destinados a estar en contacto con los productos alimenticios y alimentarios, serán fabricados y transformados y contendrán las sustancias autorizadas recogidas en las Listas Positivas (LP de ahora en adelante). ', N'Las materias primas y aditivos empleadas en la fabricación y/o transformación de MCA poliméricos estarán incluidos en las LP.', N'Dada la diversidad de situaciones que se presentan en la práctica por la gran variedad de sustancias químicas que pueden estar en contacto con los alimentos en diferentes condiciones (Tª, tº, etc.), es básico partiendo del tipo de material que tengamos, conocer su composición y estructuras química, más concretamente  diferenciar entre polimeros, plasticos (que son todos de estructura polimérica), y otros materiales que incluyen una amplísima gama de sustancias de diferentes estructuras químicas: cerámicas, vidrios, metales, cueros, pieles, etc.
La que la normativa de aplicación que abarca las listas positivas de materiales y sustancias autorizadas, restricciones y demás especificaciones difiere para cada sustancia y/o tipo de material.
Los materiales poliméricos destinados a estar en contacto con los productos alimenticios y alimentarios, serán fabricados y transformados y contendrán las sustancias autorizadas recogidas en las Listas Positivas (LP de ahora en adelante). ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1815 AS Decimal(6, 0)), N'11             ', N'Las cámaras de almacenamiento de productos congelados disponen de dispositivos que reduzcan los efectos de la apertura de las puertas.', N'Las cámaras de almacenamiento de productos congelados dispondrán de dispositivos que reduzcan los efectos de la apertura de las puertas.', N'Las cámaras de almacenamiento de productos congelados disponen de dispositivos que reduzcan los efectos de la apertura de las puertas.', N'Las cámaras de almacenamiento de productos congelados dispondrán de dispositivos que reduzcan los efectos de la apertura de las puertas.')
