INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(288 AS Decimal(6, 0)), N'43             ', N'Las operaciones de insuflado se realizan con aire higienizado.', N'En el caso de que se realice el insuflado a las canales de ovino-caprino para facilitar el desollado, éste debe realizarse con aire higienizado.', N'Las operaciones de insuflado se realizan con aire higienizado.', N'En el caso de que se realice el insuflado a las canales de ovino-caprino para facilitar el desollado, éste debe realizarse con aire higienizado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(287 AS Decimal(6, 0)), N'43             ', N'No se produce acumulo de pieles o cueros en la nave de sacrificio.', N'Una vez desollado el animal la piel debe ser inmediatamente retirada de la nave de sacrificio o bien depositada en contenedores específicos que dispondrán de tapa y cuya conducción al lugar de almacenamiento de cueros se realizará con los contenedores perfectamente cerrados. No se producirá el acumulo de pieles o cueros en la nave de sacrificio desarrollando las acciones de marcado, clasificado etc. de los mismos fuera de la nave de sacrificio.', N'No se produce acumulo de pieles o cueros en la nave de sacrificio.', N'Una vez desollado el animal la piel debe ser inmediatamente retirada de la nave de sacrificio o bien depositada en contenedores específicos que dispondrán de tapa y cuya conducción al lugar de almacenamiento de cueros se realizará con los contenedores perfectamente cerrados. No se producirá el acumulo de pieles o cueros en la nave de sacrificio desarrollando las acciones de marcado, clasificado etc. de los mismos fuera de la nave de sacrificio.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(286 AS Decimal(6, 0)), N'43             ', N'Se respeta el orden secuencial y se realizan de tal forma que se evita la contaminación de la canal a partir de la piel.', N'Durante todas las fases del desollado debe mantenerse un orden secuencial de actuación para evitar la contaminación a partir de la piel, de forma que practicada la primera incisión en la piel no se permitirá que las partes expuestas de las canales entren en contacto  con cualquier parte de otras canales hasta que se complete la inspección post-mortem. Se permitirá dicho contacto solo cuando la primera incisión no exponga los tejidos subcutáneos ni las superficies de los músculos, por tanto los animales podrán estar en contacto mutuo durante el sangrado, y en el caso de los cerdos durante el escaldado y la depilación.', N'Se respeta el orden secuencial y se realizan de tal forma que se evita la contaminación de la canal a partir de la piel.', N'Durante todas las fases del desollado debe mantenerse un orden secuencial de actuación para evitar la contaminación a partir de la piel, de forma que practicada la primera incisión en la piel no se permitirá que las partes expuestas de las canales entren en contacto  con cualquier parte de otras canales hasta que se complete la inspección post-mortem. Se permitirá dicho contacto solo cuando la primera incisión no exponga los tejidos subcutáneos ni las superficies de los músculos, por tanto los animales podrán estar en contacto mutuo durante el sangrado, y en el caso de los cerdos durante el escaldado y la depilación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(197 AS Decimal(6, 0)), N'3              ', N'Dispone de  instalaciones equipadas y acondicionadas para la carga y expedición de las carnes.', N'Dispondrá de instalaciones para la protección de las operaciones de carga de carnes. Esta protección consistirá en estructuras que se adapten a los camiones, en sus distintos tama¦os, de tal forma que cuando la puerta del remolque de dicho vehículo se abra esté acoplado al muelle y quede perfectamente aislado del exterior, evitando el acceso de animales indeseables, polvo, humos y contaminación del propio vehículo, etc.', N'Dispone de  instalaciones equipadas y acondicionadas para la carga y expedición de las carnes.', N'Dispondrá de instalaciones para la protección de las operaciones de carga de carnes. Esta protección consistirá en estructuras que se adapten a los camiones, en sus distintos tama¦os, de tal forma que cuando la puerta del remolque de dicho vehículo se abra esté acoplado al muelle y quede perfectamente aislado del exterior, evitando el acceso de animales indeseables, polvo, humos y contaminación del propio vehículo, etc.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(186 AS Decimal(6, 0)), N'3              ', N'Dispone de locales de sacrificio que permiten realizar las operaciones de faenado con separación suficiente.', N'Dispondrá de locales de sacrificio bien dimensionados, que cumplan las condiciones generales de dise¦o y disposición descritas en la IT3, de forma que todas las operaciones realizadas en la cadena de sacrificio estén perfectamente diferenciadas y espaciadas,  permitiendo realizar el trabajo con holgura y facilidad y evitando en  todo momento el arrastre de contaminación por contacto, goteo, salpicaduras etc. que de lugar a contaminaciones cruzadas. ', N'Dispone de locales de sacrificio que permiten realizar las operaciones de faenado con separación suficiente.', N'Dispondrá de locales de sacrificio bien dimensionados, que cumplan las condiciones generales de dise¦o y disposición descritas en la IT3, de forma que todas las operaciones realizadas en la cadena de sacrificio estén perfectamente diferenciadas y espaciadas,  permitiendo realizar el trabajo con holgura y facilidad y evitando en  todo momento el arrastre de contaminación por contacto, goteo, salpicaduras etc. que de lugar a contaminaciones cruzadas. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(209 AS Decimal(6, 0)), N'7              ', N'Las aguas residuales procedentes de lavamanos y esterilizadores se evacuan directamente hacia sumideros o canales.', N'Las aguas residuales procedentes de lavamanos, esterilizadores, y otras instalaciones de lavado o limpieza en la nave de sacrificio, deberán evacuarse por medio de tuberías hacia sumideros o canalizaciones. En ningún momento tendrá lugar la evacuación directa al suelo de la nave de sacrificio, así como la producción de salpicaduras del agua de los esterilizadores producidas por el movimiento de las torres de faenado.', N'Las aguas residuales procedentes de lavamanos y esterilizadores se evacuan directamente hacia sumideros o canales.', N'Las aguas residuales procedentes de lavamanos, esterilizadores, y otras instalaciones de lavado o limpieza en la nave de sacrificio, deberán evacuarse por medio de tuberías hacia sumideros o canalizaciones. En ningún momento tendrá lugar la evacuación directa al suelo de la nave de sacrificio, así como la producción de salpicaduras del agua de los esterilizadores producidas por el movimiento de las torres de faenado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(200 AS Decimal(6, 0)), N'3              ', N'Dispone de local de laboratorio para analíticas complementarias a la inspección.', N'Dispondrá de un local de laboratorio para el desarrollo de analíticas complementarias que se procesen por parte de los Servicios de Inspección Veterinaria.', N'Dispone de local de laboratorio para analíticas complementarias a la inspección.', N'Dispondrá de un local de laboratorio para el desarrollo de analíticas complementarias que se procesen por parte de los Servicios de Inspección Veterinaria.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(194 AS Decimal(6, 0)), N'3              ', N'Dispone de emplazamiento acondicionado para el depósito de estiércol.', N'Estiércol. Dispondrá de un emplazamiento especialmente acondicionado para el almacenamiento del estiércol siempre que éste se almacene en el recinto del matadero. Dicho emplazamiento dispondrá de un dispositivo para la protección de animales indeseables, estará cubierto y tendrá bordillos de contención y sumideros que evite que el líquido fluya a zonas más limpias.', N'Dispone de emplazamiento acondicionado para el depósito de estiércol.', N'Estiércol. Dispondrá de un emplazamiento especialmente acondicionado para el almacenamiento del estiércol siempre que éste se almacene en el recinto del matadero. Dicho emplazamiento dispondrá de un dispositivo para la protección de animales indeseables, estará cubierto y tendrá bordillos de contención y sumideros que evite que el líquido fluya a zonas más limpias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(185 AS Decimal(6, 0)), N'3              ', N'El local de estabulación permite la realización de la inspección ante-mortem y la separación de sospechosos. ', N'Los locales de estabulación dispondrán de instalaciones que permitan la realización de la inspección ante-mortem y medios que permitan la separación de los animales enfermos o sospechosos.', N'El local de estabulación permite la realización de la inspección ante-mortem y la separación de sospechosos. ', N'Los locales de estabulación dispondrán de instalaciones que permitan la realización de la inspección ante-mortem y medios que permitan la separación de los animales enfermos o sospechosos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(181 AS Decimal(6, 0)), N'2              ', N'El tráfico rodado dispone de medios que impidan el cruce de circuitos limpio-sucio.', N'Las zonas utilizadas por el tráfico rodado estarán dise¦adas de tal manera que impidan el cruce de circuitos limpio-sucio, debiendo existir circuitos independientes y separados físicamente, para el acceso del transporte de animales vivos y para los vehículos de carnes, sin que se produzca traslado de estiércol y contaminación del extremo sucio de la industria al extremo limpio.
En el caso de que exista una entrada única del tráfico rodado a la industria, se exigirá  igualmente que no haya coincidencia de circuitos, de forma que los camiones de animales vivos y los camiones de carne, no transiten por el mismo vial dentro del recinto vallado del matadero. ', N'El tráfico rodado dispone de medios que impidan el cruce de circuitos limpio-sucio.', N'Las zonas utilizadas por el tráfico rodado estarán dise¦adas de tal manera que impidan el cruce de circuitos limpio-sucio, debiendo existir circuitos independientes y separados físicamente, para el acceso del transporte de animales vivos y para los vehículos de carnes, sin que se produzca traslado de estiércol y contaminación del extremo sucio de la industria al extremo limpio.
En el caso de que exista una entrada única del tráfico rodado a la industria, se exigirá  igualmente que no haya coincidencia de circuitos, de forma que los camiones de animales vivos y los camiones de carne, no transiten por el mismo vial dentro del recinto vallado del matadero. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(199 AS Decimal(6, 0)), N'3              ', N'Dispone de un local acondicionado para la detección de triquina.', N'Dispondrá de un local con cámara oscura, suficientemente equipado, de acuerdo con la legislación específica, para la visualización y detección de triquinas, siempre que dicho examen se realice en el establecimiento. En dicho local se ubicará el triquinoscopio. VER NORMA DE TRIQUINAS.', N'Dispone de un local acondicionado para la detección de triquina.', N'Dispondrá de un local con cámara oscura, suficientemente equipado, de acuerdo con la legislación específica, para la visualización y detección de triquinas, siempre que dicho examen se realice en el establecimiento. En dicho local se ubicará el triquinoscopio. VER NORMA DE TRIQUINAS.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(345 AS Decimal(6, 0)), N'48             ', N'Durante la descarga los animales no son maltratados.', N'No se asustará ni causará agitación ni se maltratará a los animales y tendrá cuidado de no derribarlos. Se prohibe levantar a los animales asiéndolos por la cabeza, cuernos, orejas, patas, rabo o lana de tal modo que se les cause dolor o sufrimiento innecesario. En caso necesario, se les conducirá individualmente.', N'Durante la descarga los animales no son maltratados.', N'No se asustará ni causará agitación ni se maltratará a los animales y tendrá cuidado de no derribarlos. Se prohibe levantar a los animales asiéndolos por la cabeza, cuernos, orejas, patas, rabo o lana de tal modo que se les cause dolor o sufrimiento innecesario. En caso necesario, se les conducirá individualmente.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(346 AS Decimal(6, 0)), N'49             ', N'El estado y dise¦o de los corredores reduce el riesgo de heridas y facilita el manejo.', N'Los corredores estarán dise¦ados de tal modo que se reduzca al mínimo el riesgo de que los animales puedan herirse(ausencia de salientes, suelos antideslizantes, evitar en lo posible los cambios de dirección ;)y su disposición permitirá aprovechar la naturaleza gregaria de éstos. ', N'El estado y dise¦o de los corredores reduce el riesgo de heridas y facilita el manejo.', N'Los corredores estarán dise¦ados de tal modo que se reduzca al mínimo el riesgo de que los animales puedan herirse(ausencia de salientes, suelos antideslizantes, evitar en lo posible los cambios de dirección ;)y su disposición permitirá aprovechar la naturaleza gregaria de éstos. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(326 AS Decimal(6, 0)), N'40             ', N'La industria solo admite a sacrificio los animales que están perfectamente identificados y documentados.', N'Es responsabilidad del operador del matadero no aceptar la entrada a  sacrificio de los animales que no lleguen al matadero perfectamente identificados y documentados. 
Cuando lleguen al matadero animales:
1-Sin la ICA, o sin otra documentación.
2-O con documentación deficientemente cumplimentada.
3-O cuando su contenido presente dudas razonables sobre su validez o fiabilidad, dado que los datos de la documentación no corresponden con la identificación real que figura en los crotales orejeros/tatuajes/marcas.
No tendrá lugar el sacrificio de dicho animal, hasta que el veterinario oficial lo permita. 
Para lo cual el operador del matadero deberá notificar esta circunstancia al SVO.
', N'La industria solo admite a sacrificio los animales que están perfectamente identificados y documentados.', N'Es responsabilidad del operador del matadero no aceptar la entrada a  sacrificio de los animales que no lleguen al matadero perfectamente identificados y documentados. 
Cuando lleguen al matadero animales:
1-Sin la ICA, o sin otra documentación.
2-O con documentación deficientemente cumplimentada.
3-O cuando su contenido presente dudas razonables sobre su validez o fiabilidad, dado que los datos de la documentación no corresponden con la identificación real que figura en los crotales orejeros/tatuajes/marcas.
No tendrá lugar el sacrificio de dicho animal, hasta que el veterinario oficial lo permita. 
Para lo cual el operador del matadero deberá notificar esta circunstancia al SVO.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(451 AS Decimal(6, 0)), N'32             ', N'Los resultados analíticos se encuentran dentro de los valores aceptables y en su defecto se han adoptado las medidas necesarias para evitar que su comercialización suponga un riesgo para la salud.', N'Las carnes serán sometidas a análisis microbiológicos suficientes que garanticen los siguientes valores:
Valores aceptables:
 Bovinos, ovinos, caprinos y equinos. 
                Recuento total de colonias aerobias (TVC): menor que3,5 log
                Enterobacterias: menor que1,5 log
Porcinos.  
                Recuento total de colonias aerobias (TVC): menor que4,0g
                Enterobacterias: menor que2,0 log

Valores dudosos, (mayor quem pero _menor que M):
 Bovinos, porcinos, caprinos y equinos.
                Recuento total de colonias aerobias (TVC): menor que3,5 log (porcinos: menor que4,0 log) 
                                                                                      &Ñ150; 5 log
               Enterobacterias: menor que1,5 log (porcinos: 2,0 log)
                                          -2,5 log (porcinos: 3,0 log)

Valores inaceptables:
 Bovinos, porcinos, ovinos, caprinos y equinos.
                Recuento total de colonias aerobias (TVC): mayor que5,0 log
                Enterobacterias: mayor que2,5 log (porcinos: 3,0 log)

Valores diarios de la medida logarítmica de resultados aceptables, dudosos e inaceptables de contaminación (expresados en ufc/cm2 de bovinos, porcinos, ovinos, caprinos y equinos; muestras tomadas mediante el método destructivo.

', N'Los resultados analíticos se encuentran dentro de los valores aceptables y en su defecto se han adoptado las medidas necesarias para evitar que su comercialización suponga un riesgo para la salud.', N'Las carnes serán sometidas a análisis microbiológicos suficientes que garanticen los siguientes valores:
Valores aceptables:
 Bovinos, ovinos, caprinos y equinos. 
                Recuento total de colonias aerobias (TVC): menor que3,5 log
                Enterobacterias: menor que1,5 log
Porcinos.  
                Recuento total de colonias aerobias (TVC): menor que4,0g
                Enterobacterias: menor que2,0 log

Valores dudosos, (mayor quem pero _menor que M):
 Bovinos, porcinos, caprinos y equinos.
                Recuento total de colonias aerobias (TVC): menor que3,5 log (porcinos: menor que4,0 log) 
                                                                                      &Ñ150; 5 log
               Enterobacterias: menor que1,5 log (porcinos: 2,0 log)
                                          -2,5 log (porcinos: 3,0 log)

Valores inaceptables:
 Bovinos, porcinos, ovinos, caprinos y equinos.
                Recuento total de colonias aerobias (TVC): mayor que5,0 log
                Enterobacterias: mayor que2,5 log (porcinos: 3,0 log)

Valores diarios de la medida logarítmica de resultados aceptables, dudosos e inaceptables de contaminación (expresados en ufc/cm2 de bovinos, porcinos, ovinos, caprinos y equinos; muestras tomadas mediante el método destructivo.

')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(180 AS Decimal(6, 0)), N'1              ', N'Dispone de medios de control de accesos de los vehículos de entrada y salida.', N'El establecimiento dispondrá de medios que permitan controlar cualquier entrada o salida del matadero en relación con la producción (animales, carnes, personal?..).El acceso al mismo se realizará a través de puertas controladas.', N'Dispone de medios de control de accesos de los vehículos de entrada y salida.', N'El establecimiento dispondrá de medios que permitan controlar cualquier entrada o salida del matadero en relación con la producción (animales, carnes, personal?..).El acceso al mismo se realizará a través de puertas controladas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(201 AS Decimal(6, 0)), N'3              ', N'Dispone de un emplazamiento aislado y equipado para la limpieza y desinfección de medios de transporte de carnes.', N'Dispondrá de un emplazamiento e instalaciones adecuadas para la limpieza y desinfección de los medios de transporte de carnes, que estarán ubicadas en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.', N'Dispone de un emplazamiento aislado y equipado para la limpieza y desinfección de medios de transporte de carnes.', N'Dispondrá de un emplazamiento e instalaciones adecuadas para la limpieza y desinfección de los medios de transporte de carnes, que estarán ubicadas en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(182 AS Decimal(6, 0)), N'3              ', N'Dispone de instalaciones para la descarga y conducción de los animales a los locales de  estabulación.', N'Dispondrá de instalaciones (muelles) para la recepción de los animales vivos que garanticen el bienestar de los mismos en la descarga , sea cual fuese el transporte utilizado y conducción de los mismos a los establos del matadero. ', N'Dispone de instalaciones para la descarga y conducción de los animales a los locales de  estabulación.', N'Dispondrá de instalaciones (muelles) para la recepción de los animales vivos que garanticen el bienestar de los mismos en la descarga , sea cual fuese el transporte utilizado y conducción de los mismos a los establos del matadero. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(183 AS Decimal(6, 0)), N'3              ', N'Dispone de locales de estabulación y/o locales de espera para albergar a los animales separados de los locales de faenado y manipulación de productos.', N'Dispondrá de locales de estabulación y/o corrales de espera separados de los locales donde se manipulen productos comestibles, para albergar a los animales de manera que el dise¦o permita el respeto a las normas de bienestar animal y la higiene de los mismos.', N'Dispone de locales de estabulación y/o locales de espera para albergar a los animales separados de los locales de faenado y manipulación de productos.', N'Dispondrá de locales de estabulación y/o corrales de espera separados de los locales donde se manipulen productos comestibles, para albergar a los animales de manera que el dise¦o permita el respeto a las normas de bienestar animal y la higiene de los mismos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(184 AS Decimal(6, 0)), N'3              ', N'Los locales de estabulación están compartimentados y permiten la separación de los distintos grupos de animales.', N'Los establos estarán compartimentados permitiendo la separación de los animales por especies, lotes de origen, edades, sexo, u otros criterios atendiendo a grupos de riesgo determinados por  la Inspección Oficial.', N'Los locales de estabulación están compartimentados y permiten la separación de los distintos grupos de animales.', N'Los establos estarán compartimentados permitiendo la separación de los animales por especies, lotes de origen, edades, sexo, u otros criterios atendiendo a grupos de riesgo determinados por  la Inspección Oficial.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(212 AS Decimal(6, 0)), N'7              ', N'La eliminación de las aguas residuales procedentes de animales enfermos y sospechosos no entra en contacto con los animales sanos.', N'Existirá una eliminación de las aguas residuales procedentes de los locales de estabulación destinados a animales enfermos y sospechosos de forma que los demás animales no puedan entrar en contacto con residuos procedentes de los corrales de animales enfermos y sospechosos.', N'La eliminación de las aguas residuales procedentes de animales enfermos y sospechosos no entra en contacto con los animales sanos.', N'Existirá una eliminación de las aguas residuales procedentes de los locales de estabulación destinados a animales enfermos y sospechosos de forma que los demás animales no puedan entrar en contacto con residuos procedentes de los corrales de animales enfermos y sospechosos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(192 AS Decimal(6, 0)), N'3              ', N'Dispone de local para el embalaje y preparación de los despojos.', N'Dispondrá de local para el embalaje y preparación de los despojos, si el trabajo se efectúa en el matadero. ', N'Dispone de local para el embalaje y preparación de los despojos.', N'Dispondrá de local para el embalaje y preparación de los despojos, si el trabajo se efectúa en el matadero. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(193 AS Decimal(6, 0)), N'3              ', N'Dispone de locales para el almacenamiento de cueros, cuernos, pezu¦as y cerdas.', N'Dispondrá de un local para el almacenamiento de cueros, cuernos, pezu¦as y cerdas, separado de los locales donde se manipulen productos comestibles, en el caso de que no sean evacuados del matadero el mismo día del sacrificio.', N'Dispone de locales para el almacenamiento de cueros, cuernos, pezu¦as y cerdas.', N'Dispondrá de un local para el almacenamiento de cueros, cuernos, pezu¦as y cerdas, separado de los locales donde se manipulen productos comestibles, en el caso de que no sean evacuados del matadero el mismo día del sacrificio.')
