INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(187 AS Decimal(6, 0)), N'3              ', N'Los locales de sacrificio de ganado porcino están separadas del resto con tabique de 3m./ espacio mínimo de 5m.', N'Cuando la nave disponga de más de una línea de sacrificio, en el caso del porcino, las operaciones de escaldado, depilado, raspado y quemado estarán separadas, bien por un espacio libre de al menos 5 metros o bien por un tabique de 3 metros de altura mínimo.', N'Los locales de sacrificio de ganado porcino están separadas del resto con tabique de 3m./ espacio mínimo de 5m.', N'Cuando la nave disponga de más de una línea de sacrificio, en el caso del porcino, las operaciones de escaldado, depilado, raspado y quemado estarán separadas, bien por un espacio libre de al menos 5 metros o bien por un tabique de 3 metros de altura mínimo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(188 AS Decimal(6, 0)), N'3              ', N'Los locales de sacrificio disponen de un emplazamiento o zona diferenciada para la realización de la inspección post-mortem.', N'Dispondrá de un emplazamiento o zona diferenciada en la cadena de sacrificio, que permita efectuar, de forma eficaz y sin trabas, las tareas de inspección post-mortem. Dicho punto estará situado preferentemente, en una zona de confluencia de la canal con las vísceras rojas y blancas, permitiendo la inspección simultánea de las mismas en una única fase.', N'Los locales de sacrificio disponen de un emplazamiento o zona diferenciada para la realización de la inspección post-mortem.', N'Dispondrá de un emplazamiento o zona diferenciada en la cadena de sacrificio, que permita efectuar, de forma eficaz y sin trabas, las tareas de inspección post-mortem. Dicho punto estará situado preferentemente, en una zona de confluencia de la canal con las vísceras rojas y blancas, permitiendo la inspección simultánea de las mismas en una única fase.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(211 AS Decimal(6, 0)), N'7              ', N'Las conducciones de aguas residuales se realizan desde las partes limpias a las sucias', N'Las conducciones de aguas residuales se harán de las partes limpias a las sucias.', N'Las conducciones de aguas residuales se realizan desde las partes limpias a las sucias', N'Las conducciones de aguas residuales se harán de las partes limpias a las sucias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(344 AS Decimal(6, 0)), N'48             ', N'La descarga de los animales se realiza lo antes posible tras su llegada al matadero.', N'Los animales serán descargados lo antes posible después de su llegada. Si no puede evitarse el retraso de la operación, se les protegerá de las inclemencias del tiempo y se les proporcionará una ventilación adecuada.', N'La descarga de los animales se realiza lo antes posible tras su llegada al matadero.', N'Los animales serán descargados lo antes posible después de su llegada. Si no puede evitarse el retraso de la operación, se les protegerá de las inclemencias del tiempo y se les proporcionará una ventilación adecuada.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(210 AS Decimal(6, 0)), N'7              ', N'En los locales de estabulación las aguas residuales vierten a sumideros provistos de rejillas y sifones y están cubiertas.', N'En los locales de estabulación las aguas residuales y los líquidos se evacuarán hacia sumideros provistos de sifones y rejillas. Deberán cubrirse las conducciones a las que puedan tener acceso los animales.', N'En los locales de estabulación las aguas residuales vierten a sumideros provistos de rejillas y sifones y están cubiertas.', N'En los locales de estabulación las aguas residuales y los líquidos se evacuarán hacia sumideros provistos de sifones y rejillas. Deberán cubrirse las conducciones a las que puedan tener acceso los animales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(219 AS Decimal(6, 0)), N'58             ', N'El emplazamiento destinado a los Servicios de Inspección está completamente equipado.', N'El punto de inspección ante-mortem dispondrá de iluminación suficiente para realizar la inspección, lavamanos de uso exclusivo para la limpieza y desinfección de manos. y sistemas de inmovilización de los animales que permitan realizar la inspección detallada. ', N'El emplazamiento destinado a los Servicios de Inspección está completamente equipado.', N'El punto de inspección ante-mortem dispondrá de iluminación suficiente para realizar la inspección, lavamanos de uso exclusivo para la limpieza y desinfección de manos. y sistemas de inmovilización de los animales que permitan realizar la inspección detallada. ')
