INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(343 AS Decimal(6, 0)), N'48             ', N'Los equipos e instalaciones para la descarga (muelles, rampas,.pavimento, protección lateral etc..) evita lesiones y facilita la descarga.', N'Las zonas para la descarga de los animales, tendrán un pavimento que no sea resbaladizo, y, en caso necesario, contarán con protección lateral.
Los puentes, rampas y pasillos dispondrán de paredes, barandillas u otros medio de protección que eviten la caída de los animales fuera de ellos.
La inclusión de las rampas de salida o de acceso será la mínima posible.', N'Los equipos e instalaciones para la descarga (muelles, rampas,.pavimento, protección lateral etc..) evita lesiones y facilita la descarga.', N'Las zonas para la descarga de los animales, tendrán un pavimento que no sea resbaladizo, y, en caso necesario, contarán con protección lateral.
Los puentes, rampas y pasillos dispondrán de paredes, barandillas u otros medio de protección que eviten la caída de los animales fuera de ellos.
La inclusión de las rampas de salida o de acceso será la mínima posible.')
GO
