INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(325 AS Decimal(6, 0)), N'40             ', N'El operador económico del matadero comprueba que el origen y destino de los animales que van a ser sacrificados está acreditado por la documentación oficial de acompa¦amiento.', N'El operador económico del matadero comprueba que los animales que son trasladados al matadero deberán ir acompa¦ados de la siguiente documentación: 
1.-Guía de origen y sanidad pecuaria
2.-Declaración normalizada de información de la cadena alimentaria para el traslado de animales al matadero
3- Además, en los casos de sacrificios debido a campa¦as de saneamiento ganadero o de vaciados sanitarios, los animales irán amparados por un documento sanitario específico, (Conduce Oficial) emitido por la autoridad  competente en materia de sanidad animal.
4- En caso de animales cuyo sacrificio sea recomendado por un veterinario (siempre que se encuadre dentro de los condicionantes establecidos en la Instrucción 3/2009 del Departamento de Sanidad), irán acompa¦ados de documento que, informe de el tratamiento indicado.

La validez de la documentación de acompa¦amiento se especifica en cada documento.
', N'El operador económico del matadero comprueba que el origen y destino de los animales que van a ser sacrificados está acreditado por la documentación oficial de acompa¦amiento.', N'El operador económico del matadero comprueba que los animales que son trasladados al matadero deberán ir acompa¦ados de la siguiente documentación: 
1.-Guía de origen y sanidad pecuaria
2.-Declaración normalizada de información de la cadena alimentaria para el traslado de animales al matadero
3- Además, en los casos de sacrificios debido a campa¦as de saneamiento ganadero o de vaciados sanitarios, los animales irán amparados por un documento sanitario específico, (Conduce Oficial) emitido por la autoridad  competente en materia de sanidad animal.
4- En caso de animales cuyo sacrificio sea recomendado por un veterinario (siempre que se encuadre dentro de los condicionantes establecidos en la Instrucción 3/2009 del Departamento de Sanidad), irán acompa¦ados de documento que, informe de el tratamiento indicado.

La validez de la documentación de acompa¦amiento se especifica en cada documento.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(364 AS Decimal(6, 0)), N'52             ', N'Se dispone de un equipo de aturdimiento de repuesto en el lugar de sacrificio.', N'Se dispondrá en el lugar de sacrificio, de equipos e instrumentos de repuesto adecuados para situaciones de urgencia.', N'Se dispone de un equipo de aturdimiento de repuesto en el lugar de sacrificio.', N'Se dispondrá en el lugar de sacrificio, de equipos e instrumentos de repuesto adecuados para situaciones de urgencia.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(332 AS Decimal(6, 0)), N'46             ', N'Los sellos cumplen las características especificadas. ', N'La marca (sello oval) deberá ser legible e indeleble, y los caracteres fácilmente descifrables, siendo fijada de tal forma que sea claramente visible para la autoridad competente. Debe contener la información que a continuación se menciona:
·         Se indicará el nombre del país donde está situado el establecimiento en letras mayúsculas o bien mediante un código de dos caracteres, que según el Estado miembro dichos códigos son: AT, BE, DE, DK, ES, FI,    FR, GR, IE, ET, LU, NL, PT, SE Y UK.
·         El número del Registro General Sanitario de Alimentos del establecimiento.
·         La abreviatura CE, EC, EF, EG, EK o EY, según el idioma del estado miembro.
Las carnes declaradas NO APTAS para consumo humano no serán selladas con la marca sanitaria y se identificarán claramente de las declaradas aptas, mediante cortes que impidan la posibilidad de comercialización y con una etiqueta en la canal en la que figure el número de crotal y con la identificación expresa DECOMISADO.
En el caso del sacrificio ritual, se autorizará el marcado de las canales con el sello propio de este tipo de sacrificio, además del sello de inspección veterinaria.', N'Los sellos cumplen las características especificadas. ', N'La marca (sello oval) deberá ser legible e indeleble, y los caracteres fácilmente descifrables, siendo fijada de tal forma que sea claramente visible para la autoridad competente. Debe contener la información que a continuación se menciona:
·         Se indicará el nombre del país donde está situado el establecimiento en letras mayúsculas o bien mediante un código de dos caracteres, que según el Estado miembro dichos códigos son: AT, BE, DE, DK, ES, FI,    FR, GR, IE, ET, LU, NL, PT, SE Y UK.
·         El número del Registro General Sanitario de Alimentos del establecimiento.
·         La abreviatura CE, EC, EF, EG, EK o EY, según el idioma del estado miembro.
Las carnes declaradas NO APTAS para consumo humano no serán selladas con la marca sanitaria y se identificarán claramente de las declaradas aptas, mediante cortes que impidan la posibilidad de comercialización y con una etiqueta en la canal en la que figure el número de crotal y con la identificación expresa DECOMISADO.
En el caso del sacrificio ritual, se autorizará el marcado de las canales con el sello propio de este tipo de sacrificio, además del sello de inspección veterinaria.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(336 AS Decimal(6, 0)), N'46             ', N'Los hígado de bovinos, solípedos y porcino se marcan a fuego.', N'Los Hígados de bovinos, porcinos y solípedos aptos para consumo humano se marcarán a fuego con el sello oval de las mismas características a las descritas en los puntos anteriores.', N'Los hígado de bovinos, solípedos y porcino se marcan a fuego.', N'Los Hígados de bovinos, porcinos y solípedos aptos para consumo humano se marcarán a fuego con el sello oval de las mismas características a las descritas en los puntos anteriores.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(337 AS Decimal(6, 0)), N'46             ', N'Los demás subproductos y despojos aptos para consumo se marcan de acuerdo a las exigencias.', N'Los demás subproductos y despojos aptos para consumo se marcarán directamente a fuego o con tinta o sobre el envase con el sello oval descrito en puntos anteriores.', N'Los demás subproductos y despojos aptos para consumo se marcan de acuerdo a las exigencias.', N'Los demás subproductos y despojos aptos para consumo se marcarán directamente a fuego o con tinta o sobre el envase con el sello oval descrito en puntos anteriores.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(365 AS Decimal(6, 0)), N'53             ', N'El sangrado se realiza lo antes posible después del aturdido y antes de que el animal recupere la consciencia.', N'El sangrado de los animales que hayan sido aturdidos comenzará lo antes posible después del aturdido y se deberá efectuar de manera que se provoque un desangrado rápido, profuso y completo, mediante la incisión de al menos una arteria carótida o de los vasos de los que nacen.
En cualquier caso, deberá efectuarse el sangrado antes de que el animal recobre el conocimiento. Los plazos máximos para comenzar el sangrado tras el aturdido son los siguientes:
proyectil fijo o libre. 60 seg.
electronarcosis y contusión: 20 seg.
exposición a CO2: 60 seg. tras su retirada de la cámara.
En el caso del sacrificio ritual, al sacrificar el animal, debe realizarse un corte limpio sobre las principales vías sanguíneas (carótida, yugular) y respiratorias.
El matarife encargado de dicha tarea debe tener la formación acreditada necesaria para realizar este tipo de sacrificios. En cualquier caso, actuará bajo la supervisión del Veterinario Oficial.', N'El sangrado se realiza lo antes posible después del aturdido y antes de que el animal recupere la consciencia.', N'El sangrado de los animales que hayan sido aturdidos comenzará lo antes posible después del aturdido y se deberá efectuar de manera que se provoque un desangrado rápido, profuso y completo, mediante la incisión de al menos una arteria carótida o de los vasos de los que nacen.
En cualquier caso, deberá efectuarse el sangrado antes de que el animal recobre el conocimiento. Los plazos máximos para comenzar el sangrado tras el aturdido son los siguientes:
proyectil fijo o libre. 60 seg.
electronarcosis y contusión: 20 seg.
exposición a CO2: 60 seg. tras su retirada de la cámara.
En el caso del sacrificio ritual, al sacrificar el animal, debe realizarse un corte limpio sobre las principales vías sanguíneas (carótida, yugular) y respiratorias.
El matarife encargado de dicha tarea debe tener la formación acreditada necesaria para realizar este tipo de sacrificios. En cualquier caso, actuará bajo la supervisión del Veterinario Oficial.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(353 AS Decimal(6, 0)), N'50             ', N'Se suministra alimento a los animales que no se han sacrificado en una jornada de trabajo.', N'Los animales que permanezcan 12 horas o más en un matadero serán alojados, y cuando proceda, amarrados con ronzales de tal modo que puedan tenderse sin dificultad. Si no estuvieren amarrados con ronzales, deberán disponer de alimentos que les permitan alimentarse sin ser molestados.', N'Se suministra alimento a los animales que no se han sacrificado en una jornada de trabajo.', N'Los animales que permanezcan 12 horas o más en un matadero serán alojados, y cuando proceda, amarrados con ronzales de tal modo que puedan tenderse sin dificultad. Si no estuvieren amarrados con ronzales, deberán disponer de alimentos que les permitan alimentarse sin ser molestados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(366 AS Decimal(6, 0)), N'53             ', N'Se espera a que haya finalizado totalmente el sangrado para proceder a otras operaciones.', N'Tras la incisión de los vasos sanguíneos, no se someterá a los animales a ninguna otra operación de preparación de la canal ni a estimulación eléctrica alguna antes de que haya finalizado el sangrado.', N'Se espera a que haya finalizado totalmente el sangrado para proceder a otras operaciones.', N'Tras la incisión de los vasos sanguíneos, no se someterá a los animales a ninguna otra operación de preparación de la canal ni a estimulación eléctrica alguna antes de que haya finalizado el sangrado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(362 AS Decimal(6, 0)), N'52             ', N'El equipo de aturdido se encuentra en buenas condiciones.', N'Los equipos se mantendrán en buenas condiciones de mantenimiento.', N'El equipo de aturdido se encuentra en buenas condiciones.', N'Los equipos se mantendrán en buenas condiciones de mantenimiento.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(599 AS Decimal(6, 0)), N'39             ', N'La denominación de venta de los productos dietéticos  va acompa¦ada de la mención de sus características nutricionales especiales.', N'Estos productos podrán caracterizarse por las indicaciones dietéticos o de régimen. La denominación de venta de los productos dietéticos deberá ir acompa¦ada de la mención de sus características nutricionales especiales. Ejemplos:
sal hiposódica o asódica
pan sin gluten (destinado a enfermos celiacos);
complementos de la dieta que contienen uno o varios nutrientes con el fin de completar las cantidades ingeridas normalmente con la dieta (pólen, jalea real, propoleo, lecitina de soja, etc.),
alimentos enriquecidos cuando se le adicionen nutrientes con el fin de que el contenido de los mismos sea superior al de su composición normal
preparados para lactantes y preparados de continuación
productos alimenticios energéticos ricos en hidratos de carbono (alimentos adaptados a un intenso desgaste muscular, sobretodo para los deportistas), etc. ', N'La denominación de venta de los productos dietéticos  va acompa¦ada de la mención de sus características nutricionales especiales.', N'Estos productos podrán caracterizarse por las indicaciones dietéticos o de régimen. La denominación de venta de los productos dietéticos deberá ir acompa¦ada de la mención de sus características nutricionales especiales. Ejemplos:
sal hiposódica o asódica
pan sin gluten (destinado a enfermos celiacos);
complementos de la dieta que contienen uno o varios nutrientes con el fin de completar las cantidades ingeridas normalmente con la dieta (pólen, jalea real, propoleo, lecitina de soja, etc.),
alimentos enriquecidos cuando se le adicionen nutrientes con el fin de que el contenido de los mismos sea superior al de su composición normal
preparados para lactantes y preparados de continuación
productos alimenticios energéticos ricos en hidratos de carbono (alimentos adaptados a un intenso desgaste muscular, sobretodo para los deportistas), etc. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1746 AS Decimal(6, 0)), N'30             ', N'Los helados y granizados se mantienen a las temperaturas requeridas: -18º C + - 4º C para helados y 0º C para granizados.', N'Los helados durante el transporte se mantendrán a una temperatura
Helados: -menor que -18º C. + - 4º C.
