INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111070 AS Decimal(6, 0)), N'81             ', N'REGISTRO ACCIONES CORRECTORAS: Las acciones correctoras relacionadas con los controles anuales de la autoevaluación se adoptan y se anotan adecuadamente.', N'Se revisará que cuando se han superado los valores marcados, se han adoptado medidas, éstas son las correctas y se han anotado. Las medidas tendrán en cuenta las condiciones del producto y además de solucionar el problema irán encaminadas a evitar que suceda de nuevo.', N'REGISTRO ACCIONES CORRECTORAS: Las acciones correctoras relacionadas con los controles anuales de la autoevaluación se adoptan y se anotan adecuadamente.', N'Se revisará que cuando se han superado los valores marcados, se han adoptado medidas, éstas son las correctas y se han anotado. Las medidas tendrán en cuenta las condiciones del producto y además de solucionar el problema irán encaminadas a evitar que suceda de nuevo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1500 AS Decimal(6, 0)), N'46             ', N'El marcado sanitario se coloca correctamente según las unidades de envasado o en carnes directamente.', N'El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado. El material usado para el marcado deberá reunir todas las exigencias de la higiene: la información  que incluya dicho marcado será perfectamente legible, indeleble y en caracteres fácilmente identificables.
El marcado de inspección veterinaria comprenderá un óvalo que contenga la siguiente información en su interior:
En la parte superior las siglas en mayúsculas ESP. 
En el centro, el número del Registro General Sanitario de Alimentos del establecimiento.
En la parte inferior las siglas CEE.
Los caracteres deberán tener una altura de 0,2 cm tanto para las letras como para las cifras. 
El marcado de inspección sanitaria figurará:
En  canales no envasadas individualmente, por medio de un marchamo o un sello que no sea reutilizable.
Sobre envolturas u otros embalajes de las canales embaladas o, de modo visible, debajo de ellos.
Sobre las envolturas u otros embalajes de las partes de canales o despojos embalados en peque¦as cantidades o, de modo visible, debajo de ellos.
El marcado de inspección veterinaria deberá realizarse sobre grandes embalajes con letras que deberán tener 0,8 cm de altura y cifras de 1,1 cm. En los casos en que aparezca un marcado de inspección veterinaria sobre la envoltura o embalaje se aplicará de forma que se destruya al abrir éstos o la envoltura o el embalaje se marcarán de forma que no puedan volver a utilizarse una vez abiertos.
', N'El marcado sanitario se coloca correctamente según las unidades de envasado o en carnes directamente.', N'El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado. El material usado para el marcado deberá reunir todas las exigencias de la higiene: la información  que incluya dicho marcado será perfectamente legible, indeleble y en caracteres fácilmente identificables.
El marcado de inspección veterinaria comprenderá un óvalo que contenga la siguiente información en su interior:
En la parte superior las siglas en mayúsculas ESP. 
En el centro, el número del Registro General Sanitario de Alimentos del establecimiento.
En la parte inferior las siglas CEE.
Los caracteres deberán tener una altura de 0,2 cm tanto para las letras como para las cifras. 
El marcado de inspección sanitaria figurará:
En  canales no envasadas individualmente, por medio de un marchamo o un sello que no sea reutilizable.
Sobre envolturas u otros embalajes de las canales embaladas o, de modo visible, debajo de ellos.
Sobre las envolturas u otros embalajes de las partes de canales o despojos embalados en peque¦as cantidades o, de modo visible, debajo de ellos.
El marcado de inspección veterinaria deberá realizarse sobre grandes embalajes con letras que deberán tener 0,8 cm de altura y cifras de 1,1 cm. En los casos en que aparezca un marcado de inspección veterinaria sobre la envoltura o embalaje se aplicará de forma que se destruya al abrir éstos o la envoltura o el embalaje se marcarán de forma que no puedan volver a utilizarse una vez abiertos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(361 AS Decimal(6, 0)), N'52             ', N'Cuando el aturdido no es eficaz se repite la operación.', N'Siempre que se compruebe que el aturdido no ha sido eficaz se procederá a repetir el aturdido antes de comenzar el sangrado.
Un correcto aturdido puede comprobarse mediante la comprobación de los siguientes signos: cuerpo rígido, ausencia de reflejos oculares, ausencia de contracciones voluntarias, ritmo respiratorio normal detenido etc.
Como signos de recuperación que obligaría a un nuevo aturdido pueden citarse: respiración rítmica, vocalizaciones, reflejos oculares, pesta¦eos, reflejo de enderezamiento del lomo arqueado etc.', N'Cuando el aturdido no es eficaz se repite la operación.', N'Siempre que se compruebe que el aturdido no ha sido eficaz se procederá a repetir el aturdido antes de comenzar el sangrado.
Un correcto aturdido puede comprobarse mediante la comprobación de los siguientes signos: cuerpo rígido, ausencia de reflejos oculares, ausencia de contracciones voluntarias, ritmo respiratorio normal detenido etc.
Como signos de recuperación que obligaría a un nuevo aturdido pueden citarse: respiración rítmica, vocalizaciones, reflejos oculares, pesta¦eos, reflejo de enderezamiento del lomo arqueado etc.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(189 AS Decimal(6, 0)), N'3              ', N'Dispone de locales o instalaciones separados para el vaciado y lavado de intestinos.', N'Dispondrá de locales separados de las instalaciones donde se manipulen productos comestibles, destinados al vaciado y lavado de intestinos, excepto cuando se disponga de un equipo mecánico en circuito cerrado para el procesado de tripas e intestinos, cuyo dise¦o y funcionamiento impida de forma eficaz cualquier contaminación de las carnes frescas, dicho equipo deberá estar situado en un lugar especial separado de las carnes frescas expuestas, mediante un tabique con una altura mínima de 3 metros. ', N'Dispone de locales o instalaciones separados para el vaciado y lavado de intestinos.', N'Dispondrá de locales separados de las instalaciones donde se manipulen productos comestibles, destinados al vaciado y lavado de intestinos, excepto cuando se disponga de un equipo mecánico en circuito cerrado para el procesado de tripas e intestinos, cuyo dise¦o y funcionamiento impida de forma eficaz cualquier contaminación de las carnes frescas, dicho equipo deberá estar situado en un lugar especial separado de las carnes frescas expuestas, mediante un tabique con una altura mínima de 3 metros. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(367 AS Decimal(6, 0)), N'53             ', N'Cuando una misma persona se encarga de varias operaciones lo hace consecutivamente con un animal antes de comenzar con otro.', N'Cuando una persona se encargue del aturdido, la sujeción, el izado y el sangrado de los animales, deberá efectuar estas operaciones consecutivamente con un animal antes de efectuarlas con otro.', N'Cuando una misma persona se encarga de varias operaciones lo hace consecutivamente con un animal antes de comenzar con otro.', N'Cuando una persona se encargue del aturdido, la sujeción, el izado y el sangrado de los animales, deberá efectuar estas operaciones consecutivamente con un animal antes de efectuarlas con otro.')
GO
