INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(354 AS Decimal(6, 0)), N'50             ', N'No se observan acúmulos de estiércol, líquidos o suciedad.', N'Se evitará el acúmulo de estiércol, líquidos o suciedad en los boxees o cortinas donde están los animales.', N'No se observan acúmulos de estiércol, líquidos o suciedad.', N'Se evitará el acúmulo de estiércol, líquidos o suciedad en los boxees o cortinas donde están los animales.')
