INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(355 AS Decimal(6, 0)), N'51             ', N'El matadero dispone de equipos de sujeción eficaces para las distintas especies.', N'Equipos :Los mataderos dispondrán de equipos de sujeción que permitan realizar el aturdido evitando agitación o sufrimiento a los animales y faciliten el manejo al operario. Los medios de sujeción más eficaces son los siguientes:
Boxees de aturdido en los que el animal puede estar de pie.
Transportadores mecánicos.
Sujeción manual para los animales peque¦os.
Ronzales, collares o bridas útiles para sujetar la cabeza de bovinos y solípedos.', N'El matadero dispone de equipos de sujeción eficaces para las distintas especies.', N'Equipos :Los mataderos dispondrán de equipos de sujeción que permitan realizar el aturdido evitando agitación o sufrimiento a los animales y faciliten el manejo al operario. Los medios de sujeción más eficaces son los siguientes:
Boxees de aturdido en los que el animal puede estar de pie.
Transportadores mecánicos.
Sujeción manual para los animales peque¦os.
Ronzales, collares o bridas útiles para sujetar la cabeza de bovinos y solípedos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(349 AS Decimal(6, 0)), N'49             ', N'Los animales son trasladados al lugar de sacrificio cuando van a ser sacrificados de inmediato.', N'Los animales sólo serán trasladados al lugar de sacrificio cuando vayan a ser sacrificados de inmediato. Los animales que no fueren sacrificados inmediatamente después de su llegada, deberán estar estabulados.', N'Los animales son trasladados al lugar de sacrificio cuando van a ser sacrificados de inmediato.', N'Los animales sólo serán trasladados al lugar de sacrificio cuando vayan a ser sacrificados de inmediato. Los animales que no fueren sacrificados inmediatamente después de su llegada, deberán estar estabulados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(347 AS Decimal(6, 0)), N'49             ', N'Los instrumentos para guiar a los animales se utilizan breves momentos y con ese fin.', N'Los instrumentos destinados a guiar a los animales sólo podrán emplearse con este fin y únicamente durante breves momentos. Los instrumentos que administren descargas eléctricas sólo podrán emplearse con ganado vacuno adulto y porcino que se resista a avanzar, y siempre que las descargas no duren más de dos segundos, se administren a intervalos adecuados, y los animales dispongan de espacio libre delante de ellos para avanzar. Las descargas sólo podrán aplicarse en los músculos de los cuartos traseros.', N'Los instrumentos para guiar a los animales se utilizan breves momentos y con ese fin.', N'Los instrumentos destinados a guiar a los animales sólo podrán emplearse con este fin y únicamente durante breves momentos. Los instrumentos que administren descargas eléctricas sólo podrán emplearse con ganado vacuno adulto y porcino que se resista a avanzar, y siempre que las descargas no duren más de dos segundos, se administren a intervalos adecuados, y los animales dispongan de espacio libre delante de ellos para avanzar. Las descargas sólo podrán aplicarse en los músculos de los cuartos traseros.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(348 AS Decimal(6, 0)), N'49             ', N'Los animales no reciben un trato desconsiderado durante la conducción.', N'Se desplazará a los animales con cuidado. La reducción de los ruidos (chirridos, golpes escapes de aire de los sistemas neumáticos...) , la iluminación adecuada (rehusan entrar en un sitio oscuro) y que no produzca reflejos en el suelo y el manejo de grupos peque¦os facilita el movimiento de los animales. El olor a sangre y los objetos (papeles, etc. en el suelo de los pasillos frena el movimiento.
Se prohibe golpear a los animales o ejercer presión sobre las partes de cuerpo especialmente sensibles. En particular, se prohibe aplastar, retorcer o quebrar los rabos de los animales, o coger a los animales por los ojos. Se prohibe propinarles golpes desconsiderados, en especial puntapiés. ', N'Los animales no reciben un trato desconsiderado durante la conducción.', N'Se desplazará a los animales con cuidado. La reducción de los ruidos (chirridos, golpes escapes de aire de los sistemas neumáticos...) , la iluminación adecuada (rehusan entrar en un sitio oscuro) y que no produzca reflejos en el suelo y el manejo de grupos peque¦os facilita el movimiento de los animales. El olor a sangre y los objetos (papeles, etc. en el suelo de los pasillos frena el movimiento.
Se prohibe golpear a los animales o ejercer presión sobre las partes de cuerpo especialmente sensibles. En particular, se prohibe aplastar, retorcer o quebrar los rabos de los animales, o coger a los animales por los ojos. Se prohibe propinarles golpes desconsiderados, en especial puntapiés. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(370 AS Decimal(6, 0)), N'54             ', N'La industria dispone del registro del control regular de la higiene.', N'Registro del control regular de la higiene.
La empresa dispondrá de un registro de muestreo de canales que muestre los siguientes datos:
Tipo: región anatómica muestreada
Origen: especie a la que se toma muestra.  Nº de crotal
Fecha y hora de recogida
Persona que toma la muestra
Laboratorio que realiza la muestra
Fecha de análisis
Método utilizado
Resultados en ufc/placa y cálculo en ufc/cm2
Incidencias y Medidas correctoras adoptadas
La empresa dispondrá asimismo de un registro del control de la higiene en superficies y utillaje en el que consten los siguientes datos:
Punto de muestreo
Fecha y hora de la recogida de la muestra
Resultados que se presentarán periódicamente en forma de histograma de barras para mostrar la evolución
Incidencias y Medidas correctoras adoptadas', N'La industria dispone del registro del control regular de la higiene.', N'Registro del control regular de la higiene.
La empresa dispondrá de un registro de muestreo de canales que muestre los siguientes datos:
