INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(334 AS Decimal(6, 0)), N'46             ', N'Se colocan las marcas sanitarias en todas las partes de la canal de acuerdo con la especie.', N'Las canales se marcarán a tinta o a fuego en las siguientes piezas de la canal:
si las canales pesaran más de 65 Kg. Llevarán la marca sanitaria en cada media canal al menos en los siguientes puntos: cara externa de la pierna, lomos, costillar, pecho y espalda.
Si pesaran menos de 65 Kg deberán llevar como mínimo cuatro marcas sanitarias colocadas sobre las espaldas y sobre la cara externa de las piernas
En el caso de canales de cabritos, corderos y lechones llevarán como mínimo dos se¦ales de marcado a cada lado de la canal, en la espalda y en la parte externa de la región femoral.
En el caso de corderos, cabritos y lechones el marcado podrá hacerse mediante etiquetas o chapas de material autorizado para entrar en contacto con los alimentos y estarán dise¦adas de forma que no puedan reutilizarse.', N'Se colocan las marcas sanitarias en todas las partes de la canal de acuerdo con la especie.', N'Las canales se marcarán a tinta o a fuego en las siguientes piezas de la canal:
si las canales pesaran más de 65 Kg. Llevarán la marca sanitaria en cada media canal al menos en los siguientes puntos: cara externa de la pierna, lomos, costillar, pecho y espalda.
Si pesaran menos de 65 Kg deberán llevar como mínimo cuatro marcas sanitarias colocadas sobre las espaldas y sobre la cara externa de las piernas
En el caso de canales de cabritos, corderos y lechones llevarán como mínimo dos se¦ales de marcado a cada lado de la canal, en la espalda y en la parte externa de la región femoral.
En el caso de corderos, cabritos y lechones el marcado podrá hacerse mediante etiquetas o chapas de material autorizado para entrar en contacto con los alimentos y estarán dise¦adas de forma que no puedan reutilizarse.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(342 AS Decimal(6, 0)), N'47             ', N'Los animales que no pueden andar son sacrificados in situ o se trasladan sin producirles sufrimiento. Los lactantes se sacrifican de forma inmediata o como máximo en dos horas tras la descarga.', N'Se sacrificará o se dará muerte en las instalaciones del matadero a los animales heridos o enfermos. No obstante, el veterinario oficial, podrá autorizar el traslado de animales heridos o enfermos para su sacrificio o matanza siempre que ello no suponga sufrimientos adicionales para dichos animales.
Los animales que hayan padecido sufrimiento o dolores durante el transporte o a su llegada al matadero, así como los animales que no hayan sido destetados deberán ser sacrificados inmediatamente. Si no fuera posible, se aislarán y sacrificarán lo antes posible y al menos dentro de las dos horas siguientes. Los animales que no puedan andar no serán arrastrados al lugar de sacrificio, sino que se les dará muerte allí donde yazcan o, si fuera practicable sin que ello entra¦e ningún sufrimiento innecesario, serán transportados hasta el local de sacrificio de urgencia en una carretilla o plataforma rodante.', N'Los animales que no pueden andar son sacrificados in situ o se trasladan sin producirles sufrimiento. Los lactantes se sacrifican de forma inmediata o como máximo en dos horas tras la descarga.', N'Se sacrificará o se dará muerte en las instalaciones del matadero a los animales heridos o enfermos. No obstante, el veterinario oficial, podrá autorizar el traslado de animales heridos o enfermos para su sacrificio o matanza siempre que ello no suponga sufrimientos adicionales para dichos animales.
Los animales que hayan padecido sufrimiento o dolores durante el transporte o a su llegada al matadero, así como los animales que no hayan sido destetados deberán ser sacrificados inmediatamente. Si no fuera posible, se aislarán y sacrificarán lo antes posible y al menos dentro de las dos horas siguientes. Los animales que no puedan andar no serán arrastrados al lugar de sacrificio, sino que se les dará muerte allí donde yazcan o, si fuera practicable sin que ello entra¦e ningún sufrimiento innecesario, serán transportados hasta el local de sacrificio de urgencia en una carretilla o plataforma rodante.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(352 AS Decimal(6, 0)), N'50             ', N'Los animales estabulados disponen permanentemente de agua potable.', N'Los animales que no sean trasladados directamente al lugar de sacrificio después de su llegada, deberán tener constantemente a su disposición agua potable distribuida permanentemente mediante equipos adecuados. Se suministrará alimentos a los animales que no hayan sido sacrificados dentro de las 12 horas siguientes a su llegada y, posteriormente, se les proporcionará cantidades moderadas de alimentos a intervalos apropiados.', N'Los animales estabulados disponen permanentemente de agua potable.', N'Los animales que no sean trasladados directamente al lugar de sacrificio después de su llegada, deberán tener constantemente a su disposición agua potable distribuida permanentemente mediante equipos adecuados. Se suministrará alimentos a los animales que no hayan sido sacrificados dentro de las 12 horas siguientes a su llegada y, posteriormente, se les proporcionará cantidades moderadas de alimentos a intervalos apropiados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(368 AS Decimal(6, 0)), N'54             ', N'La industria dispone de registro de entrada de los animales.', N'Registro de entrada de los animales:
En el registro de entradas del matadero figurarán los siguientes datos
Fecha de entrada del animal al matadero
Fecha de sacrificio
Nº de identificación animal
Nº de documento sanitario
Nº de orden de sacrificio
Nombre y origen ganadero', N'La industria dispone de registro de entrada de los animales.', N'Registro de entrada de los animales:
En el registro de entradas del matadero figurarán los siguientes datos
Fecha de entrada del animal al matadero
Fecha de sacrificio
Nº de identificación animal
Nº de documento sanitario
Nº de orden de sacrificio
Nombre y origen ganadero')
GO
