INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(340 AS Decimal(6, 0)), N'47             ', N'Las personas encargadas del manejo tienen preparación y destreza para realizarlo de forma eficaz y humanitaria.', N'
Las personas que intervengan en las operaciones aquí descritas deberán poseer la preparación y destreza necesarias para llevar a cabo estos cometidos de forma humanitaria y eficaz en todas las fases del manejo de los animales vivos:
descarga, desplazamiento, estabulación, sujeción, aturdido y sangrado.', N'Las personas encargadas del manejo tienen preparación y destreza para realizarlo de forma eficaz y humanitaria.', N'
Las personas que intervengan en las operaciones aquí descritas deberán poseer la preparación y destreza necesarias para llevar a cabo estos cometidos de forma humanitaria y eficaz en todas las fases del manejo de los animales vivos:
descarga, desplazamiento, estabulación, sujeción, aturdido y sangrado.')
