INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(360 AS Decimal(6, 0)), N'52             ', N'El aturdido se realiza respetando las instrucciones para cada método y especie.', N'Los métodos de aturdido en las distintas especies y en las instrucciones de aplicación, están recogidas en el capitulo de Bienestar Animal. Dado el tama¦o del cocumento se puede acceder al mismo a partir del módulo de Documentación en la P-41.', N'El aturdido se realiza respetando las instrucciones para cada método y especie.', N'Los métodos de aturdido en las distintas especies y en las instrucciones de aplicación, están recogidas en el capitulo de Bienestar Animal. Dado el tama¦o del cocumento se puede acceder al mismo a partir del módulo de Documentación en la P-41.')
