INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(338 AS Decimal(6, 0)), N'46             ', N'La tinta que se utiliza para el sellado es la autorizada.', N'Las tintas que se podrán utilizar para el marcado sanitario son las siguientes: Marrón HT (E 155), azul brillante FCF (E 133) y ROJO ALLURA (E-129) o una mezcla de ellas', N'La tinta que se utiliza para el sellado es la autorizada.', N'Las tintas que se podrán utilizar para el marcado sanitario son las siguientes: Marrón HT (E 155), azul brillante FCF (E 133) y ROJO ALLURA (E-129) o una mezcla de ellas')
