INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(327 AS Decimal(6, 0)), N'54             ', N'La industria dispone de un sistema de gestión de la ICA recibida.', N'El operador económico del matadero desarrollará métodos que permitan evaluar adecuadamente la ICA y estarán vinculados a los procedimientos basados en APPCC, a sistemas integrados de producción, sistemas privados de control, certificaciones de terceros u otras.', N'La industria dispone de un sistema de gestión de la ICA recibida.', N'El operador económico del matadero desarrollará métodos que permitan evaluar adecuadamente la ICA y estarán vinculados a los procedimientos basados en APPCC, a sistemas integrados de producción, sistemas privados de control, certificaciones de terceros u otras.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(341 AS Decimal(6, 0)), N'47             ', N'Los animales no son maltratados por el personal.', N'
El personal encargado del manejo de los animales no les causará agitación, dolor, o sufrimientos que sean evitables durante las operaciones de desplazamiento, estabulación, sujeción, aturdido y sacrificio. (La vocalización del ganado vacuno y porcino es un indicador del malestar animal en cualquiera de las fases, excepto durante la estabulación).', N'Los animales no son maltratados por el personal.', N'
El personal encargado del manejo de los animales no les causará agitación, dolor, o sufrimientos que sean evitables durante las operaciones de desplazamiento, estabulación, sujeción, aturdido y sacrificio. (La vocalización del ganado vacuno y porcino es un indicador del malestar animal en cualquiera de las fases, excepto durante la estabulación).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(190 AS Decimal(6, 0)), N'3              ', N'Dispone de locales separados transformación de tripas e intestinos (escaldado, blanqueado, salado y secado).', N'Dispondrá de locales separados de los locales donde se manipulen productos comestibles, destinados a la transformación de tripas e intestinos (escaldado, blanqueado, salado o secado) si dichos trabajos se realizan en el matadero. ', N'Dispone de locales separados transformación de tripas e intestinos (escaldado, blanqueado, salado y secado).', N'Dispondrá de locales separados de los locales donde se manipulen productos comestibles, destinados a la transformación de tripas e intestinos (escaldado, blanqueado, salado o secado) si dichos trabajos se realizan en el matadero. ')
