INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(202 AS Decimal(6, 0)), N'3              ', N'Si dispone de un emplazamiento para la limpieza y desinfección de los medios de transporte de los animales vivos está aislado y equipado. ', N'En el caso de que disponga de emplazamiento e instalaciones para la limpieza y desinfección de los medios de transporte de animales de abasto, estos estarán ubicados en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.', N'Si dispone de un emplazamiento para la limpieza y desinfección de los medios de transporte de los animales vivos está aislado y equipado. ', N'En el caso de que disponga de emplazamiento e instalaciones para la limpieza y desinfección de los medios de transporte de animales de abasto, estos estarán ubicados en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(256 AS Decimal(6, 0)), N'26             ', N'Cumplen los requisitos y condiciones de control documental para el destino de los subproductos .', N'Los SUBPRODUCTOS generados con destino a transformación industrial irán acompa¦ados a destino del documento que será emitido por el matadero. ', N'Cumplen los requisitos y condiciones de control documental para el destino de los subproductos .', N'Los SUBPRODUCTOS generados con destino a transformación industrial irán acompa¦ados a destino del documento que será emitido por el matadero. ')
