INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(270 AS Decimal(6, 0)), N'32             ', N'En la conducción a sacrificio se cumplen las condiciones, de cadencia y orden establecido por criterio sanitario.', N'La conducción a sacrificio de los animales estabulados debe garantizar el orden establecido por criterios sanitarios, respetando los grupos
VACUNO:          1-animales menores de 12 meses.(Retirada MER)
                       2-animales entre 12 y 24 meses. (Retirada MER)
                       3-animales mayores de 24 meses.(Muestreo EEB)
                       4-animales mayores de 30 meses.(Retirada MER)
OVINO:         1-animales menores de 12 meses. (Retirada MER)
                    2-animales mayores de 12 meses. (Retirada MER)
                   3 -animales mayores de 18 meses.(Muestreo EET)
TODAS LAS ESPECIES:
                       1-reses procedentes de campa¦as de saneamiento.
                       2-reses destinadas a sacrificio de urgencia.
                       3-reses para  las que el veterinario determine un orden concreto en el sacrificio.', N'En la conducción a sacrificio se cumplen las condiciones, de cadencia y orden establecido por criterio sanitario.', N'La conducción a sacrificio de los animales estabulados debe garantizar el orden establecido por criterios sanitarios, respetando los grupos
VACUNO:          1-animales menores de 12 meses.(Retirada MER)
                       2-animales entre 12 y 24 meses. (Retirada MER)
                       3-animales mayores de 24 meses.(Muestreo EEB)
                       4-animales mayores de 30 meses.(Retirada MER)
OVINO:         1-animales menores de 12 meses. (Retirada MER)
                    2-animales mayores de 12 meses. (Retirada MER)
                   3 -animales mayores de 18 meses.(Muestreo EET)
TODAS LAS ESPECIES:
                       1-reses procedentes de campa¦as de saneamiento.
                       2-reses destinadas a sacrificio de urgencia.
                       3-reses para  las que el veterinario determine un orden concreto en el sacrificio.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(271 AS Decimal(6, 0)), N'32             ', N'El sistema de aturdimiento en ganado vacuno garantiza las normas de  protección frente a las EETs.', N'En el caso del ganado vacuno aturdido mediante el sistema de bala cautiva, el matadero dispondrá de doble equipo con el fin de garantizar el cumplimiento de las normas de protección frente a las EETs.', N'El sistema de aturdimiento en ganado vacuno garantiza las normas de  protección frente a las EETs.', N'En el caso del ganado vacuno aturdido mediante el sistema de bala cautiva, el matadero dispondrá de doble equipo con el fin de garantizar el cumplimiento de las normas de protección frente a las EETs.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(272 AS Decimal(6, 0)), N'32             ', N'El animal es abatido sobre parrilla o sistema similar que no suponga suciedad a¦adida en el faenado.', N'En todas las especies sacrificadas el animal insensibilizado será abatido sobre una superficie (parrilla, plataforma, etc.) que no le suponga una contaminación a¦adida, y dificulte el desollado higiénico del animal (especies con piel) o en el caso del ganado porcino represente un aporte de estiércol, sangre etc. al agua de la cuba de escaldado.', N'El animal es abatido sobre parrilla o sistema similar que no suponga suciedad a¦adida en el faenado.', N'En todas las especies sacrificadas el animal insensibilizado será abatido sobre una superficie (parrilla, plataforma, etc.) que no le suponga una contaminación a¦adida, y dificulte el desollado higiénico del animal (especies con piel) o en el caso del ganado porcino represente un aporte de estiércol, sangre etc. al agua de la cuba de escaldado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(263 AS Decimal(6, 0)), N'30             ', N'No se transportan conjuntamente carnes embaladas y carnes sin embalar, salvo si se dispone de compartimentos estancos.', N'No se podrá transportar en el mismo medio de transporte las carnes embaladas con las carnes sin embalar, salvo que dicho vehículo disponga de compartimentos estancos que permitan una separación física de ambos tipos de carne.', N'No se transportan conjuntamente carnes embaladas y carnes sin embalar, salvo si se dispone de compartimentos estancos.', N'No se podrá transportar en el mismo medio de transporte las carnes embaladas con las carnes sin embalar, salvo que dicho vehículo disponga de compartimentos estancos que permitan una separación física de ambos tipos de carne.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(239 AS Decimal(6, 0)), N'58             ', N'Dispone de sistemas de marcado para la aptitud de consumo de las carnes frescas.', N'Dispondrá de sistemas de marcado para la aptitud de consumo de las canales y despojos para todo tipo de sellado necesario en las tareas de inspección.', N'Dispone de sistemas de marcado para la aptitud de consumo de las carnes frescas.', N'Dispondrá de sistemas de marcado para la aptitud de consumo de las canales y despojos para todo tipo de sellado necesario en las tareas de inspección.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(265 AS Decimal(6, 0)), N'32             ', N'En la recepción de los animales en el matadero, se tiene en cuenta el grado  de limpieza de la piel y se dispone de medios para su limpieza.', N'El matadero deberá controlar la llegada de los animales a sacrificio en condiciones de limpieza que garanticen un faenado posterior en condiciones higiénicas.
En caso de que se observe la llegada de animales con un alto grado de suciedad el matadero deberá disponer de medios que permitan su limpieza antes de entrar a la nave de sacrificio a fin de reducir el riesgo de contaminación en la carne y en la nave de sacrificio.', N'En la recepción de los animales en el matadero, se tiene en cuenta el grado  de limpieza de la piel y se dispone de medios para su limpieza.', N'El matadero deberá controlar la llegada de los animales a sacrificio en condiciones de limpieza que garanticen un faenado posterior en condiciones higiénicas.
En caso de que se observe la llegada de animales con un alto grado de suciedad el matadero deberá disponer de medios que permitan su limpieza antes de entrar a la nave de sacrificio a fin de reducir el riesgo de contaminación en la carne y en la nave de sacrificio.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(243 AS Decimal(6, 0)), N'11             ', N'Dispone de registro gráfico de temperaturas en cámaras.', N'Todas las cámaras dispondrán de un registro de temperatura continuo, que sea legible o trazado en un gráfico, de modo que se disponga de un registro permanente de la temperatura existente en todo momento. Deberá ser posible identificar la fecha y la hora de los registros. No se aceptará el registro manual de la temperatura, sea cual fuere su frecuencia. En el caso de que esté conectado a un sistema informatizado, los registros podrán ser continuos o intermitentes, en este último caso deberán obtenerse al menos dos veces por hora. Se conservarán los registros como mínimo durante dos semanas y deberán mantenerse a disposición del veterinario oficial.', N'Dispone de registro gráfico de temperaturas en cámaras.', N'Todas las cámaras dispondrán de un registro de temperatura continuo, que sea legible o trazado en un gráfico, de modo que se disponga de un registro permanente de la temperatura existente en todo momento. Deberá ser posible identificar la fecha y la hora de los registros. No se aceptará el registro manual de la temperatura, sea cual fuere su frecuencia. En el caso de que esté conectado a un sistema informatizado, los registros podrán ser continuos o intermitentes, en este último caso deberán obtenerse al menos dos veces por hora. Se conservarán los registros como mínimo durante dos semanas y deberán mantenerse a disposición del veterinario oficial.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(260 AS Decimal(6, 0)), N'30             ', N'Las carnes despiezadas en un máximo de tres piezas se transportan suspendidas.', N'El transporte de canales debe estar provisto de dispositivos de suspensión colocados a una altura tal que las carnes no puedan tocar el suelo.', N'Las carnes despiezadas en un máximo de tres piezas se transportan suspendidas.', N'El transporte de canales debe estar provisto de dispositivos de suspensión colocados a una altura tal que las carnes no puedan tocar el suelo.')
GO
