INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(233 AS Decimal(6, 0)), N'58             ', N'Dispone de equipamiento completo para retirada de los MER.', N'Dispondrá de las siguientes condiciones de equipamiento para la extracción de los materiales especificados de riesgo en ganado vacuno y ovino-caprino:
Utensilios de uso exclusivo para la extracción del MER
Tinte autorizado, azul patentado V (E-131 índice de color 42.501) ó tartracina (E-102 índice de color 19.140) correctamente etiquetado.
Material de desinfección: lejía de uso comercial diluida (50% de lejía y 50% de agua) y recipiente para la inmersión de los utensilios de trabajo al menos durante una hora.', N'Dispone de equipamiento completo para retirada de los MER.', N'Dispondrá de las siguientes condiciones de equipamiento para la extracción de los materiales especificados de riesgo en ganado vacuno y ovino-caprino:
Utensilios de uso exclusivo para la extracción del MER
Tinte autorizado, azul patentado V (E-131 índice de color 42.501) ó tartracina (E-102 índice de color 19.140) correctamente etiquetado.
Material de desinfección: lejía de uso comercial diluida (50% de lejía y 50% de agua) y recipiente para la inmersión de los utensilios de trabajo al menos durante una hora.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(249 AS Decimal(6, 0)), N'20             ', N'Se facilitan dispositivos para la eliminación de ropas protectoras? sucias (calzas, guantes, toallas  papel etc.) así como para el depósito de ropa de trabajo con destino a lavandería.', N'Se facilitarán dispositivos apropiados para la eliminación de ropas protectoras sucias (calzas, guantes, etc.) así como dispositivos para el depósito de la ropa de trabajo destinada a lavandería. ', N'Se facilitan dispositivos para la eliminación de ropas protectoras? sucias (calzas, guantes, toallas  papel etc.) así como para el depósito de ropa de trabajo con destino a lavandería.', N'Se facilitarán dispositivos apropiados para la eliminación de ropas protectoras sucias (calzas, guantes, etc.) así como dispositivos para el depósito de la ropa de trabajo destinada a lavandería. ')
