INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(258 AS Decimal(6, 0)), N'26             ', N'Cumplen los requisitos y condiciones de control documental para el destino y eliminación de los decomisos .', N'Los DECOMISOS irán acompa¦ados a la planta de tratamiento de un certificado expedido por la Inspección Sanitaria indicando la cantidad y naturaleza de los mismos, que se adjuntará al documento emitido por la industria para la destrucción de los MER y se devolverá a la Inspección con la conformidad de destino.', N'Cumplen los requisitos y condiciones de control documental para el destino y eliminación de los decomisos .', N'Los DECOMISOS irán acompa¦ados a la planta de tratamiento de un certificado expedido por la Inspección Sanitaria indicando la cantidad y naturaleza de los mismos, que se adjuntará al documento emitido por la industria para la destrucción de los MER y se devolverá a la Inspección con la conformidad de destino.')
GO
