INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(266 AS Decimal(6, 0)), N'32             ', N'Los animales reposan antes de someterse a sacrificio.', N'Reposo será necesario que los animales hayan reposado antes de la matanza a fin de que sus condiciones fisiológicas sean óptimas para facilitar el faenado higiénico. ', N'Los animales reposan antes de someterse a sacrificio.', N'Reposo será necesario que los animales hayan reposado antes de la matanza a fin de que sus condiciones fisiológicas sean óptimas para facilitar el faenado higiénico. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(278 AS Decimal(6, 0)), N'42             ', N'Se utiliza un sistema de cuchillos múltiples.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se utilizará el sistema de ?cuchillos múltiples? (uno en la mano, los restantes en el equipo de desinfección) manteniendo un código de colores para los distintos usos, como práctica de trabajo para garantizar un periodo de contacto suficiente a la temperatura de desinfección (82ºC).', N'Se utiliza un sistema de cuchillos múltiples.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se utilizará el sistema de ?cuchillos múltiples? (uno en la mano, los restantes en el equipo de desinfección) manteniendo un código de colores para los distintos usos, como práctica de trabajo para garantizar un periodo de contacto suficiente a la temperatura de desinfección (82ºC).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(276 AS Decimal(6, 0)), N'42             ', N'Los utensilios contaminados se limpian y desinfectan antes de utilizarse de nuevo. ', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igalmente durante el trabajo:
Todo utensilio que haya estado en contacto con la superficie externa de los cueros, piel del cerdo no depilada, contenido de intestinos, heces, orina, bilis, leche, y abscesos u otras lesiones se considerará contaminado y deberá limpiarse y desinfectarse antes de utilizarse de nuevo en contacto con las carnes frescas.
En particular, deberán limpiarse y desinfectarse entre un animal y otro los cuchillos de degüello y desuello, cortadores de patas, equipo para  abrir la cavidad torácica, seccionar las canales, desprender las cabezas, así como los instrumentos de tracción y de fijación, que tocan tanto los cueros como las carnes. ', N'Los utensilios contaminados se limpian y desinfectan antes de utilizarse de nuevo. ', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igalmente durante el trabajo:
Todo utensilio que haya estado en contacto con la superficie externa de los cueros, piel del cerdo no depilada, contenido de intestinos, heces, orina, bilis, leche, y abscesos u otras lesiones se considerará contaminado y deberá limpiarse y desinfectarse antes de utilizarse de nuevo en contacto con las carnes frescas.
En particular, deberán limpiarse y desinfectarse entre un animal y otro los cuchillos de degüello y desuello, cortadores de patas, equipo para  abrir la cavidad torácica, seccionar las canales, desprender las cabezas, así como los instrumentos de tracción y de fijación, que tocan tanto los cueros como las carnes. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(280 AS Decimal(6, 0)), N'42             ', N'Se evitan las prácticas incorrectas (clavar cuchillos, pa¦os,...).', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Está prohibido clavar cuchillos en las carnes, limpiar dichas carnes con un pa¦o u otro material. Podrá autorizarse el insuflado de un órgano (pulmones, vejigas), cuando lo imponga un rito religioso y no se destinen a consumo.', N'Se evitan las prácticas incorrectas (clavar cuchillos, pa¦os,...).', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Está prohibido clavar cuchillos en las carnes, limpiar dichas carnes con un pa¦o u otro material. Podrá autorizarse el insuflado de un órgano (pulmones, vejigas), cuando lo imponga un rito religioso y no se destinen a consumo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(283 AS Decimal(6, 0)), N'43             ', N'Los cortes se hacen siempre de dentro hacia fuera.', N'Los cortes de desollado se harán siempre de dentro hacia fuera.', N'Los cortes se hacen siempre de dentro hacia fuera.', N'Los cortes de desollado se harán siempre de dentro hacia fuera.')
