INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(284 AS Decimal(6, 0)), N'43             ', N'Se evita que la mano sucia contacte con la canal.', N'El operario evitará en todo momento que la mano sucia (la que sujeta la piel) contacte con la canal.', N'Se evita que la mano sucia contacte con la canal.', N'El operario evitará en todo momento que la mano sucia (la que sujeta la piel) contacte con la canal.')
