INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(275 AS Decimal(6, 0)), N'32             ', N'El sistema de  recogida de sangre para consumo humano es mecánico y se respetan las pautas de higiene.', N'En el caso de que la sangre vaya a ser destinada a consumo, la recogida debe hacerse de manera higiénica: el segundo cuchillo será un trocar hueco, de tal manera que la sangre se recoja directamente de los grandes vasos ,y se conducirá  a un desfibrinador a través de un conducto cerrado específico para dicho fin.', N'El sistema de  recogida de sangre para consumo humano es mecánico y se respetan las pautas de higiene.', N'En el caso de que la sangre vaya a ser destinada a consumo, la recogida debe hacerse de manera higiénica: el segundo cuchillo será un trocar hueco, de tal manera que la sangre se recoja directamente de los grandes vasos ,y se conducirá  a un desfibrinador a través de un conducto cerrado específico para dicho fin.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111015 AS Decimal(6, 0)), N'74             ', N'Las comidas elaboradas listas para consumo que se reciben en caliente se reciben a más de 65º C y las que se reciben en frío a menos de 6º C.', N'En caso de poder observar la recepción de comidas listas para consumo, se comprobará que la temperatura a la que llegan no supera 6º C en caso de recibirse en frío. En caso de recibirse la comida en caliente se comprobará (en los casos que es posible sin perjuicio de los alimentos recibidos) que la temperatura a la que llegan supera los 65ºC', N'Las comidas elaboradas listas para consumo que se reciben en caliente se reciben a más de 65º C y las que se reciben en frío a menos de 6º C.', N'En caso de poder observar la recepción de comidas listas para consumo, se comprobará que la temperatura a la que llegan no supera 6º C en caso de recibirse en frío. En caso de recibirse la comida en caliente se comprobará (en los casos que es posible sin perjuicio de los alimentos recibidos) que la temperatura a la que llegan supera los 65ºC')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(277 AS Decimal(6, 0)), N'42             ', N'Los utensilios se introducen limpios en el desinfectador.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Los cuchillos, sierras, utensilios de ligaduras, cizallas y cualquier utensilio utilizado durante la manipulación se introducirán limpios en el desinfectador lo que exige su previo lavado. en los casos en los que dicha limpieza previa (sierras etc.) sea difícil de realizar, tendrán sistema de autolimpieza.', N'Los utensilios se introducen limpios en el desinfectador.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Los cuchillos, sierras, utensilios de ligaduras, cizallas y cualquier utensilio utilizado durante la manipulación se introducirán limpios en el desinfectador lo que exige su previo lavado. en los casos en los que dicha limpieza previa (sierras etc.) sea difícil de realizar, tendrán sistema de autolimpieza.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(274 AS Decimal(6, 0)), N'32             ', N'Los cortes garantizan el sangrado higiénico.', N'Las incisiones de desangrado han de realizarse siempre con dos cuchillos diferenciados, procediendo primero a efectuar una incisión longitudinal del cuero con un cuchillo desinfectado y después, con un segundo cuchillo, practicar un corte profundo a la entrada del pecho hasta seccionar los grandes vasos.', N'Los cortes garantizan el sangrado higiénico.', N'Las incisiones de desangrado han de realizarse siempre con dos cuchillos diferenciados, procediendo primero a efectuar una incisión longitudinal del cuero con un cuchillo desinfectado y después, con un segundo cuchillo, practicar un corte profundo a la entrada del pecho hasta seccionar los grandes vasos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(281 AS Decimal(6, 0)), N'42             ', N'Las zonas contaminadas se eliminan mediante expurgo con cuchillo limpio.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se evitará utilizar agua para eliminar restos de suciedad en las canales, la zona manchada debe eliminarse mediante expurgo con un cuchillo limpio y desinfectado.', N'Las zonas contaminadas se eliminan mediante expurgo con cuchillo limpio.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se evitará utilizar agua para eliminar restos de suciedad en las canales, la zona manchada debe eliminarse mediante expurgo con un cuchillo limpio y desinfectado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(267 AS Decimal(6, 0)), N'32             ', N'La industria dispone de un sistema de para la evacuación de las bajas ante-mortem producidas en el transporte y la estabulación.', N'Bajas Ante-mortem. El matadero dispondrá de un sistema de evacuación de los animales muertos hacia el punto de almacenamiento de animales muertos.', N'La industria dispone de un sistema de para la evacuación de las bajas ante-mortem producidas en el transporte y la estabulación.', N'Bajas Ante-mortem. El matadero dispondrá de un sistema de evacuación de los animales muertos hacia el punto de almacenamiento de animales muertos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(294 AS Decimal(6, 0)), N'44             ', N'Las ubres se retiran lo antes posible sin producir derrames.', N'Las ubres se separarán lo antes posible durante el faenado de la canal, sin que se derramen sustancias procedentes de la ubre, de forma que esta permanezca entera, intacta y sin abrir conductos lácteos. ', N'Las ubres se retiran lo antes posible sin producir derrames.', N'Las ubres se separarán lo antes posible durante el faenado de la canal, sin que se derramen sustancias procedentes de la ubre, de forma que esta permanezca entera, intacta y sin abrir conductos lácteos. ')
