INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(279 AS Decimal(6, 0)), N'42             ', N'Se evita el salpicado con agua de las canales.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Durante el faenado se evitará el salpicado de las carnes con aguas de limpieza, solo podrán utilizarse mangueras a presión en las pausas de trabajo cuando no haya carnes frescas expuestas en la cadena.', N'Se evita el salpicado con agua de las canales.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Durante el faenado se evitará el salpicado de las carnes con aguas de limpieza, solo podrán utilizarse mangueras a presión en las pausas de trabajo cuando no haya carnes frescas expuestas en la cadena.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(282 AS Decimal(6, 0)), N'42             ', N'Se evita el contacto de las carnes frescas con suelo y/o estructuras.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se evitará que cualquier parte de la canal o vísceras contacten con el suelo o con las estructuras.', N'Se evita el contacto de las carnes frescas con suelo y/o estructuras.', N'A lo largo de todo el proceso de sacrificio, en cualquiera de sus fases: sangrado, desollado, depilado, insuflado, corte de patas, cuernos, orejas, pezu¦as, pene, ubres, ri¦ones médula; ligaduras, retirada de MER, apertura de la cavidad torácica y abdominal, evisceracion, esquinado, se adoptarán las medidas destinadas a evitar la contaminación de las carnes por los trabajadores y sus útiles de trabajo.
Por tanto, las siguientes prácticas de manipulación tendrán consideración general en todas las  operación del faenado y se respetarán igualmente durante el trabajo:
Se evitará que cualquier parte de la canal o vísceras contacten con el suelo o con las estructuras.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1733 AS Decimal(6, 0)), N'3              ', N'Si la cantidad de producción lo requiriera, dispone de local o elemento dotado de llave a disposición de la Autoridad Competente.', N'En función de la actividad que realicen, los establecimientos elaboradores de helados y mezclas envasadas para congelar contarán con los siguientes locales, zonas o instalaciones.
Local acondicionado y con elementos dotados de llave, a disposición de la autoridad competente, si la cantidad de producción requiriera su presencia regular o permanente.
', N'Si la cantidad de producción lo requiriera, dispone de local o elemento dotado de llave a disposición de la Autoridad Competente.', N'En función de la actividad que realicen, los establecimientos elaboradores de helados y mezclas envasadas para congelar contarán con los siguientes locales, zonas o instalaciones.
