INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(221 AS Decimal(6, 0)), N'58             ', N'Dispone de equipos de aturdido para las distintas especies.', N'Equipos de aturdimiento e insensibilización previa al sacrificio de los animales para las distintas especies que se sacrifiquen, según se describen en la ITE22.
Para el sacrificio de animales por ritos religiosos, dispondrán de sistemas de inmovilización que permitan el degüello del animal sin sufrimiento.', N'Dispone de equipos de aturdido para las distintas especies.', N'Equipos de aturdimiento e insensibilización previa al sacrificio de los animales para las distintas especies que se sacrifiquen, según se describen en la ITE22.
Para el sacrificio de animales por ritos religiosos, dispondrán de sistemas de inmovilización que permitan el degüello del animal sin sufrimiento.')
GO
