INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(196 AS Decimal(6, 0)), N'3              ', N'Dispone de instalaciones equipadas y acondicionadas para la preparación (cuarteo o despiece, máximo 3 piezas) de las carnes. ', N'Las operaciones de preparación/clasificación de las canales tales como cuarteo o despiece (tres partes por cada media canal como máximo) previa a la carga, se realizarán en espacios situados entre los propios muelles y las cámaras frigoríficas. Estas operaciones no supondrán un transcurso de tiempo tal que las carnes frescas pierdan su Tª interior  (7ºC canales, 3ºC vísceras) en cuyo caso estas zonas deberán estar climatizadas y en cualquier caso cumplirán los requisitos generales de equipamiento (lavamanos, sierras, cuchillos, desinfectadores, etc.).', N'Dispone de instalaciones equipadas y acondicionadas para la preparación (cuarteo o despiece, máximo 3 piezas) de las carnes. ', N'Las operaciones de preparación/clasificación de las canales tales como cuarteo o despiece (tres partes por cada media canal como máximo) previa a la carga, se realizarán en espacios situados entre los propios muelles y las cámaras frigoríficas. Estas operaciones no supondrán un transcurso de tiempo tal que las carnes frescas pierdan su Tª interior  (7ºC canales, 3ºC vísceras) en cuyo caso estas zonas deberán estar climatizadas y en cualquier caso cumplirán los requisitos generales de equipamiento (lavamanos, sierras, cuchillos, desinfectadores, etc.).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(206 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona específica para preparación de cabezas.', N'Zona o local específico para la preparación de las cabezas de los animales que son objeto de muestreo de BSE. La zona destinada a este fin estará situada en un punto del matadero aislada del resto de las operaciones de faenado que evite que se produzcan contaminaciones cruzadas.', N'Dispone de local o zona específica para preparación de cabezas.', N'Zona o local específico para la preparación de las cabezas de los animales que son objeto de muestreo de BSE. La zona destinada a este fin estará situada en un punto del matadero aislada del resto de las operaciones de faenado que evite que se produzcan contaminaciones cruzadas.')
GO
