INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(236 AS Decimal(6, 0)), N'58             ', N'Dispone de equipos que permitan realizar el corte de cráneos evitando contaminaciones.', N'Para la extracción del cráneo con el cerebro en su interior para el envío de muestras para diagnóstico de BSE, se dispondrá de equipos que permitan el corte sin rotura de la cavidad orbitaria, o restos de tejido nervioso, mediante dispositivos o guías  que eviten el corte oblicuo.', N'Dispone de equipos que permitan realizar el corte de cráneos evitando contaminaciones.', N'Para la extracción del cráneo con el cerebro en su interior para el envío de muestras para diagnóstico de BSE, se dispondrá de equipos que permitan el corte sin rotura de la cavidad orbitaria, o restos de tejido nervioso, mediante dispositivos o guías  que eviten el corte oblicuo.')
