INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(237 AS Decimal(6, 0)), N'58             ', N'Dispone de sistemas de recogida o conducción directa a los locales de destino de los productos resultantes de la obtención de la canal.', N'Dispondrán de sistemas de recogida (carros estancos) o conducción directa, en su caso, a los locales de destino, de todos los productos resultantes del faenado de la canal (vísceras, despojos, subproductos y productos retirados de la cadena alimentaria, MER). ', N'Dispone de sistemas de recogida o conducción directa a los locales de destino de los productos resultantes de la obtención de la canal.', N'Dispondrán de sistemas de recogida (carros estancos) o conducción directa, en su caso, a los locales de destino, de todos los productos resultantes del faenado de la canal (vísceras, despojos, subproductos y productos retirados de la cadena alimentaria, MER). ')
