INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(229 AS Decimal(6, 0)), N'58             ', N'Sistema de recogida y evacuación de las pieles de la nave de sacrificio en condiciones de estanqueidad.', N'Sistema de recogida y evacuación directa de las pieles de la nave de sacrificio o en su defecto la retirada de los mismos de la nave de sacrificio se realizará en contenedores estancos que eviten cualquier arrastre o traslado de contaminación.', N'Sistema de recogida y evacuación de las pieles de la nave de sacrificio en condiciones de estanqueidad.', N'Sistema de recogida y evacuación directa de las pieles de la nave de sacrificio o en su defecto la retirada de los mismos de la nave de sacrificio se realizará en contenedores estancos que eviten cualquier arrastre o traslado de contaminación.')
GO
