INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(225 AS Decimal(6, 0)), N'58             ', N'Dispone de sistema de recogida higiénica de sangre para consumo humano.', N'Equipos para la recogida higiénica de la sangre cuando se destine a consumo humano que conste como mínimo de trocar o cuchillo hueco, canalización de la sangre recogida a depósito, desfibrinador mecánico previo al depósito y depósito refrigerado si la sangre se almacena.', N'Dispone de sistema de recogida higiénica de sangre para consumo humano.', N'Equipos para la recogida higiénica de la sangre cuando se destine a consumo humano que conste como mínimo de trocar o cuchillo hueco, canalización de la sangre recogida a depósito, desfibrinador mecánico previo al depósito y depósito refrigerado si la sangre se almacena.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(226 AS Decimal(6, 0)), N'58             ', N'Existen plataformas elevadas, torres móviles u otros dispositivos para realizar el trabajo con higiene.', N'Plataformas elevadas, torres móviles o similar que permitan realizar las operaciones con higiene.', N'Existen plataformas elevadas, torres móviles u otros dispositivos para realizar el trabajo con higiene.', N'Plataformas elevadas, torres móviles o similar que permitan realizar las operaciones con higiene.')
