INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(222 AS Decimal(6, 0)), N'58             ', N'Dispone de equipos para la verificación del funcionamiento de los sistemas de aturdimiento.', N'Equipos con sistema eléctrico, acústico o similar que permita la verificación del funcionamiento de los sistemas de aturdimiento, así contará con:
dispositivo que mida la impedancia de la carga (resistencia) e impida su funcionamiento si no circula la intensidad mínima requerida.
dispositivo acústico o visual que indique el tiempo de su aplicación al animal.
dispositivo que indique el voltaje(tensión) y la intensidad de la corriente, colocado donde el operario pueda verlo con claridad.', N'Dispone de equipos para la verificación del funcionamiento de los sistemas de aturdimiento.', N'Equipos con sistema eléctrico, acústico o similar que permita la verificación del funcionamiento de los sistemas de aturdimiento, así contará con:
dispositivo que mida la impedancia de la carga (resistencia) e impida su funcionamiento si no circula la intensidad mínima requerida.
dispositivo acústico o visual que indique el tiempo de su aplicación al animal.
dispositivo que indique el voltaje(tensión) y la intensidad de la corriente, colocado donde el operario pueda verlo con claridad.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(205 AS Decimal(6, 0)), N'3              ', N'Dispone de local o zona específica para la extracción de columna vertebral de bovinos mayores de 30 meses.', N'Si la extracción de la columna vertebral de vacunos mayores de 30meses se realiza posteriormente al faenado de las canales, dispondrá de una zona o local, del propio matadero, específico para realizar esta tarea.
Estará suficientemente diferenciada: mediante tabiques, mamparas o zonas neutras (sin uso), del resto de actividades del matadero y su ubicación no interferirá en las diferentes labores a realizar el normal desarrollo del trabajo del matadero. La actividad de retirada de las columnas no afectará al resto de actividades que se desarrollan simultáneamente en el matadero y estará claramente diferenciada de las mismas. ', N'Dispone de local o zona específica para la extracción de columna vertebral de bovinos mayores de 30 meses.', N'Si la extracción de la columna vertebral de vacunos mayores de 30meses se realiza posteriormente al faenado de las canales, dispondrá de una zona o local, del propio matadero, específico para realizar esta tarea.
Estará suficientemente diferenciada: mediante tabiques, mamparas o zonas neutras (sin uso), del resto de actividades del matadero y su ubicación no interferirá en las diferentes labores a realizar el normal desarrollo del trabajo del matadero. La actividad de retirada de las columnas no afectará al resto de actividades que se desarrollan simultáneamente en el matadero y estará claramente diferenciada de las mismas. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(228 AS Decimal(6, 0)), N'58             ', N'Dispone de sistema para el desollado higiénico de los animales.', N'Sistema para el desollado higiénico de los animales.', N'Dispone de sistema para el desollado higiénico de los animales.', N'Sistema para el desollado higiénico de los animales.')
