INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(268 AS Decimal(6, 0)), N'32             ', N'La organización del sacrificio tiene en cuenta la clasificación de los animales por grupos de riesgo (especie, edad, enfermedad, campa¦as, sacrificio de urgencia).', N'Separación de los animales por grupos de riesgo. Es responsabilidad de la empresa tener organizado el sacrificio de forma que se garantice la correcta separación de los animales por grupos de riesgo (especie, edad, enfermedad, campa¦as de saneamiento etc.) de acuerdo con las pautas de actuación que establezca el servicio de inspección en cada caso.
En el caso de que el sacrificio de vacuno y equino se realice en la misma línea, éste se realizará en momentos diferentes.
Los animales procedentes de campa¦as de saneamiento ganadero se ubicarán en boxes o cortijos colectivos especiales y se sacrificarán en el matadero sanitario o al final de la matanza con el fin de evitar contaminaciones.
Los animales procedentes de sacrificio de urgencia (unicamente los menores de 24 meses que hayan sufrido traumatismos o accidentes en menos de 24 horas hasta su llegada al matadero) se ubicarán en recintos específicos. El Servicio de Inspección decidirá valorando las condiciones que en cada caso concurran el sacrificio al final de la  jornada por razones de higiene o inmediatamente a su llegada al matadero por razones de bienestar animal.', N'La organización del sacrificio tiene en cuenta la clasificación de los animales por grupos de riesgo (especie, edad, enfermedad, campa¦as, sacrificio de urgencia).', N'Separación de los animales por grupos de riesgo. Es responsabilidad de la empresa tener organizado el sacrificio de forma que se garantice la correcta separación de los animales por grupos de riesgo (especie, edad, enfermedad, campa¦as de saneamiento etc.) de acuerdo con las pautas de actuación que establezca el servicio de inspección en cada caso.
En el caso de que el sacrificio de vacuno y equino se realice en la misma línea, éste se realizará en momentos diferentes.
Los animales procedentes de campa¦as de saneamiento ganadero se ubicarán en boxes o cortijos colectivos especiales y se sacrificarán en el matadero sanitario o al final de la matanza con el fin de evitar contaminaciones.
Los animales procedentes de sacrificio de urgencia (unicamente los menores de 24 meses que hayan sufrido traumatismos o accidentes en menos de 24 horas hasta su llegada al matadero) se ubicarán en recintos específicos. El Servicio de Inspección decidirá valorando las condiciones que en cada caso concurran el sacrificio al final de la  jornada por razones de higiene o inmediatamente a su llegada al matadero por razones de bienestar animal.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(238 AS Decimal(6, 0)), N'58             ', N'El punto de inspección post-mortem está completamente equipado.', N'El punto de inspección de la línea de sacrificio, deberá contar como mínimo de los siguientes equipos:
superficie de manipulación para realizar labores de corte e incisión,
foco de luz, con la intensidad establecida por normativa ( 540 lux).
utillaje de corte de uso exclusivo,
lavamanos de uso exclusivo y esterilizador de cuchillos,
torre o superficie de elevación que permita inspeccionar las regiones anatómicas de difícil acceso en las canales.', N'El punto de inspección post-mortem está completamente equipado.', N'El punto de inspección de la línea de sacrificio, deberá contar como mínimo de los siguientes equipos:
superficie de manipulación para realizar labores de corte e incisión,
foco de luz, con la intensidad establecida por normativa ( 540 lux).
utillaje de corte de uso exclusivo,
lavamanos de uso exclusivo y esterilizador de cuchillos,
torre o superficie de elevación que permita inspeccionar las regiones anatómicas de difícil acceso en las canales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(214 AS Decimal(6, 0)), N'7              ', N'Los sistemas de retención de sólidos y depuración de aguas residuales están ubicados en el extremo sucio y separados del resto de operaciones propias de la zona.', N'La ubicación de los sistemas de retención de sólidos, desbaste  y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared, del resto de operaciones propias de dicha zona (muelles de descarga de animales vivos, expedición de subproductos con destino industrial, etc.).', N'Los sistemas de retención de sólidos y depuración de aguas residuales están ubicados en el extremo sucio y separados del resto de operaciones propias de la zona.', N'La ubicación de los sistemas de retención de sólidos, desbaste  y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared, del resto de operaciones propias de dicha zona (muelles de descarga de animales vivos, expedición de subproductos con destino industrial, etc.).')
