INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(250 AS Decimal(6, 0)), N'20             ', N'Las ropas protectoras y elementos de trabajo se guardan en un lugar previsto para tal fin.', N'La ropa protectora, delantales, cinturones y en general los elementos de trabajo que no se estén utilizando, se guardarán en un lugar previsto para ese fin, donde no contaminen ni se contaminen, por lo tanto no pueden depositarse en ninguna zona del matadero destinada al sacrificio de animales, faenado de canales, o a la preparación manipulación envasado o almacenamiento de carne.', N'Las ropas protectoras y elementos de trabajo se guardan en un lugar previsto para tal fin.', N'La ropa protectora, delantales, cinturones y en general los elementos de trabajo que no se estén utilizando, se guardarán en un lugar previsto para ese fin, donde no contaminen ni se contaminen, por lo tanto no pueden depositarse en ninguna zona del matadero destinada al sacrificio de animales, faenado de canales, o a la preparación manipulación envasado o almacenamiento de carne.')
