INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(213 AS Decimal(6, 0)), N'7              ', N'La evacuación exterior de aguas residuales dentro del perímetro vallado está cubierta y protegida frente a animales indeseables. ', N'La evacuación exterior de las aguas residuales hacia estanques de sedimentación o aireación, alcantarillado etc. estará totalmente cubierta dentro del perímetro de vallado. Si no lo estuvieran, deberán existir medios adecuados de protección frente a animales indeseables. ', N'La evacuación exterior de aguas residuales dentro del perímetro vallado está cubierta y protegida frente a animales indeseables. ', N'La evacuación exterior de las aguas residuales hacia estanques de sedimentación o aireación, alcantarillado etc. estará totalmente cubierta dentro del perímetro de vallado. Si no lo estuvieran, deberán existir medios adecuados de protección frente a animales indeseables. ')
