INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(234 AS Decimal(6, 0)), N'58             ', N'El local/zona para extracción de columnas esta completamente equipado.', N'Si la extracción de columna vertebral de vacunos mayores de 30 meses se realiza en local o zona específica, después de la línea de faenado de las canales, esta zona o local dispondrá del siguiente equipamiento:
Lavamanos con agua fría y caliente.
Desinfectadores de útiles de trabajo.
Sierra y utensilios debidamente diferenciados (color o sistema equivalente) como de uso exclusivo para extracción de MER.
Contenedores para la recogida de las columnas vertebrales correctamente identificados con la leyenda MER.
Tinte autorizado: azul patentado V (E-131 índice de color 42.501) ó tartracina (E-102 índice de color 19.140) correctamente etiquetado.
Material de desinfección: lejía de uso comercial diluida (50% de lejía y 50% de agua) y recipiente para la inmersión de los utensilios de trabajo al menos durante una hora.', N'El local/zona para extracción de columnas esta completamente equipado.', N'Si la extracción de columna vertebral de vacunos mayores de 30 meses se realiza en local o zona específica, después de la línea de faenado de las canales, esta zona o local dispondrá del siguiente equipamiento:
Lavamanos con agua fría y caliente.
Desinfectadores de útiles de trabajo.
Sierra y utensilios debidamente diferenciados (color o sistema equivalente) como de uso exclusivo para extracción de MER.
Contenedores para la recogida de las columnas vertebrales correctamente identificados con la leyenda MER.
Tinte autorizado: azul patentado V (E-131 índice de color 42.501) ó tartracina (E-102 índice de color 19.140) correctamente etiquetado.
Material de desinfección: lejía de uso comercial diluida (50% de lejía y 50% de agua) y recipiente para la inmersión de los utensilios de trabajo al menos durante una hora.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(242 AS Decimal(6, 0)), N'58             ', N'Dispone de raíles diferenciados en cámaras para el almacenamiento de canales en espera del marcado sanitario.', N'Dispondrá en las cámaras frigoríficas de raíles especiales claramente diferenciados para el almacenamiento de canales en espera de ser selladas (EETs).', N'Dispone de raíles diferenciados en cámaras para el almacenamiento de canales en espera del marcado sanitario.', N'Dispondrá en las cámaras frigoríficas de raíles especiales claramente diferenciados para el almacenamiento de canales en espera de ser selladas (EETs).')
