INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(240 AS Decimal(6, 0)), N'11             ', N'Dispone de instalaciones de frío para llevar a cabo el oreo, la refrigeración y congelación si procede, de las carnes frescas producidas a la Tª requerida. ', N'Dispondrá de instalaciones de producción de frío en número suficiente para llevar a cabo el oreo y la refrigeración de las carnes producidas, para alcanzar en 24 horas 7ºC en las canales y 3ºC en los despojos. En caso de realizar congelación dispondrá de equipos que permitan el descenso de las temperaturas iguales o inferiores a ?12º.', N'Dispone de instalaciones de frío para llevar a cabo el oreo, la refrigeración y congelación si procede, de las carnes frescas producidas a la Tª requerida. ', N'Dispondrá de instalaciones de producción de frío en número suficiente para llevar a cabo el oreo y la refrigeración de las carnes producidas, para alcanzar en 24 horas 7ºC en las canales y 3ºC en los despojos. En caso de realizar congelación dispondrá de equipos que permitan el descenso de las temperaturas iguales o inferiores a ?12º.')
