INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(241 AS Decimal(6, 0)), N'11             ', N'Dispone de instalación frigorífica dotada con sistema de cierre para el depósito de las carnes consignadas', N'Cámara de Consigna. Dispondrá de Cámara frigorífica independiente, dotada de  sistema de cierre con llave para el almacenamiento de las carnes consignadas tras la inspección sanitaria (intervenidas por sospecha-decomiso-retención a la espera de resultado analítico  etc.) con el fin de  evitar su entrada en el circuito de las carnes aptas para el consumo y prevenir el riesgo de contaminación, confusión  o la manipulación de dichas carnes.
En el caso que dicha instalación no sea independiente, se podrá habilitar dentro de la cámara  de refrigeración un espacio que estará separado del resto de las carnes y dotado de un sistema de aislamiento y cierre a disposición del Servicio de Inspección Sanitaria.', N'Dispone de instalación frigorífica dotada con sistema de cierre para el depósito de las carnes consignadas', N'Cámara de Consigna. Dispondrá de Cámara frigorífica independiente, dotada de  sistema de cierre con llave para el almacenamiento de las carnes consignadas tras la inspección sanitaria (intervenidas por sospecha-decomiso-retención a la espera de resultado analítico  etc.) con el fin de  evitar su entrada en el circuito de las carnes aptas para el consumo y prevenir el riesgo de contaminación, confusión  o la manipulación de dichas carnes.
En el caso que dicha instalación no sea independiente, se podrá habilitar dentro de la cámara  de refrigeración un espacio que estará separado del resto de las carnes y dotado de un sistema de aislamiento y cierre a disposición del Servicio de Inspección Sanitaria.')
GO
