INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1763 AS Decimal(6, 0)), N'32             ', N'En el caso de que la empresa disponga de resultados analíticos referentes a recuentos microbiológicos, no sobrepasan los límites permitidos o se han tomado medidas si los sobrepasan.', N'Criterios microbiológicos.
Los helados y mezclas envasadas para congelar, cumplirán las normas microbiológicas:
Listeria monocytogenes:  ausencia en 1 gr. ó ml.
Salmonella spp.    Ausencia en 25 gr. ó ml.
