INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1486 AS Decimal(6, 0)), N'32             ', N'El desollado se realiza de forma inmediata y completa.', N'El desollado deberá ser inmediato y completo.', N' ', N'El desollado deberá ser inmediato y completo.')
