INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1484 AS Decimal(6, 0)), N'32             ', N'El aturdido es se realiza en las condiciones descritas.', N'El aturdido se realizará mediante sistema autorizado. En cualquier caso no se permitirá el sacrificio de animales en tanto en cuanto no se garantice el aturdido de los mismos. No obstante, podrá no realizarse el aturdimiento cuando lo prohiba algún rito religioso.', N' ', N'El aturdido se realizará mediante sistema autorizado. En cualquier caso no se permitirá el sacrificio de animales en tanto en cuanto no se garantice el aturdido de los mismos. No obstante, podrá no realizarse el aturdimiento cuando lo prohiba algún rito religioso.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1476 AS Decimal(6, 0)), N'32             ', N'Las jaulas son limpiadas después de cada uso.', N'Las jaulas que se utilicen para la entrega de animales se limpiarán y desinfectarán cada vez que queden vacías.', N' ', N'Las jaulas que se utilicen para la entrega de animales se limpiarán y desinfectarán cada vez que queden vacías.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1501 AS Decimal(6, 0)), N'47             ', N'El dise¦o y naturaleza de los materiales evita sufrimientos inútiles a los animales.', N'El dise¦o, la disposición y construcción de las dependencias del matadero por las que tiene lugar el tránsito de los animales vivos, ha de garantizar en todo momento el bienestar de los mismos, de forma que el planteamiento de la distribución de las instalaciones se llevará a cabo evitando exceso de luminosidad, corrientes de aire que arrastren olores etc.
Asimismo se tendrá en cuenta la naturaleza de los materiales utilizados que serán no cortantes, antideslizantes, no excesivamente rugosos, firmes y de fácil limpieza y desinfección.
De igual forma la construcción y el funcionamiento de  los equipos de los mataderos,  deberán en todo momento ser los adecuados para no ocasionar a los animales agitación, dolor o sufrimientos innecesarios.
', N' ', N'El dise¦o, la disposición y construcción de las dependencias del matadero por las que tiene lugar el tránsito de los animales vivos, ha de garantizar en todo momento el bienestar de los mismos, de forma que el planteamiento de la distribución de las instalaciones se llevará a cabo evitando exceso de luminosidad, corrientes de aire que arrastren olores etc.
Asimismo se tendrá en cuenta la naturaleza de los materiales utilizados que serán no cortantes, antideslizantes, no excesivamente rugosos, firmes y de fácil limpieza y desinfección.
De igual forma la construcción y el funcionamiento de  los equipos de los mataderos,  deberán en todo momento ser los adecuados para no ocasionar a los animales agitación, dolor o sufrimientos innecesarios.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1487 AS Decimal(6, 0)), N'32             ', N'Las pieles se retiran en condiciones que eviten contaminaciones.', N'Las pieles deben retirarse en forma continua o tan a menudo como sea necesario durante la jornada de trabajo.', N' ', N'Las pieles deben retirarse en forma continua o tan a menudo como sea necesario durante la jornada de trabajo.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1532 AS Decimal(6, 0)), N'3              ', N'Dispone de local para el almacenamiento higiénico de envases, embalajes y material auxiliar.', N'Local de almacén de envases, embalajes y material auxiliar
Contará con local independiente para el almacenamiento higiénico de envases, embalajes y  demás material auxiliar.
Este local podrá disponer de una o varias zonas para el almacenamiento higiénico de aditivos. En este supuesto podrá prescindirse del local enumerado en el apartado 8.
Los envases de transporte y almacenamiento de aceitunas de mesa a granel pueden almacenarse en locales abiertos, cubiertos y ventilados.', N' ', N'Local de almacén de envases, embalajes y material auxiliar
Contará con local independiente para el almacenamiento higiénico de envases, embalajes y  demás material auxiliar.
Este local podrá disponer de una o varias zonas para el almacenamiento higiénico de aditivos. En este supuesto podrá prescindirse del local enumerado en el apartado 8.
Los envases de transporte y almacenamiento de aceitunas de mesa a granel pueden almacenarse en locales abiertos, cubiertos y ventilados.')
GO
