INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1489 AS Decimal(6, 0)), N'32             ', N'Las vísceras ya inspeccionadas se retiran adecuadamente de la canal.', N'Después de la inspección, las vísceras que se hayan sacado deberán ser separadas inmediatamente de la canal y las partes no aptas para el consumo humano deberán ser inmediatamente separadas. Las vísceras o partes de vísceras que hayan quedado en la canal, excepto los ri¦ones, deberán ser inmediatamente retiradas, si es posible en su totalidad, en condiciones de higiene satisfactorias.', N' ', N'Después de la inspección, las vísceras que se hayan sacado deberán ser separadas inmediatamente de la canal y las partes no aptas para el consumo humano deberán ser inmediatamente separadas. Las vísceras o partes de vísceras que hayan quedado en la canal, excepto los ri¦ones, deberán ser inmediatamente retiradas, si es posible en su totalidad, en condiciones de higiene satisfactorias.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1491 AS Decimal(6, 0)), N'32             ', N'Canales y despojos no inspeccionados no entran en contacto con los ya inspeccionados.', N'Hasta el final de la inspección, las canales y despojos no inspeccionados no podrán entrar en contacto con las canales y los despojos ya inspeccionados, prohibiéndose que se proceda a la retirada, despiece o tratamiento posterior de la canal.', N' ', N'Hasta el final de la inspección, las canales y despojos no inspeccionados no podrán entrar en contacto con las canales y los despojos ya inspeccionados, prohibiéndose que se proceda a la retirada, despiece o tratamiento posterior de la canal.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1492 AS Decimal(6, 0)), N'32             ', N'Las carnes envasadas o embaladas se almacenan independientemente de las carnes frescas sin envasar.', N'Las carnes envasadas o embaladas se almacenarán en locales distintos de los usados para las carnes frescas sin envasar.', N' ', N'Las carnes envasadas o embaladas se almacenarán en locales distintos de los usados para las carnes frescas sin envasar.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1493 AS Decimal(6, 0)), N'32             ', N'El almacenamiento de carnes se realiza a temperaturas requeridas de conservación/congelación.', N'Durante el almacenamiento se mantiene a una temperatura que en ningún momento podrá ser superior a los 4º C después de su refrigeración y una temperatura igual o inferior a ?12ºC después de la congelación.', N' ', N'Durante el almacenamiento se mantiene a una temperatura que en ningún momento podrá ser superior a los 4º C después de su refrigeración y una temperatura igual o inferior a ?12ºC después de la congelación.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111077 AS Decimal(6, 0)), N'82             ', N'Se dispondrá de estudios de caducidad de productos que no sean de consumo inmediato, de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se dispone de estudios de caducidad de aquellos productos elaborados por el establecimiento que no sean de consumo inmediato, tales como salsas o comidas elaboradas con varios días de antelación. Se comprobará documentalmente que se dispone de un listado completo de los pro¬ductos de esas características que se elaboran, para los que se han llevado a cabo estos estudios de caducidad.', N'Se dispondrá de estudios de caducidad de productos que no sean de consumo inmediato, de acuerdo a los criterios establecidos en el apartado de Controles Plus del PGAH.', N'Se comprobará documentalmente que se dispone de estudios de caducidad de aquellos productos elaborados por el establecimiento que no sean de consumo inmediato, tales como salsas o comidas elaboradas con varios días de antelación. Se comprobará documentalmente que se dispone de un listado completo de los pro¬ductos de esas características que se elaboran, para los que se han llevado a cabo estos estudios de caducidad.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1499 AS Decimal(6, 0)), N'46             ', N'El marcado de inspección veterinaria reúne los requisitos especificados de información, tama¦o, dígitos etc.', N'El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado. El material usado para el marcado deberá reunir todas las exigencias de la higiene: la información  que incluya dicho marcado será perfectamente legible, indeleble y en caracteres fácilmente identificables.
El marcado de inspección veterinaria comprenderá un óvalo que contenga la siguiente información en su interior:
En la parte superior las siglas en mayúsculas ESP. 
En el centro, el número del Registro General Sanitario de Alimentos del establecimiento.
En la parte inferior las siglas CEE.
Los caracteres deberán tener una altura de 0,2 cm tanto para las letras como para las cifras. 
El marcado de inspección sanitaria figurará:
En  canales no envasadas individualmente, por medio de un marchamo o un sello que no sea reutilizable.
Sobre envolturas u otros embalajes de las canales embaladas o, de modo visible, debajo de ellos.
Sobre las envolturas u otros embalajes de las partes de canales o despojos embalados en peque¦as cantidades o, de modo visible, debajo de ellos.
El marcado de inspección veterinaria deberá realizarse sobre grandes embalajes con letras que deberán tener 0,8 cm de altura y cifras de 1,1 cm. En los casos en que aparezca un marcado de inspección veterinaria sobre la envoltura o embalaje se aplicará de forma que se destruya al abrir éstos o la envoltura o el embalaje se marcarán de forma que no puedan volver a utilizarse una vez abiertos.
', N' ', N'El marcado de inspección veterinaria deberá efectuarse bajo la supervisión del veterinario oficial. Con dicho fin se controlará el material de marcado de inspección veterinaria de las carnes, así como las etiquetas y el material de envasado. El material usado para el marcado deberá reunir todas las exigencias de la higiene: la información  que incluya dicho marcado será perfectamente legible, indeleble y en caracteres fácilmente identificables.
El marcado de inspección veterinaria comprenderá un óvalo que contenga la siguiente información en su interior:
En la parte superior las siglas en mayúsculas ESP. 
En el centro, el número del Registro General Sanitario de Alimentos del establecimiento.
En la parte inferior las siglas CEE.
Los caracteres deberán tener una altura de 0,2 cm tanto para las letras como para las cifras. 
El marcado de inspección sanitaria figurará:
En  canales no envasadas individualmente, por medio de un marchamo o un sello que no sea reutilizable.
Sobre envolturas u otros embalajes de las canales embaladas o, de modo visible, debajo de ellos.
Sobre las envolturas u otros embalajes de las partes de canales o despojos embalados en peque¦as cantidades o, de modo visible, debajo de ellos.
El marcado de inspección veterinaria deberá realizarse sobre grandes embalajes con letras que deberán tener 0,8 cm de altura y cifras de 1,1 cm. En los casos en que aparezca un marcado de inspección veterinaria sobre la envoltura o embalaje se aplicará de forma que se destruya al abrir éstos o la envoltura o el embalaje se marcarán de forma que no puedan volver a utilizarse una vez abiertos.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1496 AS Decimal(6, 0)), N'40             ', N'El origen de conejos vivos se acredita con la documentación de origen.', N'El origen de los conejos vivos será tal que pueda asegurar su salubridad y estará acreditado mediante:
la guía de origen y sanidad pecuaria
si la inspección ante mortem en la explotación de origen y en el matadero no es realizada por el mismo veterinario oficial, los animales deberán de ir acompa¦ados del original del certificado sanitario.
', N' ', N'El origen de los conejos vivos será tal que pueda asegurar su salubridad y estará acreditado mediante:
la guía de origen y sanidad pecuaria
si la inspección ante mortem en la explotación de origen y en el matadero no es realizada por el mismo veterinario oficial, los animales deberán de ir acompa¦ados del original del certificado sanitario.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1446 AS Decimal(6, 0)), N'7              ', N'La canalización de aguas residuales impide la contaminación del ambiente y de las carnes.', N'La canalización de aguas residuales en todas las dependencias del matadero, deberá hacerse por conducciones cerradas que impidan la contaminación tanto del ambiente como de las canales y despojos. Dichos sistemas estarán construidos de tal forma que eviten el cúmulo de partículas sólidas (restos de matanza y suciedad grosera).', N' ', N'La canalización de aguas residuales en todas las dependencias del matadero, deberá hacerse por conducciones cerradas que impidan la contaminación tanto del ambiente como de las canales y despojos. Dichos sistemas estarán construidos de tal forma que eviten el cúmulo de partículas sólidas (restos de matanza y suciedad grosera).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1449 AS Decimal(6, 0)), N'7              ', N'La ubicación de los sistemas de retención de sólidos y depuración de aguas residuales es la adecuada.', N'La ubicación de los sistemas de retención, desbaste de sólidos y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared del resto de operaciones propias de dicha zona.
Para contestar a las preguntas generales IT. 07. 1, IT.07.2, IT. 07.3, se tendrán en cuenta los siguientes aspectos:
En las cámaras frigoríficas destinadas a carnes consignadas y en cámaras frigoríficas destinadas a almacenar carnes a una temperatura de 4ºC como máximo, no se exigirá la salida del agua hacia sumideros trasegados con sifones y provistos de rejillas y bastará con que estén provistas de un dispositivo que permita una evacuación fácil del agua,
En las cámaras frigoríficas destinadas a almacenar carnes embaladas o envasadas a una temperatura máxima de ?12ºC, así como en las zonas y pasillos en los que se transporten carnes frescas, bastará con que el suelo sea de materiales impermeables e imputrescibles.
', N' ', N'La ubicación de los sistemas de retención, desbaste de sólidos y depuración de aguas residuales se realizará en el extremo sucio del matadero y estará convenientemente separada por espacio físico o pared del resto de operaciones propias de dicha zona.
Para contestar a las preguntas generales IT. 07. 1, IT.07.2, IT. 07.3, se tendrán en cuenta los siguientes aspectos:
En las cámaras frigoríficas destinadas a carnes consignadas y en cámaras frigoríficas destinadas a almacenar carnes a una temperatura de 4ºC como máximo, no se exigirá la salida del agua hacia sumideros trasegados con sifones y provistos de rejillas y bastará con que estén provistas de un dispositivo que permita una evacuación fácil del agua,
En las cámaras frigoríficas destinadas a almacenar carnes embaladas o envasadas a una temperatura máxima de ?12ºC, así como en las zonas y pasillos en los que se transporten carnes frescas, bastará con que el suelo sea de materiales impermeables e imputrescibles.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1461 AS Decimal(6, 0)), N'11             ', N'Dispone de equipos de frío que permiten el mantenimiento de la temperatura requerida para refrigeración y congelación.', N'Dispondrá de equipos que permitan garantizar que la carne fresca se mantiene a una temperatura que en ningún momento podrá ser superior a los 4º C después de su refrigeración y una temperatura igual o inferior a -12ºC después de la congelación.', N' ', N'Dispondrá de equipos que permitan garantizar que la carne fresca se mantiene a una temperatura que en ningún momento podrá ser superior a los 4º C después de su refrigeración y una temperatura igual o inferior a -12ºC después de la congelación.')
GO
