INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1434 AS Decimal(6, 0)), N'3              ', N'La comunicación entre el local de sacrificio y el local de eviscerado y envasado dispone de puerta de cierre automático excepto la estrecha apertura destinada al paso de los animales  sacrificados.', N'Toda comunicación entre el local de evisceración y envasado y el local de sacrificio, que no sea la estrecha apertura destinada al paso estricto de los animales sacrificados, deberá estar provista de una puerta de cierre automático.', N' ', N'Toda comunicación entre el local de evisceración y envasado y el local de sacrificio, que no sea la estrecha apertura destinada al paso estricto de los animales sacrificados, deberá estar provista de una puerta de cierre automático.')
