INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1436 AS Decimal(6, 0)), N'3              ', N'Dispone de uno o varios locales frigoríficos amplios con instalaciones que cierran con llave para carne consignada.', N'Uno o varios locales frigoríficos suficientemente amplios, con instalaciones que cierren con llave, para la carne consignada. En el caso de carnes o subproductos no destinadas a consumo humano, cuando su abundancia así lo requiera, o si no se destruyen o retiran al final de cada jornada de trabajo, dichas carnes se almacenarán en estos locales.', N' ', N'Uno o varios locales frigoríficos suficientemente amplios, con instalaciones que cierren con llave, para la carne consignada. En el caso de carnes o subproductos no destinadas a consumo humano, cuando su abundancia así lo requiera, o si no se destruyen o retiran al final de cada jornada de trabajo, dichas carnes se almacenarán en estos locales.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1465 AS Decimal(6, 0)), N'20             ', N'El lavado de delantales y botas se realiza con la frecuencia requerida.', N'El lavado de delantales y botas deberá realizarse, siempre que su grado de suciedad pueda afectar a la inocuidad de los alimentos, y al menos con los mismos criterios de limpieza establecidos para el lavado de manos y guantes, es decir, al incorporarse tras las paradas de la jornada laboral al puesto de trabajo, después de usar el retrete, y siempre que se realice cualquier actividad fuera del proceso de sacrificio cuya incorporación a la cadena de sacrificio pudiera originar contaminación en las carnes. Dicho lavado se realizará sin producir salpicaduras y traslado de contaminación a las carnes.', N' ', N'El lavado de delantales y botas deberá realizarse, siempre que su grado de suciedad pueda afectar a la inocuidad de los alimentos, y al menos con los mismos criterios de limpieza establecidos para el lavado de manos y guantes, es decir, al incorporarse tras las paradas de la jornada laboral al puesto de trabajo, después de usar el retrete, y siempre que se realice cualquier actividad fuera del proceso de sacrificio cuya incorporación a la cadena de sacrificio pudiera originar contaminación en las carnes. Dicho lavado se realizará sin producir salpicaduras y traslado de contaminación a las carnes.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1432 AS Decimal(6, 0)), N'3              ', N'La comunicación entre el local de sacrificio y el local de recepción e inspección de animales vivos antes del sacrificio dispone de puerta de cierre automático excepto la estrecha apertura destinada al paso de los animales a sacrificar.', N'Toda comunicación entre el local de sacrificio y el local o emplazamiento destinado a la recepción e inspección antes del sacrificio de los animales , que no sea la estrecha apertura destinada al paso estricto de los conejos  que deben sacrificarse, deberá estar provista de una puerta de cierre automático.', N' ', N'Toda comunicación entre el local de sacrificio y el local o emplazamiento destinado a la recepción e inspección antes del sacrificio de los animales , que no sea la estrecha apertura destinada al paso estricto de los conejos  que deben sacrificarse, deberá estar provista de una puerta de cierre automático.')
GO
