INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1552 AS Decimal(6, 0)), N'3              ', N'En caso de realizarlas dispone de local de mezclas de mostos.', N'Local de mezclas de mostos
Los locales de mezclas de mostos, cuando sean necesarios, estarán situados dentro del recinto de la fábrica, aunque separados de la sala de sacarificación y fermentación, así como de las bodegas.
', N' ', N'Local de mezclas de mostos
Los locales de mezclas de mostos, cuando sean necesarios, estarán situados dentro del recinto de la fábrica, aunque separados de la sala de sacarificación y fermentación, así como de las bodegas.
')
