INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1508 AS Decimal(6, 0)), N'52             ', N'El aturdido se realiza con métodos autorizados.', N'Los métodos autorizados para el aturdido son los siguientes:
Electro narcosis: los electrodos se colocarán de modo que ci¦an el cerebro para que la corriente pueda atravesarlo. Conviene a sí mismo tomar las medidas oportunas para obtener un buen contacto eléctrico y especialmente mojar la piel. Cuando los animales sean aturdidos individualmente, el aparato irá provisto de un dispositivo que mida la impedancia de la carga e impida su funcionamiento si no circula la intensidad mínima requerida, así como también de un dispositivo acústico o visual que indique el tiempo de aplicación al animal. Así mismo el aparato estará conectado a un dispositivo que indique la tensión e intensidad de la corriente, colocado donde el operario pueda verlo con claridad.
Percusión: sólo se podrá usar este procedimiento si se utiliza un instrumento mecánico que administre un golpe en el cráneo con el fin de conseguir un aturdido eficaz sin fracturar el cráneo.
', N' ', N'Los métodos autorizados para el aturdido son los siguientes:
Electro narcosis: los electrodos se colocarán de modo que ci¦an el cerebro para que la corriente pueda atravesarlo. Conviene a sí mismo tomar las medidas oportunas para obtener un buen contacto eléctrico y especialmente mojar la piel. Cuando los animales sean aturdidos individualmente, el aparato irá provisto de un dispositivo que mida la impedancia de la carga e impida su funcionamiento si no circula la intensidad mínima requerida, así como también de un dispositivo acústico o visual que indique el tiempo de aplicación al animal. Así mismo el aparato estará conectado a un dispositivo que indique la tensión e intensidad de la corriente, colocado donde el operario pueda verlo con claridad.
Percusión: sólo se podrá usar este procedimiento si se utiliza un instrumento mecánico que administre un golpe en el cráneo con el fin de conseguir un aturdido eficaz sin fracturar el cráneo.
')
GO
