INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1566 AS Decimal(6, 0)), N'25             ', N'Se retiran y almacenan los residuos procedentes de la obtención del mosto de forma adecuada.', N'Residuos y desechos
Los residuos procedentes de la malta ya utilizada para la obtención del mosto, así como el lúpulo y las posibles impurezas retiradas en la filtración tras la cocción del mosto, se retirarán de la sala de elaboración (sin utilizar vehículos a motor) y se almacenarán en el exterior de la empresa (en contenedores o silos), para su posterior eliminación o aprovechamiento agroganadero.
', N' ', N'Residuos y desechos
Los residuos procedentes de la malta ya utilizada para la obtención del mosto, así como el lúpulo y las posibles impurezas retiradas en la filtración tras la cocción del mosto, se retirarán de la sala de elaboración (sin utilizar vehículos a motor) y se almacenarán en el exterior de la empresa (en contenedores o silos), para su posterior eliminación o aprovechamiento agroganadero.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1555 AS Decimal(6, 0)), N'3              ', N'Dispone de local para almacenamiento de producto final envasado y embalado.', N'Local de almacenamiento de producto final envasado y embalado
Dispondrá de local para almacenamiento de producto terminado, envasado y embalado. Dentro de este local podrá disponer de una o varias zonas para el almacenamiento de envases nuevos, retornables ya higienizados, embalajes nuevos o limpios, etiquetas, tapones, etc., siempre y cuando todos ellos estén debidamente estibados y protegidos: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases (nuevos o higienizados) además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado.
En caso contrario, dispondrá de local/es para almacenamiento exclusivo de estos materiales.
', N' ', N'Local de almacenamiento de producto final envasado y embalado
Dispondrá de local para almacenamiento de producto terminado, envasado y embalado. Dentro de este local podrá disponer de una o varias zonas para el almacenamiento de envases nuevos, retornables ya higienizados, embalajes nuevos o limpios, etiquetas, tapones, etc., siempre y cuando todos ellos estén debidamente estibados y protegidos: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases (nuevos o higienizados) además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado.
En caso contrario, dispondrá de local/es para almacenamiento exclusivo de estos materiales.
')
GO
