INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1518 AS Decimal(6, 0)), N'54             ', N'La industria dispone del registro del control regular de la higiene.', N'Registro del control regular de la higiene.
La empresa dispondrá asimismo de un registro del control de la higiene en superficies y utillaje en el que consten los siguientes datos:
Punto de muestreo
Fecha y hora de la recogida de la muestra
Resultados que se presentarán periódicamente en forma de histograma de barras para mostrar la evolución
Incidencias y Medidas correctoras adoptadas
', N' ', N'Registro del control regular de la higiene.
La empresa dispondrá asimismo de un registro del control de la higiene en superficies y utillaje en el que consten los siguientes datos:
Punto de muestreo
Fecha y hora de la recogida de la muestra
Resultados que se presentarán periódicamente en forma de histograma de barras para mostrar la evolución
Incidencias y Medidas correctoras adoptadas
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1472 AS Decimal(6, 0)), N'30             ', N'Las canales, vísceras y despojos están a las temperaturas adecuadas antes de ser introducidos en el medio de transporte.', N'Las carnes están a temperaturas requeridas antes de ser introducidas en los vehículos de transporte.', N' ', N'Las carnes están a temperaturas requeridas antes de ser introducidas en los vehículos de transporte.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(2120 AS Decimal(6, 0)), N'71             ', N'El control de la leche antes de la descarga de la cisterna es correcto.', N'Antes de la descarga realiza los siguientes controles de las cisternas:
- Inspección visual de las cisternas
- Control de temperatura (<10º)
- Control de la limpieza de las cisternas en el centro lácteo o centro autorizado en las condiciones exigidas mediante hojas de registro
- Determinación del grado de acidez o estabilidad al alcohol (inferior a 18ºDornic o estabilidad en alcohol) 
', N' ', N'Antes de la descarga realiza los siguientes controles de las cisternas:
- Inspección visual de las cisternas
- Control de temperatura (<10º)
- Control de la limpieza de las cisternas en el centro lácteo o centro autorizado en las condiciones exigidas mediante hojas de registro
- Determinación del grado de acidez o estabilidad al alcohol (inferior a 18ºDornic o estabilidad en alcohol) 
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1417 AS Decimal(6, 0)), N'3              ', N'En el caso de reutilizar envases:
Dispone de local exclusivo para el lavado e higienización de los mismos.', N'Local exclusivo para la limpieza de envases usados
En el supuesto de que se reutilicen envases la empresa contará con un local exclusivo para su limpieza e higienización, aislado del resto de las dependencias.
Este local no será necesario si los envases reutilizables son higienizados, previamente, en empresa autorizada.
Este local podrá usarse, también, para almacén de envases usados sin higienizar.', N' ', N'Local exclusivo para la limpieza de envases usados
En el supuesto de que se reutilicen envases la empresa contará con un local exclusivo para su limpieza e higienización, aislado del resto de las dependencias.
Este local no será necesario si los envases reutilizables son higienizados, previamente, en empresa autorizada.
Este local podrá usarse, también, para almacén de envases usados sin higienizar.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1386 AS Decimal(6, 0)), N'32             ', N'Todas las prácticas realizadas están permitidas.', N'Se consideran prácticas permitidas:
El tratamiento de los productos con anhídrido sulfuroso gaseoso o en disolución.
El pelado químico de las materias primas por tratamientos con: ácido clorhídrico y hidróxido sódico.', N' ', N'Se consideran prácticas permitidas:
El tratamiento de los productos con anhídrido sulfuroso gaseoso o en disolución.
El pelado químico de las materias primas por tratamientos con: ácido clorhídrico y hidróxido sódico.')
GO
