INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111023 AS Decimal(6, 0)), N'75             ', N'En caso de disponer de abatidor para el enfriamiento rápido de alimentos, se utiliza correctamente.', N'En caso de realizarse algún enfriamiento rápido en abatidor, la temperatura alcanzada en el producto y el tiempo utilizado son los correctos. Además se cumplen las instrucciones de manejo que ayudan a bajar más fácilmente la temperatura: colocar los alimentos en recipientes pequeños o en capas finas de forma que se permita una correcta penetración del frío. Introducirlos sin sobrecargarlos en el abatidor regulado a una temperatura suficiente para conseguir la bajada de temperatura antes mencionada. Posteriormente introducir los alimentos en cámara de mantenimiento hasta conseguir los 6º C', N'En caso de disponer de abatidor para el enfriamiento rápido de alimentos, se utiliza correctamente.', N'En caso de realizarse algún enfriamiento rápido en abatidor, la temperatura alcanzada en el producto y el tiempo utilizado son los correctos. Además se cumplen las instrucciones de manejo que ayudan a bajar más fácilmente la temperatura: colocar los alimentos en recipientes pequeños o en capas finas de forma que se permita una correcta penetración del frío. Introducirlos sin sobrecargarlos en el abatidor regulado a una temperatura suficiente para conseguir la bajada de temperatura antes mencionada. Posteriormente introducir los alimentos en cámara de mantenimiento hasta conseguir los 6º C')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1630 AS Decimal(6, 0)), N'32             ', N'En el caso de zumos de uva, una vez reconstituidos los productos cumplen las especificaciones técnicas.', N'Zumo de uva concentrado
Una vez reconstituidos, los productos zumo de uva, zumo de uva concentrado y zumo de uva deshidratado, deberán cumplir las siguientes especificaciones técnicas:
