INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1305 AS Decimal(6, 0)), N'30             ', N'Caso de carne no envasada se transporta suspendida', N'Si las carnes frescas no estuvieran envasadas y embaladas, deberán permanecer suspendidas durante todo el transporte y el almacenamiento, o colocadas sobre soportes (de material no susceptible a la corrosión) en el caso de carnes despiezadas y despojos. En todos los casos deberán llevar sello de inspección veterinaria.', N' ', N'Si las carnes frescas no estuvieran envasadas y embaladas, deberán permanecer suspendidas durante todo el transporte y el almacenamiento, o colocadas sobre soportes (de material no susceptible a la corrosión) en el caso de carnes despiezadas y despojos. En todos los casos deberán llevar sello de inspección veterinaria.')
