INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1267 AS Decimal(6, 0)), N'30             ', N'El sistema de cierre garantiza la hermeticidad y el mantenimiento de las temperaturas internas de las carnes (c.refrigeradas y despojos -< +4ºC, c. congeladas -< -12ºC. )', N'Para el transporte de carne fresca (refrigerada o congelada) se dispondrá de medios de transporte que mantengan las temperaturas internas de las carnes.
Para carne de conejo, carne de aves de caza de granja refrigeradas, sus despojos y despiece -menor que +4ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC.', N' ', N'Para el transporte de carne fresca (refrigerada o congelada) se dispondrá de medios de transporte que mantengan las temperaturas internas de las carnes.
Para carne de conejo, carne de aves de caza de granja refrigeradas, sus despojos y despiece -menor que +4ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC.')
GO
