INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1258 AS Decimal(6, 0)), N'3              ', N'Dispone de un emplazamiento para la limpieza de vehículos de transporte en caso de transporte de carnes sin embalar o en su defecto se realiza en instalaciones externas autorizadas.', N'Emplazamiento de limpieza de vehículos
Si las labores de limpieza de vehículos se realizan en el establecimiento, éste debe disponer de un emplazamiento para la limpieza de los vehículos dedicado al transporte de carnes sin embalar perfectamente equipado para realizar la limpieza e higiene de los vehículos y la eliminación del agua y restos generados en la misma.
Este servicio también puede realizarse en instalaciones externas autorizadas.
', N' ', N'Emplazamiento de limpieza de vehículos
Si las labores de limpieza de vehículos se realizan en el establecimiento, éste debe disponer de un emplazamiento para la limpieza de los vehículos dedicado al transporte de carnes sin embalar perfectamente equipado para realizar la limpieza e higiene de los vehículos y la eliminación del agua y restos generados en la misma.
Este servicio también puede realizarse en instalaciones externas autorizadas.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1335 AS Decimal(6, 0)), N'30             ', N'Si se transportan con carnes, las tripas han sido escaldadas y lavadas y las patas desolladas o escaldadas y depiladas', N'El transporte de estómagos y tripas sólo podrá realizarse con carnes en caso de que estén escaldados o lavados. Igualmente para las cabezas y patas si no se encuentran desollados, escaldados y depilados. ', N' ', N'El transporte de estómagos y tripas sólo podrá realizarse con carnes en caso de que estén escaldados o lavados. Igualmente para las cabezas y patas si no se encuentran desollados, escaldados y depilados. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1356 AS Decimal(6, 0)), N'38             ', N'Cuando se embalan en eurocajas, las carnes están previamente envasadas y etiquetadas.', N'Está permitido el uso de las eurocajas como segundo envase, es decir como embalaje. Dadas las características de no estanqueidad que tienen, y debido a los orificios que presentan, así como que carecen de dispositivo que evite que las carnes depositadas en su interior puedan ser manejadas fraudulentamente, es obligatorio que en caso de utilizar estas eurocajas, las carnes estén previamente envasadas (primer envase). Por lo tanto, las eurocajas pueden ser utilizadas como recipientes para el depòsito de carnes despiezadas, envasadas y etiquetadas, cumpliendo las condiciones generales de los envases/embalajes reutilizables.', N' ', N'Está permitido el uso de las eurocajas como segundo envase, es decir como embalaje. Dadas las características de no estanqueidad que tienen, y debido a los orificios que presentan, así como que carecen de dispositivo que evite que las carnes depositadas en su interior puedan ser manejadas fraudulentamente, es obligatorio que en caso de utilizar estas eurocajas, las carnes estén previamente envasadas (primer envase). Por lo tanto, las eurocajas pueden ser utilizadas como recipientes para el depòsito de carnes despiezadas, envasadas y etiquetadas, cumpliendo las condiciones generales de los envases/embalajes reutilizables.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1312 AS Decimal(6, 0)), N'32             ', N'Las carnes frescas y los despojos se almacenan en refrigeración a temperaturas internas iguales o inferiores a +7ºC para canales y sus trozos y +3ºC para los despojos. Las carnes y despojos congelados se almacenan a una Tª  igual o inferior a -12ºC.', N'Durante el almacenamiento en refrigeración, las carnes frescas y los despojos deben mantenerse a temperaturas internas iguales o inferiores a +7ªC para canales y sus trozos y a +3ºC para los despojos.
 Las carnes y los despojos congelados se almacenarán a una Tª igual o inferior a -12ºC.', N' ', N'Durante el almacenamiento en refrigeración, las carnes frescas y los despojos deben mantenerse a temperaturas internas iguales o inferiores a +7ªC para canales y sus trozos y a +3ºC para los despojos.
 Las carnes y los despojos congelados se almacenarán a una Tª igual o inferior a -12ºC.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1325 AS Decimal(6, 0)), N'3              ', N'Dispone de un local independiente para almacenar envases, embalajes, etiquetas y resto de material auxiliar.', N'Local de almacenamiento de envases, embalajes y material auxiliar
Debe disponer de un local independiente para el almacenamiento higiénico de los envases, embalajes, etiquetas y demás material auxiliar.   ', N' ', N'Local de almacenamiento de envases, embalajes y material auxiliar
Debe disponer de un local independiente para el almacenamiento higiénico de los envases, embalajes, etiquetas y demás material auxiliar.   ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1351 AS Decimal(6, 0)), N'38             ', N'Las carnes despiezadas y los despojos se envasan, salvo si se transportan suspendidas, o si son trozos de tocino y pecho.', N'Las carnes despiezadas y los despojos deberán estar provistos de un envase protector. Sólo se exceptuan de envasado las carnes que se transporten suspendidas.', N' ', N'Las carnes despiezadas y los despojos deberán estar provistos de un envase protector. Sólo se exceptuan de envasado las carnes que se transporten suspendidas.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1354 AS Decimal(6, 0)), N'38             ', N'La carne envasada es embalada.', N'Las carnes envasadas deberán embalarse.', N' ', N'Las carnes envasadas deberán embalarse.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1345 AS Decimal(6, 0)), N'32             ', N'Las carnes troceadas destinadas a la congelación se congelan sin demora una vez realizadas esas operaciones.
Las carnes congeladas, alcanzan y mantienen una temperatura interna igual o inferior a -12ºC.
', N'La congelación de canales, las medias canales, las medias canales despiezadas en un máximo de tres piezas, los cuartos, los subproductos y despojos se realizará inmediatamente después de su maduración.
Las carnes destinadas a la congelación, troceadas, fileteadas o cortadas deberán congelarse sin demora. Las carnes congeladas deberán alcanzar una temperatura interna igual o inferior a -12ºC y no podrán almacenarse a continuación a una temperatura superior a ésta.
', N' ', N'La congelación de canales, las medias canales, las medias canales despiezadas en un máximo de tres piezas, los cuartos, los subproductos y despojos se realizará inmediatamente después de su maduración.
Las carnes destinadas a la congelación, troceadas, fileteadas o cortadas deberán congelarse sin demora. Las carnes congeladas deberán alcanzar una temperatura interna igual o inferior a -12ºC y no podrán almacenarse a continuación a una temperatura superior a ésta.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1343 AS Decimal(6, 0)), N'32             ', N'Las carnes frescas destinadas a la congelación proceden directamente de un matadero o de una sala de despiece.', N'Las carnes frescas destinadas a la congelación deberán  proceder directamente de un matadero o de una sala de despiece.
', N' ', N'Las carnes frescas destinadas a la congelación deberán  proceder directamente de un matadero o de una sala de despiece.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1332 AS Decimal(6, 0)), N'30             ', N'El sistema de cierre garantiza la hermeticidad y el mantenimiento de las temperaturas internas de las carnes (c.refrigeradas -< +7ºC, despojos -<+3ºC, c. congeladas -< -12ºC. )', N'Para el transporte de carnes frescas (refrigeradas o congeladas) se dispondrá de medios de transporte con sistemas de cierre que garanticen la hermeticidad de los mismos, con la finalidad de mantener las temperaturas internas de las carnes.
Para carnes refrigeradas y carnes despiezadas de la canal -menor que +7ºC
Para despojos refrigerados estén o no unidas a sus canales -menor que +3ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC
', N' ', N'Para el transporte de carnes frescas (refrigeradas o congeladas) se dispondrá de medios de transporte con sistemas de cierre que garanticen la hermeticidad de los mismos, con la finalidad de mantener las temperaturas internas de las carnes.
Para carnes refrigeradas y carnes despiezadas de la canal -menor que +7ºC
Para despojos refrigerados estén o no unidas a sus canales -menor que +3ºC
Para carnes congeladas (canales, carnes despiezadas y despojos) -menor que -12ºC
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1330 AS Decimal(6, 0)), N'11             ', N'Para la congelación de las carnes dispone de equipos tecnológicos adecuados.', N'La congelación de las carnes frescas sólo se podrá realizar si el establecimiento dispone de un equipo adecuado tecnológicamente a este fin (túnel de congelación, abatidor de temperatura, etc.).', N' ', N'La congelación de las carnes frescas sólo se podrá realizar si el establecimiento dispone de un equipo adecuado tecnológicamente a este fin (túnel de congelación, abatidor de temperatura, etc.).')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1546 AS Decimal(6, 0)), N'32             ', N'Los coadyuvantes utilizados son los autorizados, y las dosis máximas las permitidas.', N'Aceitunas de mesa:
Durante la fermentación y conservación se vigilarán periódicamente las bocas de los recipientes y se prestará especial atención a la existencia de películas y velos de levadura o mohos que se eliminarán periódicamente.
Se autoriza el empleo de los siguientes productos:
Aceituna, agua, sal, vinagre, aceite de oliva, azucares alimenticios, cualquier producto alimenticio, especias, plantas o cualquier otro producto aromático o sus extractos naturales, y salmuera.
Coadyuvantes tecnológicos autorizados:
Hidróxido sódico (solo para preparación de lejía alcalina)
Ácido clorhídrico (para neutralización de la lejía residual)
Cultivos lácticos como iniciadores del proceso de fermentación
Condiciones de pureza del ácido clorhídricomayor que      residuos no volátilesmayor que  no mas del 0,5%
                                                                       sustancias reductoras no más de 70 mg/Kg como SO2
                                                                       sustancias oxidantes no más de 30 mg/Kg como Cl2
                                                                       sulfatos   no mas del 0,5%
                                                                       arsénico   no más de 1mg/Kg
                                                                       metales pesados  no más de 5 mg/Kg
                                                                       hierro    no más de 5 mg/Kg
El ácido clorhídrico producido en la fabricación de insecticidas hidrocarbonados clonados nunca podrá ser considerado de calidad alimentaria.
Si se realiza tratamiento térmico:
En recipientes a presión atmosférica para las conservas de pH final 4,6 o inferiores
En autoclaves para la esterilización, a presión, de conservas pH superior a 4,6 .
Cuando se utilicen sistemas continuos o discontinuos a presión normal deberán disponer de los controles de tiempo y temperatura que permitan el conocimiento de la marcha del proceso de esterilización.
', N' ', N'Aceitunas de mesa:
Durante la fermentación y conservación se vigilarán periódicamente las bocas de los recipientes y se prestará especial atención a la existencia de películas y velos de levadura o mohos que se eliminarán periódicamente.
Se autoriza el empleo de los siguientes productos:
Aceituna, agua, sal, vinagre, aceite de oliva, azucares alimenticios, cualquier producto alimenticio, especias, plantas o cualquier otro producto aromático o sus extractos naturales, y salmuera.
Coadyuvantes tecnológicos autorizados:
Hidróxido sódico (solo para preparación de lejía alcalina)
Ácido clorhídrico (para neutralización de la lejía residual)
Cultivos lácticos como iniciadores del proceso de fermentación
Condiciones de pureza del ácido clorhídricomayor que      residuos no volátilesmayor que  no mas del 0,5%
                                                                       sustancias reductoras no más de 70 mg/Kg como SO2
                                                                       sustancias oxidantes no más de 30 mg/Kg como Cl2
                                                                       sulfatos   no mas del 0,5%
                                                                       arsénico   no más de 1mg/Kg
                                                                       metales pesados  no más de 5 mg/Kg
                                                                       hierro    no más de 5 mg/Kg
El ácido clorhídrico producido en la fabricación de insecticidas hidrocarbonados clonados nunca podrá ser considerado de calidad alimentaria.
Si se realiza tratamiento térmico:
En recipientes a presión atmosférica para las conservas de pH final 4,6 o inferiores
En autoclaves para la esterilización, a presión, de conservas pH superior a 4,6 .
Cuando se utilicen sistemas continuos o discontinuos a presión normal deberán disponer de los controles de tiempo y temperatura que permitan el conocimiento de la marcha del proceso de esterilización.
')
GO
