INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1444 AS Decimal(6, 0)), N'3              ', N'Si dispone de emplazamiento e instalaciones para limpieza y desinfección de medios de transporte y de jaulas usadas está aislado y equipado.', N'En el caso de que disponga de emplazamiento e instalaciones para la limpieza y desinfección de los medios de transporte y de jaulas usadas, éstos estarán ubicados en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.
No obstante dichos emplazamientos e instalaciones no serán obligatorios si estas tareas se realizan en establecimientos oficialmente autorizados.
', N' ', N'En el caso de que disponga de emplazamiento e instalaciones para la limpieza y desinfección de los medios de transporte y de jaulas usadas, éstos estarán ubicados en un punto del recinto del matadero aislado del resto de las instalaciones, y dispondrán de agua fría y caliente y desinfectante, así como sumideros para la eliminación de los restos del lavado.
No obstante dichos emplazamientos e instalaciones no serán obligatorios si estas tareas se realizan en establecimientos oficialmente autorizados.
')
GO
