INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1400 AS Decimal(6, 0)), N'5              ', N'La estructura de los puestos de venta es rígida, de material duradero y fácil de mantener, limpiar y desinfectar.', N'Estructura:
Las instalaciones de los puestos de venta, quioscos, vehículos etc., dispondrán de estructuras (fijas o móviles)  de materiales duraderos, impermeables, inadsorventes y fáciles de mantener, limpiar y desinfectar.
En el caso de las instalaciones móviles desmontables, la estructura de las mismas será de materiales rígidos (ej estructura tubular, PVC, metálica, etc.) cubierta de materiales impermeables, resistentes y de fácil limpieza (ej. Lona, material plástico etc.)que hagan la función de techo y paredes.', N' ', N'Estructura:
Las instalaciones de los puestos de venta, quioscos, vehículos etc., dispondrán de estructuras (fijas o móviles)  de materiales duraderos, impermeables, inadsorventes y fáciles de mantener, limpiar y desinfectar.
En el caso de las instalaciones móviles desmontables, la estructura de las mismas será de materiales rígidos (ej estructura tubular, PVC, metálica, etc.) cubierta de materiales impermeables, resistentes y de fácil limpieza (ej. Lona, material plástico etc.)que hagan la función de techo y paredes.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1401 AS Decimal(6, 0)), N'5              ', N'Los suelos de los puestos de venta son de material firme y estable.', N'Suelos:
Los suelos en los que se ubiquen los puestos de venta serán de material firme y estable (loseta, cemento, asfalto, etc.). No se admitirán suelos de arena, tierra u otro material inestable que pueda contribuir a la formación de fuentes de contaminación, como barro, polvo etc.
', N' ', N'Suelos:
Los suelos en los que se ubiquen los puestos de venta serán de material firme y estable (loseta, cemento, asfalto, etc.). No se admitirán suelos de arena, tierra u otro material inestable que pueda contribuir a la formación de fuentes de contaminación, como barro, polvo etc.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1402 AS Decimal(6, 0)), N'12             ', N'En el caso de fraccionar la venta y manipular alimentos sin envasar dispone de instalaciones, equipos, utensilios y lavamanos completo.', N'Fraccionamiento y loncheado:
Cuando se realicen operaciones de fraccionado y loncheado con los productos, el puesto de venta dispondrá de equipos y utensilios que permitan realizar la manipulación en condiciones higiénicas. Dispondrá asimismo en la zona de manipulación exclusiva para dichas operaciones de un lavamanos completo de fácil acceso.', N' ', N'Fraccionamiento y loncheado:
Cuando se realicen operaciones de fraccionado y loncheado con los productos, el puesto de venta dispondrá de equipos y utensilios que permitan realizar la manipulación en condiciones higiénicas. Dispondrá asimismo en la zona de manipulación exclusiva para dichas operaciones de un lavamanos completo de fácil acceso.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1403 AS Decimal(6, 0)), N'19             ', N'El personal manipulador dispone de la indumentaria requerida para la manipulación que realiza.', N'Indumentaria:
El personal manipulador al comienzo de la jornada laboral dispondrá de equipo de trabajo e indumentaria exclusiva para uso en el trabajo, que será de fácil limpieza. Dispondrá, a lo largo de la jornada laboral, de otra indumentaria si fuera necesario, bien porque la que está utilizando esté excesivamente sucia o por cualquier otro motivo por el que se puedan producir contaminaciones.

', N' ', N'Indumentaria:
El personal manipulador al comienzo de la jornada laboral dispondrá de equipo de trabajo e indumentaria exclusiva para uso en el trabajo, que será de fácil limpieza. Dispondrá, a lo largo de la jornada laboral, de otra indumentaria si fuera necesario, bien porque la que está utilizando esté excesivamente sucia o por cualquier otro motivo por el que se puedan producir contaminaciones.

')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1404 AS Decimal(6, 0)), N'32             ', N'El puesto de venta cumple las condiciones exigidas para manipulaciones tales como el corte, loncheado y fileteado.', N'Fraccionamiento (corte, fileteado, loncheado):
Cuando se realice el fraccionamiento de los productos, esta actividad se llevará a cabo de tal forma que se cumplan las condiciones descritas en la IT.17.4 en caso contrario deberán expedirse envasados de modo que se garantice el mantenimiento de las características microbiológicas, organolépticas, etc.', N' ', N'Fraccionamiento (corte, fileteado, loncheado):
Cuando se realice el fraccionamiento de los productos, esta actividad se llevará a cabo de tal forma que se cumplan las condiciones descritas en la IT.17.4 en caso contrario deberán expedirse envasados de modo que se garantice el mantenimiento de las características microbiológicas, organolépticas, etc.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1480 AS Decimal(6, 0)), N'32             ', N'No se rellenan las carnes a menos que se use para ello despojos comestibles o el cuello de uno de los animales sacrificado en el matadero.', N'Se prohibe rellenar las canales, a menos que se usen para ello despojos comestibles o el cuello de uno de los animales sacrificados en el establecimiento.', N' ', N'Se prohibe rellenar las canales, a menos que se usen para ello despojos comestibles o el cuello de uno de los animales sacrificados en el establecimiento.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1405 AS Decimal(6, 0)), N'39             ', N'Mantiene correctamente la información de los productos de venta fraccionada.', N'Información del producto de venta fraccionada:
Cuando para su comercialización se fraccionen o loncheen productos deberán conservar la información correspondiente al etiquetado original del envase hasta la finalización de la venta, para permitir en cualquier momento una correcta identificación del producto.
', N' ', N'Información del producto de venta fraccionada:
Cuando para su comercialización se fraccionen o loncheen productos deberán conservar la información correspondiente al etiquetado original del envase hasta la finalización de la venta, para permitir en cualquier momento una correcta identificación del producto.
')
GO
