INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1442 AS Decimal(6, 0)), N'3              ', N'Dispone de zona o emplazamiento que permite llevar a cabo labores de inspección veterinaria adecuadamente.', N'Dispondrá de un emplazamiento o zona diferenciada en la cadena de sacrificio, que permita efectuar de forma eficaz y sin trabas, las tareas de inspección post-mortem. ', N' ', N'Dispondrá de un emplazamiento o zona diferenciada en la cadena de sacrificio, que permita efectuar de forma eficaz y sin trabas, las tareas de inspección post-mortem. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1438 AS Decimal(6, 0)), N'3              ', N'Dispone de local o instalación para recuperar pieles si éstas no se tratan como desperdicios.', N'Local o instalación para la recuperación de pieles, a menos que éstas se traten como desperdicios. Este local estará separado de los locales donde se manipulen productos comestibles.', N' ', N'Local o instalación para la recuperación de pieles, a menos que éstas se traten como desperdicios. Este local estará separado de los locales donde se manipulen productos comestibles.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1395 AS Decimal(6, 0)), N'67             ', N'La identificación de la fabricación o fecha de envasado y elaboración se realiza en una de las formas autorizadas en la IT.', N'Identificación de la fabricación o fecha de envasado y elaboración. La fecha de envasado se inscribirá de la forma siguiente:
En los envases metálicos de las conservas se inscribirá mediante troquelado una letra que represente el a¦o de fabricación, acordada por la Administración y de la que se dará cuenta al consumidor.
En otros tipos de envases, incluidas las tarrinas metálicas, la identificación podrá también inscribirse en la etiqueta, cierre de los envases, tapones o precintos.
En las semiconservas y productos congelados destinados a la venta al público cualquiera que sea el tipo de envase, es obligatorio consignar claramente un número comprendido entre el 1 y el 25, correspondiente al número de orden de la semana, seguido de la letra correspondiente al a¦o de fabricación.
También se podrá utilizar la impresión sobre la pared metálica con procedimientos indelebles como la litografía, electrónicos , electroquímicos o térmicos y la utilización de tintas especiales cuya impresión permanezca legible bajo la acción de los agentes y condiciones siguientes: agua, aceites vegetales, vinagre, salmueras, salsas, el manejo natural del envase y la limpieza del mismo.
', N' ', N'Identificación de la fabricación o fecha de envasado y elaboración. La fecha de envasado se inscribirá de la forma siguiente:
En los envases metálicos de las conservas se inscribirá mediante troquelado una letra que represente el a¦o de fabricación, acordada por la Administración y de la que se dará cuenta al consumidor.
En otros tipos de envases, incluidas las tarrinas metálicas, la identificación podrá también inscribirse en la etiqueta, cierre de los envases, tapones o precintos.
En las semiconservas y productos congelados destinados a la venta al público cualquiera que sea el tipo de envase, es obligatorio consignar claramente un número comprendido entre el 1 y el 25, correspondiente al número de orden de la semana, seguido de la letra correspondiente al a¦o de fabricación.
También se podrá utilizar la impresión sobre la pared metálica con procedimientos indelebles como la litografía, electrónicos , electroquímicos o térmicos y la utilización de tintas especiales cuya impresión permanezca legible bajo la acción de los agentes y condiciones siguientes: agua, aceites vegetales, vinagre, salmueras, salsas, el manejo natural del envase y la limpieza del mismo.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1413 AS Decimal(6, 0)), N'3              ', N'En el caso de reutilizar envases / embalajes:
Dispone de local específico o zona (dentro del almacén de producto final) para el almacenamiento de envases y/o embalajes retornables, ya higienizados.', N'Local de almacén de envases y embalajes recuperables, ya higienizados.
Si las labores de limpieza e higienización de envases se realizan en el establecimiento estos se almacenarán debidamente estibados, con su embocadura protegida de manera que se  evite la entrada de contaminantes en su interior y tras un completo escurrido (interno y externo) del agua de lavado.', N' ', N'Local de almacén de envases y embalajes recuperables, ya higienizados.
Si las labores de limpieza e higienización de envases se realizan en el establecimiento estos se almacenarán debidamente estibados, con su embocadura protegida de manera que se  evite la entrada de contaminantes en su interior y tras un completo escurrido (interno y externo) del agua de lavado.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1415 AS Decimal(6, 0)), N'3              ', N'Dispone de local de almacenamiento de producto final embotellado.', N'Local de almacenamiento de producto terminado embotellado.
Este almacén de producto terminado podrá utilizarse, también, para el almacenamiento de corchos, envases nuevos o higienizados, etiquetas y embalajes, siempre y cuando todos ellos estén debidamente estibados y protegidos: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases (nuevos o higienizados) además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado. En este supuesto podrá prescindirse de los locales enumerados en los apartados 8, 9 y 10.
Dispondrá  de algún sistema, permanente, que impida que los vehículos accedan al interior del mismo, en caso contrario deberá disponer de un local previo destinado a las labores de carga y descarga.', N' ', N'Local de almacenamiento de producto terminado embotellado.
Este almacén de producto terminado podrá utilizarse, también, para el almacenamiento de corchos, envases nuevos o higienizados, etiquetas y embalajes, siempre y cuando todos ellos estén debidamente estibados y protegidos: de manera general con envoltura que los proteja del polvo y cualquier otro tipo de contaminación y en el caso particular de los envases (nuevos o higienizados) además mediante sistema que proteja su embocadura y evite la entrada de contaminantes en su interior. En los envases higienizados esta protección deberá ir precedida de un completo escurrido (interno y externo) del agua de lavado. En este supuesto podrá prescindirse de los locales enumerados en los apartados 8, 9 y 10.
Dispondrá  de algún sistema, permanente, que impida que los vehículos accedan al interior del mismo, en caso contrario deberá disponer de un local previo destinado a las labores de carga y descarga.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1411 AS Decimal(6, 0)), N'3              ', N'Dispone de local exclusivo (o zona dentro del local de elaboración) para las labores de envasado de producto final.', N'Local de envasado:
Destinado a las labores de embotellado / taponado de la sidra elaborada.

En su defecto, se admitirá zona de envasado/embotellado, dentro del local de elaboración, cuando no se simultanee dicha actividad  con la de triturado/prensado de la manzana. Además, cuando se simultanee el envasado con otras labores de elaboración o limpieza dicha zona estará aislada  (delimitada) mediante mamparas, paneles o similares de suficiente altura para que impidan el transito a través de la misma de productos, equipamiento o personal ajenos a las labores de envasado.

En caso de simultanear las labores de triturado/prensado con las de embotellado, o cuando el local de elaboración se utilice para  la actividad de Comedor Colectivo (txotx), el establecimiento deberá contar obligatoriamente con Local de envasado, exclusivo para esta actividad e independiente del local de elaboración.', N' ', N'Local de envasado:
Destinado a las labores de embotellado / taponado de la sidra elaborada.

En su defecto, se admitirá zona de envasado/embotellado, dentro del local de elaboración, cuando no se simultanee dicha actividad  con la de triturado/prensado de la manzana. Además, cuando se simultanee el envasado con otras labores de elaboración o limpieza dicha zona estará aislada  (delimitada) mediante mamparas, paneles o similares de suficiente altura para que impidan el transito a través de la misma de productos, equipamiento o personal ajenos a las labores de envasado.

En caso de simultanear las labores de triturado/prensado con las de embotellado, o cuando el local de elaboración se utilice para  la actividad de Comedor Colectivo (txotx), el establecimiento deberá contar obligatoriamente con Local de envasado, exclusivo para esta actividad e independiente del local de elaboración.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1631 AS Decimal(6, 0)), N'68             ', N'No utiliza la denominación Vitamina C si la usa como antioxidante. Figura como Acido L ascórbico.', N'Vitamina C
Cuando la cantidad de vitamina C a¦adida no rebase la cantidad máxima autorizada como antioxidante se denominará únicamente ácido L-ascórbico. (También en zumo de uva).
Unicamente se hará mención de su contenido en vitamina C tanto en la lista de ingredientes como en otras inscripciones, cuando se garantice en el producto y hasta la fecha de duración mínima, un mínimo de 400 mg/l, en cuyo caso el producto tendrá consideración de enriquecido.
', N' ', N'Vitamina C
Cuando la cantidad de vitamina C a¦adida no rebase la cantidad máxima autorizada como antioxidante se denominará únicamente ácido L-ascórbico. (También en zumo de uva).
Unicamente se hará mención de su contenido en vitamina C tanto en la lista de ingredientes como en otras inscripciones, cuando se garantice en el producto y hasta la fecha de duración mínima, un mínimo de 400 mg/l, en cuyo caso el producto tendrá consideración de enriquecido.
')
GO
