INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1423 AS Decimal(6, 0)), N'25             ', N'Los residuos procedentes del prensado de la manzana se retiran de forma, higiénica, continua y directa al exterior desde la zona/local de prensado y se almacenan adecuadamente hasta su eliminación.', N'Los residuos procedentes del prensado de la manzana se retirarán de la zona / local de prensado de manera, higiénica, continua y directa al exterior (sin utilizar vehículos a motor) y se almacenarán en el exterior de la empresa (en contenedores o silos) hasta su entrega para posterior aprovechamiento o destrucción.', N' ', N'Los residuos procedentes del prensado de la manzana se retirarán de la zona / local de prensado de manera, higiénica, continua y directa al exterior (sin utilizar vehículos a motor) y se almacenarán en el exterior de la empresa (en contenedores o silos) hasta su entrega para posterior aprovechamiento o destrucción.')
