INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1422 AS Decimal(6, 0)), N'57             ', N'En el caso de reutilizar embalajes (cajas de plástico):
Dispone de sistema de higienización de los mismos.
', N'En el caso de reutilizarse embalajes (cajas plásticas retornables):
Dispondrá de algún .sistema que asegure la limpieza e higienización de cajas o contenedores retornables, antes de su nuevo uso.
Este equipamiento no será necesario si los embalajes reutilizables son higienizados, previamente, en empresa autorizada.', N' ', N'En el caso de reutilizarse embalajes (cajas plásticas retornables):
