INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1393 AS Decimal(6, 0)), N'67             ', N'Siempre figura el numero de registro sanitario de la industria elaboradora.', N'Número de registro sanitario de la industria fabricante. Cuando la elaboración de un producto sea realizada bajo marca de un    distribuidor, además de figurar sus datos, se incluirán los de la industria elaboradora o su número de registro, precedidos por la expresión Fabricado por.... ', N' ', N'Número de registro sanitario de la industria fabricante. Cuando la elaboración de un producto sea realizada bajo marca de un    distribuidor, además de figurar sus datos, se incluirán los de la industria elaboradora o su número de registro, precedidos por la expresión Fabricado por.... ')
