INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1570 AS Decimal(6, 0)), N'32             ', N'No se realiza ninguna de las prácticas prohibidas se¦aladas en la instrucción específica.', N'Prácticas prohibidas
La utilización del procedimiento denominado al amilo para sacarificar el almidón procedente de los cereales.
La adición de alcohol.
El empleo de sucedáneos del lúpulo o de principios amargos extra¦os.
La neutralización después del proceso de fermentación
El empleo de coadyuvantes tecnológicos que no estén expresamente autorizados para estos productos.
La adición de glicerina en cantidad que exceda de 2 g/1.000 g m/m de cerveza y, en general, de sustancias que alteren la composición normal de la cerveza.
', N' ', N'Prácticas prohibidas
La utilización del procedimiento denominado al amilo para sacarificar el almidón procedente de los cereales.
La adición de alcohol.
El empleo de sucedáneos del lúpulo o de principios amargos extra¦os.
La neutralización después del proceso de fermentación
El empleo de coadyuvantes tecnológicos que no estén expresamente autorizados para estos productos.
La adición de glicerina en cantidad que exceda de 2 g/1.000 g m/m de cerveza y, en general, de sustancias que alteren la composición normal de la cerveza.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1613 AS Decimal(6, 0)), N'65             ', N'No figurando en el envase el contenido de los protocolos 1608, 1610 y 1611, esta información figura en el documento comercial.', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, las menciones descritas para los protocolos 1608, 1610 y 1611,  además de la identificación del lote de fabricación y la identificación del fabricante o envasador, podrán figurar sólo en documentos comerciales relativos a la partida, que se deberán presentar en el momento de la entrega o antes de ésta, a condición de que, en lugar visible del envase o del embalaje del producto considerado, figure la indicación para la fabricación de productos alimenticios, con exclusión de toda venta al por menor.', N' ', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, las menciones descritas para los protocolos 1608, 1610 y 1611,  además de la identificación del lote de fabricación y la identificación del fabricante o envasador, podrán figurar sólo en documentos comerciales relativos a la partida, que se deberán presentar en el momento de la entrega o antes de ésta, a condición de que, en lugar visible del envase o del embalaje del producto considerado, figure la indicación para la fabricación de productos alimenticios, con exclusión de toda venta al por menor.')
GO
