GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1661 AS Decimal(6, 0)), N'3              ', N'Dispone de local para las labores de elaboración, envasado y embalado.', N'Local de fabricación/elaboración y envasado/embalado
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará suficientemente aislado (independizado) de los locales de almacenamiento. En el caso de la utilización de patata sin pelar deberá disponer de un Local para las labores de pelado de las mismas, dichas labores se podrán realizar en una Zona diferenciada del local de elaboración si el establecimiento dispone de equipamiento e instalaciones para que las labores pelado y retirada de desechos se realicen de forma higiénica.', N'Dispone de local para las labores de elaboración, envasado y embalado.', N'Local de fabricación/elaboración y envasado/embalado
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará suficientemente aislado (independizado) de los locales de almacenamiento. En el caso de la utilización de patata sin pelar deberá disponer de un Local para las labores de pelado de las mismas, dichas labores se podrán realizar en una Zona diferenciada del local de elaboración si el establecimiento dispone de equipamiento e instalaciones para que las labores pelado y retirada de desechos se realicen de forma higiénica.')
GO
