INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1594 AS Decimal(6, 0)), N'58             ', N'El local de limpieza está dotado de instalaciones mecánicas que aseguren una correcta limpieza y desinfección de útiles, maquinaria, vajilla, contenedores y envases reutilizables.', N'El local de limpieza estará dotado de instalaciones mecánicas (tren de limpieza  plonge) que aseguren una correcta limpieza y desinfección de útiles, maquinaria, vajilla, contenedores y envases reutilizables (con capacidad suficiente,  para la limpieza de los contenedores).', N'El local de limpieza está dotado de instalaciones mecánicas que aseguren una correcta limpieza y desinfección de útiles, maquinaria, vajilla, contenedores y envases reutilizables.', N'El local de limpieza estará dotado de instalaciones mecánicas (tren de limpieza  plonge) que aseguren una correcta limpieza y desinfección de útiles, maquinaria, vajilla, contenedores y envases reutilizables (con capacidad suficiente,  para la limpieza de los contenedores).')
