INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1596 AS Decimal(6, 0)), N'32             ', N'Las temperaturas de los alimentos que requieren mantenimiento a tª regulada están comprendidas entre las siguientes:
De 0 a 4ºC para alimentos que requieran refrigeración, con vida útil > 24 h.
De 0 a 8ºC para alimentos que requieran refrigeración, con ????', N'Las temperaturas de almacenamiento, conservación y transporte de los alimentos que requieran mantenimiento a temperatura controlada, serán las siguientes: 
De 0 a 4 ºC para alimentos que requieran refrigeración, con vida útil mayor que 24 h. 
De 0 a 8 ºC para alimentos que requieran refrigeración, con vida útil menor que 24 h. 
Inferior o igual a -18 ºC, para alimentos congelados.', N'Las temperaturas de los alimentos que requieren mantenimiento a tª regulada están comprendidas entre las siguientes:
De 0 a 4ºC para alimentos que requieran refrigeración, con vida útil > 24 h.
De 0 a 8ºC para alimentos que requieran refrigeración, con ????', N'Las temperaturas de almacenamiento, conservación y transporte de los alimentos que requieran mantenimiento a temperatura controlada, serán las siguientes: 
De 0 a 4 ºC para alimentos que requieran refrigeración, con vida útil mayor que 24 h. 
De 0 a 8 ºC para alimentos que requieran refrigeración, con vida útil menor que 24 h. 
Inferior o igual a -18 ºC, para alimentos congelados.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1650 AS Decimal(6, 0)), N'32             ', N'Cuando se trata de vegetales obtenidos por deshidratación, dispone se reduce el contenido de humedad del producto hasta un nivel suficiente para su adecuada conservación por este medio.', N'Los vegetales deshidratados y desecados: la reducción del contenido de humedad permite la adecuada conservación del producto.', N'Cuando se trata de vegetales obtenidos por deshidratación, dispone se reduce el contenido de humedad del producto hasta un nivel suficiente para su adecuada conservación por este medio.', N'Los vegetales deshidratados y desecados: la reducción del contenido de humedad permite la adecuada conservación del producto.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1586 AS Decimal(6, 0)), N'3              ', N'Dispone de local de cocinado  correctamente acondicionado.', N'Local de cocinado
Debe disponer de un local independiente para el tratamiento térmico de los productos que lo precisen (cocción, horneado ?), al cual accederán directamente desde sus locales de limpieza y manipulación previa, o de almacenamiento, en el caso de alimentos de tratamiento directo sin necesidad de manipulación.
Dicho local, deberá comunicar directamente además, con el local de limpieza de útiles, de modo que los útiles y vajilla una vez utilizados, puedan depositarse en dicho local para su limpieza y desinfección.', N'Dispone de local de cocinado  correctamente acondicionado.', N'Local de cocinado
Debe disponer de un local independiente para el tratamiento térmico de los productos que lo precisen (cocción, horneado ?), al cual accederán directamente desde sus locales de limpieza y manipulación previa, o de almacenamiento, en el caso de alimentos de tratamiento directo sin necesidad de manipulación.
Dicho local, deberá comunicar directamente además, con el local de limpieza de útiles, de modo que los útiles y vajilla una vez utilizados, puedan depositarse en dicho local para su limpieza y desinfección.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1642 AS Decimal(6, 0)), N'3              ', N'El local / zona de expedición dispone de local previo (de carga) o de  sistema permanente que impida la entrada de vehículos  a su interior.', N'Zona de salida /Local  de expedición de producto final para establecimientos elaboradores
Estará independizada de la entrada de materia prima  y de su almacenamiento. Contará con sistema permanente que impida la entrada de vehículos al interior del mismo o en su defecto de local previo destinado a las labores de carga y que lo independice  del exterior.', N'El local / zona de expedición dispone de local previo (de carga) o de  sistema permanente que impida la entrada de vehículos  a su interior.', N'Zona de salida /Local  de expedición de producto final para establecimientos elaboradores
Estará independizada de la entrada de materia prima  y de su almacenamiento. Contará con sistema permanente que impida la entrada de vehículos al interior del mismo o en su defecto de local previo destinado a las labores de carga y que lo independice  del exterior.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1624 AS Decimal(6, 0)), N'39             ', N'El nombre comercial o de fantasía va en la cara principal o anverso de la envoltura y, sin la utilización de las palabras cacao o chocolate, así como también los grupos de sílabas o letras que puedan recordar aquellas palabras (choco, choc,  late, cao, et????', N'El nombre comercial o de fantasía irá en la cara principal o anverso de la envoltura y sin la utilización de las palabras cacao o chocolate, así como también los grupos de sílabas o letras que puedan recordar aquellas palabras (choco, choc, late, cao, etc.) aunque si puede figurar en la lista de ingredientes.', N'El nombre comercial o de fantasía va en la cara principal o anverso de la envoltura y, sin la utilización de las palabras cacao o chocolate, así como también los grupos de sílabas o letras que puedan recordar aquellas palabras (choco, choc,  late, cao, et????', N'El nombre comercial o de fantasía irá en la cara principal o anverso de la envoltura y sin la utilización de las palabras cacao o chocolate, así como también los grupos de sílabas o letras que puedan recordar aquellas palabras (choco, choc, late, cao, etc.) aunque si puede figurar en la lista de ingredientes.')
GO
