INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1584 AS Decimal(6, 0)), N'3              ', N'Dispone de local / emplazamiento para el almacenamiento de envases .', N'Local/emplazamiento para el almacenamiento de envases
En función del volumen de comercialización de comidas envasadas en raciones, deberá disponer de un local específico o emplazamiento diferenciado con cierres, para el almacenamiento del material de envasad.', N'Dispone de local / emplazamiento para el almacenamiento de envases .', N'Local/emplazamiento para el almacenamiento de envases
En función del volumen de comercialización de comidas envasadas en raciones, deberá disponer de un local específico o emplazamiento diferenciado con cierres, para el almacenamiento del material de envasad.')
