INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1585 AS Decimal(6, 0)), N'3              ', N'Dispone de local o áreas diferenciadas dentro de un mismo local, correctamente acondicionado, para la manipulación y limpieza de las distintas materias primas.', N'Local para la limpieza y manipulación de materias primas
Debe disponer de locales o áreas diferenciadas dentro de un mismo local, para la manipulación y limpieza de las distintas materias primas (carne, pescado y verduras). Dichas dependencias, cuando el producto lo requiera, dispondrán de un sistema de climatización que permita garantizar una temperatura menor de 18ºC', N'Dispone de local o áreas diferenciadas dentro de un mismo local, correctamente acondicionado, para la manipulación y limpieza de las distintas materias primas.', N'Local para la limpieza y manipulación de materias primas
Debe disponer de locales o áreas diferenciadas dentro de un mismo local, para la manipulación y limpieza de las distintas materias primas (carne, pescado y verduras). Dichas dependencias, cuando el producto lo requiera, dispondrán de un sistema de climatización que permita garantizar una temperatura menor de 18ºC')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1588 AS Decimal(6, 0)), N'3              ', N'Dispone de un local correctamente dise¦ado para el almacenamiento de contenedores y envases reutilizables limpios.', N'Local de almacenamiento de contenedores y envases reutilizables limpios
Próximo (anexo) al local de limpieza y al local de envasado/entermado, debe disponer de un local para el almacenamiento, tras el proceso de limpieza y secado,  de los contenedores y envases reutilizables.', N'Dispone de un local correctamente dise¦ado para el almacenamiento de contenedores y envases reutilizables limpios.', N'Local de almacenamiento de contenedores y envases reutilizables limpios
Próximo (anexo) al local de limpieza y al local de envasado/entermado, debe disponer de un local para el almacenamiento, tras el proceso de limpieza y secado,  de los contenedores y envases reutilizables.')
GO
