INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1604 AS Decimal(6, 0)), N'32             ', N'La empresa fabricante, mezcladora o envasadora de aditivos alimentarios realiza los controles de cada lote de producto terminado que exige la fabricación correcta.', N'Las empresas fabricantes, mezcladoras y envasadoras de aditivos alimentarios deberán realizar los controles de cada lote de producto terminado que exija la fabricación correcta.', N' ', N'Las empresas fabricantes, mezcladoras y envasadoras de aditivos alimentarios deberán realizar los controles de cada lote de producto terminado que exija la fabricación correcta.')
