INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1605 AS Decimal(6, 0)), N'32             ', N'La empresa mezcladora y/o envasadora de aditivos alimentarios realiza controles de materias primas y/o prescinde de ellos cuando el proveedor de las mismas le haya suministrado certificado de análisis del producto. ', N'Las empresas mezcladoras y envasadoras de aditivos alimentarios deberán realizar igualmente controles de materias primas, pudiendo prescindir de los mismos cuando el proveedor le haya suministrado certificado de análisis del producto.', N' ', N'Las empresas mezcladoras y envasadoras de aditivos alimentarios deberán realizar igualmente controles de materias primas, pudiendo prescindir de los mismos cuando el proveedor le haya suministrado certificado de análisis del producto.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1606 AS Decimal(6, 0)), N'32             ', N'La empresa comercializadora o importadora que no manipula los productos, realiza controles y/o dispone del certificado de análisis entregado por el proveedor (en el caso de productos de importación).', N'Para las empresas comercializadoras e importadoras que no manipulen los productos se considerará suficiente el certificado de análisis entregado por el proveedor y que, en el caso de productos de importación, deberá estar avalado por un organismo oficial competente del país de origen.', N' ', N'Para las empresas comercializadoras e importadoras que no manipulen los productos se considerará suficiente el certificado de análisis entregado por el proveedor y que, en el caso de productos de importación, deberá estar avalado por un organismo oficial competente del país de origen.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1592 AS Decimal(6, 0)), N'3              ', N'Dispone de un local/zona para el envasado del producto.', N'Local / zona de envasado
Cuando el establecimiento realice la distribución de las comidas preparadas en raciones, dispondrá de un local específico para su envasado. Dicha operación, podrá realizarse en el mismo local de manipulación de producto elaborado, siempre que éste sea lo suficientemente amplio y se diferencien claramente ambas zonas. ', N' ', N'Local / zona de envasado
Cuando el establecimiento realice la distribución de las comidas preparadas en raciones, dispondrá de un local específico para su envasado. Dicha operación, podrá realizarse en el mismo local de manipulación de producto elaborado, siempre que éste sea lo suficientemente amplio y se diferencien claramente ambas zonas. ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(221 AS Decimal(3, 0)), CAST(111027 AS Decimal(6, 0)), N'75             ', N'Los alimentos que se conservan en caliente se mantienen constantemente a una temperatura igual o mayor de 65º C.', N'Los alimentos que se están mantenidos en caliente por diversos sistemas como el fuego, chapa, baño maría, mesas calientes, tienen en el centro del producto 65º C y que el calor se distribuye correctamente por todo el producto. Además se comprobará que la temperatura de nuestro termómetro se corresponde con las anotadas en el registro.', N'Los alimentos que se conservan en caliente se mantienen constantemente a una temperatura igual o mayor de 65º C.', N'Los alimentos que se están mantenidos en caliente por diversos sistemas como el fuego, chapa, baño maría, mesas calientes, tienen en el centro del producto 65º C y que el calor se distribuye correctamente por todo el producto. Además se comprobará que la temperatura de nuestro termómetro se corresponde con las anotadas en el registro._')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1568 AS Decimal(6, 0)), N'32             ', N'Dispone de resultados analíticos necesarios para verificar la composición del producto final y la cerveza y/o malta líquida elaboradas reúnen las características se¦aladas en cuanto a presentación (aspecto), acidez total expresada en ácido láctico, conten????', N'Características de la cerveza y de la malta líquida y métodos analíticos.
Se presentará límpida o ligeramente opalina, sin sedimento apreciable, a excepción de las refermentadas en su propio envase.
Se utilizarán los métodos analíticos oficiales aprobados para la determinación de los siguientes parámetros:
La acidez total, previa eliminación del anhídrido carbónico, expresada en ácido láctico, no será superior al 0.3%.
El anhídrido carbónico contenido no será inferior a 3 g / litro.
El contenido en glicerina no será superior a 3 g / litro.
El pH estará comprendido entre 3.5 y 5.
Las cenizas no serán superiores al 0.4% en masa.
El contenido en metales pesados no excederá de los siguientes límites máximos:
Cobre 1.0 ppm.
Zinc 1.0 ppm
Plomo 0.2 ppm.
Arsénico 0.1 ppm.
Cobalto 50 ppb.
El ácido fosfórico no sobrepasará los 0.12 g % expresado en P2O5
Los hidratos de carbono no sobrepasarán los 7.5 g % de cerveza.

Cervezas y maltas líquidas no aptas para el consumo:
Las que se presentan turbias o contengan un sedimento apreciable a simple vista, a excepción de las refermentadas en su propio envase.
Las que tengan olor, color o sabor anormales.
Las que por su análisis químico o examen microscópico u organoléptico acusen alteración.
Las adulteradas o que, en general, hayan sido objeto en su elaboración de una práctica no autorizada.
', N' ', N'Características de la cerveza y de la malta líquida y métodos analíticos.
Se presentará límpida o ligeramente opalina, sin sedimento apreciable, a excepción de las refermentadas en su propio envase.
Se utilizarán los métodos analíticos oficiales aprobados para la determinación de los siguientes parámetros:
La acidez total, previa eliminación del anhídrido carbónico, expresada en ácido láctico, no será superior al 0.3%.
El anhídrido carbónico contenido no será inferior a 3 g / litro.
El contenido en glicerina no será superior a 3 g / litro.
El pH estará comprendido entre 3.5 y 5.
Las cenizas no serán superiores al 0.4% en masa.
El contenido en metales pesados no excederá de los siguientes límites máximos:
Cobre 1.0 ppm.
Zinc 1.0 ppm
Plomo 0.2 ppm.
Arsénico 0.1 ppm.
Cobalto 50 ppb.
El ácido fosfórico no sobrepasará los 0.12 g % expresado en P2O5
Los hidratos de carbono no sobrepasarán los 7.5 g % de cerveza.

Cervezas y maltas líquidas no aptas para el consumo:
Las que se presentan turbias o contengan un sedimento apreciable a simple vista, a excepción de las refermentadas en su propio envase.
Las que tengan olor, color o sabor anormales.
Las que por su análisis químico o examen microscópico u organoléptico acusen alteración.
Las adulteradas o que, en general, hayan sido objeto en su elaboración de una práctica no autorizada.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1589 AS Decimal(6, 0)), N'3              ', N'Dispone de un local o emplazamiento aislado para el almacenamiento de útiles y vajilla limpios.', N'Local/emplazamiento de almacén de útiles y vajilla limpios.
Los útiles y la vajilla, tras su limpieza y desinfección deben almacenarse, protegidos de la contaminación. Dicho almacenamiento, puede realizarse en un local aislado o en un emplazamiento diferenciado, a modo de armario, en una zona limpia, entendiéndose como local posible el local de almacenamiento de contenedores y envases reutilizables limpios.', N'Dispone de un local o emplazamiento aislado para el almacenamiento de útiles y vajilla limpios.', N'Local/emplazamiento de almacén de útiles y vajilla limpios.
Los útiles y la vajilla, tras su limpieza y desinfección deben almacenarse, protegidos de la contaminación. Dicho almacenamiento, puede realizarse en un local aislado o en un emplazamiento diferenciado, a modo de armario, en una zona limpia, entendiéndose como local posible el local de almacenamiento de contenedores y envases reutilizables limpios.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1581 AS Decimal(6, 0)), N'3              ', N'Dispone de accesos adecuados para la materia prima, materia auxiliar, personal y expedición de producto.', N'Accesos adecuados para la materia prima, material auxiliar, personal y expedición de producto.
El acceso de las materias primas y materiales auxiliares hasta sus locales de almacenamiento, el acceso del personal hasta sus respectivos vestuarios y la expedición del producto, se realizará de un modo directo desde el exterior e independiente, evitando cruces entre los mismos. En edificios industriales con un solo portón de entrada, se permitirá la existencia de un recinto a modo de distribuidor, desde el cual acceder a los distintos locales descritos.', N' ', N'Accesos adecuados para la materia prima, material auxiliar, personal y expedición de producto.
El acceso de las materias primas y materiales auxiliares hasta sus locales de almacenamiento, el acceso del personal hasta sus respectivos vestuarios y la expedición del producto, se realizará de un modo directo desde el exterior e independiente, evitando cruces entre los mismos. En edificios industriales con un solo portón de entrada, se permitirá la existencia de un recinto a modo de distribuidor, desde el cual acceder a los distintos locales descritos.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1582 AS Decimal(6, 0)), N'3              ', N'Los contenedores y envases reutilizables acceden directamente desde el exterior hasta el local de limpieza.', N'Accesos adecuados de contenedores y envases reutilizables.
Los contenedores isotermos que han sido utilizados para la distribución de comida y los envases reutilizables en general, accederán de forma directa e independiente desde el exterior hasta el local de lavado, para su correspondiente limpieza y desinfección.', N'Los contenedores y envases reutilizables acceden directamente desde el exterior hasta el local de limpieza.', N'Accesos adecuados de contenedores y envases reutilizables.
Los contenedores isotermos que han sido utilizados para la distribución de comida y los envases reutilizables en general, accederán de forma directa e independiente desde el exterior hasta el local de lavado, para su correspondiente limpieza y desinfección.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1612 AS Decimal(6, 0)), N'65             ', N'Si la misma limitación cuantitativa se aplica a un grupo de componentes utilizados por separado o combinados, el porcentaje combinado se indica con una sola cifra.', N'En caso de que la misma limitación cuantitativa indicada en el punto anterior se aplique a un grupo de componentes utilizados por separado o combinados, el porcentaje combinado podrá indicarse con una sola cifra.', N'Si la misma limitación cuantitativa se aplica a un grupo de componentes utilizados por separado o combinados, el porcentaje combinado se indica con una sola cifra.', N'En caso de que la misma limitación cuantitativa indicada en el punto anterior se aplique a un grupo de componentes utilizados por separado o combinados, el porcentaje combinado podrá indicarse con una sola cifra.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1590 AS Decimal(6, 0)), N'3              ', N'Dispone de local para el almacenamiento de desperdicios, cuando es necesario.', N'Local para el almacenamiento de subproductos y/o desechos
Cuando sea necesario, debe disponer de un local específico para el almacenamiento de subproductos y/o desechos, con acceso directo exterior, para evitar cruces con zonas limpias.  ', N'Dispone de local para el almacenamiento de desperdicios, cuando es necesario.', N'Local para el almacenamiento de subproductos y/o desechos
Cuando sea necesario, debe disponer de un local específico para el almacenamiento de subproductos y/o desechos, con acceso directo exterior, para evitar cruces con zonas limpias.  ')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1580 AS Decimal(6, 0)), N'32             ', N'Ni se adiciona a los productos ni se dispone en el establecimiento de ácido acético que no proceda de productos de origen agrario.', N'Se prohibe la adición y tenencia en el establecimiento de ácido acético que no proceda de productos de origen agrario vino, frutas, sidra, alcohol destilado de origen agrícola, cereales, malta miel y suero de leche.', N'Ni se adiciona a los productos ni se dispone en el establecimiento de ácido acético que no proceda de productos de origen agrario.', N'Se prohibe la adición y tenencia en el establecimiento de ácido acético que no proceda de productos de origen agrario vino, frutas, sidra, alcohol destilado de origen agrícola, cereales, malta miel y suero de leche.')
GO
