INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1614 AS Decimal(6, 0)), N'65             ', N'No figurando en el envase el lote de fabricación y/o la identificación de la industria o establecimiento, figura esta en el documento comercial.', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, la identificación del lote de fabricación y la identificación del fabricante o envasador, podrán figurar sólo en documentos comerciales relativos a la partida, que se deberán presentar en el momento de la entrega o antes de ésta, a condición de que, en lugar visible del envase o del embalaje del producto considerado, figure la indicación para la fabricación de productos alimenticios, con exclusión de toda venta al por menor.', N'No figurando en el envase el lote de fabricación y/o la identificación de la industria o establecimiento, figura esta en el documento comercial.', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, la identificación del lote de fabricación y la identificación del fabricante o envasador, podrán figurar sólo en documentos comerciales relativos a la partida, que se deberán presentar en el momento de la entrega o antes de ésta, a condición de que, en lugar visible del envase o del embalaje del producto considerado, figure la indicación para la fabricación de productos alimenticios, con exclusión de toda venta al por menor.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1583 AS Decimal(6, 0)), N'3              ', N'Dispone de local (o dispositivo) para el almacenamiento de productos no perecederos .', N'Local para el almacenamiento de productos no perecederos.
Debe disponer de un local independiente ( o dispositivo, en el caso de establecimientos de poco volúmen) para el almacenamiento de productos que no requieren temperaturas de refrigeración para su conservación. El acceso de los mismos hasta sus respectivas zonas de manipulación y cocción se realizará directamente, evitando cruces.', N'Dispone de local (o dispositivo) para el almacenamiento de produc', N'Local para el almacenamiento de productos no perecederos.
Debe disponer de un local independiente ( o dispositivo, en el caso de establecimientos de poco volúmen) para el almacenamiento de productos que no requieren temperaturas de refrigeración para su conservación. El acceso de los mismos hasta sus respectivas zonas de manipulación y cocción se realizará directamente, evitando cruces.')
GO
