INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1611 AS Decimal(6, 0)), N'65             ', N'Aparece en el envase o embalaje la indicación del porcentaje de todo componente cuya incorporación a un alimento esté sujeta a una limitación cuantitativa, o una información adecuada sobre la composición.', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, la indicación del porcentaje de todo componente cuya incorporación a un alimento esté sujeta a una limitación cuantitativa, o una información adecuada sobre la composición para que el comprador pueda atenerse a las disposiciones comunitarias o, en su defecto, a las disposiciones nacionales aplicables al alimento de que se trate.', N'Aparece en el envase o embalaje la indicación del porcentaje de todo componente cuya incorporación a un alimento esté sujeta a una limitación cuantitativa, o una información adecuada sobre la composición.', N'En el caso de aditivos alimentarios que no se destinen a la venta al consumidor final, la indicación del porcentaje de todo componente cuya incorporación a un alimento esté sujeta a una limitación cuantitativa, o una información adecuada sobre la composición para que el comprador pueda atenerse a las disposiciones comunitarias o, en su defecto, a las disposiciones nacionales aplicables al alimento de que se trate.')
GO
