INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1690 AS Decimal(6, 0)), N'58             ', N'Dispone de horno mecanizado de calefacción indirecta y régimen continuo, o bien de calefacción directa si el combustible es gaseoso.', N'Horno mecanizado de calefacción indirecta y régimen continuo.
Debe disponer de horno mecanizado de calefacción indirecta y régimen continuo, aunque podrá ser de calefacción directa si el combustible es gaseoso.
Los paramentos y superficies exteriores de los hornos, deberán revestirse con material aislante, estarán separados de paredes y techos para que el aire circule libremente por ellos y serán fáciles de limpiar.
', N'Dispone de horno mecanizado de calefacción indirecta y régimen continuo, o bien de calefacción directa si el combustible es gaseoso.', N'Horno mecanizado de calefacción indirecta y régimen continuo.
Debe disponer de horno mecanizado de calefacción indirecta y régimen continuo, aunque podrá ser de calefacción directa si el combustible es gaseoso.
Los paramentos y superficies exteriores de los hornos, deberán revestirse con material aislante, estarán separados de paredes y techos para que el aire circule libremente por ellos y serán fáciles de limpiar.
')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1662 AS Decimal(6, 0)), N'3              ', N'El local de elaboración/envasado está suficientemente independizado de los almacenes.', N'Local de fabricación/elaboración y envasado/embalado
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará suficientemente aislado (independizado) de los locales de almacenamiento. En el caso de la utilización de patata sin pelar deberá disponer de un Local para las labores de pelado de las mismas, dichas labores se podrán realizar en una Zona diferenciada del local de elaboración si el establecimiento dispone de equipamiento e instalaciones para que las labores pelado y retirada de desechos se realicen de forma higiénica.', N'El local de elaboración/envasado está suficientemente independizado de los almacenes.', N'Local de fabricación/elaboración y envasado/embalado
Destinado a las diferentes labores a realizar hasta la obtención del producto terminado.
Estará suficientemente aislado (independizado) de los locales de almacenamiento. En el caso de la utilización de patata sin pelar deberá disponer de un Local para las labores de pelado de las mismas, dichas labores se podrán realizar en una Zona diferenciada del local de elaboración si el establecimiento dispone de equipamiento e instalaciones para que las labores pelado y retirada de desechos se realicen de forma higiénica.')
GO
