INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1617 AS Decimal(6, 0)), N'66             ', N'Aparece en el envase o embalaje la composición cualitativa de aromas o mezclas de aromas, y/o de mezclas de aromas con otras sustancias o con aditivos o productos para su disolución o dilución, de forma adecuada.', N'Se deberá incluir la composición cualitativa:
Cuando se trate de un aroma o mezcla de aromas se enumerarán por orden ponderal decreciente las categorías de sustancias aromatizantes presentes.
Cuando se trate de una mezcla de aromas con otras sustancias o materias, se enumeraran, por orden ponderal decreciente, en la mezcla: bien de las categorías de los aromas, bien el nombre de cada una de las otras sustancias o materias o, en su caso, de su número CEE.
', N'Aparece en el envase o embalaje la composición cualitativa de aromas o mezclas de aromas, y/o de mezclas de aromas con otras sustancias o con aditivos o productos para su disolución o dilución, de forma adecuada.', N'Se deberá incluir la composición cualitativa:
Cuando se trate de un aroma o mezcla de aromas se enumerarán por orden ponderal decreciente las categorías de sustancias aromatizantes presentes.
Cuando se trate de una mezcla de aromas con otras sustancias o materias, se enumeraran, por orden ponderal decreciente, en la mezcla: bien de las categorías de los aromas, bien el nombre de cada una de las otras sustancias o materias o, en su caso, de su número CEE.
')
GO
