INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1652 AS Decimal(6, 0)), N'32             ', N'La temperatura marcada por los registros es equivalente a las contrastadas por el técnico.', N'Los alimentos congelados
Se elaboran en condiciones tales que permiten alcanzar ?18ºC en el interior del producto en el menor tiempo posible, manteniendo se esta temperatura en todo momento, permitiéndose una fluctuación  + 3º C durante el transporte.
La temperatura marcada por el registro de las instalaciones de frío  y la  que contrasta el técnico con su termómetro deberán ser equivalentes.', N'La temperatura marcada por los registros es equivalente a las contrastadas por el técnico.', N'Los alimentos congelados
Se elaboran en condiciones tales que permiten alcanzar ?18ºC en el interior del producto en el menor tiempo posible, manteniendo se esta temperatura en todo momento, permitiéndose una fluctuación  + 3º C durante el transporte.
La temperatura marcada por el registro de las instalaciones de frío  y la  que contrasta el técnico con su termómetro deberán ser equivalentes.')
GO
INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1653 AS Decimal(6, 0)), N'32             ', N'Las temperaturas son las adecuadas.', N'Los alimentos congelados
Se elaboran en condiciones tales que permiten alcanzar ?18ºC en el interior del producto en el menor tiempo posible, manteniendo se esta temperatura en todo momento, permitiéndose una fluctuación  + 3º C durante el transporte.
La temperatura marcada por el registro de las instalaciones de frío  y la  que contrasta el técnico con su termómetro deberán ser equivalentes.', N'Las temperaturas son las adecuadas.', N'Los alimentos congelados
