INSERT [SYSPRO].[TSCIJPR3] ([TPR3_COD_IT], [TPR3_COD_PROTOCOLO], [TPR3_COD_TDT_GRUPO], [TPR3_DES_PROTO], [TPR3_TEX_PROTO], [TPR3_DES_PROTO_E], [TPR3_TEX_PROTO_E]) VALUES (CAST(21 AS Decimal(3, 0)), CAST(1654 AS Decimal(6, 0)), N'69             ', N'Cada envase lleva agrupadas en una de sus caras todas las indicaciones necesarias.', N'Agrupados en una de sus caras figuraran las indicaciones siguientes: denominación del producto, nombre de la variedad (caso de exigirlo la norma de calidad), categoría comercial, calibre, identificación de la empresa y origen de los productos (indicar la zona de producción. Para los productos importados el país de origen).', N'Cada envase lleva agrupadas en una de sus caras todas las indicaciones necesarias.', N'Agrupados en una de sus caras figuraran las indicaciones siguientes: denominación del producto, nombre de la variedad (caso de exigirlo la norma de calidad), categoría comercial, calibre, identificación de la empresa y origen de los productos (indicar la zona de producción. Para los productos importados el país de origen).')
GO
